fn runtime_intent_frame_from_trace(
    nl: &str,
    trace: &RuntimeQueryFrameTrace,
    atlas: &RuntimeSemanticAtlas,
) -> IntentFrameTrace {
    let mut intent = IntentFrameTrace {
        schema_version: 1,
        source: "runtime_intent_frame".to_string(),
        question: nl.to_string(),
        intent_kind: "rejected".to_string(),
        subject_entity: trace
            .projection
            .as_ref()
            .map(|projection| projection.entity.clone()),
        projections: Vec::new(),
        predicates: Vec::new(),
        dimensions: Vec::new(),
        measures: Vec::new(),
        time_windows: Vec::new(),
        order_by: trace.order_by.as_ref().map(|order| IntentFrameOrderTrace {
            field: order.field.clone(),
            expression: order.expression.clone(),
            direction: order.direction.clone(),
            limit: order.limit,
        }),
        limit: trace.order_by.as_ref().map(|order| order.limit),
        codebook_candidates: runtime_intent_codebook_candidates(nl, atlas),
        reject_reason: None,
        confidence: 0.0,
    };
    if !trace.routed {
        intent.reject_reason = Some(trace.route_reason.clone());
        return intent;
    }
    intent.confidence = 1.0;
    let sql = trace.sql.as_deref().unwrap_or_default();
    intent.intent_kind = runtime_intent_kind(trace, sql);
    if let Some(projection) = &trace.projection {
        if projection.fields.is_empty() {
            intent.projections.push(IntentFrameProjectionTrace {
                field: projection.field.clone(),
                expression: projection.expression.clone(),
                evidence: vec!["runtime_projection".to_string()],
            });
        } else {
            for field in &projection.fields {
                intent.projections.push(IntentFrameProjectionTrace {
                    field: Some(field.clone()),
                    expression: projection.expression.clone(),
                    evidence: vec!["runtime_projection_field".to_string()],
                });
            }
        }
        if runtime_expression_is_measure(&projection.expression) {
            intent.measures.push(projection.expression.clone());
        }
    }
    let groups = runtime_sql_group_by_expressions(sql);
    intent.dimensions = groups;
    for predicate in &trace.predicates {
        let evidence = runtime_predicate_value_evidence(nl, predicate, atlas);
        let predicate_trace = IntentFramePredicateTrace {
            field: predicate.field.clone(),
            operator: predicate.operator.clone(),
            value: predicate.value.clone(),
            evidence,
        };
        if atlas
            .field(&predicate.field)
            .is_some_and(graph_field_looks_date_like)
        {
            intent.time_windows.push(predicate_trace.clone());
        }
        intent.predicates.push(predicate_trace);
    }
    if let Some(order) = &trace.order_by {
        if runtime_expression_is_measure(&order.expression) {
            intent.measures.push(order.expression.clone());
        }
    }
    intent.measures.sort();
    intent.measures.dedup();
    intent
}

const RUNTIME_INTENT_CODEBOOK_LIMIT: usize = 24;
const RUNTIME_INTENT_CODEBOOK_PER_KIND_LIMIT: usize = 8;

fn runtime_intent_codebook_candidates(
    nl: &str,
    atlas: &RuntimeSemanticAtlas,
) -> Vec<SemanticAtlasCodebookCandidate> {
    let mut out = Vec::new();
    out.extend(atlas.lookup_entities(nl, RUNTIME_INTENT_CODEBOOK_PER_KIND_LIMIT));
    out.extend(atlas.lookup_fields(nl, RUNTIME_INTENT_CODEBOOK_PER_KIND_LIMIT));
    out.extend(atlas.lookup_values(nl, RUNTIME_INTENT_CODEBOOK_PER_KIND_LIMIT));
    out.extend(atlas.lookup_metrics(nl, RUNTIME_INTENT_CODEBOOK_PER_KIND_LIMIT));
    out.extend(atlas.lookup_join_paths(nl, RUNTIME_INTENT_CODEBOOK_PER_KIND_LIMIT));
    semantic_codebook_finish(out, RUNTIME_INTENT_CODEBOOK_LIMIT)
}

fn runtime_intent_kind(trace: &RuntimeQueryFrameTrace, sql: &str) -> String {
    let lower_sql = sql.to_ascii_lowercase();
    let Some(projection) = &trace.projection else {
        return "unknown".to_string();
    };
    let expression = projection.expression.to_ascii_lowercase();
    if lower_sql.contains(" group by ") && runtime_expression_is_measure(&projection.expression) {
        return "grouped_aggregate".to_string();
    }
    if lower_sql.contains(" group by ") && expression.contains("count(") {
        return "grouped_count".to_string();
    }
    if expression.contains("count(") {
        return "count".to_string();
    }
    if expression.starts_with("avg(") {
        return "average".to_string();
    }
    if expression.starts_with("sum(") {
        return "sum".to_string();
    }
    if expression.contains(" / ") || expression.contains("* 1.0") {
        return "ratio_metric".to_string();
    }
    if trace.order_by.is_some() {
        return "top_k".to_string();
    }
    if trace.predicates.is_empty() {
        "list".to_string()
    } else {
        "lookup".to_string()
    }
}

fn runtime_expression_is_measure(expression: &str) -> bool {
    let lower = expression.trim_start().to_ascii_lowercase();
    lower.starts_with("avg(")
        || lower.starts_with("sum(")
        || lower.starts_with("count(")
        || lower.contains(" / ")
        || lower.contains("* 1.0")
}

fn runtime_sql_group_by_expressions(sql: &str) -> Vec<String> {
    let lower = sql.to_ascii_lowercase();
    let Some(group_start) = lower.find(" group by ") else {
        return Vec::new();
    };
    let group_body_start = group_start + " group by ".len();
    let mut group_body_end = sql.len();
    for marker in [" order by ", " having ", " limit "] {
        if let Some(offset) = lower[group_body_start..].find(marker) {
            group_body_end = group_body_end.min(group_body_start + offset);
        }
    }
    sql[group_body_start..group_body_end]
        .split(',')
        .map(str::trim)
        .filter(|part| !part.is_empty())
        .map(ToString::to_string)
        .collect()
}

fn runtime_bound_query_plan_from_trace(
    nl: &str,
    trace: &RuntimeQueryFrameTrace,
    atlas: &RuntimeSemanticAtlas,
    intent: &IntentFrameTrace,
) -> BoundQueryPlanTrace {
    let mut plan = BoundQueryPlanTrace {
        schema_version: 1,
        source: "runtime_bound_query_plan".to_string(),
        valid: false,
        reject_reason: None,
        route_source: trace.source.clone(),
        base_entity: trace
            .projection
            .as_ref()
            .map(|projection| projection.entity.clone()),
        projections: Vec::new(),
        predicates: Vec::new(),
        joins: Vec::new(),
        groups: intent.dimensions.clone(),
        order_by: None,
        sql: trace.sql.clone(),
        diagnostics: Vec::new(),
    };
    if !trace.routed {
        plan.reject_reason = Some(trace.route_reason.clone());
        return plan;
    }
    if !runtime_sql_is_read_only_select(trace.sql.as_deref().unwrap_or_default()) {
        plan.reject_reason = Some("not_read_only_select".to_string());
        return plan;
    }
    let Some(projection) = &trace.projection else {
        plan.reject_reason = Some("missing_projection".to_string());
        return plan;
    };
    if atlas.entity(&projection.entity).is_none() {
        plan.reject_reason = Some("unknown_base_entity".to_string());
        return plan;
    }
    if projection.fields.is_empty() {
        let backed_by_atlas = projection
            .field
            .as_deref()
            .map(|field| atlas.field(field).is_some())
            .unwrap_or_else(|| runtime_expression_is_measure(&projection.expression));
        if !backed_by_atlas {
            plan.reject_reason = Some("unknown_projection_field".to_string());
            return plan;
        }
        plan.projections.push(BoundPlanProjectionTrace {
            field: projection.field.clone(),
            expression: projection.expression.clone(),
            backed_by_atlas,
            evidence: vec!["runtime_projection".to_string()],
        });
    } else {
        for field in &projection.fields {
            let backed_by_atlas = atlas.field(field).is_some();
            if !backed_by_atlas {
                plan.reject_reason = Some("unknown_projection_field".to_string());
                return plan;
            }
            plan.projections.push(BoundPlanProjectionTrace {
                field: Some(field.clone()),
                expression: projection.expression.clone(),
                backed_by_atlas,
                evidence: vec!["runtime_projection_field".to_string()],
            });
        }
    }
    for predicate in &trace.predicates {
        let backed_by_atlas = atlas.field(&predicate.field).is_some();
        if !backed_by_atlas {
            plan.reject_reason = Some("unknown_predicate_field".to_string());
            return plan;
        }
        if !runtime_predicate_operator_supported(&predicate.operator) {
            plan.reject_reason = Some("unsupported_predicate_operator".to_string());
            return plan;
        }
        let mut evidence = runtime_predicate_value_evidence(nl, predicate, atlas);
        if evidence.is_empty()
            && runtime_predicate_has_route_measure_threshold_evidence(predicate, trace, atlas)
        {
            evidence.push("route_measure_threshold".to_string());
        }
        if evidence.is_empty() {
            plan.diagnostics.push(BoundPlanDiagnosticTrace {
                code: "missing_value_evidence".to_string(),
                detail: format!(
                    "{} {} {}",
                    predicate.field, predicate.operator, predicate.value
                ),
            });
            plan.predicates.push(BoundPlanPredicateTrace {
                field: predicate.field.clone(),
                operator: predicate.operator.clone(),
                value: predicate.value.clone(),
                backed_by_atlas,
                evidence,
            });
            plan.reject_reason = Some("missing_value_evidence".to_string());
            return plan;
        }
        plan.predicates.push(BoundPlanPredicateTrace {
            field: predicate.field.clone(),
            operator: predicate.operator.clone(),
            value: predicate.value.clone(),
            backed_by_atlas,
            evidence,
        });
    }
    for step in &trace.joins {
        let from_field = format!("{}.{}", step.from_entity, step.from_field);
        let to_field = format!("{}.{}", step.to_entity, step.to_field);
        let backed_by_atlas = atlas.entity(&step.from_entity).is_some()
            && atlas.entity(&step.to_entity).is_some()
            && atlas
                .field_from_parts(&step.from_entity, &step.from_field)
                .is_some()
            && atlas
                .field_from_parts(&step.to_entity, &step.to_field)
                .is_some()
            && runtime_join_backed_by_relationship(step, atlas);
        if !backed_by_atlas {
            plan.reject_reason = Some("unknown_join_path".to_string());
            return plan;
        }
        plan.joins.push(BoundPlanJoinTrace {
            from_entity: step.from_entity.clone(),
            from_field,
            to_entity: step.to_entity.clone(),
            to_field,
            backed_by_atlas,
        });
    }
    if let Some(order) = &trace.order_by {
        let backed_by_atlas = atlas.field(&order.field).is_some();
        if !backed_by_atlas {
            plan.reject_reason = Some("unknown_order_field".to_string());
            return plan;
        }
        if order.limit > 100 {
            plan.reject_reason = Some("unsupported_limit".to_string());
            return plan;
        }
        plan.order_by = Some(BoundPlanOrderTrace {
            field: order.field.clone(),
            expression: order.expression.clone(),
            direction: order.direction.clone(),
            limit: order.limit,
            backed_by_atlas,
        });
    }
    if let Some(reject_reason) =
        runtime_bound_plan_semantic_reject_reason(nl, trace, atlas, intent, &plan)
    {
        plan.reject_reason = Some(reject_reason);
        return plan;
    }
    plan.valid = true;
    plan
}

fn runtime_sql_is_read_only_select(sql: &str) -> bool {
    let trimmed = sql.trim();
    if trimmed.is_empty() {
        return false;
    }
    let lower = trimmed.to_ascii_lowercase();
    lower.starts_with("select ")
        && ![
            " delete ",
            " update ",
            " insert ",
            " drop ",
            " alter ",
            " create ",
            " truncate ",
            " attach ",
            " detach ",
            " pragma ",
        ]
        .iter()
        .any(|needle| lower.contains(needle))
        && !lower.contains("select *")
}

fn runtime_predicate_operator_supported(operator: &str) -> bool {
    matches!(
        operator,
        "=" | "!=" | "<>" | "<" | "<=" | ">" | ">=" | "range" | "in"
    )
}

fn runtime_bound_plan_semantic_reject_reason(
    nl: &str,
    trace: &RuntimeQueryFrameTrace,
    atlas: &RuntimeSemanticAtlas,
    intent: &IntentFrameTrace,
    plan: &BoundQueryPlanTrace,
) -> Option<String> {
    let lower = format!(" {} ", nl.to_ascii_lowercase().replace('\n', " "));
    if runtime_prompt_requests_anti_join(&lower)
        && trace.source != "runtime_graph_query_frame_anti_join_temporal"
    {
        return Some("unsupported_anti_join_shape".to_string());
    }
    if runtime_prompt_months(&lower).next().is_some()
        && runtime_plan_collapsed_month_to_year(plan, atlas)
    {
        return Some("missing_month_date_window".to_string());
    }
    if runtime_prompt_requests_group_dimension(&lower, intent, trace)
        && intent.dimensions.is_empty()
    {
        return Some("missing_group_dimension".to_string());
    }
    if trace.source == "runtime_graph_query_frame_grouped_aggregate" {
        if let Some(reject_reason) =
            runtime_bound_plan_grouped_aggregate_semantic_reject_reason(nl, trace, atlas)
        {
            return Some(reject_reason);
        }
    }
    if runtime_prompt_requests_superlative_order(&lower) && trace.order_by.is_none() {
        return Some("missing_superlative_order".to_string());
    }
    if runtime_prompt_requests_comparison(&lower)
        && !runtime_plan_has_comparison_dimension(trace, plan)
    {
        return Some("missing_comparison_dimension".to_string());
    }
    if runtime_prompt_has_named_month_or_quarter(&lower)
        && !runtime_plan_has_specific_date_window(plan, atlas)
    {
        return Some("missing_specific_date_window".to_string());
    }
    if runtime_prompt_contains_numeric_threshold(nl)
        && !runtime_plan_has_numeric_threshold_predicate(nl, plan, atlas)
    {
        return Some("missing_numeric_threshold".to_string());
    }
    if runtime_prompt_contains_numeric_range(nl)
        && !runtime_plan_has_numeric_range_predicate(plan, atlas)
        && !runtime_plan_numeric_range_satisfied_by_selected_fields(nl, plan, trace, atlas)
    {
        return Some("missing_numeric_range_predicate".to_string());
    }
    if runtime_prompt_requests_row_projection_but_plan_counts(&lower, trace) {
        return Some("missing_requested_row_projection".to_string());
    }
    if runtime_prompt_requested_date_projection_missing(&lower, trace, atlas) {
        return Some("missing_requested_date_projection".to_string());
    }
    if runtime_prompt_date_role_mismatch(&lower, plan, atlas) {
        return Some("date_role_mismatch".to_string());
    }
    if runtime_prompt_actor_filter_missing(&lower, plan, atlas) {
        return Some("missing_actor_filter".to_string());
    }
    if runtime_plan_has_role_word_value_misbound(nl, plan, atlas) {
        return Some("role_word_value_misbound".to_string());
    }
    if runtime_prompt_superlative_order_field_mismatch(nl, trace, atlas) {
        return Some("order_field_mismatch".to_string());
    }
    if runtime_prompt_ratio_of_groups_mismatch(&lower, trace) {
        return Some("ratio_shape_mismatch".to_string());
    }
    if runtime_prompt_explicit_numeric_predicate_field_missing(nl, plan, atlas) {
        return Some("missing_explicit_predicate_field".to_string());
    }
    if runtime_prompt_high_confidence_value_candidate_missing(nl, plan, intent) {
        return Some("missing_value_candidate".to_string());
    }
    if runtime_prompt_related_predicate_field_ambiguity(nl, plan, atlas) {
        return Some("ambiguous_related_predicate_field".to_string());
    }
    if runtime_prompt_subject_entity_mismatch(nl, trace, atlas) {
        return Some("subject_entity_mismatch".to_string());
    }
    if runtime_prompt_relation_display_projection_missing(&lower, trace, atlas, intent) {
        return Some("missing_related_display_projection".to_string());
    }
    if runtime_prompt_requested_projection_missing(nl, trace, atlas) {
        return Some("missing_requested_projection".to_string());
    }
    if runtime_prompt_scope_predicate_misbound(nl, trace, atlas) {
        return Some("misbound_scope_predicate".to_string());
    }
    if runtime_plan_has_lifecycle_event_ambiguity(nl, trace, atlas, plan) {
        return Some("missing_lifecycle_event_table".to_string());
    }
    None
}

fn runtime_prompt_contains_numeric_range(nl: &str) -> bool {
    let lower = format!(" {} ", nl.to_ascii_lowercase().replace('\n', " "));
    if lower.contains(" between ")
        && (lower.contains(" and ") || lower.contains(" to "))
        && graph_literal_tokens(nl)
            .iter()
            .filter(|literal| graph_is_plain_number(literal))
            .count()
            >= 2
    {
        return true;
    }
    let compact = nl
        .chars()
        .filter(|ch| !matches!(ch, ',' | '_' | ' '))
        .collect::<String>();
    let chars = compact.chars().collect::<Vec<_>>();
    chars.windows(3).any(|window| {
        window[0].is_ascii_digit()
            && matches!(window[1], '-' | '–' | '—')
            && window[2].is_ascii_digit()
    })
}

fn runtime_plan_has_numeric_range_predicate(
    plan: &BoundQueryPlanTrace,
    atlas: &RuntimeSemanticAtlas,
) -> bool {
    if plan.predicates.iter().any(|predicate| {
        predicate.operator == "range"
            && atlas
                .field(&predicate.field)
                .is_some_and(graph_field_looks_numeric)
    }) {
        return true;
    }
    let mut comparison_fields = HashSet::new();
    for predicate in &plan.predicates {
        if !matches!(predicate.operator.as_str(), ">" | ">=" | "<" | "<=") {
            continue;
        }
        if atlas
            .field(&predicate.field)
            .is_some_and(graph_field_looks_numeric)
            && !comparison_fields.insert(predicate.field.to_ascii_lowercase())
        {
            return true;
        }
    }
    false
}

fn runtime_plan_numeric_range_satisfied_by_selected_fields(
    nl: &str,
    plan: &BoundQueryPlanTrace,
    trace: &RuntimeQueryFrameTrace,
    atlas: &RuntimeSemanticAtlas,
) -> bool {
    let markers = runtime_prompt_numeric_range_markers(nl);
    if markers.is_empty() {
        return false;
    }
    let mut field_keys = Vec::new();
    for projection in &plan.projections {
        if let Some(field) = &projection.field {
            field_keys.push(field.as_str());
        }
    }
    if let Some(projection) = &trace.projection {
        field_keys.extend(projection.fields.iter().map(String::as_str));
    }
    if let Some(order) = &trace.order_by {
        field_keys.push(order.field.as_str());
    }
    field_keys.into_iter().any(|field_key| {
        atlas.field(field_key).is_some_and(|field| {
            let mut forms = semantic_field_aliases(field, &atlas.vocabulary);
            forms.push(field.field.clone());
            forms.push(field.db_column.clone());
            if let Some(label) = &field.display_label {
                forms.push(label.clone());
            }
            forms.into_iter().any(|form| {
                let compact = graph_alnum_compact(&form);
                markers.iter().any(|marker| compact.contains(marker))
            })
        })
    })
}

fn runtime_prompt_numeric_range_markers(nl: &str) -> Vec<String> {
    let chars = nl.chars().collect::<Vec<_>>();
    let mut markers = Vec::new();
    for (idx, ch) in chars.iter().enumerate() {
        if !matches!(ch, '-' | '–' | '—') {
            continue;
        }
        let mut left_start = idx;
        while left_start > 0 && chars[left_start - 1].is_ascii_digit() {
            left_start -= 1;
        }
        let mut right_end = idx + 1;
        while right_end < chars.len() && chars[right_end].is_ascii_digit() {
            right_end += 1;
        }
        if left_start == idx || right_end == idx + 1 {
            continue;
        }
        let left = chars[left_start..idx].iter().collect::<String>();
        let right = chars[idx + 1..right_end].iter().collect::<String>();
        for marker in [
            format!("{left}{right}"),
            format!("age{left}{right}"),
            format!("ages{left}{right}"),
        ] {
            if !markers.iter().any(|existing| existing == &marker) {
                markers.push(marker);
            }
        }
    }
    markers
}

fn graph_alnum_compact(text: &str) -> String {
    text.chars()
        .filter(|ch| ch.is_ascii_alphanumeric())
        .map(|ch| ch.to_ascii_lowercase())
        .collect()
}

fn runtime_prompt_requests_row_projection_but_plan_counts(
    lower: &str,
    trace: &RuntimeQueryFrameTrace,
) -> bool {
    let Some(projection) = &trace.projection else {
        return false;
    };
    if !projection.expression.eq_ignore_ascii_case("COUNT(*)") {
        return false;
    }
    if lower.contains(" how many ") || lower.contains(" count ") || lower.contains(" number of ") {
        return false;
    }
    lower.contains(" what are ")
        || lower.contains(" which ")
        || lower.contains(" list ")
        || lower.contains(" show ")
        || lower.contains(" give ")
        || lower.contains(" state ")
        || lower.contains(" include ")
}

fn runtime_prompt_requested_date_projection_missing(
    lower: &str,
    trace: &RuntimeQueryFrameTrace,
    atlas: &RuntimeSemanticAtlas,
) -> bool {
    let Some(role) = runtime_prompt_requested_date_role(lower) else {
        return false;
    };
    if !(lower.contains(" when ") || lower.starts_with(" when ")) {
        return false;
    }
    let Some(projection) = &trace.projection else {
        return true;
    };
    let projected_date_matches = projection
        .field
        .as_deref()
        .into_iter()
        .chain(projection.fields.iter().map(String::as_str))
        .filter_map(|field| atlas.field(field))
        .any(|field| {
            graph_field_looks_date_like(field) && runtime_field_matches_date_role(field, role)
        });
    !projected_date_matches
}

fn runtime_prompt_date_role_mismatch(
    lower: &str,
    plan: &BoundQueryPlanTrace,
    atlas: &RuntimeSemanticAtlas,
) -> bool {
    let Some(role) = runtime_prompt_requested_date_role(lower) else {
        return false;
    };
    let mut saw_date = false;
    let mut saw_matching = false;
    for predicate in &plan.predicates {
        let Some(field) = atlas.field(&predicate.field) else {
            continue;
        };
        if !graph_field_looks_date_like(field) {
            continue;
        }
        saw_date = true;
        if runtime_field_matches_date_role(field, role) {
            saw_matching = true;
        }
    }
    saw_date && !saw_matching
}

fn runtime_prompt_requested_date_role(lower: &str) -> Option<&'static str> {
    if lower.contains(" when did ") && lower.contains(" open") {
        return Some("start");
    }
    if [
        " opened ",
        " created ",
        " started ",
        " began ",
        " launched ",
    ]
    .iter()
    .any(|marker| lower.contains(marker))
    {
        return Some("start");
    }
    if lower.contains(" when did ") && lower.contains(" close") {
        return Some("end");
    }
    if [
        " closed ",
        " ended ",
        " finished ",
        " cancelled ",
        " canceled ",
    ]
    .iter()
    .any(|marker| lower.contains(marker))
    {
        return Some("end");
    }
    None
}

fn runtime_field_matches_date_role(field: &FieldRow, role: &str) -> bool {
    let haystack = graph_norm(&format!(
        "{} {} {}",
        field.db_column,
        field.field,
        field.display_label.as_deref().unwrap_or_default()
    ));
    let compact = graph_compact_field_name(field);
    match role {
        "start" => [
            "open", "opened", "start", "started", "create", "created", "begin", "launch",
        ]
        .iter()
        .any(|token| {
            graph_norm_contains(&haystack, token) || (token.len() >= 4 && compact.contains(token))
        }),
        "end" => [
            "close",
            "closed",
            "end",
            "ended",
            "finish",
            "cancel",
            "cancelled",
            "canceled",
        ]
        .iter()
        .any(|token| {
            graph_norm_contains(&haystack, token) || (token.len() >= 4 && compact.contains(token))
        }),
        _ => false,
    }
}

fn runtime_prompt_actor_filter_missing(
    lower: &str,
    plan: &BoundQueryPlanTrace,
    atlas: &RuntimeSemanticAtlas,
) -> bool {
    let actor_markers = [
        " managed by ",
        " owned by ",
        " assigned to ",
        " assigned by ",
        " handled by ",
        " created by ",
    ];
    if !actor_markers.iter().any(|marker| lower.contains(marker)) {
        return false;
    }
    plan.predicates.iter().all(|predicate| {
        atlas.field(&predicate.field).map_or(true, |field| {
            !(graph_field_looks_display_field(field)
                || graph_person_first_name_field(field)
                || graph_person_last_name_field(field)
                || graph_field_looks_status_like(field))
        })
    })
}

fn runtime_plan_has_role_word_value_misbound(
    nl: &str,
    plan: &BoundQueryPlanTrace,
    atlas: &RuntimeSemanticAtlas,
) -> bool {
    plan.predicates.iter().any(|predicate| {
        if predicate.operator != "="
            || graph_value_appears_quoted(nl, &graph_norm(&predicate.value))
        {
            return false;
        }
        let Some(field) = atlas.field(&predicate.field) else {
            return false;
        };
        if graph_field_looks_status_like(field) || is_boolean_field_type(&field.field_type) {
            return false;
        }
        let value_norm = graph_norm(graph_unquote_predicate_value(&predicate.value));
        if !runtime_role_word_values().contains(value_norm.as_str()) {
            return false;
        }
        let context = graph_norm(&graph_mention_context(nl, &predicate.value));
        if runtime_context_explicitly_targets_field(&context, field, atlas) {
            return false;
        }
        graph_field_looks_display_field(field)
            || graph_person_first_name_field(field)
            || graph_person_last_name_field(field)
    })
}

fn runtime_role_word_values() -> HashSet<&'static str> {
    [
        "administrator",
        "admin",
        "manager",
        "owner",
        "agent",
        "assignee",
        "handler",
        "free",
        "paid",
    ]
    .into_iter()
    .collect()
}

fn runtime_context_explicitly_targets_field(
    context_norm: &str,
    field: &FieldRow,
    atlas: &RuntimeSemanticAtlas,
) -> bool {
    let context_tokens = graph_tokens(context_norm);
    let field_tokens = graph_field_tokens_with_vocab(field, &atlas.vocabulary);
    !context_tokens.is_disjoint(&field_tokens)
        || semantic_field_aliases(field, &atlas.vocabulary)
            .iter()
            .any(|alias| graph_norm_contains(context_norm, &graph_norm(alias)))
        || [" named ", " name is ", " last name ", " first name "]
            .iter()
            .any(|marker| format!(" {context_norm} ").contains(marker))
}

fn runtime_prompt_superlative_order_field_mismatch(
    nl: &str,
    trace: &RuntimeQueryFrameTrace,
    atlas: &RuntimeSemanticAtlas,
) -> bool {
    if trace.source == "runtime_graph_query_frame_attribute" {
        return false;
    }
    let Some(order) = &trace.order_by else {
        return false;
    };
    let Some(phrase) = runtime_superlative_order_phrase(nl) else {
        return false;
    };
    let Some(order_field) = atlas.field(&order.field) else {
        return false;
    };
    if runtime_phrase_matches_field(&phrase, order_field, atlas) {
        return false;
    }
    let required_entities = trace
        .required_entities
        .iter()
        .map(|entity| entity.to_ascii_lowercase())
        .collect::<HashSet<_>>();
    atlas.fields.values().any(|field| {
        (required_entities.is_empty()
            || required_entities.contains(&field.entity.to_ascii_lowercase()))
            && runtime_phrase_matches_field(&phrase, field, atlas)
    })
}

fn runtime_superlative_order_phrase(nl: &str) -> Option<String> {
    let tokens = graph_ordered_tokens(nl);
    let marker_idx = tokens.iter().position(|token| {
        matches!(
            token.as_str(),
            "most"
                | "least"
                | "highest"
                | "lowest"
                | "largest"
                | "smallest"
                | "biggest"
                | "fewest"
                | "greatest"
                | "first"
                | "last"
        )
    })?;
    let mut phrase = Vec::new();
    for token in tokens.iter().skip(marker_idx + 1) {
        if matches!(
            token.as_str(),
            "open"
                | "opened"
                | "closed"
                | "close"
                | "created"
                | "start"
                | "started"
                | "in"
                | "where"
                | "with"
                | "whose"
                | "which"
                | "what"
                | "list"
                | "show"
        ) {
            break;
        }
        if !matches!(
            token.as_str(),
            "the" | "a" | "an" | "of" | "by" | "for" | "to" | "from"
        ) && token.parse::<u32>().is_err()
        {
            phrase.push(token.clone());
        }
    }
    (!phrase.is_empty()).then(|| phrase.join(" "))
}

fn runtime_phrase_matches_field(
    phrase: &str,
    field: &FieldRow,
    atlas: &RuntimeSemanticAtlas,
) -> bool {
    let phrase_tokens = graph_name_tokens(phrase);
    runtime_term_matches_field(phrase, &phrase_tokens, field, atlas)
}

fn runtime_prompt_ratio_of_groups_mismatch(lower: &str, trace: &RuntimeQueryFrameTrace) -> bool {
    if !lower.contains(" ratio of ") || !lower.contains(" to ") {
        return false;
    }
    if trace.source != "runtime_graph_query_frame_metric" {
        return false;
    }
    let expression = trace
        .projection
        .as_ref()
        .map(|projection| projection.expression.to_ascii_lowercase())
        .unwrap_or_default();
    trace.order_by.is_some() || (!expression.contains("case when") && trace.predicates.len() >= 2)
}

fn runtime_prompt_explicit_numeric_predicate_field_missing(
    nl: &str,
    plan: &BoundQueryPlanTrace,
    atlas: &RuntimeSemanticAtlas,
) -> bool {
    for term in runtime_explicit_numeric_field_terms(nl) {
        let term_tokens = graph_name_tokens(&term);
        if term_tokens.is_empty() {
            continue;
        }
        let candidates = atlas
            .fields
            .values()
            .filter(|field| {
                graph_field_looks_numeric(field)
                    && runtime_term_matches_field(&term, &term_tokens, field, atlas)
            })
            .map(|field| field.canonical().to_ascii_lowercase())
            .collect::<HashSet<_>>();
        if candidates.is_empty() {
            continue;
        }
        let has_predicate = plan
            .predicates
            .iter()
            .any(|predicate| candidates.contains(&predicate.field.to_ascii_lowercase()));
        if !has_predicate {
            return true;
        }
    }
    false
}

fn runtime_explicit_numeric_field_terms(nl: &str) -> Vec<String> {
    let mut out = Vec::new();
    for literal in graph_literal_tokens(nl) {
        if !graph_is_plain_number(&literal) || graph_is_year_literal(&literal) {
            continue;
        }
        let context = graph_mention_context(nl, &literal);
        let tokens = graph_ordered_tokens(&context);
        let literal_digits = literal
            .chars()
            .filter(|ch| ch.is_ascii_digit())
            .collect::<String>();
        let Some(index) = tokens.iter().position(|token| {
            token
                .chars()
                .filter(|ch| ch.is_ascii_digit())
                .collect::<String>()
                == literal_digits
        }) else {
            continue;
        };
        let mut prefix = tokens[..index].to_vec();
        while prefix.last().is_some_and(|token| {
            matches!(
                token.as_str(),
                "is" | "are"
                    | "was"
                    | "were"
                    | "equals"
                    | "equal"
                    | "greater"
                    | "less"
                    | "than"
                    | "over"
                    | "under"
                    | "above"
                    | "below"
                    | "at"
                    | "least"
                    | "more"
                    | "not"
                    | "no"
            )
        }) {
            prefix.pop();
        }
        let start = prefix
            .iter()
            .rposition(|token| {
                matches!(
                    token.as_str(),
                    "which"
                        | "where"
                        | "with"
                        | "whose"
                        | "and"
                        | "or"
                        | "the"
                        | "a"
                        | "an"
                        | "of"
                        | "for"
                        | "in"
                )
            })
            .map(|idx| idx + 1)
            .unwrap_or(0);
        let term_tokens = prefix[start..]
            .iter()
            .filter(|token| {
                !matches!(
                    token.as_str(),
                    "the" | "a" | "an" | "of" | "for" | "in" | "to" | "from"
                )
            })
            .take(5)
            .cloned()
            .collect::<Vec<_>>();
        if !term_tokens.is_empty() {
            out.push(term_tokens.join(" "));
        }
    }
    out.sort();
    out.dedup();
    out
}

fn runtime_bound_plan_grouped_aggregate_semantic_reject_reason(
    nl: &str,
    trace: &RuntimeQueryFrameTrace,
    atlas: &RuntimeSemanticAtlas,
) -> Option<String> {
    let projection = trace.projection.as_ref()?;
    let fields = atlas.fields.values().cloned().collect::<Vec<_>>();
    let field_map = graph_field_map(&fields);
    let expr = projection.expression.to_ascii_lowercase();
    if !expr.starts_with("count(")
        && !graph_grouped_aggregate_has_requested_measure(nl, trace, &fields, &atlas.vocabulary)
    {
        return Some("missing_grouped_measure_signal".to_string());
    }
    for field_key in &projection.fields {
        let Some(field) = field_map.get(field_key) else {
            continue;
        };
        if graph_field_looks_identity_or_relationship_key(field, trace, &atlas.vocabulary) {
            return Some("unsafe_grouped_dimension".to_string());
        }
    }
    if !expr.starts_with("count(")
        && fields.iter().any(|field| {
            graph_expr_contains_field_ref(&expr, field)
                && graph_field_looks_identity_or_relationship_key(field, trace, &atlas.vocabulary)
        })
    {
        return Some("unsafe_grouped_measure".to_string());
    }
    if !expr.starts_with("count(")
        && graph_grouped_measure_anchor_mismatch(nl, trace, &fields, &atlas.vocabulary)
    {
        return Some("grouped_measure_entity_mismatch".to_string());
    }
    let groups = runtime_sql_group_by_expressions(trace.sql.as_deref().unwrap_or_default());
    let group_exprs = groups
        .iter()
        .map(|group| group.trim().to_ascii_lowercase())
        .collect::<HashSet<_>>();
    let group_fields = fields
        .iter()
        .filter(|field| {
            group_exprs
                .iter()
                .any(|expr| graph_group_expr_matches_field(expr, field))
        })
        .collect::<Vec<_>>();
    if graph_group_over_time_dimension_field(nl, &projection.entity, &fields, &atlas.vocabulary)
        .is_some()
        && (group_fields.len() < 2
            || !group_fields
                .iter()
                .any(|field| graph_field_looks_date_like(field))
            || !group_fields
                .iter()
                .any(|field| !graph_field_looks_date_like(field)))
    {
        return Some("missing_grouped_time_dimension".to_string());
    }
    if fields.iter().any(|field| {
        group_exprs
            .iter()
            .any(|expr| graph_group_expr_matches_field(expr, field))
            && graph_field_looks_identity_or_relationship_key(field, trace, &atlas.vocabulary)
    }) {
        return Some("unsafe_grouped_dimension".to_string());
    }
    None
}

fn runtime_plan_has_lifecycle_event_ambiguity(
    nl: &str,
    trace: &RuntimeQueryFrameTrace,
    atlas: &RuntimeSemanticAtlas,
    plan: &BoundQueryPlanTrace,
) -> bool {
    if !graph_prompt_mentions_lifecycle_event(nl) {
        return false;
    }
    let Some(base_entity) = plan.base_entity.as_deref().or_else(|| {
        trace
            .projection
            .as_ref()
            .map(|projection| projection.entity.as_str())
    }) else {
        return false;
    };
    let Some(status_values) = plan.predicates.iter().find_map(|predicate| {
        let field = atlas.field(&predicate.field)?;
        (field.entity.eq_ignore_ascii_case(base_entity)
            && predicate.operator == "="
            && graph_field_looks_status_like(field)
            && graph_lifecycle_status_value(&predicate.value))
        .then(|| {
            graph_lifecycle_equivalent_status_values(graph_unquote_predicate_value(
                &predicate.value,
            ))
        })
    }) else {
        return false;
    };
    let base_non_lifecycle_date_window = plan.predicates.iter().any(|predicate| {
        atlas.field(&predicate.field).is_some_and(|field| {
            field.entity.eq_ignore_ascii_case(base_entity)
                && graph_field_looks_date_like(field)
                && !graph_field_looks_lifecycle_date(field)
                && predicate.operator == "range"
        })
    });
    if !base_non_lifecycle_date_window {
        return false;
    }
    let related_lifecycle_entities: HashSet<String> = atlas
        .fields
        .values()
        .filter(|field| {
            !field.entity.eq_ignore_ascii_case(base_entity)
                && runtime_entity_related_to_base(&field.entity, base_entity, atlas)
                && graph_field_looks_status_like(field)
                && runtime_atlas_sample_value_contains_any(atlas, field, &status_values)
        })
        .map(|field| field.entity.clone())
        .collect();
    if related_lifecycle_entities.is_empty() {
        return false;
    }
    atlas.fields.values().any(|field| {
        related_lifecycle_entities.contains(&field.entity)
            && graph_field_looks_lifecycle_date(field)
    })
}

fn runtime_entity_related_to_base(
    entity: &str,
    base_entity: &str,
    atlas: &RuntimeSemanticAtlas,
) -> bool {
    atlas.relationships.iter().any(|relationship| {
        (relationship.from_entity.eq_ignore_ascii_case(entity)
            && relationship.to_entity.eq_ignore_ascii_case(base_entity))
            || (relationship.from_entity.eq_ignore_ascii_case(base_entity)
                && relationship.to_entity.eq_ignore_ascii_case(entity))
    })
}

fn runtime_atlas_sample_value_contains_any(
    atlas: &RuntimeSemanticAtlas,
    field: &FieldRow,
    values: &HashSet<String>,
) -> bool {
    atlas
        .sample_values
        .get(&field.canonical().to_ascii_lowercase())
        .is_some_and(|row| {
            row.examples
                .iter()
                .any(|sample| values.contains(&graph_norm(sample)))
        })
}

fn runtime_prompt_requests_anti_join(lower: &str) -> bool {
    (lower.contains(" no ")
        || lower.contains(" without ")
        || lower.contains(" have not ")
        || lower.contains(" has not ")
        || lower.contains(" not had "))
        && (lower.contains(" event")
            || lower.contains(" activity")
            || lower.contains(" login")
            || lower.contains(" ticket")
            || lower.contains(" invoice"))
}

fn runtime_prompt_months(lower: &str) -> impl Iterator<Item = &'static str> + '_ {
    [
        " january ",
        " february ",
        " march ",
        " april ",
        " may ",
        " june ",
        " july ",
        " august ",
        " september ",
        " october ",
        " november ",
        " december ",
    ]
    .into_iter()
    .filter(move |month| lower.contains(month))
}

fn runtime_plan_collapsed_month_to_year(
    plan: &BoundQueryPlanTrace,
    atlas: &RuntimeSemanticAtlas,
) -> bool {
    plan.predicates.iter().any(|predicate| {
        atlas
            .field(&predicate.field)
            .is_some_and(graph_field_looks_date_like)
            && graph_is_year_literal(&predicate.value)
            && predicate.operator != "range"
    })
}

fn runtime_prompt_has_named_month_or_quarter(lower: &str) -> bool {
    runtime_prompt_months(lower).next().is_some() || runtime_prompt_has_quarter_date_window(lower)
}

fn runtime_prompt_has_quarter_date_window(lower: &str) -> bool {
    [
        " first quarter ",
        " second quarter ",
        " third quarter ",
        " fourth quarter ",
    ]
    .iter()
    .any(|marker| lower.contains(marker))
        || ([" q1 ", " q2 ", " q3 ", " q4 "]
            .iter()
            .any(|marker| lower.contains(marker))
            && (lower.contains(" 19")
                || lower.contains(" 20")
                || lower.contains(" fy")
                || lower.contains(" quarter ")))
}

fn runtime_plan_has_specific_date_window(
    plan: &BoundQueryPlanTrace,
    atlas: &RuntimeSemanticAtlas,
) -> bool {
    plan.predicates.iter().any(|predicate| {
        atlas
            .field(&predicate.field)
            .is_some_and(graph_field_looks_date_like)
            && (predicate.operator == "range"
                || (!graph_is_year_literal(&predicate.value)
                    && (graph_is_date_like(&predicate.value) || predicate.value.contains(".."))))
    })
}

fn runtime_prompt_requests_group_dimension(
    lower: &str,
    intent: &IntentFrameTrace,
    trace: &RuntimeQueryFrameTrace,
) -> bool {
    if !lower.contains(" by ") {
        return false;
    }
    if [
        " owned by ",
        " edited by ",
        " created by ",
        " assigned by ",
        " managed by ",
        " handled by ",
        " used by ",
    ]
    .iter()
    .any(|marker| lower.contains(marker))
    {
        return false;
    }
    if trace.order_by.is_some() && runtime_prompt_requests_superlative_order(lower) {
        return false;
    }
    if runtime_prompt_requests_time_series_group_dimension(lower) {
        return true;
    }
    matches!(
        intent.intent_kind.as_str(),
        "count" | "average" | "sum" | "grouped_count" | "grouped_aggregate" | "ratio_metric"
    ) || !intent.measures.is_empty()
}

fn runtime_prompt_requests_time_series_group_dimension(lower: &str) -> bool {
    lower.contains(" by ")
        && [
            " daily ",
            " weekly ",
            " monthly ",
            " yearly ",
            " per day ",
            " per week ",
            " per month ",
            " per year ",
        ]
        .iter()
        .any(|marker| lower.contains(marker))
}

fn runtime_prompt_requests_superlative_order(lower: &str) -> bool {
    [
        " top ",
        " most ",
        " least ",
        " highest ",
        " lowest ",
        " largest ",
        " smallest ",
        " biggest ",
        " best ",
        " worst ",
        " fastest ",
        " slowest ",
        " longest ",
        " shortest ",
        " ranked ",
        " rank ",
    ]
    .iter()
    .any(|marker| lower.contains(marker))
}

fn runtime_prompt_requests_comparison(lower: &str) -> bool {
    [
        " compare ",
        " compared ",
        " comparison ",
        " versus ",
        " vs ",
        " vs. ",
    ]
    .iter()
    .any(|marker| lower.contains(marker))
}

fn runtime_plan_has_comparison_dimension(
    trace: &RuntimeQueryFrameTrace,
    plan: &BoundQueryPlanTrace,
) -> bool {
    !plan.groups.is_empty()
        || trace
            .order_by
            .as_ref()
            .is_some_and(|order| order.limit == 0)
        || plan.predicates.iter().any(|predicate| {
            predicate.operator.eq_ignore_ascii_case("in")
                || predicate.value.contains(',')
                || predicate.value.contains('|')
        })
}

fn runtime_prompt_contains_numeric_threshold(nl: &str) -> bool {
    !runtime_prompt_numeric_threshold_literals(nl).is_empty()
}

fn runtime_prompt_numeric_threshold_literals(nl: &str) -> Vec<String> {
    graph_literal_tokens(nl)
        .into_iter()
        .filter(|literal| graph_is_plain_number(literal))
        .filter(|literal| {
            let context = graph_mention_context(nl, literal).to_ascii_lowercase();
            if graph_is_year_literal(literal) {
                return false;
            }
            if context.contains(" top ")
                || context.contains(" first ")
                || context.contains(" last ")
                || context.contains(" q1 ")
                || context.contains(" q2 ")
                || context.contains(" q3 ")
                || context.contains(" q4 ")
            {
                return false;
            }
            [
                " over ",
                " above ",
                " greater than ",
                " more than ",
                " at least ",
                " under ",
                " below ",
                " less than ",
                " fewer than ",
                " scored ",
                " score ",
                " rating ",
                " rated ",
                " exactly ",
                " equals ",
                " equal to ",
                " = ",
                " > ",
                " < ",
                " >= ",
                " <= ",
            ]
            .iter()
            .any(|marker| context.contains(marker))
        })
        .collect()
}

fn runtime_plan_has_numeric_threshold_predicate(
    nl: &str,
    plan: &BoundQueryPlanTrace,
    atlas: &RuntimeSemanticAtlas,
) -> bool {
    let literals = runtime_prompt_numeric_threshold_literals(nl);
    !literals.is_empty()
        && literals.iter().all(|literal| {
            plan.predicates.iter().any(|predicate| {
                atlas
                    .field(&predicate.field)
                    .is_some_and(graph_field_looks_numeric)
                    && graph_norm(&predicate.value) == graph_norm(literal)
            }) || runtime_plan_uses_numeric_field_label_containing(plan, atlas, literal)
        })
}

fn runtime_plan_uses_numeric_field_label_containing(
    plan: &BoundQueryPlanTrace,
    atlas: &RuntimeSemanticAtlas,
    literal: &str,
) -> bool {
    let field_matches_literal = |field: &FieldRow| {
        graph_field_looks_numeric(field)
            && (graph_norm(&field.canonical()).contains(&graph_norm(literal))
                || graph_norm(&field.db_column).contains(&graph_norm(literal))
                || field
                    .display_label
                    .as_deref()
                    .is_some_and(|label| graph_norm(label).contains(&graph_norm(literal))))
    };
    plan.order_by
        .as_ref()
        .and_then(|order| atlas.field(&order.field))
        .is_some_and(field_matches_literal)
        || plan
            .projections
            .iter()
            .filter_map(|projection| projection.field.as_deref())
            .filter_map(|field| atlas.field(field))
            .any(field_matches_literal)
        || plan
            .predicates
            .iter()
            .filter_map(|predicate| atlas.field(&predicate.field))
            .any(field_matches_literal)
}

fn runtime_entities_overlap(left: &str, right: &str) -> bool {
    let left_tokens = graph_name_tokens(left);
    let right_tokens = graph_name_tokens(right);
    !left_tokens.is_empty() && !right_tokens.is_empty() && !left_tokens.is_disjoint(&right_tokens)
}

fn pre_resolved_bare_entity_should_fail_closed(
    nl: &str,
    natsql: &str,
    entities: &[EntityRow],
) -> bool {
    let lower = format!(
        " {} ",
        natsql.to_ascii_lowercase().replace(['\n', '\r', '\t'], " ")
    );
    if !lower.contains(" select * from ")
        || [
            " where ",
            " join ",
            " group by ",
            " order by ",
            " limit ",
            " count(",
            " sum(",
            " avg(",
            " min(",
            " max(",
        ]
        .iter()
        .any(|needle| lower.contains(needle))
    {
        return false;
    }
    let Some(entity) = graph_bare_select_entity(natsql) else {
        return true;
    };
    !entities.iter().any(|row| {
        row.canonical_name.eq_ignore_ascii_case(&entity)
            && graph_entity_mentioned_in_prompt(nl, &row.canonical_name)
    })
}

fn graph_bare_select_entity(natsql: &str) -> Option<String> {
    let lower = natsql.to_ascii_lowercase();
    let from_pos = lower.find(" from ")?;
    let after_from = natsql[from_pos + 6..].trim();
    let entity = after_from
        .split_whitespace()
        .next()
        .unwrap_or_default()
        .trim_matches(|ch: char| ch == '"' || ch == '`' || ch == ';');
    (!entity.is_empty()).then(|| entity.to_string())
}

fn runtime_entity_is_projection_subject(projected: &str, mentioned: &str) -> bool {
    projected.eq_ignore_ascii_case(mentioned) || runtime_entities_overlap(projected, mentioned)
}

fn runtime_prompt_related_predicate_field_ambiguity(
    nl: &str,
    plan: &BoundQueryPlanTrace,
    atlas: &RuntimeSemanticAtlas,
) -> bool {
    plan.predicates.iter().any(|predicate| {
        if predicate
            .evidence
            .iter()
            .any(|item| item == "scope_predicate_vocabulary")
        {
            return false;
        }
        if !matches!(predicate.operator.as_str(), "=" | "in") {
            return false;
        }
        let Some(selected) = atlas.field(&predicate.field) else {
            return false;
        };
        if graph_field_looks_date_like(selected) {
            return false;
        }
        let selected_score = runtime_predicate_field_label_score(nl, selected, atlas);
        atlas.fields.values().any(|candidate| {
            if candidate
                .canonical()
                .eq_ignore_ascii_case(&selected.canonical())
                || !graph_entities_are_related(
                    &selected.entity,
                    &candidate.entity,
                    &atlas.relationships,
                )
                || graph_field_looks_date_like(candidate) != graph_field_looks_date_like(selected)
                || !runtime_field_has_predicate_value_evidence(candidate, predicate, atlas)
            {
                return false;
            }
            let candidate_score = runtime_predicate_field_label_score(nl, candidate, atlas);
            candidate_score >= selected_score + 2
        })
    })
}

fn runtime_prompt_high_confidence_value_candidate_missing(
    nl: &str,
    plan: &BoundQueryPlanTrace,
    intent: &IntentFrameTrace,
) -> bool {
    intent.codebook_candidates.iter().any(|candidate| {
        if candidate.kind != SemanticAtlasCodebookKind::Value
            || candidate.score < 15.0
            || !matches!(
                candidate.source.as_str(),
                "sample_values" | "vocabulary_scope_predicate"
            )
            || !runtime_value_candidate_alias_strongly_grounded(nl, &candidate.matched_alias)
        {
            return false;
        }
        let Some(value) = candidate.value.as_deref() else {
            return false;
        };
        if runtime_plan_value_covers_codebook_candidate(plan, candidate) {
            return false;
        }
        !plan.predicates.iter().any(|predicate| {
            predicate.field.eq_ignore_ascii_case(&candidate.target)
                && graph_norm(&predicate.value) == graph_norm(value)
        })
    })
}

fn runtime_plan_value_covers_codebook_candidate(
    plan: &BoundQueryPlanTrace,
    candidate: &SemanticAtlasCodebookCandidate,
) -> bool {
    let alias_norm = graph_norm(&candidate.matched_alias);
    if alias_norm.len() < 3 {
        return false;
    }
    let alias_tokens = graph_tokens_with_aliases(&alias_norm);
    let candidate_value_norm = candidate.value.as_deref().map(graph_norm);
    plan.predicates.iter().any(|predicate| {
        let value_norm = graph_norm(&predicate.value);
        if value_norm.len() < 3 {
            return false;
        }
        if candidate_value_norm
            .as_deref()
            .is_some_and(|candidate_value| {
                candidate_value == value_norm
                    || runtime_lifecycle_values_equivalent(candidate_value, &value_norm)
            })
        {
            return true;
        }
        if graph_norm_contains(&value_norm, &alias_norm) {
            return true;
        }
        let value_tokens = graph_tokens_with_aliases(&value_norm);
        !alias_tokens.is_empty()
            && alias_tokens.is_subset(&value_tokens)
            && value_tokens.len() > alias_tokens.len()
    })
}

fn runtime_lifecycle_values_equivalent(left: &str, right: &str) -> bool {
    fn lifecycle_terminal_class(value: &str) -> Option<&'static str> {
        match graph_norm(value).as_str() {
            "churn" | "churned" | "cancel" | "cancelled" | "canceled" | "ended" | "terminated" => {
                Some("terminal")
            }
            "active" | "current" | "open" | "ongoing" => Some("active"),
            _ => None,
        }
    }
    matches!(
        (lifecycle_terminal_class(left), lifecycle_terminal_class(right)),
        (Some(left_class), Some(right_class)) if left_class == right_class
    )
}

fn runtime_value_candidate_alias_strongly_grounded(nl: &str, alias: &str) -> bool {
    let alias_norm = graph_norm(alias);
    if alias_norm.len() < 3 {
        return false;
    }
    let nl_norm = graph_norm(nl);
    if graph_norm_query_match_variant(&nl_norm, &alias_norm).is_some() {
        return true;
    }
    let mut alias_tokens = graph_tokens_with_aliases(alias);
    alias_tokens.retain(|token| {
        !matches!(
            token.as_str(),
            "the"
                | "a"
                | "an"
                | "of"
                | "for"
                | "in"
                | "and"
                | "or"
                | "school"
                | "schools"
                | "student"
                | "students"
                | "public"
        )
    });
    if alias_tokens.len() < 2 {
        return false;
    }
    let nl_tokens = graph_tokens_with_aliases(nl);
    let overlap = alias_tokens.intersection(&nl_tokens).count();
    overlap >= 2 && overlap as f32 / alias_tokens.len() as f32 >= 0.8
}

fn runtime_predicate_field_label_score(
    nl: &str,
    field: &FieldRow,
    atlas: &RuntimeSemanticAtlas,
) -> i32 {
    let nl_norm = graph_norm(nl);
    let q_tokens = graph_schema_match_tokens(nl);
    let entity_tokens = graph_entity_tokens_with_vocab(&field.entity, &atlas.vocabulary);
    let mut score = 0;
    for form in graph_field_display_forms_with_vocab(field, &atlas.vocabulary) {
        let form_norm = graph_norm(&form);
        if form_norm.len() < 2 {
            continue;
        }
        let mut tokens = graph_name_tokens(&form_norm);
        tokens.retain(|token| {
            !entity_tokens.contains(token)
                && !matches!(
                    token.as_str(),
                    "date" | "time" | "on" | "at" | "before" | "after" | "from" | "to"
                )
        });
        score += tokens.intersection(&q_tokens).count() as i32 * 2;
        if tokens.len() > 1 && form_norm.len() >= 4 && graph_norm_contains(&nl_norm, &form_norm) {
            score += 6;
        }
    }
    score
}

fn runtime_field_has_predicate_value_evidence(
    field: &FieldRow,
    predicate: &BoundPlanPredicateTrace,
    atlas: &RuntimeSemanticAtlas,
) -> bool {
    predicate.value.split('|').map(str::trim).all(|value| {
        if value.is_empty() {
            return true;
        }
        let target = graph_norm(value.trim_matches('\''));
        if target.is_empty() {
            return false;
        }
        let sample_match = atlas
            .sample_values
            .get(&field.canonical().to_ascii_lowercase())
            .is_some_and(|row| {
                !row.pii_redacted
                    && row
                        .examples
                        .iter()
                        .any(|sample| graph_norm(sample) == target)
            });
        if sample_match {
            return true;
        }
        graph_literal_compatible_with_field("", value, field)
            || atlas.vocabulary.iter().any(|entry| {
                entry
                    .canonical_value
                    .eq_ignore_ascii_case(&field.canonical())
                    && graph_norm(&entry.term) == target
            })
    })
}

fn runtime_prompt_subject_entity_mismatch(
    nl: &str,
    trace: &RuntimeQueryFrameTrace,
    atlas: &RuntimeSemanticAtlas,
) -> bool {
    if runtime_grouped_aggregate_allows_subject_shift(trace) {
        return false;
    }
    let Some(projection) = &trace.projection else {
        return false;
    };
    let prompt_norm = graph_norm(nl);
    let Some((first_position, first_entity)) = runtime_first_entity_mention(&prompt_norm, atlas)
    else {
        return false;
    };
    if runtime_entity_is_projection_subject(&projection.entity, &first_entity) {
        return false;
    }
    if runtime_entity_first_alias_position(&prompt_norm, atlas, &projection.entity)
        .is_some_and(|position| position == first_position)
    {
        return false;
    }
    if runtime_aggregate_allows_dimension_subject(trace, &first_entity) {
        return false;
    }
    if runtime_metric_allows_related_fact_subject(trace, atlas, &first_entity) {
        return false;
    }
    true
}

fn runtime_metric_allows_related_fact_subject(
    trace: &RuntimeQueryFrameTrace,
    atlas: &RuntimeSemanticAtlas,
    mentioned_entity: &str,
) -> bool {
    let Some(projection) = &trace.projection else {
        return false;
    };
    if !runtime_expression_is_measure(&projection.expression) {
        return false;
    }
    if !matches!(
        trace.source.as_str(),
        "runtime_graph_query_frame_metric"
            | "runtime_graph_query_frame_scalar_aggregate"
            | "runtime_graph_query_frame_rank"
    ) {
        return false;
    }
    if !trace.joins.is_empty() {
        return false;
    }
    if !runtime_entity_related_to_base(&projection.entity, mentioned_entity, atlas) {
        return false;
    }
    let projected_entity = projection.entity.to_ascii_lowercase();
    let all_predicates_on_projected_entity = trace.predicates.iter().all(|predicate| {
        predicate
            .field
            .split_once('.')
            .map(|(entity, _)| entity.eq_ignore_ascii_case(&projected_entity))
            .unwrap_or(false)
    });
    let order_on_projected_entity = trace.order_by.as_ref().map_or(true, |order| {
        order
            .field
            .split_once('.')
            .map(|(entity, _)| entity.eq_ignore_ascii_case(&projected_entity))
            .unwrap_or(false)
    });
    all_predicates_on_projected_entity && order_on_projected_entity
}

fn runtime_aggregate_allows_dimension_subject(
    trace: &RuntimeQueryFrameTrace,
    mentioned_entity: &str,
) -> bool {
    let Some(projection) = &trace.projection else {
        return false;
    };
    if !runtime_expression_is_measure(&projection.expression) {
        return false;
    }
    runtime_trace_has_join_path_between(trace, &projection.entity, mentioned_entity)
}

fn runtime_trace_has_join_path_between(
    trace: &RuntimeQueryFrameTrace,
    start: &str,
    target: &str,
) -> bool {
    if start.eq_ignore_ascii_case(target) {
        return true;
    }
    let mut seen = HashSet::from([start.to_ascii_lowercase()]);
    let mut frontier = vec![start.to_ascii_lowercase()];
    let target = target.to_ascii_lowercase();
    while let Some(entity) = frontier.pop() {
        for join in &trace.joins {
            let endpoints = [
                (
                    join.from_entity.to_ascii_lowercase(),
                    join.to_entity.to_ascii_lowercase(),
                ),
                (
                    join.to_entity.to_ascii_lowercase(),
                    join.from_entity.to_ascii_lowercase(),
                ),
            ];
            for (from, to) in endpoints {
                if from != entity || !seen.insert(to.clone()) {
                    continue;
                }
                if to == target {
                    return true;
                }
                frontier.push(to);
            }
        }
    }
    false
}

fn runtime_grouped_aggregate_allows_subject_shift(trace: &RuntimeQueryFrameTrace) -> bool {
    if !matches!(
        trace.source.as_str(),
        "runtime_graph_query_frame_grouped_aggregate"
            | "runtime_graph_query_frame_grouped_duration"
    ) {
        return false;
    }
    let Some(projection) = &trace.projection else {
        return false;
    };
    if !runtime_expression_is_measure(&projection.expression) {
        return false;
    }
    let Some(sql) = trace.sql.as_deref() else {
        return false;
    };
    !runtime_sql_group_by_expressions(sql).is_empty()
}

fn runtime_first_entity_mention(
    prompt_norm: &str,
    atlas: &RuntimeSemanticAtlas,
) -> Option<(usize, String)> {
    let mut best: Option<(usize, String)> = None;
    for entity in atlas.entities.values() {
        for alias in semantic_entity_aliases(entity, &atlas.vocabulary) {
            let alias_norm = graph_norm(&alias);
            if alias_norm.len() < 3 {
                continue;
            }
            if let Some(position) = runtime_phrase_position(prompt_norm, &alias_norm) {
                if best
                    .as_ref()
                    .map_or(true, |(best_position, _)| position < *best_position)
                {
                    best = Some((position, entity.canonical_name.clone()));
                }
            }
        }
    }
    best
}

fn runtime_entity_first_alias_position(
    prompt_norm: &str,
    atlas: &RuntimeSemanticAtlas,
    entity_name: &str,
) -> Option<usize> {
    let entity = atlas.entity(entity_name)?;
    semantic_entity_aliases(entity, &atlas.vocabulary)
        .iter()
        .filter_map(|alias| {
            let alias_norm = graph_norm(alias);
            (alias_norm.len() >= 3)
                .then(|| runtime_phrase_position(prompt_norm, &alias_norm))
                .flatten()
        })
        .min()
}

fn runtime_phrase_position(haystack_norm: &str, needle_norm: &str) -> Option<usize> {
    if needle_norm.is_empty() {
        return None;
    }
    let padded_haystack = format!(" {haystack_norm} ");
    let padded_needle = format!(" {needle_norm} ");
    padded_haystack
        .find(&padded_needle)
        .map(|position| position.saturating_sub(1))
}

fn runtime_prompt_relation_display_projection_missing(
    lower: &str,
    trace: &RuntimeQueryFrameTrace,
    atlas: &RuntimeSemanticAtlas,
    intent: &IntentFrameTrace,
) -> bool {
    if intent.intent_kind != "lookup"
        || ![
            " owned by ",
            " assigned to ",
            " assigned by ",
            " managed by ",
            " handled by ",
        ]
        .iter()
        .any(|marker| lower.contains(marker))
    {
        return false;
    }
    trace.joins.iter().any(|join| {
        let related_entity = if trace
            .projection
            .as_ref()
            .is_some_and(|projection| projection.entity.eq_ignore_ascii_case(&join.from_entity))
        {
            &join.to_entity
        } else if trace
            .projection
            .as_ref()
            .is_some_and(|projection| projection.entity.eq_ignore_ascii_case(&join.to_entity))
        {
            &join.from_entity
        } else {
            return false;
        };
        runtime_trace_has_group_filter_on_entity(trace, related_entity, atlas)
            && runtime_entity_has_display_field(related_entity, atlas)
            && !runtime_trace_projects_entity_display(trace, related_entity, atlas)
    })
}

fn runtime_trace_has_group_filter_on_entity(
    trace: &RuntimeQueryFrameTrace,
    entity: &str,
    atlas: &RuntimeSemanticAtlas,
) -> bool {
    trace.predicates.iter().any(|predicate| {
        atlas
            .field(&predicate.field)
            .is_some_and(|field| field.entity.eq_ignore_ascii_case(entity))
            && (runtime_predicate_value_means_active(&predicate.value)
                || matches!(
                    predicate
                        .value
                        .trim_matches('\'')
                        .to_ascii_lowercase()
                        .as_str(),
                    "0" | "false" | "f" | "no" | "n" | "inactive" | "support" | "sales"
                ))
    })
}

fn runtime_entity_has_display_field(entity: &str, atlas: &RuntimeSemanticAtlas) -> bool {
    atlas.fields.values().any(|field| {
        field.entity.eq_ignore_ascii_case(entity)
            && semantic_field_roles(field)
                .iter()
                .any(|role| role == "display")
    })
}

fn runtime_trace_projects_entity_display(
    trace: &RuntimeQueryFrameTrace,
    entity: &str,
    atlas: &RuntimeSemanticAtlas,
) -> bool {
    trace
        .projection
        .as_ref()
        .map(|projection| {
            projection.fields.iter().any(|field_key| {
                atlas.field(field_key).is_some_and(|field| {
                    field.entity.eq_ignore_ascii_case(entity)
                        && semantic_field_roles(field)
                            .iter()
                            .any(|role| role == "display")
                })
            })
        })
        .unwrap_or(false)
}

fn runtime_prompt_requested_projection_missing(
    nl: &str,
    trace: &RuntimeQueryFrameTrace,
    atlas: &RuntimeSemanticAtlas,
) -> bool {
    let requested_terms = runtime_requested_projection_terms(nl);
    if requested_terms.is_empty() {
        return false;
    }
    requested_terms.into_iter().any(|term| {
        if runtime_term_is_predicate_context(&term, trace, atlas) {
            return false;
        }
        runtime_term_maps_to_atlas_projection(&term, trace, atlas)
            && !runtime_term_present_in_projected_fields(&term, trace, atlas)
    })
}

fn runtime_term_is_predicate_context(
    term: &str,
    trace: &RuntimeQueryFrameTrace,
    atlas: &RuntimeSemanticAtlas,
) -> bool {
    let term_norm = graph_norm(term);
    if term_norm.is_empty() {
        return false;
    }
    let term_tokens = graph_name_tokens(term);
    trace.predicates.iter().any(|predicate| {
        let Some(field) = atlas.field(&predicate.field) else {
            return false;
        };
        if !runtime_term_matches_field(term, &term_tokens, field, atlas) {
            return false;
        }
        if matches!(
            predicate.operator.as_str(),
            "range" | "<" | "<=" | ">" | ">="
        ) || graph_field_looks_date_like(field)
        {
            return true;
        }
        graph_predicate_value_norms(&predicate.value)
            .into_iter()
            .any(|value_norm| {
                !value_norm.is_empty() && graph_norm_contains(&term_norm, &value_norm)
            })
    })
}

fn graph_predicate_value_norms(value: &str) -> Vec<String> {
    value
        .split(['|'])
        .flat_map(|part| part.split(".."))
        .map(graph_unquote_predicate_value)
        .map(graph_norm)
        .filter(|norm| !norm.is_empty())
        .collect()
}

fn runtime_requested_projection_terms(nl: &str) -> Vec<String> {
    let lower = nl.to_ascii_lowercase();
    let mut out = Vec::new();
    for marker in [
        " with their ",
        " with its ",
        " with ",
        " showing their ",
        " showing its ",
        " showing ",
        " including their ",
        " including its ",
        " including ",
    ] {
        let mut search_start = 0;
        while let Some(offset) = lower[search_start..].find(marker) {
            let start = search_start + offset + marker.len();
            let end = runtime_projection_phrase_end(&lower, start);
            for part in lower[start..end].split([',', '/', '&']) {
                for subpart in part.split(" and ") {
                    let term = subpart
                        .trim()
                        .trim_start_matches("the ")
                        .trim_start_matches("an ")
                        .trim_start_matches("a ");
                    if runtime_projection_term_is_filter_or_order_phrase(term) {
                        continue;
                    }
                    let Some(term) = runtime_projection_output_term(term) else {
                        continue;
                    };
                    out.push(term);
                }
            }
            search_start = end;
        }
    }
    out.sort();
    out.dedup();
    out
}

fn runtime_explicit_projection_terms(nl: &str) -> Vec<String> {
    let mut out = runtime_requested_projection_terms(nl);
    out.extend(runtime_command_projection_terms(nl));
    out.sort();
    out.dedup();
    out
}

fn runtime_command_projection_terms(nl: &str) -> Vec<String> {
    let cleaned = graph_norm(&graph_text_without_quoted_phrases(nl));
    let mut lower = cleaned.as_str();
    for prefix in ["please ", "kindly ", "can you ", "could you "] {
        if let Some(rest) = lower.strip_prefix(prefix) {
            lower = rest;
            break;
        }
    }
    let Some(tail) = [
        "show me ", "show ", "list me ", "list ", "display ", "give me ", "give ", "provide ",
    ]
    .iter()
    .find_map(|prefix| lower.strip_prefix(prefix)) else {
        return Vec::new();
    };
    let mut phrase = tail.trim();
    for article in [
        "the ", "all ", "their ", "its ", "a ", "an ", "each ", "every ",
    ] {
        if let Some(rest) = phrase.strip_prefix(article) {
            phrase = rest.trim_start();
            break;
        }
    }
    let end = runtime_command_projection_phrase_end(phrase);
    let phrase = phrase[..end].trim();
    if phrase.is_empty() {
        return Vec::new();
    }
    let mut out = Vec::new();
    for part in phrase.split([',', '/', '&']) {
        for subpart in part.split(" and ") {
            let term = subpart
                .trim()
                .trim_start_matches("the ")
                .trim_start_matches("an ")
                .trim_start_matches("a ");
            let Some(term) = runtime_projection_output_term(term) else {
                continue;
            };
            out.push(term);
        }
    }
    out
}

fn runtime_command_projection_phrase_end(phrase: &str) -> usize {
    let mut end = phrase.len();
    for marker in [
        " of ",
        " for ",
        " from ",
        " where ",
        " that ",
        " which ",
        " whose ",
        " with ",
        " by ",
        " in ",
        " after ",
        " before ",
        " since ",
        " opened ",
        " closed ",
        " created ",
        " signed ",
        " renewing ",
        " ordered ",
        " ranked ",
        " based on ",
    ] {
        if let Some(offset) = phrase.find(marker) {
            end = end.min(offset);
        }
    }
    end
}

fn runtime_projection_output_term(term: &str) -> Option<String> {
    let mut words = graph_norm(term)
        .split_whitespace()
        .map(ToString::to_string)
        .collect::<Vec<_>>();
    while words
        .first()
        .is_some_and(|word| runtime_projection_prefix_word(word))
    {
        words.remove(0);
    }
    let cleaned = words.join(" ");
    if cleaned.is_empty() || runtime_projection_term_is_filter_or_order_phrase(&cleaned) {
        return None;
    }
    Some(cleaned)
}

fn runtime_projection_prefix_word(word: &str) -> bool {
    matches!(
        word,
        "the"
            | "all"
            | "their"
            | "its"
            | "a"
            | "an"
            | "each"
            | "every"
            | "top"
            | "bottom"
            | "highest"
            | "lowest"
            | "largest"
            | "smallest"
            | "greatest"
            | "fewest"
            | "most"
            | "least"
            | "best"
            | "worst"
            | "first"
            | "last"
            | "one"
            | "two"
            | "three"
            | "four"
            | "five"
            | "six"
            | "seven"
            | "eight"
            | "nine"
            | "ten"
    ) || word.parse::<u32>().is_ok()
}

fn runtime_projection_term_is_filter_or_order_phrase(term: &str) -> bool {
    [
        "top ",
        "highest ",
        "lowest ",
        "most ",
        "least ",
        "largest ",
        "smallest ",
        "best ",
        "worst ",
        "fastest ",
        "slowest ",
        "over ",
        "under ",
        "above ",
        "below ",
        "greater ",
        "less ",
        "score of ",
        "no ",
        "without ",
    ]
    .iter()
    .any(|prefix| term.starts_with(prefix))
        || term.contains('.')
        || term.contains('@')
        || term.ends_with(" event")
        || term.ends_with(" events")
        || term.ends_with(" activity")
        || term.ends_with(" activities")
        || term.ends_with(" ticket")
        || term.ends_with(" tickets")
        || term.ends_with(" invoice")
        || term.ends_with(" invoices")
        || [
            " over ",
            " under ",
            " above ",
            " below ",
            " greater than ",
            " less than ",
            " at least ",
            " fewer than ",
            " more than ",
        ]
        .iter()
        .any(|marker| term.contains(marker))
}

fn runtime_projection_phrase_end(lower: &str, start: usize) -> usize {
    let mut end = lower.len();
    for marker in [
        " where ",
        " signed ",
        " renewing ",
        " ordered ",
        " ranked ",
        " by ",
        " after ",
        " before ",
        " in ",
    ] {
        if let Some(offset) = lower[start..].find(marker) {
            end = end.min(start + offset);
        }
    }
    end
}

fn runtime_term_maps_to_atlas_projection(
    term: &str,
    trace: &RuntimeQueryFrameTrace,
    atlas: &RuntimeSemanticAtlas,
) -> bool {
    let term_tokens = graph_name_tokens(term);
    if term_tokens.is_empty() {
        return false;
    }
    let required_entities: HashSet<&str> =
        trace.required_entities.iter().map(String::as_str).collect();
    atlas.fields.values().any(|field| {
        required_entities.contains(field.entity.as_str())
            && runtime_term_matches_field(term, &term_tokens, field, atlas)
    })
}

fn runtime_term_present_in_projected_fields(
    term: &str,
    trace: &RuntimeQueryFrameTrace,
    atlas: &RuntimeSemanticAtlas,
) -> bool {
    let Some(projection) = &trace.projection else {
        return false;
    };
    let term_tokens = graph_name_tokens(term);
    if projection
        .expression
        .to_ascii_lowercase()
        .contains(&term.to_ascii_lowercase())
    {
        return true;
    }
    if runtime_term_present_as_relation_display(term, trace, atlas) {
        return true;
    }
    projection.fields.iter().any(|field_key| {
        atlas
            .field(field_key)
            .is_some_and(|field| runtime_term_matches_field(term, &term_tokens, field, atlas))
    })
}

fn runtime_term_present_as_relation_display(
    term: &str,
    trace: &RuntimeQueryFrameTrace,
    atlas: &RuntimeSemanticAtlas,
) -> bool {
    let term_tokens = graph_name_tokens(term);
    if term_tokens.is_empty() {
        return false;
    }
    let Some(projection) = &trace.projection else {
        return false;
    };
    projection.fields.iter().any(|field_key| {
        let Some(field) = atlas.field(field_key) else {
            return false;
        };
        if field.entity.eq_ignore_ascii_case(&projection.entity)
            || !semantic_field_roles(field)
                .iter()
                .any(|role| role == "display")
        {
            return false;
        }
        let path_tokens = graph_relationship_path_role_tokens_between_in_atlas(
            &projection.entity,
            &field.entity,
            atlas,
        );
        !path_tokens.is_disjoint(&term_tokens)
    })
}

fn runtime_term_matches_field(
    term: &str,
    term_tokens: &HashSet<String>,
    field: &FieldRow,
    atlas: &RuntimeSemanticAtlas,
) -> bool {
    let field_tokens = graph_field_tokens_with_vocab(field, &atlas.vocabulary);
    if !term_tokens.is_empty() && !term_tokens.is_disjoint(&field_tokens) {
        return true;
    }
    semantic_field_aliases(field, &atlas.vocabulary)
        .iter()
        .any(|alias| graph_norm(alias) == graph_norm(term))
}

fn runtime_prompt_scope_predicate_misbound(
    nl: &str,
    trace: &RuntimeQueryFrameTrace,
    atlas: &RuntimeSemanticAtlas,
) -> bool {
    let Some(projection) = &trace.projection else {
        return false;
    };
    let subject = &projection.entity;
    if !runtime_prompt_qualifies_subject_with(nl, subject, "active", atlas) {
        return false;
    }
    let subject_has_active_field = atlas.fields.values().any(|field| {
        field.entity.eq_ignore_ascii_case(subject)
            && (graph_norm(&field.field).contains("active")
                || graph_norm(&field.db_column).contains("active")
                || graph_sample_value_contains(
                    &atlas.sample_values.values().cloned().collect::<Vec<_>>(),
                    &field.canonical(),
                    "active",
                ))
    });
    if !subject_has_active_field {
        return false;
    }
    trace.predicates.iter().any(|predicate| {
        runtime_predicate_value_means_active(&predicate.value)
            && atlas
                .field(&predicate.field)
                .is_some_and(|field| !field.entity.eq_ignore_ascii_case(subject))
    })
}

fn runtime_prompt_qualifies_subject_with(
    nl: &str,
    subject: &str,
    qualifier: &str,
    atlas: &RuntimeSemanticAtlas,
) -> bool {
    let lower = format!(" {} ", nl.to_ascii_lowercase().replace('\n', " "));
    let Some(entity) = atlas.entity(subject) else {
        return false;
    };
    semantic_entity_aliases(entity, &atlas.vocabulary)
        .iter()
        .map(|alias| graph_norm(alias))
        .filter(|alias| !alias.is_empty())
        .any(|alias| lower.contains(&format!(" {qualifier} {alias} ")))
}

fn runtime_predicate_value_means_active(value: &str) -> bool {
    matches!(
        value.trim_matches('\'').to_ascii_lowercase().as_str(),
        "1" | "true" | "t" | "yes" | "y" | "active"
    )
}

fn runtime_join_backed_by_relationship(
    step: &RuntimeQueryFrameJoinTrace,
    atlas: &RuntimeSemanticAtlas,
) -> bool {
    atlas.relationships.iter().any(|relationship| {
        (relationship
            .from_entity
            .eq_ignore_ascii_case(&step.from_entity)
            && relationship
                .from_field
                .eq_ignore_ascii_case(&step.from_field)
            && relationship.to_entity.eq_ignore_ascii_case(&step.to_entity)
            && relationship.to_field.eq_ignore_ascii_case(&step.to_field))
            || (relationship
                .from_entity
                .eq_ignore_ascii_case(&step.to_entity)
                && relationship.from_field.eq_ignore_ascii_case(&step.to_field)
                && relationship
                    .to_entity
                    .eq_ignore_ascii_case(&step.from_entity)
                && relationship.to_field.eq_ignore_ascii_case(&step.from_field))
    })
}

fn runtime_predicate_value_evidence(
    nl: &str,
    predicate: &RuntimeQueryFramePredicateTrace,
    atlas: &RuntimeSemanticAtlas,
) -> Vec<String> {
    let mut evidence = Vec::new();
    let Some(field) = atlas.field(&predicate.field) else {
        return evidence;
    };
    if graph_sample_value_contains(
        &atlas.sample_values.values().cloned().collect::<Vec<_>>(),
        &predicate.field,
        &predicate.value,
    ) {
        evidence.push("sample_value".to_string());
    }
    if graph_vocab_enum_predicate_is_grounded(nl, predicate, field, &atlas.vocabulary) {
        evidence.push("enum_vocabulary".to_string());
    }
    if graph_vocab_scope_predicate_is_grounded(nl, predicate, field, &atlas.vocabulary) {
        evidence.push("scope_predicate_vocabulary".to_string());
    }
    if graph_relative_date_predicate_is_grounded(nl, predicate, field) {
        evidence.push("relative_date".to_string());
    }
    if graph_named_date_window_predicate_is_grounded(nl, predicate, field) {
        evidence.push("named_date_window".to_string());
    }
    if graph_inferred_date_window_predicate_is_grounded(
        nl,
        predicate,
        field,
        &atlas.sample_values.values().cloned().collect::<Vec<_>>(),
    ) {
        evidence.push("inferred_date_window".to_string());
    }
    if graph_field_looks_date_like(field)
        && (graph_is_date_like(&predicate.value)
            || graph_is_year_literal(&predicate.value)
            || predicate.operator == "range")
    {
        evidence.push("structured_date".to_string());
    }
    if graph_field_looks_numeric(field)
        && predicate
            .value
            .split(['|', '.'])
            .any(|part| part.chars().any(|ch| ch.is_ascii_digit()))
        && graph_literal_compatible_with_field(nl, &predicate.value, field)
    {
        evidence.push("structured_number".to_string());
    }
    if is_boolean_field_type(&field.field_type)
        && matches!(
            predicate
                .value
                .trim_matches('\'')
                .to_ascii_lowercase()
                .as_str(),
            "1" | "0" | "true" | "false" | "yes" | "no" | "y" | "n"
        )
    {
        evidence.push("structured_boolean".to_string());
    }
    evidence.sort();
    evidence.dedup();
    evidence
}

fn runtime_predicate_has_route_measure_threshold_evidence(
    predicate: &RuntimeQueryFramePredicateTrace,
    trace: &RuntimeQueryFrameTrace,
    atlas: &RuntimeSemanticAtlas,
) -> bool {
    if !matches!(
        predicate.operator.as_str(),
        ">" | ">=" | "<" | "<=" | "range"
    ) || !predicate
        .value
        .split(['|', '.'])
        .any(|part| part.chars().any(|ch| ch.is_ascii_digit()))
    {
        return false;
    }
    let Some(field) = atlas.field(&predicate.field) else {
        return false;
    };
    let lower_name = field.db_column.to_ascii_lowercase();
    if !graph_field_looks_numeric(field)
        || lower_name == "id"
        || lower_name.ends_with("_id")
        || lower_name.ends_with("id")
    {
        return false;
    }
    let projection_mentions_measure = trace.projection.as_ref().is_some_and(|projection| {
        let expression = projection.expression.to_ascii_lowercase();
        graph_expr_contains_field_ref(&expression, field)
            && (runtime_expression_is_measure(&expression)
                || projection
                    .field
                    .as_deref()
                    .is_some_and(|projected| projected.eq_ignore_ascii_case(&field.canonical()))
                || projection
                    .fields
                    .iter()
                    .any(|projected| projected.eq_ignore_ascii_case(&field.canonical())))
    });
    let order_mentions_measure = trace.order_by.as_ref().is_some_and(|order| {
        let expression = order.expression.to_ascii_lowercase();
        graph_expr_contains_field_ref(&expression, field)
            && (runtime_expression_is_measure(&expression)
                || order.field.eq_ignore_ascii_case(&field.canonical()))
    });
    projection_mentions_measure || order_mentions_measure
}

#[derive(Clone, Debug)]
struct GraphMetricRatioCandidate<'a> {
    numerator: &'a FieldRow,
    denominator: &'a FieldRow,
    score: f32,
}

#[derive(Clone, Debug)]
struct GraphAttributeSuperlativeRequest {
    concept: String,
    aliases: Vec<String>,
    direction: String,
    limit: u32,
}

#[derive(Clone, Debug)]
struct GraphAttributeNameMatch<'a> {
    field: &'a FieldRow,
    value: String,
    score: f32,
}

#[derive(Clone, Debug)]
struct GraphPersonNameMatch<'a> {
    first_field: &'a FieldRow,
    last_field: &'a FieldRow,
    first_value: String,
    last_value: String,
}

impl RuntimeQueryFrameTrace {
    fn rejected(question: &str, route_reason: &str) -> Self {
        Self {
            schema_version: 1,
            source: "runtime_graph_query_frame".to_string(),
            question: question.to_string(),
            routed: false,
            used_for_final_sql: false,
            route_reason: route_reason.to_string(),
            sql: None,
            projection: None,
            predicates: Vec::new(),
            required_entities: Vec::new(),
            joins: Vec::new(),
            order_by: None,
        }
    }
}

#[cfg(test)]
fn graph_query_frame_trace(
    nl: &str,
    entities: &[EntityRow],
    fields: &[FieldRow],
    relationships: &[RelationshipRow],
    sample_values: &[SampleValueRow],
) -> RuntimeQueryFrameTrace {
    graph_query_frame_trace_with_vocab(nl, entities, fields, relationships, sample_values, &[])
}

fn graph_query_frame_trace_with_vocab(
    nl: &str,
    entities: &[EntityRow],
    fields: &[FieldRow],
    relationships: &[RelationshipRow],
    sample_values: &[SampleValueRow],
    vocabulary: &[VocabularyEntry],
) -> RuntimeQueryFrameTrace {
    let trace_route_timings = std::env::var_os("SEMSQL_ROUTE_TIMINGS").is_some();
    let route_phase = |name: &str, started: Instant| {
        if trace_route_timings {
            eprintln!("route_timing_{name}={}us", started.elapsed().as_micros());
        }
    };
    let mut trace = RuntimeQueryFrameTrace::rejected(nl, "not_routed_unset");
    if entities.is_empty() || fields.is_empty() {
        trace.route_reason = "not_routed_no_graph".to_string();
        return trace;
    }
    if graph_large_schema_grouped_metric_should_fail_fast(nl, entities, fields, relationships) {
        let phase = Instant::now();
        if let Some(grouped_metric_trace) = graph_large_schema_grouped_aggregate_query_frame_trace(
            nl,
            entities,
            fields,
            relationships,
            sample_values,
            vocabulary,
        ) {
            route_phase("large_schema_grouped_aggregate", phase);
            return grouped_metric_trace;
        }
        route_phase("large_schema_grouped_aggregate", phase);
        trace.route_reason =
            "not_routed_large_schema_grouped_metric_needs_typed_proposal".to_string();
        return trace;
    }
    let phase = Instant::now();
    let anti_join_trace = graph_anti_join_temporal_query_frame_trace(
        nl,
        entities,
        fields,
        relationships,
        sample_values,
        vocabulary,
    );
    route_phase("anti_join_temporal", phase);
    if let Some(anti_join_trace) = anti_join_trace {
        return anti_join_trace;
    }
    let phase = Instant::now();
    let grouped_ratio_trace = graph_grouped_ratio_query_frame_trace(
        nl,
        entities,
        fields,
        relationships,
        sample_values,
        vocabulary,
    );
    route_phase("grouped_ratio", phase);
    if let Some(grouped_ratio_trace) = grouped_ratio_trace {
        return grouped_ratio_trace;
    }
    let phase = Instant::now();
    let conditional_rate_trace = graph_conditional_rate_query_frame_trace(
        nl,
        entities,
        fields,
        relationships,
        sample_values,
        vocabulary,
    );
    route_phase("conditional_rate", phase);
    if let Some(conditional_rate_trace) = conditional_rate_trace {
        return conditional_rate_trace;
    }
    let phase = Instant::now();
    let grouped_duration_trace = graph_grouped_duration_query_frame_trace(
        nl,
        entities,
        fields,
        relationships,
        sample_values,
        vocabulary,
    );
    route_phase("grouped_duration", phase);
    if let Some(grouped_duration_trace) = grouped_duration_trace {
        return grouped_duration_trace;
    }
    let phase = Instant::now();
    let metric_trace = graph_metric_query_frame_trace(
        nl,
        entities,
        fields,
        relationships,
        sample_values,
        vocabulary,
    );
    route_phase("metric", phase);
    if let Some(metric_trace) = metric_trace {
        return metric_trace;
    }
    let phase = Instant::now();
    let avg_related_count_trace = graph_average_related_count_query_frame_trace(
        nl,
        entities,
        fields,
        relationships,
        sample_values,
        vocabulary,
    );
    route_phase("average_related_count", phase);
    if let Some(avg_related_count_trace) = avg_related_count_trace {
        return avg_related_count_trace;
    }
    let phase = Instant::now();
    let grouped_aggregate_trace = graph_grouped_aggregate_query_frame_trace(
        nl,
        entities,
        fields,
        relationships,
        sample_values,
        vocabulary,
    );
    route_phase("grouped_aggregate", phase);
    if let Some(grouped_aggregate_trace) = grouped_aggregate_trace {
        return grouped_aggregate_trace;
    }
    if graph_grouped_metric_topk_unresolved_should_fail_closed(nl, fields, vocabulary) {
        trace.route_reason = "not_routed_grouped_metric_topk_unresolved".to_string();
        return trace;
    }
    let phase = Instant::now();
    let rank_trace = graph_rank_query_frame_trace(
        nl,
        entities,
        fields,
        relationships,
        sample_values,
        vocabulary,
    );
    route_phase("rank", phase);
    if let Some(rank_trace) = rank_trace {
        return rank_trace;
    }
    let phase = Instant::now();
    let attribute_trace = graph_attribute_superlative_query_frame_trace(
        nl,
        entities,
        fields,
        relationships,
        sample_values,
        vocabulary,
    );
    route_phase("attribute_superlative", phase);
    if let Some(attribute_trace) = attribute_trace {
        return attribute_trace;
    }
    let phase = Instant::now();
    let person_event_trace = graph_person_event_query_frame_trace(
        nl,
        entities,
        fields,
        relationships,
        sample_values,
        vocabulary,
    );
    route_phase("person_event", phase);
    if let Some(person_event_trace) = person_event_trace {
        return person_event_trace;
    }
    let phase = Instant::now();
    let aggregate_trace = graph_scalar_aggregate_query_frame_trace(
        nl,
        entities,
        fields,
        relationships,
        sample_values,
        vocabulary,
    );
    route_phase("scalar_aggregate", phase);
    if let Some(aggregate_trace) = aggregate_trace {
        return aggregate_trace;
    }
    if graph_query_looks_complex(nl) {
        trace.route_reason = "not_routed_complex_shape".to_string();
        return trace;
    }

    let mut predicates = graph_query_predicates_with_vocab(nl, fields, sample_values, vocabulary);
    predicates = graph_rewrite_lifecycle_predicates_to_related_table(
        nl,
        entities,
        fields,
        relationships,
        sample_values,
        vocabulary,
        predicates,
    );
    predicates = graph_promote_related_predicate_fields(
        nl,
        fields,
        relationships,
        sample_values,
        vocabulary,
        predicates,
    );
    trace.predicates = predicates.iter().map(graph_predicate_trace).collect();
    let order_like = graph_order_direction_limit(nl).is_some();
    if (predicates.is_empty() && !order_like) || predicates.len() > 3 {
        trace.route_reason = if predicates.is_empty() {
            "not_routed_no_predicates"
        } else {
            "not_routed_too_many_predicates"
        }
        .to_string();
        return trace;
    }

    let field_map = graph_field_map(fields);
    let entity_map = graph_entity_map(entities);
    if predicates
        .iter()
        .any(|predicate| !field_map.contains_key(&predicate.field))
    {
        trace.route_reason = "not_routed_graph_mapping".to_string();
        return trace;
    }

    let projection = graph_query_projection(
        nl,
        entities,
        fields,
        relationships,
        &predicates,
        &entity_map,
        vocabulary,
    );
    let Some(projection) = projection else {
        trace.route_reason = "not_routed_no_projection".to_string();
        return trace;
    };
    trace.projection = Some(graph_projection_trace(&projection));

    let order = graph_query_order(nl, fields, &predicates, &field_map, &entity_map, vocabulary)
        .or_else(|| {
            graph_projection_metric_default_order(
                nl,
                &projection,
                &field_map,
                &entity_map,
                vocabulary,
            )
        })
        .or_else(|| {
            graph_projection_date_predicate_default_order(
                nl,
                &projection,
                &predicates,
                &field_map,
                &entity_map,
                vocabulary,
            )
        });
    trace.order_by = order.as_ref().map(graph_order_trace);

    let mut required_entities: HashSet<String> = predicates
        .iter()
        .filter_map(|predicate| {
            field_map
                .get(&predicate.field)
                .map(|field| field.entity.clone())
        })
        .collect();
    required_entities.insert(projection.entity.clone());
    for projection_field in &projection.fields {
        if let Some(field) = field_map.get(projection_field) {
            required_entities.insert(field.entity.clone());
        }
    }
    if let Some(order) = &order {
        if let Some((entity, _)) = order.field.split_once('.') {
            required_entities.insert(entity.to_string());
        }
    }

    let mut required_entity_list: Vec<String> = required_entities.iter().cloned().collect();
    required_entity_list.sort();
    trace.required_entities = required_entity_list;

    if graph_ambiguous_physical_table_family_for_required_entities(entities, &required_entities)
        .is_some()
    {
        trace.route_reason = "not_routed_ambiguous_physical_table_family".to_string();
        return trace;
    }

    let Some(joins) = graph_join_plan(nl, &projection.entity, &required_entities, relationships)
    else {
        trace.route_reason = "not_routed_no_join_path".to_string();
        return trace;
    };
    trace.joins = joins.iter().map(graph_join_trace).collect();

    let Some(base_entity) = entity_map.get(&projection.entity) else {
        trace.route_reason = "not_routed_graph_mapping".to_string();
        return trace;
    };
    let Some(join_sql) = graph_render_joins(&projection.entity, &joins, &entity_map, &field_map)
    else {
        trace.route_reason = "not_routed_render_error".to_string();
        return trace;
    };
    let Some(where_sql) = graph_render_where(&predicates, &field_map, &entity_map) else {
        trace.route_reason = "not_routed_render_error".to_string();
        return trace;
    };

    let grouped_order = order.as_ref().and_then(|order| {
        graph_grouped_order_aggregate(nl, &projection, order, &field_map, &entity_map)
    });
    let projection_expr = if let Some(grouped) = &grouped_order {
        grouped.select_expr.as_str()
    } else if order.is_some() {
        projection
            .expr
            .trim_start()
            .strip_prefix("DISTINCT ")
            .unwrap_or(&projection.expr)
    } else {
        &projection.expr
    };
    let plain_field_projection = grouped_order.is_none()
        && projection.field.is_some()
        && order.is_none()
        && !projection.expr.contains('(')
        && !projection.expr.trim_start().starts_with("DISTINCT ");
    let entity_identity_list_projection =
        graph_projection_identity_description_list(nl, &projection, &field_map);
    let select_keyword = if entity_identity_list_projection
        || graph_query_requests_distinct_value_projection(nl, &projection, &field_map)
        || (plain_field_projection && nl_requests_unique_list(nl))
    {
        "SELECT DISTINCT"
    } else {
        "SELECT"
    };
    let mut sql = format!(
        "{select_keyword} {} FROM {}",
        projection_expr,
        graph_quote_ident(&base_entity.db_table)
    );
    if !join_sql.is_empty() {
        sql.push(' ');
        sql.push_str(&join_sql);
    }
    if !where_sql.is_empty() {
        sql.push_str(" WHERE ");
        sql.push_str(&where_sql);
    }
    if let Some(grouped) = &grouped_order {
        sql.push_str(" GROUP BY ");
        sql.push_str(&grouped.group_by_expr);
    }
    if let Some(order) = &order {
        sql.push_str(" ORDER BY ");
        if let Some(grouped) = &grouped_order {
            sql.push_str(&grouped.order_expr);
        } else {
            sql.push_str(&order.expr);
        }
        sql.push(' ');
        sql.push_str(&order.direction);
        if order.limit > 0 {
            sql.push_str(" LIMIT ");
            sql.push_str(&order.limit.to_string());
        }
    }

    trace.routed = true;
    trace.route_reason = "routed".to_string();
    trace.sql = Some(sql);
    trace
}

fn graph_large_schema_grouped_metric_should_fail_fast(
    nl: &str,
    entities: &[EntityRow],
    fields: &[FieldRow],
    relationships: &[RelationshipRow],
) -> bool {
    let large_schema = entities.len() > 120 || fields.len() > 1_500 || relationships.len() > 600;
    let grouped_metric_prompt = graph_explicit_grouped_metric_aggregate_prompt(nl)
        || graph_grouped_count_prompt(nl)
        || graph_topk_grouped_count_prompt(nl)
        || graph_grouped_time_series_prompt(nl)
        || graph_grouped_comparison_prompt(nl);
    if !large_schema || !(graph_prompt_requests_grouped_aggregate(nl) || grouped_metric_prompt) {
        return false;
    }
    grouped_metric_prompt
}

fn graph_large_schema_grouped_aggregate_query_frame_trace(
    nl: &str,
    entities: &[EntityRow],
    fields: &[FieldRow],
    relationships: &[RelationshipRow],
    sample_values: &[SampleValueRow],
    vocabulary: &[VocabularyEntry],
) -> Option<RuntimeQueryFrameTrace> {
    let trace_route_timings = std::env::var_os("SEMSQL_ROUTE_TIMINGS").is_some();
    let candidate_started = Instant::now();
    let candidate_fields = graph_large_schema_grouped_metric_candidate_fields(
        nl,
        entities,
        fields,
        relationships,
        sample_values,
        vocabulary,
    )?;
    if trace_route_timings {
        eprintln!(
            "route_timing_large_schema_candidate_fields={}us fields={}",
            candidate_started.elapsed().as_micros(),
            candidate_fields.len()
        );
    }
    let candidate_field_keys = candidate_fields
        .iter()
        .map(FieldRow::canonical)
        .collect::<HashSet<_>>();
    let candidate_entities = candidate_fields
        .iter()
        .map(|field| field.entity.clone())
        .collect::<HashSet<_>>();
    let candidate_sample_values = sample_values
        .iter()
        .filter(|row| candidate_field_keys.contains(&row.field_canonical))
        .cloned()
        .collect::<Vec<_>>();
    let candidate_vocabulary = vocabulary
        .iter()
        .filter(|entry| match entry.canonical_kind.as_str() {
            "field" => candidate_field_keys.contains(&entry.canonical_value),
            "entity" => candidate_entities.contains(&entry.canonical_value),
            _ => false,
        })
        .cloned()
        .collect::<Vec<_>>();
    let route_started = Instant::now();
    let trace = graph_grouped_aggregate_query_frame_trace(
        nl,
        entities,
        &candidate_fields,
        relationships,
        &candidate_sample_values,
        &candidate_vocabulary,
    );
    if trace_route_timings {
        eprintln!(
            "route_timing_large_schema_grouped_route={}us",
            route_started.elapsed().as_micros()
        );
    }
    trace
}

fn graph_large_schema_grouped_metric_candidate_fields(
    nl: &str,
    entities: &[EntityRow],
    fields: &[FieldRow],
    relationships: &[RelationshipRow],
    sample_values: &[SampleValueRow],
    vocabulary: &[VocabularyEntry],
) -> Option<Vec<FieldRow>> {
    let subject_entity = graph_grouped_metric_subject_entity(nl, entities, vocabulary);
    let measure =
        graph_grouped_measure_field_scoped(nl, fields, vocabulary, subject_entity.as_deref())?;
    let by_phrase = graph_topk_group_dimension_phrase(nl, fields, relationships, vocabulary)
        .or_else(|| graph_group_by_phrase(nl))?;
    let by_tokens = graph_schema_match_tokens(&by_phrase);
    let lower_nl = format!(" {} ", nl.to_ascii_lowercase().replace(['_', '-'], " "));
    let nl_norm = graph_norm(nl);
    let mut keep_entities: HashSet<String> = HashSet::from([measure.entity.clone()]);
    let mut by_entities: HashSet<String> = HashSet::new();
    let by_phrase_norm = graph_norm(&by_phrase);
    for entity in entities {
        let entity_tokens = graph_entity_tokens_for_row_with_vocab(entity, vocabulary);
        let label_match = graph_entity_labels_for_prompt(entity).iter().any(|label| {
            let label_norm = graph_norm(label);
            !label_norm.is_empty() && graph_norm_contains(&by_phrase_norm, &label_norm)
        });
        if label_match || !entity_tokens.is_disjoint(&by_tokens) {
            keep_entities.insert(entity.canonical_name.clone());
            by_entities.insert(entity.canonical_name.clone());
        }
    }
    let mut by_entity_tokens = HashSet::new();
    for entity in entities {
        if by_entities.contains(&entity.canonical_name) {
            by_entity_tokens.extend(graph_entity_tokens_for_row_with_vocab(entity, vocabulary));
        }
    }
    let by_field_tokens = by_tokens
        .difference(&by_entity_tokens)
        .cloned()
        .collect::<HashSet<_>>();

    let mut keep_fields: HashSet<String> = HashSet::from([measure.canonical()]);
    for field in fields {
        let field_key = field.canonical();
        if field_key == measure.canonical() {
            keep_fields.insert(field.canonical());
            continue;
        }
        let field_tokens = graph_field_tokens_with_vocab(field, vocabulary);
        let field_matches_by = !by_field_tokens.is_empty()
            && !field_tokens.is_disjoint(&by_field_tokens)
            || [
                field.field.as_str(),
                field.db_column.as_str(),
                field.display_label.as_deref().unwrap_or(""),
            ]
            .iter()
            .any(|label| {
                let label_norm = graph_norm(label);
                !label_norm.is_empty() && graph_norm_contains(&by_phrase_norm, &label_norm)
            });
        if field_matches_by
            || (by_field_tokens.is_empty()
                && by_entities.contains(&field.entity)
                && graph_field_looks_display_field(field))
            || !graph_boolean_mentions_for_field(&lower_nl, field, sample_values, vocabulary)
                .is_empty()
        {
            keep_fields.insert(field.canonical());
        }
    }
    for row in sample_values {
        let Some(sample_field) = fields
            .iter()
            .find(|field| field.canonical().eq_ignore_ascii_case(&row.field_canonical))
        else {
            continue;
        };
        for value in &row.examples {
            let value_norm = graph_norm(value);
            if value_norm.len() >= 2 && graph_norm_contains(&nl_norm, &value_norm) {
                keep_fields.insert(row.field_canonical.clone());
            }
            for alias in graph_sample_value_query_aliases(value, sample_field) {
                let alias_norm = graph_norm(alias);
                if alias_norm.len() >= 2 && graph_norm_contains(&nl_norm, &alias_norm) {
                    keep_fields.insert(row.field_canonical.clone());
                }
            }
        }
    }
    for relationship in relationships {
        keep_fields.insert(format!(
            "{}.{}",
            relationship.from_entity, relationship.from_field
        ));
        keep_fields.insert(format!(
            "{}.{}",
            relationship.to_entity, relationship.to_field
        ));
    }

    let mut out = fields
        .iter()
        .filter(|field| keep_fields.contains(&field.canonical()))
        .cloned()
        .collect::<Vec<_>>();
    out.sort_by_key(FieldRow::canonical);
    out.dedup_by(|left, right| left.canonical() == right.canonical());
    (!out.is_empty()).then_some(out)
}

fn graph_grouped_aggregate_query_frame_trace(
    nl: &str,
    entities: &[EntityRow],
    fields: &[FieldRow],
    relationships: &[RelationshipRow],
    sample_values: &[SampleValueRow],
    vocabulary: &[VocabularyEntry],
) -> Option<RuntimeQueryFrameTrace> {
    let trace_route_timings = std::env::var_os("SEMSQL_ROUTE_TIMINGS").is_some();
    let prepare_started = Instant::now();
    let subject_entity = graph_grouped_metric_subject_entity(nl, entities, vocabulary);
    let measure_probe =
        graph_grouped_measure_field_scoped(nl, fields, vocabulary, subject_entity.as_deref());
    let value_grouped_comparison =
        graph_prompt_requests_value_grouped_comparison(nl, fields, sample_values, vocabulary);
    let metric_topk = graph_grouped_metric_topk_prompt(nl, measure_probe);
    if !graph_prompt_requests_grouped_aggregate(nl) && !value_grouped_comparison && !metric_topk {
        return None;
    }
    if graph_order_direction_limit(nl).is_some()
        && !graph_topk_grouped_count_prompt(nl)
        && !metric_topk
    {
        return None;
    }
    let lower = format!(" {} ", graph_norm(nl));
    if [" rate ", " ratio ", " percentage ", " percent "]
        .iter()
        .any(|needle| lower.contains(needle))
    {
        return None;
    }
    if graph_prompt_requests_rank(nl) {
        return None;
    }
    if trace_route_timings {
        eprintln!(
            "route_timing_grouped_aggregate_prepare={}us fields={}",
            prepare_started.elapsed().as_micros(),
            fields.len()
        );
    }
    let field_map = graph_field_map(fields);
    let entity_map = graph_entity_map(entities);
    let predicates_started = Instant::now();
    let mut predicates = graph_query_predicates_with_vocab(nl, fields, sample_values, vocabulary);
    graph_merge_comparison_value_predicate(nl, fields, sample_values, vocabulary, &mut predicates);
    graph_add_best_date_window_predicate(nl, fields, sample_values, vocabulary, &mut predicates);
    if trace_route_timings {
        eprintln!(
            "route_timing_grouped_aggregate_predicates={}us count={}",
            predicates_started.elapsed().as_micros(),
            predicates.len()
        );
    }
    let explicit_measure =
        graph_explicit_grouped_metric_aggregate_prompt(nl) && measure_probe.is_some();
    let count_like = !explicit_measure
        && (graph_grouped_count_prompt(nl)
            || graph_grouped_default_count_prompt(nl, entities, fields, &predicates, vocabulary));
    let measure = if count_like { None } else { measure_probe };
    let aggregate_kind = if count_like {
        Some("count")
    } else {
        graph_aggregate_kind(&nl.to_ascii_lowercase()).or_else(|| measure.map(|_| "sum"))
    }?;
    let base_entity = if let Some(measure) = measure {
        measure.entity.clone()
    } else {
        graph_grouped_count_base_entity(
            nl,
            entities,
            fields,
            relationships,
            &predicates,
            vocabulary,
        )?
    };
    let refine_started = Instant::now();
    let predicates = graph_refine_grouped_aggregate_predicates(
        nl,
        &base_entity,
        measure,
        fields,
        sample_values,
        vocabulary,
        predicates,
    );
    let predicates = graph_filter_group_by_dimension_predicates(
        nl,
        fields,
        relationships,
        vocabulary,
        predicates,
    );
    if trace_route_timings {
        eprintln!(
            "route_timing_grouped_aggregate_refine={}us count={}",
            refine_started.elapsed().as_micros(),
            predicates.len()
        );
    }
    if predicates.len() > 3 {
        return None;
    }
    let comparison_dimension = graph_comparison_dimension_from_predicates(&predicates, &field_map);
    let grouped_comparison = graph_grouped_comparison_prompt(nl) || value_grouped_comparison;
    let dimensions_started = Instant::now();
    let dimensions = if grouped_comparison {
        comparison_dimension.map_or_else(Vec::new, |field| vec![field])
    } else {
        graph_group_dimension_fields(
            nl,
            &base_entity,
            fields,
            relationships,
            &predicates,
            vocabulary,
        )
    };
    if graph_group_dimension_request_ambiguous(
        nl,
        &base_entity,
        fields,
        relationships,
        &predicates,
        vocabulary,
    ) {
        return None;
    }
    if trace_route_timings {
        eprintln!(
            "route_timing_grouped_aggregate_dimensions={}us count={}",
            dimensions_started.elapsed().as_micros(),
            dimensions.len()
        );
    }
    if dimensions.is_empty() || dimensions.len() > 2 {
        return None;
    }
    if graph_grouped_time_series_prompt(nl)
        && dimensions
            .iter()
            .any(|dimension| !dimension.entity.eq_ignore_ascii_case(&base_entity))
    {
        return None;
    }
    if measure.is_some_and(|measure| {
        dimensions
            .iter()
            .any(|dimension| dimension.canonical() == measure.canonical())
    }) {
        return None;
    }
    let mut required_entities: HashSet<String> = HashSet::from([base_entity.clone()]);
    for dimension in &dimensions {
        required_entities.insert(dimension.entity.clone());
    }
    if let Some(measure) = measure {
        required_entities.insert(measure.entity.clone());
    }
    for predicate in &predicates {
        let field = field_map.get(&predicate.field)?;
        required_entities.insert(field.entity.clone());
    }
    if graph_ambiguous_physical_table_family_for_required_entities(entities, &required_entities)
        .is_some()
    {
        return None;
    }
    let join_started = Instant::now();
    let joins = graph_join_plan_from_base(nl, &base_entity, &required_entities, relationships)?;
    let base = entity_map.get(&base_entity)?;
    let join_sql = graph_render_joins(&base_entity, &joins, &entity_map, &field_map)?;
    let mut where_sql = graph_render_where(&predicates, &field_map, &entity_map)?;
    if aggregate_kind == "avg" {
        if let Some(measure) = measure {
            let measure_ref = graph_field_ref(measure, &entity_map)?;
            if !where_sql.is_empty() {
                where_sql.push_str(" AND ");
            }
            where_sql.push_str(&measure_ref);
            where_sql.push_str(" IS NOT NULL");
        }
    }
    if trace_route_timings {
        eprintln!(
            "route_timing_grouped_aggregate_join_render={}us joins={}",
            join_started.elapsed().as_micros(),
            joins.len()
        );
    }
    let dimension_exprs = dimensions
        .iter()
        .map(|dimension| graph_field_ref(dimension, &entity_map))
        .collect::<Option<Vec<_>>>()?;
    let (projection_field, aggregate_expr, aggregate_order_field) = match (aggregate_kind, measure)
    {
        ("count", None) => {
            let count_field = graph_identity_key_field_for_entity(&base_entity, fields);
            let count_expr = count_field
                .and_then(|field| graph_field_ref(field, &entity_map))
                .unwrap_or_else(|| "*".to_string());
            let alias = graph_grouped_count_alias(&base_entity);
            (
                None,
                format!("COUNT({count_expr}) AS {alias}"),
                count_field.map(FieldRow::canonical),
            )
        }
        ("sum", Some(measure)) => {
            let alias = graph_grouped_measure_alias("total", measure);
            let sum_expr = format!("SUM({}) AS {alias}", graph_field_ref(measure, &entity_map)?);
            if graph_grouped_distribution_includes_count(nl, &base_entity, measure, vocabulary) {
                let count_field = graph_identity_key_field_for_entity(&base_entity, fields);
                let count_expr = count_field
                    .and_then(|field| graph_field_ref(field, &entity_map))
                    .unwrap_or_else(|| "*".to_string());
                let count_alias = graph_grouped_count_alias(&base_entity);
                (
                    Some(measure.canonical()),
                    format!("COUNT({count_expr}) AS {count_alias}, {sum_expr}"),
                    Some(measure.canonical()),
                )
            } else {
                (
                    Some(measure.canonical()),
                    sum_expr,
                    Some(measure.canonical()),
                )
            }
        }
        ("avg", Some(measure)) => {
            let alias = graph_grouped_measure_alias("avg", measure);
            (
                Some(measure.canonical()),
                format!("AVG({}) AS {alias}", graph_field_ref(measure, &entity_map)?),
                Some(measure.canonical()),
            )
        }
        _ => return None,
    };
    let mut select_parts = dimension_exprs.clone();
    select_parts.push(aggregate_expr.clone());
    let mut sql = format!(
        "SELECT {} FROM {}",
        select_parts.join(", "),
        graph_quote_ident(&base.db_table)
    );
    if !join_sql.is_empty() {
        sql.push(' ');
        sql.push_str(&join_sql);
    }
    if !where_sql.is_empty() {
        sql.push_str(" WHERE ");
        sql.push_str(&where_sql);
    }
    sql.push_str(" GROUP BY ");
    sql.push_str(&dimension_exprs.join(", "));
    let mut order_by = None;
    if graph_grouped_time_series_prompt(nl) {
        sql.push_str(" ORDER BY ");
        sql.push_str(&dimension_exprs.join(", "));
    } else if grouped_comparison {
        sql.push_str(" ORDER BY ");
        sql.push_str(&dimension_exprs.join(", "));
        if let Some(dimension) = dimensions.first() {
            order_by = Some(RuntimeQueryFrameOrderTrace {
                field: dimension.canonical(),
                expression: graph_field_ref(dimension, &entity_map)?,
                direction: "ASC".to_string(),
                limit: 0,
            });
        }
    } else {
        let alias = aggregate_expr
            .rsplit_once(" AS ")
            .map(|(_, alias)| alias)
            .unwrap_or("group_value");
        sql.push_str(" ORDER BY ");
        sql.push_str(alias);
        if let Some((direction, limit)) = graph_grouped_topk_order(nl, aggregate_kind, measure) {
            sql.push(' ');
            sql.push_str(&direction);
            sql.push_str(" LIMIT ");
            sql.push_str(&limit.to_string());
            if let Some(field) = aggregate_order_field {
                order_by = Some(RuntimeQueryFrameOrderTrace {
                    field,
                    expression: alias.to_string(),
                    direction,
                    limit,
                });
            }
        } else {
            sql.push(' ');
            sql.push_str(graph_grouped_aggregate_default_direction(
                nl,
                aggregate_kind,
                measure,
            ));
        }
    }
    let mut required_entity_list: Vec<String> = required_entities.into_iter().collect();
    required_entity_list.sort();
    let projection_fields = dimensions
        .iter()
        .map(|dimension| dimension.canonical())
        .collect::<Vec<_>>();
    let projection_field = projection_fields.first().cloned().or(projection_field);
    Some(RuntimeQueryFrameTrace {
        schema_version: 1,
        source: "runtime_graph_query_frame_grouped_aggregate".to_string(),
        question: nl.to_string(),
        routed: true,
        used_for_final_sql: false,
        route_reason: "routed_grouped_aggregate".to_string(),
        sql: Some(sql),
        projection: Some(RuntimeQueryFrameProjectionTrace {
            entity: base_entity,
            field: projection_field,
            fields: projection_fields,
            expression: aggregate_expr,
        }),
        predicates: predicates.iter().map(graph_predicate_trace).collect(),
        required_entities: required_entity_list,
        joins: joins.iter().map(graph_join_trace).collect(),
        order_by,
    })
}

fn graph_grouped_duration_query_frame_trace(
    nl: &str,
    entities: &[EntityRow],
    fields: &[FieldRow],
    relationships: &[RelationshipRow],
    sample_values: &[SampleValueRow],
    vocabulary: &[VocabularyEntry],
) -> Option<RuntimeQueryFrameTrace> {
    if !graph_prompt_requests_grouped_duration(nl) {
        return None;
    }
    let field_map = graph_field_map(fields);
    let entity_map = graph_entity_map(entities);
    let mut predicates = graph_query_predicates_with_vocab(nl, fields, sample_values, vocabulary);
    graph_merge_comparison_value_predicate(nl, fields, sample_values, vocabulary, &mut predicates);
    graph_add_best_date_window_predicate(nl, fields, sample_values, vocabulary, &mut predicates);
    if predicates.len() > 3 {
        return None;
    }
    let (base_entity, start_field, end_field) =
        graph_grouped_duration_field_pair(nl, fields, &predicates, vocabulary)?;
    let dimensions = graph_group_dimension_fields(
        nl,
        &base_entity,
        fields,
        relationships,
        &predicates,
        vocabulary,
    );
    if dimensions.is_empty() || dimensions.len() > 1 {
        return None;
    }
    let dimension = dimensions[0];
    if dimension.canonical() == start_field.canonical()
        || dimension.canonical() == end_field.canonical()
    {
        return None;
    }
    let mut required_entities: HashSet<String> =
        HashSet::from([base_entity.clone(), dimension.entity.clone()]);
    for predicate in &predicates {
        let field = field_map.get(&predicate.field)?;
        required_entities.insert(field.entity.clone());
    }
    if graph_ambiguous_physical_table_family_for_required_entities(entities, &required_entities)
        .is_some()
    {
        return None;
    }
    let joins = graph_join_plan_from_base(nl, &base_entity, &required_entities, relationships)?;
    let base = entity_map.get(&base_entity)?;
    let join_sql = graph_render_joins(&base_entity, &joins, &entity_map, &field_map)?;
    let where_sql = graph_render_where(&predicates, &field_map, &entity_map)?;
    let dimension_expr = graph_field_ref(dimension, &entity_map)?;
    let start_expr = graph_field_ref(start_field, &entity_map)?;
    let end_expr = graph_field_ref(end_field, &entity_map)?;
    let alias = graph_grouped_duration_alias(nl, start_field, end_field);
    let duration_expr = format!("AVG(julianday({end_expr}) - julianday({start_expr})) AS {alias}");
    let mut sql = format!(
        "SELECT {dimension_expr}, {duration_expr} FROM {}",
        graph_quote_ident(&base.db_table)
    );
    if !join_sql.is_empty() {
        sql.push(' ');
        sql.push_str(&join_sql);
    }
    if !where_sql.is_empty() {
        sql.push_str(" WHERE ");
        sql.push_str(&where_sql);
    }
    sql.push_str(" GROUP BY ");
    sql.push_str(&dimension_expr);
    sql.push_str(" ORDER BY ");
    sql.push_str(&alias);
    sql.push_str(" ASC");

    let mut required_entity_list: Vec<String> = required_entities.into_iter().collect();
    required_entity_list.sort();
    Some(RuntimeQueryFrameTrace {
        schema_version: 1,
        source: "runtime_graph_query_frame_grouped_duration".to_string(),
        question: nl.to_string(),
        routed: true,
        used_for_final_sql: false,
        route_reason: "routed_grouped_duration".to_string(),
        sql: Some(sql),
        projection: Some(RuntimeQueryFrameProjectionTrace {
            entity: base_entity,
            field: Some(end_field.canonical()),
            fields: Vec::new(),
            expression: duration_expr,
        }),
        predicates: predicates.iter().map(graph_predicate_trace).collect(),
        required_entities: required_entity_list,
        joins: joins.iter().map(graph_join_trace).collect(),
        order_by: Some(RuntimeQueryFrameOrderTrace {
            field: end_field.canonical(),
            expression: alias,
            direction: "ASC".to_string(),
            limit: 0,
        }),
    })
}

fn graph_prompt_requests_grouped_duration(nl: &str) -> bool {
    if graph_order_direction_limit(nl).is_some() || graph_group_by_phrase(nl).is_none() {
        return false;
    }
    let lower = format!(" {} ", graph_norm(nl));
    let asks_average = [
        " average ",
        " avg ",
        " mean ",
        " typical ",
        " average time ",
        " avg time ",
    ]
    .iter()
    .any(|needle| lower.contains(needle));
    let asks_duration = [
        " days ",
        " duration ",
        " cycle ",
        " time to ",
        " turnaround ",
        " elapsed ",
        " aging ",
        " age by ",
    ]
    .iter()
    .any(|needle| lower.contains(needle));
    let excluded = [" rate ", " ratio ", " percentage ", " percent "]
        .iter()
        .any(|needle| lower.contains(needle));
    asks_average && asks_duration && !excluded
}

fn graph_grouped_duration_field_pair<'a>(
    nl: &str,
    fields: &'a [FieldRow],
    predicates: &[GraphQueryPredicate],
    vocabulary: &[VocabularyEntry],
) -> Option<(String, &'a FieldRow, &'a FieldRow)> {
    let query_tokens = graph_schema_match_tokens(nl);
    let predicate_entities: HashSet<String> = predicates
        .iter()
        .filter_map(|predicate| {
            predicate
                .field
                .split_once('.')
                .map(|(entity, _)| entity.to_string())
        })
        .collect();
    let mut entity_names = fields
        .iter()
        .filter(|field| graph_field_looks_date_like(field))
        .map(|field| field.entity.clone())
        .collect::<Vec<_>>();
    entity_names.sort();
    entity_names.dedup();
    let mut candidates: Vec<(f32, String, &FieldRow, &FieldRow)> = Vec::new();
    for entity in entity_names {
        let date_fields = fields
            .iter()
            .filter(|field| {
                field.entity.eq_ignore_ascii_case(&entity) && graph_field_looks_date_like(field)
            })
            .collect::<Vec<_>>();
        for start in &date_fields {
            for end in &date_fields {
                if start.canonical() == end.canonical() {
                    continue;
                }
                let start_score = graph_duration_start_field_score(nl, start, &query_tokens);
                let end_score = graph_duration_end_field_score(nl, end, &query_tokens);
                if start_score <= 0.0 || end_score <= 0.0 {
                    continue;
                }
                let mut score = start_score + end_score;
                score += graph_entity_tokens_with_vocab(&entity, vocabulary)
                    .intersection(&query_tokens)
                    .count() as f32
                    * 3.0;
                if predicate_entities.contains(&entity) {
                    score += 5.0;
                }
                if graph_duration_start_end_pair_looks_ordered(start, end) {
                    score += 2.0;
                }
                candidates.push((score, entity.clone(), start, end));
            }
        }
    }
    candidates.sort_by(|a, b| {
        b.0.partial_cmp(&a.0)
            .unwrap_or(std::cmp::Ordering::Equal)
            .then_with(|| a.1.cmp(&b.1))
            .then_with(|| a.2.canonical().cmp(&b.2.canonical()))
            .then_with(|| a.3.canonical().cmp(&b.3.canonical()))
    });
    candidates
        .into_iter()
        .map(|(_, entity, start, end)| (entity, start, end))
        .next()
}

fn graph_duration_start_field_score(
    nl: &str,
    field: &FieldRow,
    query_tokens: &HashSet<String>,
) -> f32 {
    let lower = format!(" {} ", graph_norm(nl));
    let compact = graph_compact_field_name(field);
    let mut score = 0.0;
    for needle in [
        "created",
        "create",
        "start",
        "started",
        "open",
        "opened",
        "signup",
        "signedup",
        "issued",
        "submitted",
        "requested",
        "occurred",
        "begin",
        "began",
    ] {
        if compact.contains(needle) {
            score += 5.0;
        }
    }
    score += graph_field_tokens(field).intersection(query_tokens).count() as f32 * 1.5;
    if lower.contains(" from ") && graph_field_context_requested_in_prompt(nl, field, &[]) {
        score += 2.0;
    }
    score
}

fn graph_duration_end_field_score(
    nl: &str,
    field: &FieldRow,
    query_tokens: &HashSet<String>,
) -> f32 {
    let lower = format!(" {} ", graph_norm(nl));
    let compact = graph_compact_field_name(field);
    let mut score = 0.0;
    for needle in [
        "close",
        "closed",
        "resolved",
        "resolve",
        "ended",
        "end",
        "paid",
        "completed",
        "complete",
        "cancel",
        "cancelled",
        "canceled",
        "churn",
        "renewed",
        "approved",
        "finished",
    ] {
        if compact.contains(needle) {
            score += 5.0;
        }
    }
    score += graph_field_tokens(field).intersection(query_tokens).count() as f32 * 1.5;
    if lower.contains(" to ") && graph_field_context_requested_in_prompt(nl, field, &[]) {
        score += 2.0;
    }
    score
}

fn graph_duration_start_end_pair_looks_ordered(start: &FieldRow, end: &FieldRow) -> bool {
    graph_duration_start_field_score("", start, &HashSet::new()) > 0.0
        && graph_duration_end_field_score("", end, &HashSet::new()) > 0.0
}

fn graph_grouped_duration_alias(nl: &str, start: &FieldRow, end: &FieldRow) -> String {
    let lower = format!(" {} ", graph_norm(nl));
    if lower.contains(" cycle ") {
        let entity_norm = start.entity.trim_matches('_').to_ascii_lowercase();
        let entity_stem = graph_simple_singular_form(&entity_norm).unwrap_or(entity_norm);
        return graph_sql_alias(&format!("avg_{entity_stem}_cycle_days"));
    }
    let start_alias = graph_safe_sql_alias(&start.db_column);
    let end_alias = graph_safe_sql_alias(&end.db_column);
    graph_sql_alias(&format!("avg_{end_alias}_minus_{start_alias}_days"))
}

fn graph_anti_join_temporal_query_frame_trace(
    nl: &str,
    entities: &[EntityRow],
    fields: &[FieldRow],
    relationships: &[RelationshipRow],
    sample_values: &[SampleValueRow],
    vocabulary: &[VocabularyEntry],
) -> Option<RuntimeQueryFrameTrace> {
    let lower = format!(" {} ", nl.to_ascii_lowercase().replace('\n', " "));
    if !runtime_prompt_requests_anti_join(&lower) {
        return None;
    }
    let raw_predicates = graph_query_predicates_with_vocab(nl, fields, sample_values, vocabulary);
    let base_entity =
        graph_subject_entity_with_vocab(nl, entities, fields, &raw_predicates, vocabulary)?;
    let child_entity = graph_anti_join_child_entity(
        nl,
        &base_entity,
        entities,
        fields,
        relationships,
        &raw_predicates,
        vocabulary,
    )?;
    let relationship =
        graph_anti_join_relationship_between(&base_entity, &child_entity, relationships)?;
    let entity_map = graph_entity_map(entities);
    let field_map = graph_field_map(fields);
    let base = entity_map.get(&base_entity)?;
    let projection_field =
        graph_default_display_field_for_entity_with_vocab(&base_entity, fields, vocabulary)?;
    let projection_expr = graph_field_ref(projection_field, &entity_map)?;
    let base_predicates =
        graph_anti_join_base_predicates(nl, &base_entity, fields, &raw_predicates)?;
    let child_predicates = graph_anti_join_child_predicates(
        nl,
        &child_entity,
        fields,
        &raw_predicates,
        sample_values,
        vocabulary,
    )?;
    if base_predicates.is_empty() || child_predicates.is_empty() || child_predicates.len() > 3 {
        return None;
    }

    let (base_join_field, child_join_field) =
        graph_anti_join_join_fields(&base_entity, &child_entity, relationship, &field_map)?;
    let base_join_expr = graph_field_ref(base_join_field, &entity_map)?;
    let child_join_expr = graph_field_ref(child_join_field, &entity_map)?;
    let base_where = graph_render_where(&base_predicates, &field_map, &entity_map)?;
    let child_where = graph_render_where(&child_predicates, &field_map, &entity_map)?;
    let child_table = entity_map.get(&child_entity)?;
    let sql = format!(
        "SELECT {projection_expr} FROM {} WHERE {base_where} AND NOT EXISTS (SELECT 1 FROM {} WHERE {child_join_expr} = {base_join_expr} AND {child_where}) ORDER BY {projection_expr} ASC",
        graph_quote_ident(&base.db_table),
        graph_quote_ident(&child_table.db_table),
    );
    let mut trace_predicates = base_predicates.clone();
    trace_predicates.extend(child_predicates.clone());
    trace_predicates.sort_by(|a, b| {
        a.field
            .cmp(&b.field)
            .then_with(|| a.operator.cmp(&b.operator))
            .then_with(|| a.value.cmp(&b.value))
    });
    let mut required_entities = vec![base_entity.clone(), child_entity.clone()];
    required_entities.sort();
    required_entities.dedup();
    let join_step = GraphJoinStep {
        from_entity: relationship.from_entity.clone(),
        from_field: relationship.from_field.clone(),
        to_entity: relationship.to_entity.clone(),
        to_field: relationship.to_field.clone(),
    };
    Some(RuntimeQueryFrameTrace {
        schema_version: 1,
        source: "runtime_graph_query_frame_anti_join_temporal".to_string(),
        question: nl.to_string(),
        routed: true,
        used_for_final_sql: false,
        route_reason: "routed_anti_join_temporal".to_string(),
        sql: Some(sql),
        projection: Some(RuntimeQueryFrameProjectionTrace {
            entity: base_entity,
            field: Some(projection_field.canonical()),
            fields: vec![projection_field.canonical()],
            expression: projection_expr.clone(),
        }),
        predicates: trace_predicates.iter().map(graph_predicate_trace).collect(),
        required_entities,
        joins: vec![graph_join_trace(&join_step)],
        order_by: Some(RuntimeQueryFrameOrderTrace {
            field: projection_field.canonical(),
            expression: projection_expr,
            direction: "ASC".to_string(),
            limit: 0,
        }),
    })
}

fn graph_anti_join_child_entity(
    nl: &str,
    base_entity: &str,
    entities: &[EntityRow],
    fields: &[FieldRow],
    relationships: &[RelationshipRow],
    raw_predicates: &[GraphQueryPredicate],
    vocabulary: &[VocabularyEntry],
) -> Option<String> {
    let tail = graph_anti_join_tail(nl);
    let tail_tokens = graph_tokens_with_aliases(&tail);
    let query_tokens = graph_tokens_with_aliases(nl);
    let field_map = graph_field_map(fields);
    let predicate_entities: HashSet<String> = raw_predicates
        .iter()
        .filter_map(|predicate| {
            field_map
                .get(&predicate.field)
                .map(|field| field.entity.clone())
        })
        .collect();
    let mut candidates: Vec<(f32, String)> = entities
        .iter()
        .filter(|entity| !entity.canonical_name.eq_ignore_ascii_case(base_entity))
        .filter(|entity| {
            graph_anti_join_relationship_between(base_entity, &entity.canonical_name, relationships)
                .is_some()
        })
        .filter_map(|entity| {
            let entity_tokens = graph_entity_tokens_with_vocab(&entity.canonical_name, vocabulary);
            let mut score = entity_tokens.intersection(&tail_tokens).count() as f32 * 8.0;
            score += entity_tokens.intersection(&query_tokens).count() as f32 * 2.0;
            if predicate_entities.contains(&entity.canonical_name) {
                score += 5.0;
            }
            for field in fields
                .iter()
                .filter(|field| field.entity.eq_ignore_ascii_case(&entity.canonical_name))
            {
                let field_tokens = graph_field_tokens_with_vocab(field, vocabulary);
                score += field_tokens.intersection(&tail_tokens).count() as f32 * 2.0;
                if graph_field_looks_date_like(field) {
                    score += 1.0;
                }
            }
            (score >= 3.0).then_some((score, entity.canonical_name.clone()))
        })
        .collect();
    candidates.sort_by(|a, b| {
        b.0.partial_cmp(&a.0)
            .unwrap_or(std::cmp::Ordering::Equal)
            .then_with(|| a.1.cmp(&b.1))
    });
    candidates.into_iter().map(|(_, entity)| entity).next()
}

fn graph_anti_join_relationship_between<'a>(
    base_entity: &str,
    child_entity: &str,
    relationships: &'a [RelationshipRow],
) -> Option<&'a RelationshipRow> {
    relationships.iter().find(|relationship| {
        (relationship.from_entity.eq_ignore_ascii_case(base_entity)
            && relationship.to_entity.eq_ignore_ascii_case(child_entity))
            || (relationship.from_entity.eq_ignore_ascii_case(child_entity)
                && relationship.to_entity.eq_ignore_ascii_case(base_entity))
    })
}

fn graph_anti_join_join_fields<'a>(
    base_entity: &str,
    child_entity: &str,
    relationship: &RelationshipRow,
    field_map: &HashMap<String, &'a FieldRow>,
) -> Option<(&'a FieldRow, &'a FieldRow)> {
    if relationship.from_entity.eq_ignore_ascii_case(base_entity)
        && relationship.to_entity.eq_ignore_ascii_case(child_entity)
    {
        Some((
            graph_field_from_parts(
                &relationship.from_entity,
                &relationship.from_field,
                field_map,
            )?,
            graph_field_from_parts(&relationship.to_entity, &relationship.to_field, field_map)?,
        ))
    } else if relationship.from_entity.eq_ignore_ascii_case(child_entity)
        && relationship.to_entity.eq_ignore_ascii_case(base_entity)
    {
        Some((
            graph_field_from_parts(&relationship.to_entity, &relationship.to_field, field_map)?,
            graph_field_from_parts(
                &relationship.from_entity,
                &relationship.from_field,
                field_map,
            )?,
        ))
    } else {
        None
    }
}

fn graph_anti_join_base_predicates(
    nl: &str,
    base_entity: &str,
    fields: &[FieldRow],
    raw_predicates: &[GraphQueryPredicate],
) -> Option<Vec<GraphQueryPredicate>> {
    let field_map = graph_field_map(fields);
    let marker = graph_anti_join_marker_position(nl).unwrap_or(usize::MAX);
    let mut out = Vec::new();
    for predicate in raw_predicates {
        let Some(field) = field_map.get(&predicate.field).copied() else {
            continue;
        };
        if !field.entity.eq_ignore_ascii_case(base_entity)
            || graph_field_looks_date_like(field)
            || graph_field_looks_unsafe_id(field)
        {
            continue;
        }
        let mut predicate = predicate.clone();
        if predicate.operator == "!="
            && graph_anti_join_value_position(nl, &predicate.value).is_some_and(|pos| pos < marker)
        {
            predicate.operator = "=".to_string();
        }
        if predicate.operator == "=" {
            out.push(predicate);
        }
    }
    out.sort_by(|a, b| {
        a.field
            .cmp(&b.field)
            .then_with(|| a.operator.cmp(&b.operator))
            .then_with(|| a.value.cmp(&b.value))
    });
    out.dedup_by(|a, b| a.field == b.field && a.operator == b.operator && a.value == b.value);
    (out.len() <= 2).then_some(out)
}

fn graph_anti_join_child_predicates(
    nl: &str,
    child_entity: &str,
    fields: &[FieldRow],
    raw_predicates: &[GraphQueryPredicate],
    sample_values: &[SampleValueRow],
    vocabulary: &[VocabularyEntry],
) -> Option<Vec<GraphQueryPredicate>> {
    let field_map = graph_field_map(fields);
    let mut out = Vec::new();
    if let Some(date_predicate) =
        graph_anti_join_temporal_predicate(nl, child_entity, fields, sample_values, vocabulary)
    {
        out.push(date_predicate);
    }
    for predicate in raw_predicates {
        let Some(field) = field_map.get(&predicate.field).copied() else {
            continue;
        };
        if !field.entity.eq_ignore_ascii_case(child_entity)
            || graph_field_looks_date_like(field)
            || graph_field_looks_unsafe_id(field)
        {
            continue;
        }
        let mut predicate = predicate.clone();
        if predicate.operator == "!=" {
            predicate.operator = "=".to_string();
        }
        if predicate.operator == "=" {
            out.push(predicate);
        }
    }
    out.sort_by(|a, b| {
        a.field
            .cmp(&b.field)
            .then_with(|| a.operator.cmp(&b.operator))
            .then_with(|| a.value.cmp(&b.value))
    });
    out.dedup_by(|a, b| a.field == b.field && a.operator == b.operator && a.value == b.value);
    out.iter()
        .any(|predicate| {
            field_map
                .get(&predicate.field)
                .is_some_and(|field| graph_field_looks_date_like(field))
        })
        .then_some(out)
}

fn graph_anti_join_temporal_predicate(
    nl: &str,
    child_entity: &str,
    fields: &[FieldRow],
    sample_values: &[SampleValueRow],
    vocabulary: &[VocabularyEntry],
) -> Option<GraphQueryPredicate> {
    let _ = sample_values;
    let (mention, value) = graph_anti_join_explicit_date(nl)?;
    let field = graph_anti_join_child_date_field(nl, &mention, child_entity, fields, vocabulary)?;
    let operator = graph_anti_join_date_operator(nl, &mention);
    Some(GraphQueryPredicate {
        field: field.canonical(),
        value,
        operator: operator.to_string(),
    })
}

fn graph_anti_join_child_date_field<'a>(
    nl: &str,
    mention: &str,
    child_entity: &str,
    fields: &'a [FieldRow],
    vocabulary: &[VocabularyEntry],
) -> Option<&'a FieldRow> {
    let context = graph_mention_context(nl, mention);
    let context_tokens = graph_tokens_with_aliases(&context);
    let child_tokens = graph_entity_tokens_with_vocab(child_entity, vocabulary);
    let mut candidates: Vec<(f32, &FieldRow)> = fields
        .iter()
        .filter(|field| {
            field.entity.eq_ignore_ascii_case(child_entity) && graph_field_looks_date_like(field)
        })
        .map(|field| {
            let compact = graph_compact_field_name(field);
            let mut score = graph_field_tokens_with_vocab(field, vocabulary)
                .intersection(&context_tokens)
                .count() as f32
                * 4.0;
            score += child_tokens.intersection(&context_tokens).count() as f32 * 2.0;
            if compact.contains("occurred") || compact.contains("happened") {
                score += 7.0;
            }
            if compact.contains("created") || compact.contains("opened") {
                score += 4.0;
            }
            if compact.contains("resolved") || compact.contains("closed") {
                score += 2.0;
            }
            (score, field)
        })
        .collect();
    candidates.sort_by(|a, b| {
        b.0.partial_cmp(&a.0)
            .unwrap_or(std::cmp::Ordering::Equal)
            .then_with(|| a.1.canonical().cmp(&b.1.canonical()))
    });
    candidates.into_iter().map(|(_, field)| field).next()
}

fn graph_anti_join_explicit_date(nl: &str) -> Option<(String, String)> {
    let tokens = graph_norm(nl)
        .split_whitespace()
        .map(ToString::to_string)
        .collect::<Vec<_>>();
    for window in tokens.windows(3) {
        let Some(month) = graph_month_number(&window[0]) else {
            continue;
        };
        let Some(day) = graph_parse_day_token(&window[1]) else {
            continue;
        };
        let Some(year) = graph_parse_year_token(&window[2]) else {
            continue;
        };
        return Some((
            format!("{} {} {}", window[0], window[1], window[2]),
            format!("{year:04}-{month:02}-{day:02}"),
        ));
    }
    for literal in graph_structured_literals(nl) {
        if graph_is_date_like(&literal) {
            let value = graph_normalise_date_literal(&literal)?;
            return Some((literal, value));
        }
    }
    graph_named_date_windows(nl)
        .into_iter()
        .find(|window| !window.value.contains(".."))
        .map(|window| (window.mention, window.value))
}

fn graph_parse_day_token(token: &str) -> Option<u32> {
    let day = token.parse::<u32>().ok()?;
    (1..=31).contains(&day).then_some(day)
}

fn graph_anti_join_date_operator(nl: &str, mention: &str) -> &'static str {
    let context = graph_mention_context(nl, mention).to_ascii_lowercase();
    if context.contains(" after ") {
        ">"
    } else if context.contains(" before ") || context.contains(" until ") {
        "<"
    } else {
        ">="
    }
}

fn graph_anti_join_tail(nl: &str) -> String {
    let lower = graph_norm(nl);
    let marker = graph_anti_join_marker_position(nl).unwrap_or(0);
    lower.get(marker..).unwrap_or(&lower).to_string()
}

fn graph_anti_join_marker_position(nl: &str) -> Option<usize> {
    let lower = format!(" {} ", graph_norm(nl));
    [" no ", " without ", " have not ", " has not ", " not had "]
        .iter()
        .filter_map(|marker| lower.find(marker))
        .min()
}

fn graph_anti_join_value_position(nl: &str, value: &str) -> Option<usize> {
    let lower = graph_norm(nl);
    let value_norm = graph_norm(value);
    (!value_norm.is_empty())
        .then(|| lower.find(&value_norm))
        .flatten()
}

fn graph_grouped_ratio_query_frame_trace(
    nl: &str,
    entities: &[EntityRow],
    fields: &[FieldRow],
    relationships: &[RelationshipRow],
    sample_values: &[SampleValueRow],
    vocabulary: &[VocabularyEntry],
) -> Option<RuntimeQueryFrameTrace> {
    if !graph_prompt_requests_grouped_ratio(nl) {
        return None;
    }
    let field_map = graph_field_map(fields);
    let entity_map = graph_entity_map(entities);
    let mut predicates = graph_query_predicates_with_vocab(nl, fields, sample_values, vocabulary);
    let condition_index =
        graph_grouped_ratio_condition_index(nl, &predicates, &field_map, vocabulary)?;
    let condition = predicates.remove(condition_index);
    let condition_field = field_map.get(&condition.field).copied()?;
    if condition.operator != "=" {
        return None;
    }
    predicates.retain(|predicate| {
        !graph_grouped_ratio_target_role_predicate(
            nl,
            predicate,
            &condition,
            condition_field,
            &field_map,
        )
    });
    let base_entity = condition_field.entity.clone();
    let dimensions = graph_group_dimension_fields(
        nl,
        &base_entity,
        fields,
        relationships,
        &predicates,
        vocabulary,
    );
    if dimensions.is_empty() || dimensions.len() > 1 {
        return None;
    }
    let dimension = dimensions[0];
    let mut required_entities: HashSet<String> =
        HashSet::from([base_entity.clone(), dimension.entity.clone()]);
    for predicate in predicates.iter().chain(std::iter::once(&condition)) {
        let field = field_map.get(&predicate.field)?;
        required_entities.insert(field.entity.clone());
    }
    if graph_ambiguous_physical_table_family_for_required_entities(entities, &required_entities)
        .is_some()
    {
        return None;
    }
    let joins = graph_join_plan_from_base(nl, &base_entity, &required_entities, relationships)?;
    let base = entity_map.get(&base_entity)?;
    let join_sql = graph_render_joins(&base_entity, &joins, &entity_map, &field_map)?;
    let where_sql = graph_render_where(&predicates, &field_map, &entity_map)?;
    let condition_sql =
        graph_render_where(std::slice::from_ref(&condition), &field_map, &entity_map)?;
    let denominator = graph_identity_key_field_for_entity(&base_entity, fields)?;
    let dimension_expr = graph_field_ref(dimension, &entity_map)?;
    let denominator_expr = graph_field_ref(denominator, &entity_map)?;
    let alias = graph_grouped_ratio_alias(nl, condition_field, &condition.value);
    let ratio_expr = format!(
        "CAST(SUM(CASE WHEN {condition_sql} THEN 1 ELSE 0 END) AS REAL) * 100.0 / COUNT({denominator_expr}) AS {alias}"
    );
    let mut sql = format!(
        "SELECT {dimension_expr}, {ratio_expr} FROM {}",
        graph_quote_ident(&base.db_table)
    );
    if !join_sql.is_empty() {
        sql.push(' ');
        sql.push_str(&join_sql);
    }
    if !where_sql.is_empty() {
        sql.push_str(" WHERE ");
        sql.push_str(&where_sql);
    }
    sql.push_str(" GROUP BY ");
    sql.push_str(&dimension_expr);
    sql.push_str(" ORDER BY ");
    sql.push_str(&alias);
    sql.push_str(" DESC");

    let mut trace_predicates = predicates;
    trace_predicates.push(condition.clone());
    trace_predicates.sort_by(|a, b| {
        a.field
            .cmp(&b.field)
            .then_with(|| a.operator.cmp(&b.operator))
            .then_with(|| a.value.cmp(&b.value))
    });
    let mut required_entity_list: Vec<String> = required_entities.into_iter().collect();
    required_entity_list.sort();
    Some(RuntimeQueryFrameTrace {
        schema_version: 1,
        source: "runtime_graph_query_frame_grouped_ratio".to_string(),
        question: nl.to_string(),
        routed: true,
        used_for_final_sql: false,
        route_reason: "routed_grouped_ratio".to_string(),
        sql: Some(sql),
        projection: Some(RuntimeQueryFrameProjectionTrace {
            entity: base_entity,
            field: Some(condition.field.clone()),
            fields: Vec::new(),
            expression: ratio_expr,
        }),
        predicates: trace_predicates.iter().map(graph_predicate_trace).collect(),
        required_entities: required_entity_list,
        joins: joins.iter().map(graph_join_trace).collect(),
        order_by: Some(RuntimeQueryFrameOrderTrace {
            field: condition.field,
            expression: alias,
            direction: "DESC".to_string(),
            limit: 0,
        }),
    })
}

fn graph_prompt_requests_grouped_ratio(nl: &str) -> bool {
    if graph_order_direction_limit(nl).is_some() || !graph_prompt_requests_metric_ratio(nl) {
        return false;
    }
    let lower = format!(" {} ", graph_norm(nl));
    lower.contains(" by ") && graph_group_by_phrase(nl).is_some()
}

fn graph_grouped_ratio_condition_index(
    nl: &str,
    predicates: &[GraphQueryPredicate],
    field_map: &HashMap<String, &FieldRow>,
    vocabulary: &[VocabularyEntry],
) -> Option<usize> {
    let query_tokens = graph_schema_match_tokens(nl);
    let mut scored = Vec::new();
    for (idx, predicate) in predicates.iter().enumerate() {
        if predicate.operator != "=" {
            continue;
        }
        let Some(field) = field_map.get(&predicate.field).copied() else {
            continue;
        };
        if graph_field_looks_date_like(field) || graph_field_looks_unsafe_id(field) {
            continue;
        }
        let field_tokens = graph_field_tokens_with_vocab(field, vocabulary);
        let value_tokens = graph_schema_match_tokens(&predicate.value);
        let mut score = field_tokens.intersection(&query_tokens).count() as f32 * 2.0;
        score += value_tokens.intersection(&query_tokens).count() as f32 * 4.0;
        score += graph_grouped_ratio_condition_semantic_bonus(nl, field, &predicate.value);
        if score >= 3.0 {
            scored.push((score, idx));
        }
    }
    scored.sort_by(|a, b| {
        b.0.partial_cmp(&a.0)
            .unwrap_or(std::cmp::Ordering::Equal)
            .then_with(|| a.1.cmp(&b.1))
    });
    scored.into_iter().map(|(_, idx)| idx).next()
}

fn graph_grouped_ratio_target_role_predicate(
    nl: &str,
    predicate: &GraphQueryPredicate,
    condition: &GraphQueryPredicate,
    condition_field: &FieldRow,
    field_map: &HashMap<String, &FieldRow>,
) -> bool {
    if predicate.operator != "=" || predicate.field == condition.field {
        return false;
    }
    let lower = format!(" {} ", graph_norm(nl));
    if !lower.contains(" conversion ") && !lower.contains(" converted ") {
        return false;
    }
    if graph_norm(&condition.value) != "converted" {
        return false;
    }
    let Some(predicate_field) = field_map.get(&predicate.field).copied() else {
        return false;
    };
    if predicate_field
        .entity
        .eq_ignore_ascii_case(&condition_field.entity)
    {
        return false;
    }
    let value_norm = graph_norm(&predicate.value);
    !value_norm.is_empty() && graph_conversion_rate_target_role_norms(nl).contains(&value_norm)
}

fn graph_conversion_rate_target_role_norms(nl: &str) -> HashSet<String> {
    let norm = graph_norm(nl);
    let Some((_, tail)) = norm.split_once(" to ") else {
        return HashSet::new();
    };
    let mut end = tail.len();
    for marker in [
        " conversion ",
        " converted ",
        " rate ",
        " ratio ",
        " percent ",
        " percentage ",
        " by ",
        " for ",
        " in ",
        " with ",
        " where ",
    ] {
        if let Some(index) = tail.find(marker) {
            end = end.min(index);
        }
    }
    let phrase = tail[..end].trim();
    if phrase.is_empty() {
        return HashSet::new();
    }
    let mut out = HashSet::from([phrase.to_string()]);
    for token in graph_ordered_tokens(phrase) {
        out.insert(token.clone());
        if let Some(stem) = token.strip_suffix('s') {
            if stem.len() >= 2 {
                out.insert(stem.to_string());
            }
        } else {
            out.insert(format!("{token}s"));
        }
    }
    out
}

fn graph_grouped_ratio_condition_semantic_bonus(nl: &str, field: &FieldRow, value: &str) -> f32 {
    let lower = format!(" {} ", graph_norm(nl));
    let compact = graph_compact_field_name(field);
    let value_norm = graph_norm(value);
    let mut score = 0.0;
    if lower.contains(" conversion ") || lower.contains(" converted ") {
        if value_norm == "converted" {
            score += 8.0;
        }
        if compact.contains("status") || compact.contains("stage") {
            score += 3.0;
        }
    }
    if lower.contains(" breach ") || lower.contains(" breached ") {
        if value_norm == "1" || value_norm == "true" {
            score += 8.0;
        }
        if compact.contains("breach") || compact.contains("sla") {
            score += 6.0;
        }
    }
    score
}

fn graph_grouped_ratio_alias(nl: &str, field: &FieldRow, value: &str) -> String {
    let lower = format!(" {} ", graph_norm(nl));
    if lower.contains(" conversion ") || lower.contains(" converted ") {
        return "conversion_rate".to_string();
    }
    let compact = graph_compact_field_name(field);
    if (lower.contains(" breach ") || lower.contains(" breached "))
        && (compact.contains("sla") || compact.contains("breach"))
    {
        return "sla_breach_rate".to_string();
    }
    let field_alias = graph_safe_sql_alias(&field.db_column);
    let value_alias = graph_safe_sql_alias(value);
    if value_alias.is_empty() {
        format!("{field_alias}_rate")
    } else {
        format!("{field_alias}_{value_alias}_rate")
    }
}

fn graph_conditional_rate_query_frame_trace(
    nl: &str,
    entities: &[EntityRow],
    fields: &[FieldRow],
    relationships: &[RelationshipRow],
    sample_values: &[SampleValueRow],
    vocabulary: &[VocabularyEntry],
) -> Option<RuntimeQueryFrameTrace> {
    if !graph_prompt_requests_conditional_rate(nl) {
        return None;
    }
    let field_map = graph_field_map(fields);
    let entity_map = graph_entity_map(entities);
    let subject_entity = graph_rate_subject_entity(nl, entities);
    let (condition, condition_mention_norm) = graph_conditional_rate_boolean_condition(
        nl,
        fields,
        sample_values,
        vocabulary,
        subject_entity.as_deref(),
    )?;
    let condition_field = field_map.get(&condition.field).copied()?;
    if condition.operator != "="
        || !graph_field_looks_boolean_rate_condition_with_samples(condition_field, sample_values)
    {
        return None;
    }
    let base_entity = subject_entity.unwrap_or_else(|| condition_field.entity.clone());
    let mut predicates = graph_query_predicates_with_vocab(nl, fields, sample_values, vocabulary);
    predicates.retain(|predicate| {
        if predicate.field == condition.field
            || graph_norm(&predicate.value) == condition_mention_norm
            || graph_conditional_rate_predicate_shadowed_by_condition(
                predicate,
                &condition,
                &condition_mention_norm,
            )
        {
            return false;
        }
        let Some(field) = field_map.get(&predicate.field).copied() else {
            return false;
        };
        if graph_field_looks_boolean_rate_condition_with_samples(field, sample_values)
            && graph_boolean_predicate_value(&predicate.value)
            && !field.entity.eq_ignore_ascii_case(&base_entity)
        {
            return graph_conditional_rate_extra_boolean_filter_allowed(nl, field);
        }
        true
    });
    let mut required_entities: HashSet<String> = HashSet::from([base_entity.clone()]);
    for predicate in predicates.iter().chain(std::iter::once(&condition)) {
        let field = field_map.get(&predicate.field)?;
        required_entities.insert(field.entity.clone());
    }
    if graph_ambiguous_physical_table_family_for_required_entities(entities, &required_entities)
        .is_some()
    {
        return None;
    }
    let joins = graph_join_plan_from_base(nl, &base_entity, &required_entities, relationships)?;
    let base = entity_map.get(&base_entity)?;
    let join_sql = graph_render_joins(&base_entity, &joins, &entity_map, &field_map)?;
    let where_sql = graph_render_where(&predicates, &field_map, &entity_map)?;
    let condition_sql =
        graph_render_where(std::slice::from_ref(&condition), &field_map, &entity_map)?;
    let denominator = graph_identity_key_field_for_entity(&base_entity, fields)?;
    let denominator_expr = graph_field_ref(denominator, &entity_map)?;
    let alias = graph_grouped_ratio_alias(nl, condition_field, &condition.value);
    let ratio_expr = format!(
        "SUM(CASE WHEN {condition_sql} THEN 1 ELSE 0 END) * 100.0 / NULLIF(COUNT({denominator_expr}), 0) AS {alias}"
    );
    let mut sql = format!(
        "SELECT {ratio_expr} FROM {}",
        graph_quote_ident(&base.db_table)
    );
    if !join_sql.is_empty() {
        sql.push(' ');
        sql.push_str(&join_sql);
    }
    if !where_sql.is_empty() {
        sql.push_str(" WHERE ");
        sql.push_str(&where_sql);
    }
    let mut trace_predicates = predicates;
    trace_predicates.push(condition.clone());
    trace_predicates.sort_by(|a, b| {
        a.field
            .cmp(&b.field)
            .then_with(|| a.operator.cmp(&b.operator))
            .then_with(|| a.value.cmp(&b.value))
    });
    let mut required_entity_list: Vec<String> = required_entities.into_iter().collect();
    required_entity_list.sort();
    Some(RuntimeQueryFrameTrace {
        schema_version: 1,
        source: "runtime_graph_query_frame_conditional_rate".to_string(),
        question: nl.to_string(),
        routed: true,
        used_for_final_sql: false,
        route_reason: "routed_conditional_rate".to_string(),
        sql: Some(sql),
        projection: Some(RuntimeQueryFrameProjectionTrace {
            entity: base_entity,
            field: Some(condition.field.clone()),
            fields: Vec::new(),
            expression: ratio_expr,
        }),
        predicates: trace_predicates.iter().map(graph_predicate_trace).collect(),
        required_entities: required_entity_list,
        joins: joins.iter().map(graph_join_trace).collect(),
        order_by: None,
    })
}

fn graph_conditional_rate_predicate_shadowed_by_condition(
    predicate: &GraphQueryPredicate,
    condition: &GraphQueryPredicate,
    condition_mention_norm: &str,
) -> bool {
    if predicate.field == condition.field {
        return true;
    }
    let value_norm = graph_norm(&predicate.value);
    if value_norm.is_empty() || condition_mention_norm.is_empty() {
        return false;
    }
    value_norm == condition_mention_norm
        || graph_norm_contains(condition_mention_norm, &value_norm)
        || graph_norm_contains(&value_norm, condition_mention_norm)
}

fn graph_prompt_requests_conditional_rate(nl: &str) -> bool {
    if graph_order_direction_limit(nl).is_some()
        || graph_group_by_phrase(nl).is_some()
        || graph_prompt_requests_grouped_ratio(nl)
        || graph_metric_prompt_has_unsafe_terms(nl)
    {
        return false;
    }
    graph_prompt_requests_metric_ratio(nl)
}

fn graph_conditional_rate_boolean_condition(
    nl: &str,
    fields: &[FieldRow],
    sample_values: &[SampleValueRow],
    vocabulary: &[VocabularyEntry],
    subject_entity: Option<&str>,
) -> Option<(GraphQueryPredicate, String)> {
    let field_map = graph_field_map(fields);
    let query_tokens = graph_schema_match_tokens(nl);
    let mut scored = Vec::new();
    for (base_score, mention_norm, field, value) in
        graph_derived_boolean_predicates(nl, fields, sample_values, vocabulary)
    {
        let Some(field_row) = field_map.get(&field).copied() else {
            continue;
        };
        if !graph_field_looks_boolean_rate_condition_with_samples(field_row, sample_values) {
            continue;
        }
        let mut score = base_score;
        score += graph_field_tokens_with_vocab(field_row, vocabulary)
            .intersection(&query_tokens)
            .count() as f32
            * 2.0;
        score += graph_entity_tokens_with_vocab(&field_row.entity, vocabulary)
            .intersection(&query_tokens)
            .count() as f32
            * 4.0;
        if subject_entity.is_some_and(|entity| entity.eq_ignore_ascii_case(&field_row.entity)) {
            score += 18.0;
        }
        if matches!(value.as_str(), "1" | "true") {
            score += 2.0;
        }
        if score >= 3.0 {
            scored.push((score, mention_norm, field, value));
        }
    }
    scored.sort_by(|a, b| {
        b.0.partial_cmp(&a.0)
            .unwrap_or(std::cmp::Ordering::Equal)
            .then_with(|| b.1.len().cmp(&a.1.len()))
            .then_with(|| a.2.cmp(&b.2))
    });
    scored
        .into_iter()
        .map(|(_, mention_norm, field, value)| {
            (
                GraphQueryPredicate {
                    operator: graph_operator_for_mention(nl, &mention_norm).to_string(),
                    field,
                    value,
                },
                mention_norm,
            )
        })
        .next()
}

fn graph_boolean_predicate_value(value: &str) -> bool {
    matches!(
        value.to_ascii_lowercase().as_str(),
        "0" | "1" | "true" | "false"
    )
}

fn graph_conditional_rate_extra_boolean_filter_allowed(nl: &str, field: &FieldRow) -> bool {
    let lower = format!(" {} ", graph_norm(nl));
    graph_boolean_field_phrases(field).iter().any(|phrase| {
        if phrase.is_empty() || !graph_norm_contains(&lower, phrase) {
            return false;
        }
        [
            format!(" with {phrase} "),
            format!(" where {phrase} "),
            format!(" for {phrase} "),
            format!(" among {phrase} "),
            format!(" from {phrase} "),
            format!(" only {phrase} "),
            format!(" {phrase} only "),
        ]
        .iter()
        .any(|needle| lower.contains(needle))
    })
}

fn graph_rate_subject_entity(nl: &str, entities: &[EntityRow]) -> Option<String> {
    let tokens = graph_ordered_tokens(nl);
    let mut start = None;
    for (idx, token) in tokens.iter().enumerate() {
        if matches!(
            token.as_str(),
            "percentage" | "percent" | "rate" | "ratio" | "share"
        ) {
            start = Some(idx + 1);
            break;
        }
    }
    let mut start = start?;
    while tokens
        .get(start)
        .is_some_and(|token| matches!(token.as_str(), "of" | "the" | "a" | "an"))
    {
        start += 1;
    }
    graph_count_subject_entity_phrase_match(&tokens, start, entities).or_else(|| {
        tokens.iter().skip(start).take(6).find_map(|token| {
            if matches!(
                token.as_str(),
                "are" | "is" | "was" | "were" | "have" | "has" | "had" | "with" | "where"
            ) {
                return None;
            }
            entities.iter().find_map(|entity| {
                let entity_tokens = graph_entity_tokens(entity);
                entity_tokens
                    .contains(token)
                    .then(|| entity.canonical_name.clone())
            })
        })
    })
}

fn graph_field_looks_boolean_rate_condition(field: &FieldRow) -> bool {
    (is_boolean_field_type(&field.field_type) || field_name_suggests_boolean(&field.canonical()))
        && !graph_field_looks_date_like(field)
        && !graph_field_looks_unsafe_id(field)
}

fn graph_field_looks_boolean_rate_condition_with_samples(
    field: &FieldRow,
    sample_values: &[SampleValueRow],
) -> bool {
    (graph_field_looks_boolean_rate_condition(field)
        || graph_field_has_boolean_sample_domain(field, sample_values))
        && !graph_field_looks_date_like(field)
        && !graph_field_looks_unsafe_id(field)
}

