fn graph_grouped_measure_field<'a>(
    nl: &str,
    fields: &'a [FieldRow],
    vocabulary: &[VocabularyEntry],
) -> Option<&'a FieldRow> {
    graph_grouped_measure_field_scoped(nl, fields, vocabulary, None)
}

fn graph_grouped_measure_field_scoped<'a>(
    nl: &str,
    fields: &'a [FieldRow],
    vocabulary: &[VocabularyEntry],
    subject_entity: Option<&str>,
) -> Option<&'a FieldRow> {
    let nl_norm = graph_norm(nl);
    let mut exact_matches = Vec::new();
    for field in fields.iter().filter(|field| {
        graph_field_looks_numeric(field)
            && !graph_field_looks_unsafe_id(field)
            && !graph_field_has_identity_alias(field, vocabulary)
            && !graph_field_looks_actor_reference_numeric(field)
    }) {
        for raw in [
            field.field.as_str(),
            field.db_column.as_str(),
            field.display_label.as_deref().unwrap_or(""),
        ] {
            let phrase = graph_norm(raw);
            if !phrase.contains(' ') || !graph_norm_contains(&nl_norm, &phrase) {
                continue;
            }
            let subject_match =
                subject_entity.is_some_and(|entity| entity.eq_ignore_ascii_case(&field.entity));
            exact_matches.push((subject_match, phrase.len(), field));
        }
    }
    exact_matches.sort_by(|a, b| {
        b.0.cmp(&a.0)
            .then_with(|| b.1.cmp(&a.1))
            .then_with(|| a.2.canonical().cmp(&b.2.canonical()))
    });
    if let Some((subject_match, _, field)) = exact_matches.into_iter().next() {
        if subject_match || subject_entity.is_none() {
            return Some(field);
        }
    }

    let lower = nl.to_ascii_lowercase();
    let tokens = graph_schema_match_tokens(nl);
    let mut scored: Vec<(f32, &FieldRow)> = fields
        .iter()
        .filter(|field| {
            graph_field_looks_numeric(field)
                && !graph_field_looks_unsafe_id(field)
                && !graph_field_has_identity_alias(field, vocabulary)
                && !graph_field_looks_actor_reference_numeric(field)
        })
        .filter_map(|field| {
            let field_tokens = graph_field_tokens_with_vocab(field, vocabulary);
            let mut direct_score = field_tokens.intersection(&tokens).count() as f32 * 3.0;
            direct_score += graph_projection_phrase_bonus(&lower, field);
            direct_score += graph_field_vocab_phrase_bonus(nl, field, vocabulary);
            direct_score += graph_field_exact_multi_token_phrase_bonus(nl, field);
            direct_score += graph_grouped_measure_semantic_bonus(nl, field, vocabulary);
            direct_score += graph_measure_entity_anchor_score(nl, field, vocabulary);
            let mut score = direct_score;
            score += graph_name_tokens(&field.entity)
                .intersection(&tokens)
                .count() as f32;
            if subject_entity.is_some_and(|entity| entity.eq_ignore_ascii_case(&field.entity)) {
                score += 18.0;
            }
            (direct_score >= 2.0).then_some((score, field))
        })
        .collect();
    scored.sort_by(|a, b| {
        b.0.partial_cmp(&a.0)
            .unwrap_or(std::cmp::Ordering::Equal)
            .then_with(|| a.1.canonical().cmp(&b.1.canonical()))
    });
    scored.into_iter().map(|(_, field)| field).next()
}

fn graph_grouped_metric_subject_entity(
    nl: &str,
    entities: &[EntityRow],
    vocabulary: &[VocabularyEntry],
) -> Option<String> {
    let tokens = graph_ordered_tokens(nl);
    for (idx, token) in tokens.iter().enumerate() {
        if !matches!(token.as_str(), "for" | "from" | "among" | "within") {
            continue;
        }
        if let Some(entity) = graph_count_subject_entity_phrase_match_with_vocab(
            &tokens,
            idx + 1,
            entities,
            vocabulary,
        ) {
            return Some(entity);
        }
    }
    None
}

fn graph_field_exact_multi_token_phrase_bonus(nl: &str, field: &FieldRow) -> f32 {
    let nl_norm = graph_norm(nl);
    [
        field.field.as_str(),
        field.db_column.as_str(),
        field.display_label.as_deref().unwrap_or(""),
    ]
    .iter()
    .filter_map(|raw| {
        let phrase = graph_norm(raw);
        if !phrase.contains(' ') || !graph_norm_contains(&nl_norm, &phrase) {
            return None;
        }
        Some(8.0 + phrase.split_whitespace().count() as f32)
    })
    .fold(0.0, f32::max)
}

fn graph_grouped_measure_semantic_bonus(
    nl: &str,
    field: &FieldRow,
    vocabulary: &[VocabularyEntry],
) -> f32 {
    let lower = format!(" {} ", graph_norm(nl));
    let compact = graph_compact_field_name(field);
    let mut score = 0.0;
    if [
        " total ",
        " totals ",
        " amount ",
        " amounts ",
        " value ",
        " values ",
        " revenue ",
    ]
    .iter()
    .any(|needle| lower.contains(needle))
        && (compact.contains("amount")
            || compact.contains("total")
            || compact.contains("value")
            || compact.contains("revenue")
            || compact.contains("mrr")
            || compact.contains("arr"))
    {
        score += 6.0;
    }
    if (lower.contains(" paid ") || lower.contains(" payment ") || lower.contains(" payments "))
        && (compact.contains("paid") || compact.contains("payment"))
    {
        score += 12.0;
    }
    if lower.contains(" amount paid ") && compact.contains("amountpaid") {
        score += 8.0;
    }
    if graph_field_looks_pipeline_amount_with_vocab(field, vocabulary)
        && (lower.contains(" pipeline ")
            || (graph_prompt_mentions_opportunity_fact(&lower)
                && runtime_prompt_contains_numeric_threshold(nl)))
    {
        score += 8.0;
    }
    score
}

fn graph_prompt_entity_anchored_measure_field<'a>(
    nl: &str,
    fields: &'a [FieldRow],
    vocabulary: &[VocabularyEntry],
) -> Option<&'a FieldRow> {
    let mut scored = fields
        .iter()
        .filter(|field| {
            graph_field_looks_numeric(field)
                && !graph_field_looks_unsafe_id(field)
                && !graph_field_has_identity_alias(field, vocabulary)
                && !graph_field_looks_actor_reference_numeric(field)
        })
        .filter_map(|field| {
            let score = graph_measure_entity_anchor_score(nl, field, vocabulary);
            (score >= 18.0).then_some((score, field))
        })
        .collect::<Vec<_>>();
    scored.sort_by(|a, b| {
        b.0.partial_cmp(&a.0)
            .unwrap_or(std::cmp::Ordering::Equal)
            .then_with(|| a.1.canonical().cmp(&b.1.canonical()))
    });
    let (top_score, top_field) = scored.first().copied()?;
    let unique = match scored.get(1) {
        Some((next_score, _)) => top_score - *next_score >= 3.0,
        None => true,
    };
    unique.then_some(top_field)
}

fn graph_measure_entity_anchor_score(
    nl: &str,
    field: &FieldRow,
    vocabulary: &[VocabularyEntry],
) -> f32 {
    let tokens = graph_ordered_tokens(nl);
    if tokens.is_empty() {
        return 0.0;
    }
    let field_tokens = graph_field_tokens_with_vocab(field, vocabulary);
    let entity_tokens = graph_entity_tokens_with_vocab(&field.entity, vocabulary);
    if field_tokens.is_empty() || entity_tokens.is_empty() {
        return 0.0;
    }
    let mut best = 0.0_f32;
    for (field_idx, token) in tokens.iter().enumerate() {
        if !field_tokens.contains(token) {
            continue;
        }
        for (entity_idx, entity_token) in tokens.iter().enumerate() {
            if !entity_tokens.contains(entity_token) {
                continue;
            }
            let distance = field_idx.abs_diff(entity_idx);
            let score = match distance {
                0 => 12.0,
                1 => 30.0,
                2 => 24.0,
                3 => 18.0,
                4..=6 => 8.0,
                _ => 0.0,
            };
            best = best.max(score);
        }
    }
    best
}

fn graph_field_looks_pipeline_amount(field: &FieldRow) -> bool {
    graph_field_looks_numeric(field)
        && graph_compact_field_name(field).ends_with("amount")
        && graph_entity_looks_opportunity_fact(&field.entity)
}

fn graph_field_looks_pipeline_amount_with_vocab(
    field: &FieldRow,
    vocabulary: &[VocabularyEntry],
) -> bool {
    if graph_field_looks_pipeline_amount(field) {
        return true;
    }
    graph_field_looks_numeric(field)
        && graph_compact_field_name(field).ends_with("amount")
        && graph_entity_looks_opportunity_fact_with_vocab(&field.entity, vocabulary)
}

fn graph_entity_looks_opportunity_fact(entity: &str) -> bool {
    let tokens = graph_name_tokens(entity);
    tokens.contains("opportunity")
        || tokens.contains("opportunities")
        || tokens.contains("deal")
        || tokens.contains("deals")
        || tokens.contains("pipeline")
}

fn graph_entity_looks_opportunity_fact_with_vocab(
    entity: &str,
    vocabulary: &[VocabularyEntry],
) -> bool {
    if graph_entity_looks_opportunity_fact(entity) {
        return true;
    }
    let tokens = graph_entity_tokens_with_vocab(entity, vocabulary);
    tokens.contains("opportunity")
        || tokens.contains("opportunities")
        || tokens.contains("deal")
        || tokens.contains("deals")
        || tokens.contains("pipeline")
}

fn graph_prompt_mentions_opportunity_fact(lower_norm: &str) -> bool {
    lower_norm.contains(" opportunit")
        || lower_norm.contains(" deal ")
        || lower_norm.contains(" deals ")
        || lower_norm.contains(" pipeline ")
}

fn graph_refine_grouped_aggregate_predicates(
    nl: &str,
    base_entity: &str,
    measure: Option<&FieldRow>,
    fields: &[FieldRow],
    sample_values: &[SampleValueRow],
    vocabulary: &[VocabularyEntry],
    predicates: Vec<GraphQueryPredicate>,
) -> Vec<GraphQueryPredicate> {
    let mut out = predicates;
    let field_map = graph_field_map(fields);
    for predicate in &mut out {
        if predicate.operator == "=" {
            if let Some(field) =
                graph_named_filter_field_for_value(nl, base_entity, fields, &predicate.value)
            {
                predicate.field = field;
            }
        }
    }
    for phrase in graph_quoted_phrases(nl) {
        let value = phrase.trim();
        if value.is_empty() {
            continue;
        }
        let Some(field) = graph_named_filter_field_for_value(nl, base_entity, fields, value) else {
            continue;
        };
        out.retain(|predicate| !(predicate.field == field && predicate.operator == "="));
        if !out
            .iter()
            .any(|predicate| predicate.field == field && predicate.operator == "=")
        {
            out.push(GraphQueryPredicate {
                field,
                value: value.to_string(),
                operator: "=".to_string(),
            });
        }
    }
    out.retain(|predicate| {
        let Some(field) = field_map.get(&predicate.field).copied() else {
            return false;
        };
        if let Some(measure) = measure {
            if predicate.field == measure.canonical()
                && predicate.operator == "="
                && !graph_measure_equality_filter_explicitly_requested(nl, predicate)
            {
                return false;
            }
        }
        if graph_field_looks_boolean_rate_condition_with_samples(field, sample_values)
            && graph_boolean_predicate_value(&predicate.value)
            && !field.entity.eq_ignore_ascii_case(base_entity)
        {
            return graph_conditional_rate_extra_boolean_filter_allowed(nl, field);
        }
        true
    });
    if let Some(open_stage) =
        graph_open_pipeline_stage_predicate(nl, base_entity, fields, sample_values)
    {
        out.retain(|predicate| {
            !(graph_norm(&predicate.value) == "open" && predicate.field != open_stage.field)
        });
        if !out
            .iter()
            .any(|predicate| predicate.field == open_stage.field && predicate.operator == "in")
        {
            out.push(open_stage);
        }
    }
    if let Some(threshold) = graph_measure_numeric_threshold_predicate(nl, measure, vocabulary) {
        out.retain(|predicate| {
            !(predicate.field == threshold.field
                && matches!(predicate.operator.as_str(), ">" | ">=" | "<" | "<="))
        });
        out.push(threshold);
    }
    out.sort_by(|a, b| {
        a.field
            .cmp(&b.field)
            .then_with(|| a.operator.cmp(&b.operator))
            .then_with(|| a.value.cmp(&b.value))
    });
    out.dedup_by(|a, b| a.field == b.field && a.operator == b.operator && a.value == b.value);
    out
}

fn graph_measure_equality_filter_explicitly_requested(
    nl: &str,
    predicate: &GraphQueryPredicate,
) -> bool {
    let value_norm = graph_norm(&predicate.value);
    !value_norm.is_empty() && graph_norm_contains(&graph_norm(nl), &value_norm)
}

fn graph_named_filter_field_for_value(
    nl: &str,
    base_entity: &str,
    fields: &[FieldRow],
    value: &str,
) -> Option<String> {
    let lower = format!(" {} ", graph_norm(nl));
    let value_norm = graph_norm(value);
    if value_norm.is_empty() {
        return None;
    }
    let mut candidates = fields
        .iter()
        .filter(|field| field.entity.eq_ignore_ascii_case(base_entity))
        .filter(|field| !graph_field_looks_unsafe_id(field))
        .flat_map(|field| {
            [
                field.field.as_str(),
                field.db_column.as_str(),
                field.display_label.as_deref().unwrap_or(""),
            ]
            .into_iter()
            .filter_map(|raw| {
                let phrase = graph_norm(raw);
                if phrase.len() < 2 {
                    return None;
                }
                let matched = [
                    format!(" {phrase} is {value_norm} "),
                    format!(" {phrase} equals {value_norm} "),
                    format!(" {phrase} = {value_norm} "),
                    format!(" where {phrase} {value_norm} "),
                ]
                .iter()
                .any(|needle| lower.contains(needle));
                matched.then(|| (phrase.len(), field.canonical()))
            })
            .collect::<Vec<_>>()
        })
        .collect::<Vec<_>>();
    candidates.sort_by(|a, b| b.0.cmp(&a.0).then_with(|| a.1.cmp(&b.1)));
    candidates.into_iter().map(|(_, field)| field).next()
}

fn graph_filter_group_by_dimension_predicates(
    nl: &str,
    fields: &[FieldRow],
    relationships: &[RelationshipRow],
    vocabulary: &[VocabularyEntry],
    predicates: Vec<GraphQueryPredicate>,
) -> Vec<GraphQueryPredicate> {
    let topk_by_phrase = graph_order_direction_limit(nl)
        .and_then(|_| graph_topk_group_dimension_phrase(nl, fields, relationships, vocabulary));
    let Some(by_phrase) = topk_by_phrase.or_else(|| graph_group_by_phrase(nl)) else {
        return predicates;
    };
    let by_norm = graph_norm(&by_phrase);
    let by_tokens = graph_schema_match_tokens(&by_phrase);
    if by_norm.is_empty() && by_tokens.is_empty() {
        return predicates;
    }
    let field_map = graph_field_map(fields);
    let dimension_tokens: HashSet<String> = fields
        .iter()
        .filter(|field| graph_field_is_group_dimension(field))
        .flat_map(|field| {
            let field_tokens = graph_field_tokens_with_vocab(field, vocabulary);
            if field_tokens.is_disjoint(&by_tokens) {
                HashSet::new()
            } else {
                field_tokens.intersection(&by_tokens).cloned().collect()
            }
        })
        .collect();
    predicates
        .into_iter()
        .filter(|predicate| {
            let value_norm = graph_norm(&predicate.value);
            if predicate.operator == "in"
                && predicate
                    .value
                    .split('|')
                    .filter(|part| !part.trim().is_empty())
                    .count()
                    >= 2
            {
                return true;
            }
            if value_norm.len() >= 2 && value_norm == by_norm {
                return false;
            }
            let value_tokens = graph_tokens(&value_norm);
            if !value_tokens.is_empty()
                && value_tokens
                    .iter()
                    .all(|token| dimension_tokens.contains(token))
            {
                return false;
            }
            let Some(field) = field_map.get(&predicate.field) else {
                return true;
            };
            let field_norm = graph_norm(&field.field.replace('_', " "));
            let column_norm = graph_norm(&field.db_column.replace('_', " "));
            if field_norm.len() >= 2 && graph_norm_contains(&by_norm, &field_norm) {
                return false;
            }
            if column_norm.len() >= 2 && graph_norm_contains(&by_norm, &column_norm) {
                return false;
            }
            true
        })
        .collect()
}

fn graph_merge_comparison_value_predicate(
    nl: &str,
    fields: &[FieldRow],
    sample_values: &[SampleValueRow],
    vocabulary: &[VocabularyEntry],
    predicates: &mut Vec<GraphQueryPredicate>,
) {
    let Some(comparison) = graph_comparison_value_predicate(nl, fields, sample_values, vocabulary)
    else {
        return;
    };
    predicates.retain(|predicate| !predicate.field.eq_ignore_ascii_case(&comparison.field));
    predicates.push(comparison);
    predicates.sort_by(|a, b| {
        a.field
            .cmp(&b.field)
            .then_with(|| a.operator.cmp(&b.operator))
            .then_with(|| a.value.cmp(&b.value))
    });
}

fn graph_add_best_date_window_predicate(
    nl: &str,
    fields: &[FieldRow],
    sample_values: &[SampleValueRow],
    vocabulary: &[VocabularyEntry],
    predicates: &mut Vec<GraphQueryPredicate>,
) {
    if predicates.len() >= 3 {
        return;
    }
    let field_map = graph_field_map(fields);
    if predicates.iter().any(|predicate| {
        field_map.get(&predicate.field).is_some_and(|field| {
            graph_field_looks_date_like(field)
                && matches!(
                    predicate.operator.as_str(),
                    "range" | "<" | "<=" | ">" | ">="
                )
        })
    }) {
        return;
    }
    let mut consumed_value_norms = HashSet::new();
    for predicate in predicates.iter() {
        for value in predicate.value.split('|') {
            let norm = graph_norm(value);
            if !norm.is_empty() {
                consumed_value_norms.insert(norm);
            }
        }
    }
    let mut candidates = graph_derived_named_date_window_predicates(
        nl,
        fields,
        sample_values,
        vocabulary,
        &consumed_value_norms,
    );
    candidates.sort_by(|a, b| {
        b.0.partial_cmp(&a.0)
            .unwrap_or(std::cmp::Ordering::Equal)
            .then_with(|| a.2.cmp(&b.2))
    });
    for (_, _, field, value, operator) in candidates {
        if predicates
            .iter()
            .any(|predicate| predicate.field.eq_ignore_ascii_case(&field))
        {
            continue;
        }
        predicates.push(GraphQueryPredicate {
            field,
            value,
            operator,
        });
        predicates.sort_by(|a, b| {
            a.field
                .cmp(&b.field)
                .then_with(|| a.operator.cmp(&b.operator))
                .then_with(|| a.value.cmp(&b.value))
        });
        return;
    }
}

type GraphComparisonCandidate = (f32, String, Vec<(usize, String)>);

fn graph_comparison_value_predicate(
    nl: &str,
    fields: &[FieldRow],
    sample_values: &[SampleValueRow],
    vocabulary: &[VocabularyEntry],
) -> Option<GraphQueryPredicate> {
    let field_map = graph_field_map(fields);
    let nl_norm = graph_norm(nl);
    let mut candidates: Vec<GraphComparisonCandidate> = Vec::new();
    for row in sample_values {
        if row.pii_redacted {
            continue;
        }
        let Some(field) = field_map.get(&row.field_canonical).copied() else {
            continue;
        };
        if !graph_field_is_group_dimension(field) {
            continue;
        }
        let mut values = Vec::new();
        for value in &row.examples {
            let value_norm = graph_norm(value);
            let mut position = graph_norm_token_position(&nl_norm, &value_norm);
            if position.is_none() {
                for alias in graph_sample_value_query_aliases(value, field) {
                    let alias_norm = graph_norm(alias);
                    position = graph_norm_token_position(&nl_norm, &alias_norm);
                    if position.is_some() {
                        break;
                    }
                }
            }
            let Some(position) = position else {
                continue;
            };
            if values
                .iter()
                .any(|(_, existing): &(usize, String)| graph_norm(existing) == value_norm)
            {
                continue;
            }
            values.push((position, value.clone()));
        }
        if values.len() < 2 {
            continue;
        }
        values.sort_by(|a, b| a.0.cmp(&b.0).then_with(|| a.1.cmp(&b.1)));
        let q_tokens = graph_schema_match_tokens(nl);
        let mut score = values.len() as f32 * 20.0;
        score += graph_field_tokens_with_vocab(field, vocabulary)
            .intersection(&q_tokens)
            .count() as f32
            * 4.0;
        score += graph_name_tokens(&field.entity)
            .intersection(&q_tokens)
            .count() as f32
            * 3.0;
        if graph_field_looks_display_field(field) {
            score += 2.0;
        }
        candidates.push((score, field.canonical(), values));
    }
    candidates.sort_by(|a, b| {
        b.0.partial_cmp(&a.0)
            .unwrap_or(std::cmp::Ordering::Equal)
            .then_with(|| b.2.len().cmp(&a.2.len()))
            .then_with(|| a.1.cmp(&b.1))
    });
    let (_, field, values) = candidates.into_iter().next()?;
    Some(GraphQueryPredicate {
        field,
        value: values
            .into_iter()
            .map(|(_, value)| value)
            .collect::<Vec<_>>()
            .join("|"),
        operator: "in".to_string(),
    })
}

fn graph_norm_token_position(haystack_norm: &str, needle_norm: &str) -> Option<usize> {
    if needle_norm.len() < 2 {
        return None;
    }
    let padded_haystack = format!(" {haystack_norm} ");
    let padded_needle = format!(" {needle_norm} ");
    padded_haystack
        .find(&padded_needle)
        .map(|position| position.saturating_sub(1))
}

fn graph_comparison_dimension_from_predicates<'a>(
    predicates: &[GraphQueryPredicate],
    field_map: &HashMap<String, &'a FieldRow>,
) -> Option<&'a FieldRow> {
    let mut matches = predicates
        .iter()
        .filter(|predicate| predicate.operator.eq_ignore_ascii_case("in"))
        .filter(|predicate| {
            predicate
                .value
                .split('|')
                .filter(|part| !part.trim().is_empty())
                .count()
                >= 2
        })
        .filter_map(|predicate| field_map.get(&predicate.field).copied())
        .filter(|field| graph_field_is_group_dimension(field))
        .collect::<Vec<_>>();
    matches.sort_by_key(|field| field.canonical());
    matches.dedup_by(|a, b| a.canonical() == b.canonical());
    (matches.len() == 1).then(|| matches[0])
}

fn graph_open_pipeline_stage_predicate(
    nl: &str,
    base_entity: &str,
    fields: &[FieldRow],
    sample_values: &[SampleValueRow],
) -> Option<GraphQueryPredicate> {
    let lower = format!(" {} ", graph_norm(nl));
    if !lower.contains(" open ") || !graph_prompt_mentions_opportunity_fact(&lower) {
        return None;
    }
    let stage_field = fields
        .iter()
        .filter(|field| field.entity.eq_ignore_ascii_case(base_entity))
        .find(|field| graph_field_looks_pipeline_stage_field(field))?;
    let field_key = stage_field.canonical();
    let mut values = Vec::new();
    for row in sample_values
        .iter()
        .filter(|row| row.field_canonical.eq_ignore_ascii_case(&field_key))
    {
        for value in &row.examples {
            if graph_sample_value_is_open_pipeline_stage(value) && !values.contains(value) {
                values.push(value.clone());
            }
        }
    }
    if values.is_empty() {
        return None;
    }
    Some(GraphQueryPredicate {
        field: field_key,
        value: values.join("|"),
        operator: "in".to_string(),
    })
}

fn graph_field_looks_pipeline_stage_field(field: &FieldRow) -> bool {
    let compact = graph_compact_field_name(field);
    matches!(compact.as_str(), "stage" | "status" | "state") || compact.ends_with("stage")
}

fn graph_sample_value_is_open_pipeline_stage(value: &str) -> bool {
    let norm = graph_norm(value);
    if norm.is_empty() {
        return false;
    }
    ![
        "closed",
        "lost",
        "won",
        "cancelled",
        "canceled",
        "churned",
        "inactive",
        "void",
        "resolved",
    ]
    .iter()
    .any(|marker| norm.contains(marker))
}

fn graph_measure_numeric_threshold_predicate(
    nl: &str,
    measure: Option<&FieldRow>,
    vocabulary: &[VocabularyEntry],
) -> Option<GraphQueryPredicate> {
    let measure = measure?;
    for literal in runtime_prompt_numeric_threshold_literals(nl) {
        if !(graph_literal_compatible_with_field(nl, &literal, measure)
            || graph_field_looks_pipeline_amount_with_vocab(measure, vocabulary)
                && graph_prompt_mentions_opportunity_fact(&format!(" {} ", graph_norm(nl))))
        {
            continue;
        }
        let operator = graph_operator_for_mention(nl, &literal);
        if matches!(operator, ">" | ">=" | "<" | "<=") {
            return Some(GraphQueryPredicate {
                field: measure.canonical(),
                value: literal,
                operator: operator.to_string(),
            });
        }
    }
    None
}

fn graph_grouped_distribution_includes_count(
    nl: &str,
    base_entity: &str,
    measure: &FieldRow,
    vocabulary: &[VocabularyEntry],
) -> bool {
    let lower = format!(" {} ", graph_norm(nl));
    lower.contains(" by ")
        && runtime_prompt_contains_numeric_threshold(nl)
        && graph_entity_looks_opportunity_fact_with_vocab(base_entity, vocabulary)
        && graph_field_looks_pipeline_amount_with_vocab(measure, vocabulary)
        && !lower.contains(" pipeline ")
        && !lower.contains(" amount ")
        && !lower.contains(" total ")
        && !lower.contains(" sum ")
}

fn graph_grouped_count_base_entity(
    nl: &str,
    entities: &[EntityRow],
    fields: &[FieldRow],
    relationships: &[RelationshipRow],
    predicates: &[GraphQueryPredicate],
    vocabulary: &[VocabularyEntry],
) -> Option<String> {
    graph_grouped_time_series_base_entity(nl, fields, predicates, vocabulary)
        .or_else(|| graph_count_subject_entity_with_vocab(nl, entities, vocabulary))
        .or_else(|| graph_entity_before_group_by(nl, entities, vocabulary))
        .or_else(|| graph_subject_entity_with_vocab(nl, entities, fields, predicates, vocabulary))
        .or_else(|| graph_grouped_count_entity_from_date_predicate(predicates, fields))
        .or_else(|| {
            graph_grouped_count_entity_from_dimension_phrase(
                nl,
                entities,
                fields,
                relationships,
                predicates,
                vocabulary,
            )
        })
}

fn graph_grouped_time_series_base_entity(
    nl: &str,
    fields: &[FieldRow],
    predicates: &[GraphQueryPredicate],
    vocabulary: &[VocabularyEntry],
) -> Option<String> {
    if !graph_grouped_time_series_prompt(nl) {
        return None;
    }
    let by_phrase = graph_group_by_phrase(nl)?;
    let by_tokens = graph_schema_match_tokens(&by_phrase);
    if by_tokens.is_empty() {
        return None;
    }
    let q_tokens = graph_tokens(nl);
    let field_map = graph_field_map(fields);
    let predicate_fields: HashSet<&str> = predicates
        .iter()
        .map(|predicate| predicate.field.as_str())
        .collect();
    let mut scored: Vec<(f32, String)> = predicates
        .iter()
        .filter(|predicate| predicate.operator == "range")
        .filter_map(|predicate| field_map.get(&predicate.field).copied())
        .filter(|field| graph_field_looks_date_like(field))
        .filter_map(|date_field| {
            let dimension_score = fields
                .iter()
                .filter(|field| field.entity.eq_ignore_ascii_case(&date_field.entity))
                .filter(|field| !predicate_fields.contains(field.canonical().as_str()))
                .filter(|field| graph_field_is_group_dimension(field))
                .map(|field| {
                    let field_tokens = graph_field_tokens_with_vocab(field, vocabulary);
                    let mut score = field_tokens.intersection(&by_tokens).count() as f32 * 5.0;
                    score += graph_projection_phrase_bonus(&by_phrase.to_ascii_lowercase(), field);
                    score += graph_field_vocab_phrase_bonus(&by_phrase, field, vocabulary);
                    score
                })
                .fold(0.0_f32, f32::max);
            if dimension_score < 2.0 {
                return None;
            }
            let entity_score = graph_entity_tokens_with_vocab(&date_field.entity, vocabulary)
                .intersection(&q_tokens)
                .count() as f32
                * 2.0;
            let date_role_score =
                graph_time_series_date_subject_bonus(nl, date_field).max(entity_score);
            Some((
                10.0 + dimension_score + date_role_score,
                date_field.entity.clone(),
            ))
        })
        .collect();
    scored.sort_by(|a, b| {
        b.0.partial_cmp(&a.0)
            .unwrap_or(std::cmp::Ordering::Equal)
            .then_with(|| a.1.cmp(&b.1))
    });
    scored.into_iter().map(|(_, entity)| entity).next()
}

fn graph_time_series_date_subject_bonus(nl: &str, field: &FieldRow) -> f32 {
    let lower = format!(" {} ", nl.to_ascii_lowercase().replace(['_', '-'], " "));
    let compact = graph_compact_field_name(field);
    if [
        " signup ",
        " signups ",
        " signed up ",
        " registration ",
        " registrations ",
        " acquisition ",
        " acquisitions ",
        " new leads ",
        " new customers ",
        " new users ",
    ]
    .iter()
    .any(|needle| lower.contains(needle))
        && (compact.contains("signup") || compact.contains("created"))
    {
        return 6.0;
    }
    if [" opened ", " created ", " added ", " joined "]
        .iter()
        .any(|needle| lower.contains(needle))
        && compact.contains("created")
    {
        return 4.0;
    }
    0.0
}

fn graph_entity_before_group_by(
    nl: &str,
    entities: &[EntityRow],
    vocabulary: &[VocabularyEntry],
) -> Option<String> {
    let tokens = graph_ordered_tokens(nl);
    let by_index = tokens
        .iter()
        .position(|token| token == "by")
        .unwrap_or(tokens.len());
    let prefix: HashSet<String> = tokens.into_iter().take(by_index).collect();
    let mut scored: Vec<(usize, String)> = entities
        .iter()
        .filter_map(|entity| {
            let overlap = graph_entity_tokens_for_row_with_vocab(entity, vocabulary)
                .intersection(&prefix)
                .count();
            (overlap > 0).then_some((overlap, entity.canonical_name.clone()))
        })
        .collect();
    scored.sort_by(|a, b| b.0.cmp(&a.0).then_with(|| a.1.cmp(&b.1)));
    scored.into_iter().map(|(_, entity)| entity).next()
}

fn graph_grouped_count_entity_from_date_predicate(
    predicates: &[GraphQueryPredicate],
    fields: &[FieldRow],
) -> Option<String> {
    let field_map = graph_field_map(fields);
    predicates.iter().find_map(|predicate| {
        field_map
            .get(&predicate.field)
            .and_then(|field| graph_field_looks_date_like(field).then(|| field.entity.clone()))
    })
}

fn graph_grouped_count_entity_from_dimension_phrase(
    nl: &str,
    entities: &[EntityRow],
    fields: &[FieldRow],
    relationships: &[RelationshipRow],
    predicates: &[GraphQueryPredicate],
    vocabulary: &[VocabularyEntry],
) -> Option<String> {
    let predicate_entities: HashSet<String> = predicates
        .iter()
        .filter_map(|predicate| {
            predicate
                .field
                .split_once('.')
                .map(|(entity, _)| entity.to_string())
        })
        .collect();
    let mut scored: Vec<(f32, String)> = entities
        .iter()
        .filter_map(|entity| {
            let dimensions = graph_group_dimension_fields(
                nl,
                &entity.canonical_name,
                fields,
                relationships,
                predicates,
                vocabulary,
            );
            if dimensions.is_empty() {
                return None;
            }
            let mut score = dimensions.len() as f32;
            if predicate_entities.contains(&entity.canonical_name) {
                score += 2.0;
            }
            Some((score, entity.canonical_name.clone()))
        })
        .collect();
    scored.sort_by(|a, b| {
        b.0.partial_cmp(&a.0)
            .unwrap_or(std::cmp::Ordering::Equal)
            .then_with(|| a.1.cmp(&b.1))
    });
    scored.into_iter().map(|(_, entity)| entity).next()
}

fn graph_group_dimension_fields<'a>(
    nl: &str,
    base_entity: &str,
    fields: &'a [FieldRow],
    relationships: &[RelationshipRow],
    predicates: &[GraphQueryPredicate],
    vocabulary: &[VocabularyEntry],
) -> Vec<&'a FieldRow> {
    let topk_by_phrase = graph_order_direction_limit(nl)
        .and_then(|_| graph_topk_group_dimension_phrase(nl, fields, relationships, vocabulary));
    let Some(by_phrase) = topk_by_phrase.or_else(|| graph_group_by_phrase(nl)) else {
        return Vec::new();
    };
    let by_tokens = graph_schema_match_tokens(&by_phrase);
    let entity_tokens: HashSet<String> = fields
        .iter()
        .flat_map(|field| graph_name_tokens(&field.entity))
        .collect();
    let role_request_tokens: HashSet<String> =
        by_tokens.difference(&entity_tokens).cloned().collect();
    let predicate_fields: HashSet<&str> = predicates
        .iter()
        .filter(|predicate| !predicate.operator.eq_ignore_ascii_case("in"))
        .map(|predicate| predicate.field.as_str())
        .collect();
    let wants_time_dimension =
        graph_grouped_time_dimension_requested(nl, base_entity, fields, predicates, vocabulary);
    let max_dimensions = if wants_time_dimension { 2 } else { 1 };
    let predicate_entities: HashSet<String> = predicates
        .iter()
        .filter_map(|predicate| {
            predicate
                .field
                .split_once('.')
                .map(|(entity, _)| entity.to_string())
        })
        .collect();
    let mut out: Vec<&FieldRow> = Vec::new();
    if wants_time_dimension {
        if let Some(date_field) = graph_group_requested_time_dimension_field(
            nl,
            base_entity,
            fields,
            predicates,
            vocabulary,
        ) {
            out.push(date_field);
        }
    }
    if out.is_empty() {
        if let Some(explicit_dimension) = graph_explicit_entity_field_group_dimension(
            &by_phrase,
            base_entity,
            fields,
            relationships,
            vocabulary,
        ) {
            out.push(explicit_dimension);
        }
    }
    if out.is_empty() {
        if let Some(display_field) = graph_group_entity_display_dimension(
            &by_phrase,
            base_entity,
            fields,
            relationships,
            vocabulary,
        ) {
            out.push(display_field);
        }
    }
    if out.is_empty() {
        if let Some(base_dimension) = graph_base_entity_exact_group_dimension(
            base_entity,
            fields,
            &by_tokens,
            &predicate_fields,
            vocabulary,
        ) {
            out.push(base_dimension);
        }
    }
    let base_related_entities = graph_immediate_related_entities(base_entity, relationships);
    let predicate_entities_lower: HashSet<String> = predicate_entities
        .iter()
        .map(|entity| entity.to_ascii_lowercase())
        .collect();
    let mut predicate_related_entities = HashSet::new();
    for entity in &predicate_entities {
        predicate_related_entities.extend(graph_immediate_related_entities(entity, relationships));
    }
    let mut path_role_tokens_by_entity: HashMap<String, HashSet<String>> = HashMap::new();
    let mut candidates: Vec<(f32, &FieldRow)> = Vec::new();
    for field in fields {
        let canonical = field.canonical();
        if predicate_fields.contains(canonical.as_str())
            || !graph_field_is_group_dimension(field)
            || (wants_time_dimension && !field.entity.eq_ignore_ascii_case(base_entity))
        {
            continue;
        }
        let entity_lower = field.entity.to_ascii_lowercase();
        let relationship_role_tokens = path_role_tokens_by_entity
            .entry(entity_lower.clone())
            .or_insert_with(|| {
                graph_relationship_path_role_tokens_between(
                    base_entity,
                    &field.entity,
                    relationships,
                    fields,
                    vocabulary,
                )
            })
            .clone();
        if !field.entity.eq_ignore_ascii_case(base_entity)
            && !base_related_entities.contains(&entity_lower)
            && relationship_role_tokens.is_disjoint(&by_tokens)
            && !predicate_entities_lower.contains(&entity_lower)
            && !predicate_related_entities.contains(&entity_lower)
        {
            continue;
        }

        let field_tokens = graph_field_tokens_with_vocab(field, vocabulary);
        let entity_tokens = graph_entity_tokens_with_vocab(&field.entity, vocabulary);
        let field_overlap = field_tokens.intersection(&by_tokens).count() as f32;
        let entity_overlap = entity_tokens.intersection(&by_tokens).count() as f32;
        let relationship_role_overlap =
            relationship_role_tokens.intersection(&by_tokens).count() as f32;
        let mut score = field_overlap * 5.0 + entity_overlap * 2.5;
        score += relationship_role_overlap * 4.0;
        if !role_request_tokens.is_empty()
            && role_request_tokens.is_subset(&relationship_role_tokens)
        {
            score += 8.0;
        }
        score += graph_projection_phrase_bonus(&by_phrase.to_ascii_lowercase(), field);
        score += graph_field_vocab_phrase_bonus(&by_phrase, field, vocabulary);
        if entity_overlap > 0.0
            && graph_field_looks_display_field(field)
            && !graph_field_looks_unsafe_id(field)
        {
            score += 3.0;
        }
        if relationship_role_overlap > 0.0
            && graph_field_looks_display_field(field)
            && !graph_field_looks_unsafe_id(field)
        {
            score += 3.0;
        }
        if field.entity.eq_ignore_ascii_case(base_entity) {
            score += 1.0;
            if !by_tokens.is_empty() && by_tokens.is_subset(&field_tokens) {
                score += 6.0;
            }
        }
        if score >= 2.0 {
            candidates.push((score, field));
        }
    }
    candidates.sort_by(|a, b| {
        b.0.partial_cmp(&a.0)
            .unwrap_or(std::cmp::Ordering::Equal)
            .then_with(|| a.1.canonical().cmp(&b.1.canonical()))
    });
    for (_, field) in candidates {
        if out.len() == max_dimensions {
            break;
        }
        if !out
            .iter()
            .any(|existing| existing.canonical() == field.canonical())
        {
            out.push(field);
        }
    }
    out
}

fn graph_group_dimension_request_ambiguous(
    nl: &str,
    base_entity: &str,
    fields: &[FieldRow],
    relationships: &[RelationshipRow],
    predicates: &[GraphQueryPredicate],
    vocabulary: &[VocabularyEntry],
) -> bool {
    let Some(by_phrase) = graph_group_by_phrase(nl) else {
        return false;
    };
    let by_tokens = graph_schema_match_tokens(&by_phrase);
    if by_tokens.is_empty() {
        return false;
    }
    let generic_display_request = by_tokens
        .iter()
        .all(|token| matches!(token.as_str(), "name" | "title" | "label"));
    if !generic_display_request {
        return false;
    }
    let predicate_fields: HashSet<&str> = predicates
        .iter()
        .map(|predicate| predicate.field.as_str())
        .collect();
    let mut matches = fields
        .iter()
        .filter(|field| graph_field_is_group_dimension(field))
        .filter(|field| !graph_field_looks_unsafe_id(field))
        .filter(|field| !predicate_fields.contains(field.canonical().as_str()))
        .filter(|field| {
            field.entity.eq_ignore_ascii_case(base_entity)
                || graph_entities_have_bounded_join_path(
                    base_entity,
                    &field.entity,
                    relationships,
                    3,
                )
        })
        .filter(|field| {
            let field_tokens = graph_field_tokens_with_vocab(field, vocabulary);
            by_tokens.is_subset(&field_tokens)
        })
        .map(FieldRow::canonical)
        .collect::<Vec<_>>();
    matches.sort();
    matches.dedup();
    matches.len() > 1
}

fn graph_explicit_entity_field_group_dimension<'a>(
    by_phrase: &str,
    base_entity: &str,
    fields: &'a [FieldRow],
    relationships: &[RelationshipRow],
    vocabulary: &[VocabularyEntry],
) -> Option<&'a FieldRow> {
    let by_tokens = graph_schema_match_tokens(by_phrase);
    if by_tokens.is_empty() {
        return None;
    }
    let by_phrase_norm = graph_norm(by_phrase);
    let mut candidates = fields
        .iter()
        .filter(|field| graph_field_is_group_dimension(field))
        .filter(|field| !graph_field_looks_unsafe_id(field))
        .filter(|field| {
            field.entity.eq_ignore_ascii_case(base_entity)
                || graph_entities_have_bounded_join_path(
                    base_entity,
                    &field.entity,
                    relationships,
                    3,
                )
        })
        .filter_map(|field| {
            let entity_tokens = graph_entity_tokens_with_vocab(&field.entity, vocabulary);
            let field_tokens = graph_field_tokens_with_vocab(field, vocabulary);
            let entity_overlap = entity_tokens.intersection(&by_tokens).count() as i32;
            let field_overlap = field_tokens.intersection(&by_tokens).count() as i32;
            if entity_overlap == 0 || field_overlap == 0 {
                return None;
            }
            let role_tokens = by_tokens
                .difference(&entity_tokens)
                .cloned()
                .collect::<HashSet<_>>();
            if !role_tokens.is_empty() && !role_tokens.is_subset(&field_tokens) {
                return None;
            }
            let exact_entity_bonus = graph_entity_labels_for_prompt_name(&field.entity, vocabulary)
                .iter()
                .filter_map(|label| {
                    let label_norm = graph_norm(label);
                    (!label_norm.is_empty() && graph_norm_contains(&by_phrase_norm, &label_norm))
                        .then_some(label_norm.len() as i32)
                })
                .max()
                .unwrap_or(0);
            let score = entity_overlap * 8 + field_overlap * 10 + exact_entity_bonus;
            Some((score, field))
        })
        .collect::<Vec<_>>();
    candidates.sort_by(|a, b| {
        b.0.cmp(&a.0)
            .then_with(|| a.1.canonical().cmp(&b.1.canonical()))
    });
    candidates.into_iter().map(|(_, field)| field).next()
}

fn graph_entity_labels_for_prompt_name(
    entity_name: &str,
    vocabulary: &[VocabularyEntry],
) -> Vec<String> {
    let spaced = entity_name.replace('_', " ");
    let mut labels = vec![entity_name.to_string(), spaced.clone()];
    if let Some(stripped) = spaced.strip_suffix('s') {
        if stripped.len() >= 2 {
            labels.push(stripped.to_string());
        }
    }
    for entry in vocabulary {
        if entry.canonical_kind == "entity"
            && entry.confidence >= 0.4
            && entry.canonical_value.eq_ignore_ascii_case(entity_name)
        {
            labels.push(entry.term.clone());
        }
    }
    labels.sort();
    labels.dedup();
    labels
}

fn graph_base_entity_exact_group_dimension<'a>(
    base_entity: &str,
    fields: &'a [FieldRow],
    by_tokens: &HashSet<String>,
    predicate_fields: &HashSet<&str>,
    vocabulary: &[VocabularyEntry],
) -> Option<&'a FieldRow> {
    if by_tokens.is_empty() {
        return None;
    }
    let mut candidates = fields
        .iter()
        .filter(|field| field.entity.eq_ignore_ascii_case(base_entity))
        .filter(|field| graph_field_is_group_dimension(field))
        .filter(|field| !predicate_fields.contains(field.canonical().as_str()))
        .filter_map(|field| {
            let field_tokens = graph_field_tokens_with_vocab(field, vocabulary);
            by_tokens
                .is_subset(&field_tokens)
                .then_some((field_tokens.len(), field))
        })
        .collect::<Vec<_>>();
    candidates.sort_by(|a, b| {
        a.0.cmp(&b.0)
            .then_with(|| a.1.canonical().cmp(&b.1.canonical()))
    });
    candidates.into_iter().map(|(_, field)| field).next()
}

fn graph_group_entity_display_dimension<'a>(
    by_phrase: &str,
    base_entity: &str,
    fields: &'a [FieldRow],
    relationships: &[RelationshipRow],
    vocabulary: &[VocabularyEntry],
) -> Option<&'a FieldRow> {
    let by_tokens = graph_schema_match_tokens(by_phrase);
    if by_tokens.is_empty() {
        return None;
    }
    let mut candidates: Vec<String> = fields.iter().map(|field| field.entity.clone()).collect();
    candidates.sort();
    candidates.dedup();
    let mut matches = Vec::new();
    for entity in candidates {
        let entity_tokens = graph_entity_tokens_with_vocab(&entity, vocabulary);
        if entity_tokens.is_empty() || entity_tokens.is_disjoint(&by_tokens) {
            continue;
        }
        let extra_tokens: HashSet<String> = by_tokens.difference(&entity_tokens).cloned().collect();
        if !extra_tokens.is_empty() {
            continue;
        }
        if entity.eq_ignore_ascii_case(base_entity)
            || graph_entities_have_bounded_join_path(base_entity, &entity, relationships, 3)
        {
            matches.push(entity);
        }
    }
    matches.sort();
    matches.dedup();
    if matches.len() != 1 {
        return None;
    }
    graph_default_group_display_field_for_entity(by_phrase, &matches[0], fields, vocabulary)
}

fn graph_default_group_display_field_for_entity<'a>(
    by_phrase: &str,
    entity: &str,
    fields: &'a [FieldRow],
    vocabulary: &[VocabularyEntry],
) -> Option<&'a FieldRow> {
    let by_tokens = graph_schema_match_tokens(by_phrase);
    let mut candidates = fields
        .iter()
        .filter(|field| field.entity.eq_ignore_ascii_case(entity))
        .filter(|field| !graph_field_looks_unsafe_id(field))
        .filter(|field| !graph_field_has_identity_alias(field, vocabulary))
        .filter_map(|field| {
            let field_tokens = graph_field_tokens_with_vocab(field, vocabulary);
            let token_overlap = field_tokens.intersection(&by_tokens).count() as i32;
            let mut display_tokens = graph_name_tokens(&field.db_column);
            display_tokens.extend(graph_name_tokens(&field.field));
            if let Some(label) = &field.display_label {
                display_tokens.extend(graph_name_tokens(label));
            }
            let display_label_bonus = if display_tokens.contains("name")
                || display_tokens.contains("title")
                || display_tokens.contains("label")
                || (display_tokens.contains("full") && display_tokens.contains("name"))
            {
                12
            } else if display_tokens.contains("company") {
                10
            } else {
                0
            };
            let mut score = token_overlap * 10 + display_label_bonus;
            if graph_field_matches_entity_display_name(entity, field) {
                score += 8;
            }
            if graph_field_looks_display_field(field) {
                score += 4;
            }
            if graph_field_looks_date_like(field) || graph_field_looks_numeric(field) {
                score -= 8;
            }
            (score > 0).then_some((score, field))
        })
        .collect::<Vec<_>>();
    candidates.sort_by(|a, b| {
        b.0.cmp(&a.0)
            .then_with(|| a.1.canonical().cmp(&b.1.canonical()))
    });
    candidates.into_iter().map(|(_, field)| field).next()
}

fn graph_group_by_phrase(nl: &str) -> Option<String> {
    let lower = format!(" {} ", nl.trim().to_ascii_lowercase().replace('\n', " "));
    let by_index = lower.find(" by ")? + " by ".len();
    let tail = &lower[by_index..];
    let mut end = tail.len();
    for marker in [
        " for ",
        " in ",
        " with ",
        " where ",
        " over ",
        " under ",
        " before ",
        " after ",
        " since ",
        " closing ",
        " renewing ",
        " ordered ",
        " sorted ",
    ] {
        if let Some(index) = tail.find(marker) {
            end = end.min(index);
        }
    }
    let phrase = tail[..end].trim();
    (!phrase.is_empty()).then(|| phrase.to_string())
}

fn graph_topk_group_dimension_phrase(
    nl: &str,
    fields: &[FieldRow],
    relationships: &[RelationshipRow],
    vocabulary: &[VocabularyEntry],
) -> Option<String> {
    if graph_order_direction_limit(nl).is_none() || !graph_topk_group_dimension_prompt(nl) {
        return None;
    }
    let tokens = graph_ordered_tokens(nl);
    let start = tokens
        .iter()
        .position(|token| {
            matches!(
                token.as_str(),
                "which" | "who" | "what" | "top" | "show" | "list" | "display"
            )
        })
        .map(|idx| idx + 1)
        .unwrap_or(0);
    let order_end = tokens[start..]
        .iter()
        .position(|token| {
            matches!(
                token.as_str(),
                "most"
                    | "least"
                    | "highest"
                    | "lowest"
                    | "largest"
                    | "smallest"
                    | "biggest"
                    | "fewest"
                    | "greatest"
            )
        })
        .map(|idx| start + idx)
        .unwrap_or(tokens.len());
    let relation_end = tokens[start..order_end]
        .iter()
        .position(|token| graph_topk_dimension_boundary_token(token))
        .map(|idx| start + idx)
        .unwrap_or(order_end);
    let phrase_tokens = graph_collapse_adjacent_alias_tokens(
        tokens[start..relation_end]
            .iter()
            .filter(|token| {
                !matches!(
                    token.as_str(),
                    "the" | "a" | "an" | "with" | "of" | "by" | "for"
                ) && token.parse::<u32>().is_err()
            })
            .cloned()
            .collect::<Vec<_>>(),
    );
    let dimension_tokens = graph_topk_dimension_schema_tokens(fields, relationships, vocabulary);
    let last_schema_token = phrase_tokens
        .iter()
        .rposition(|token| dimension_tokens.contains(token));
    let phrase = if let Some(index) = last_schema_token {
        phrase_tokens[..=index].join(" ")
    } else {
        phrase_tokens.join(" ")
    };
    (!phrase.is_empty()).then_some(phrase)
}

fn graph_collapse_adjacent_alias_tokens(tokens: Vec<String>) -> Vec<String> {
    let mut out: Vec<String> = Vec::new();
    for token in tokens {
        if out
            .last()
            .is_some_and(|previous| graph_tokens_are_adjacent_aliases(previous, &token))
        {
            continue;
        }
        out.push(token);
    }
    out
}

fn graph_tokens_are_adjacent_aliases(left: &str, right: &str) -> bool {
    left == right
        || left
            .strip_suffix('s')
            .is_some_and(|stem| stem.len() >= 2 && stem == right)
        || right
            .strip_suffix('s')
            .is_some_and(|stem| stem.len() >= 2 && stem == left)
}

fn graph_topk_dimension_boundary_token(token: &str) -> bool {
    matches!(
        token,
        "who"
            | "that"
            | "which"
            | "has"
            | "have"
            | "having"
            | "had"
            | "is"
            | "are"
            | "was"
            | "were"
            | "with"
            | "where"
            | "by"
    )
}

fn graph_topk_dimension_schema_tokens(
    fields: &[FieldRow],
    relationships: &[RelationshipRow],
    vocabulary: &[VocabularyEntry],
) -> HashSet<String> {
    let mut tokens = HashSet::new();
    let mut entities: Vec<String> = fields.iter().map(|field| field.entity.clone()).collect();
    entities.sort();
    entities.dedup();
    for entity in entities {
        tokens.extend(graph_entity_tokens_with_vocab(&entity, vocabulary));
    }
    for field in fields {
        if graph_field_is_group_dimension(field) {
            tokens.extend(graph_field_tokens_with_vocab(field, vocabulary));
        }
    }
    for relationship in relationships {
        tokens.extend(graph_fk_role_tokens(&relationship.from_field));
        tokens.extend(graph_fk_role_tokens(&relationship.to_field));
        tokens.extend(graph_name_tokens(&relationship.from_entity));
        tokens.extend(graph_name_tokens(&relationship.to_entity));
    }
    tokens
}

fn graph_relationship_path_role_tokens_between(
    left_entity: &str,
    right_entity: &str,
    relationships: &[RelationshipRow],
    fields: &[FieldRow],
    vocabulary: &[VocabularyEntry],
) -> HashSet<String> {
    let mut tokens = HashSet::new();
    if left_entity.eq_ignore_ascii_case(right_entity) {
        return tokens;
    }
    let starts = HashSet::from([left_entity.to_string()]);
    let Some(path) = graph_shortest_join_path("", &starts, right_entity, relationships) else {
        return tokens;
    };
    if path.len() > 3 {
        return HashSet::new();
    }
    let field_map = graph_field_map(fields);
    for step in path {
        tokens.extend(graph_relationship_endpoint_role_tokens(
            &step.from_entity,
            &step.from_field,
            &field_map,
            vocabulary,
        ));
        tokens.extend(graph_relationship_endpoint_role_tokens(
            &step.to_entity,
            &step.to_field,
            &field_map,
            vocabulary,
        ));
        tokens.extend(graph_entity_tokens_with_vocab(
            &step.from_entity,
            vocabulary,
        ));
        tokens.extend(graph_entity_tokens_with_vocab(&step.to_entity, vocabulary));
    }
    tokens
}

fn graph_relationship_path_role_tokens_between_in_atlas(
    left_entity: &str,
    right_entity: &str,
    atlas: &RuntimeSemanticAtlas,
) -> HashSet<String> {
    let mut tokens = HashSet::new();
    if left_entity.eq_ignore_ascii_case(right_entity) {
        return tokens;
    }
    let starts = HashSet::from([left_entity.to_string()]);
    let Some(path) = graph_shortest_join_path("", &starts, right_entity, &atlas.relationships)
    else {
        return tokens;
    };
    if path.len() > 3 {
        return HashSet::new();
    }
    for step in path {
        tokens.extend(graph_relationship_endpoint_role_tokens_from_field(
            &step.from_field,
            atlas.field_from_parts(&step.from_entity, &step.from_field),
            &atlas.vocabulary,
        ));
        tokens.extend(graph_relationship_endpoint_role_tokens_from_field(
            &step.to_field,
            atlas.field_from_parts(&step.to_entity, &step.to_field),
            &atlas.vocabulary,
        ));
        tokens.extend(graph_entity_tokens_with_vocab(
            &step.from_entity,
            &atlas.vocabulary,
        ));
        tokens.extend(graph_entity_tokens_with_vocab(
            &step.to_entity,
            &atlas.vocabulary,
        ));
    }
    tokens
}

fn graph_relationship_endpoint_role_tokens(
    entity: &str,
    field_segment: &str,
    field_map: &HashMap<String, &FieldRow>,
    vocabulary: &[VocabularyEntry],
) -> HashSet<String> {
    let canonical = if field_segment.contains('.') {
        field_segment.to_string()
    } else {
        format!("{entity}.{field_segment}")
    };
    graph_relationship_endpoint_role_tokens_from_field(
        field_segment,
        field_map.get(&canonical).copied(),
        vocabulary,
    )
}

fn graph_relationship_endpoint_role_tokens_from_field(
    field_segment: &str,
    field: Option<&FieldRow>,
    vocabulary: &[VocabularyEntry],
) -> HashSet<String> {
    let mut tokens = graph_fk_role_tokens(field_segment);
    if let Some(field) = field {
        tokens.extend(graph_field_tokens_with_vocab(field, vocabulary));
    }
    tokens.retain(|token| !matches!(token.as_str(), "id" | "ids" | "uuid" | "uuids"));
    tokens
}

fn graph_group_time_dimension_field<'a>(
    base_entity: &str,
    fields: &'a [FieldRow],
    predicates: &[GraphQueryPredicate],
) -> Option<&'a FieldRow> {
    let field_map = graph_field_map(fields);
    predicates.iter().find_map(|predicate| {
        field_map.get(&predicate.field).and_then(|field| {
            (field.entity.eq_ignore_ascii_case(base_entity)
                && graph_field_looks_date_like(field)
                && predicate.operator == "range")
                .then_some(*field)
        })
    })
}

fn graph_group_requested_time_dimension_field<'a>(
    nl: &str,
    base_entity: &str,
    fields: &'a [FieldRow],
    predicates: &[GraphQueryPredicate],
    vocabulary: &[VocabularyEntry],
) -> Option<&'a FieldRow> {
    if graph_grouped_time_series_prompt(nl) {
        graph_group_time_dimension_field(base_entity, fields, predicates)
            .or_else(|| graph_group_over_time_dimension_field(nl, base_entity, fields, vocabulary))
    } else {
        graph_group_over_time_dimension_field(nl, base_entity, fields, vocabulary)
    }
}

fn graph_group_over_time_dimension_field<'a>(
    nl: &str,
    base_entity: &str,
    fields: &'a [FieldRow],
    vocabulary: &[VocabularyEntry],
) -> Option<&'a FieldRow> {
    let phrase = graph_over_time_dimension_phrase(nl)?;
    let phrase_tokens = graph_schema_match_tokens(&phrase);
    if phrase_tokens.is_empty()
        || phrase_tokens
            .iter()
            .any(|token| token.chars().next().is_some_and(|ch| ch.is_ascii_digit()))
    {
        return None;
    }
    let phrase_norm = graph_norm(&phrase);
    let generic_time_phrase = phrase_tokens.iter().all(|token| {
        matches!(
            token.as_str(),
            "time" | "date" | "day" | "week" | "month" | "quarter" | "year"
        )
    });
    let mut candidates = fields
        .iter()
        .filter(|field| field.entity.eq_ignore_ascii_case(base_entity))
        .filter(|field| graph_field_looks_date_like(field))
        .filter_map(|field| {
            let field_tokens = graph_field_tokens_with_vocab(field, vocabulary);
            let overlap = field_tokens.intersection(&phrase_tokens).count() as i32;
            let exact_bonus = [
                field.field.as_str(),
                field.db_column.as_str(),
                field.display_label.as_deref().unwrap_or(""),
            ]
            .iter()
            .filter_map(|raw| {
                let raw_norm = graph_norm(raw);
                (!raw_norm.is_empty() && graph_norm_contains(&phrase_norm, &raw_norm))
                    .then_some(12 + raw_norm.len() as i32)
            })
            .max()
            .unwrap_or(0);
            let vocab_bonus = vocabulary
                .iter()
                .filter(|entry| {
                    entry.canonical_kind == "field"
                        && entry.confidence >= 0.4
                        && entry
                            .canonical_value
                            .eq_ignore_ascii_case(&field.canonical())
                })
                .filter_map(|entry| {
                    let term_norm = graph_norm(&entry.term);
                    (!term_norm.is_empty() && graph_norm_contains(&phrase_norm, &term_norm))
                        .then_some(10 + term_norm.len() as i32)
                })
                .max()
                .unwrap_or(0);
            let generic_bonus = if generic_time_phrase {
                graph_time_series_date_subject_bonus(nl, field) as i32
            } else {
                0
            };
            let score = overlap * 5 + exact_bonus + vocab_bonus + generic_bonus;
            (score >= if generic_time_phrase { 4 } else { 5 }).then_some((score, field))
        })
        .collect::<Vec<_>>();
    candidates.sort_by(|a, b| {
        b.0.cmp(&a.0)
            .then_with(|| a.1.canonical().cmp(&b.1.canonical()))
    });
    candidates.into_iter().map(|(_, field)| field).next()
}

fn graph_over_time_dimension_phrase(nl: &str) -> Option<String> {
    let lower = format!(" {} ", graph_norm(nl));
    let over_index = lower.find(" over ")? + " over ".len();
    let tail = lower[over_index..].trim();
    if tail
        .chars()
        .next()
        .is_some_and(|ch| ch.is_ascii_digit() || ch == '-' || ch == '+')
    {
        return None;
    }
    let mut end = tail.len();
    for marker in [
        " for ",
        " with ",
        " where ",
        " when ",
        " during ",
        " ordered ",
        " sorted ",
        " limit ",
        " by ",
    ] {
        if let Some(index) = tail.find(marker) {
            end = end.min(index);
        }
    }
    let phrase = tail[..end].trim();
    (!phrase.is_empty()).then(|| phrase.to_string())
}

fn graph_field_is_group_dimension(field: &FieldRow) -> bool {
    !graph_field_looks_unsafe_id(field)
        && (graph_field_looks_display_field(field)
            || is_boolean_field_type(&field.field_type)
            || graph_field_looks_date_like(field))
}

fn graph_grouped_count_alias(base_entity: &str) -> String {
    let stem = base_entity
        .trim_end_matches('s')
        .trim_matches('_')
        .to_ascii_lowercase();
    graph_sql_alias(&format!("{stem}_count"))
}

fn graph_grouped_measure_alias(prefix: &str, field: &FieldRow) -> String {
    graph_measure_alias(prefix, field)
}

fn graph_grouped_aggregate_default_direction(
    nl: &str,
    aggregate_kind: &str,
    measure: Option<&FieldRow>,
) -> &'static str {
    let lower = format!(" {} ", graph_norm(nl));
    if [
        " lowest ",
        " least ",
        " smallest ",
        " fastest ",
        " shortest ",
        " quickest ",
        " slowest ",
    ]
    .iter()
    .any(|needle| lower.contains(needle))
    {
        return "ASC";
    }
    if [
        " highest ",
        " most ",
        " largest ",
        " biggest ",
        " greatest ",
        " top ",
    ]
    .iter()
    .any(|needle| lower.contains(needle))
    {
        return "DESC";
    }
    if aggregate_kind == "avg" && measure.is_some_and(graph_measure_lower_is_better) {
        return "ASC";
    }
    "DESC"
}

fn graph_measure_lower_is_better(field: &FieldRow) -> bool {
    let compact = graph_compact_field_name(field);
    [
        "duration",
        "elapsed",
        "latency",
        "resolution",
        "response",
        "cycle",
        "wait",
        "delay",
        "age",
        "hours",
        "minutes",
        "seconds",
        "days",
    ]
    .iter()
    .any(|needle| compact.contains(needle))
}

fn graph_sql_alias(raw: &str) -> String {
    let mut out = String::new();
    let mut previous_underscore = false;
    for ch in raw.chars() {
        if ch.is_ascii_alphanumeric() {
            out.push(ch.to_ascii_lowercase());
            previous_underscore = false;
        } else if !previous_underscore {
            out.push('_');
            previous_underscore = true;
        }
    }
    let alias = out.trim_matches('_');
    if alias.is_empty() {
        "group_value".to_string()
    } else {
        alias.to_string()
    }
}

#[derive(Clone, Debug)]
struct GraphGroupedOrderAggregate {
    select_expr: String,
    group_by_expr: String,
    order_expr: String,
}

fn graph_grouped_order_aggregate(
    nl: &str,
    projection: &GraphQueryProjection,
    order: &GraphQueryOrder,
    field_map: &HashMap<String, &FieldRow>,
    entity_map: &HashMap<String, &EntityRow>,
) -> Option<GraphGroupedOrderAggregate> {
    let projection_field_key = projection.field.as_deref()?;
    if projection.fields.len() != 1 {
        return None;
    }
    let projection_field = field_map.get(projection_field_key).copied()?;
    let order_field = field_map.get(&order.field).copied()?;
    if projection_field
        .entity
        .eq_ignore_ascii_case(&order_field.entity)
        || projection.expr.contains('(')
        || !graph_field_looks_numeric(order_field)
        || graph_field_looks_unsafe_id(order_field)
    {
        return None;
    }
    if !graph_dimension_measure_rank_prompt(nl, projection_field, order_field) {
        return None;
    }
    if graph_order_measure_is_row_level_lookup(nl, order_field) {
        return None;
    }

    let projection_expr = graph_field_ref(projection_field, entity_map)?;
    let measure_expr = graph_field_ref(order_field, entity_map)?;
    let lower = nl.to_ascii_lowercase();
    let aggregate_fn = if graph_aggregate_kind(&lower) == Some("avg") {
        "AVG"
    } else {
        "SUM"
    };
    let alias_prefix = if aggregate_fn == "AVG" {
        "average"
    } else {
        "total"
    };
    let alias = graph_measure_alias(alias_prefix, order_field);
    Some(GraphGroupedOrderAggregate {
        select_expr: format!("{projection_expr}, {aggregate_fn}({measure_expr}) AS {alias}"),
        group_by_expr: projection_expr,
        order_expr: alias,
    })
}

fn graph_order_measure_is_row_level_lookup(nl: &str, order_field: &FieldRow) -> bool {
    if graph_aggregate_kind(&nl.to_ascii_lowercase()).is_some() {
        return false;
    }
    let entity = order_field.entity.to_ascii_lowercase();
    let table_role_is_metric = ["metric", "score", "stat", "summary", "snapshot"]
        .iter()
        .any(|needle| entity.contains(needle));
    if !table_role_is_metric {
        return false;
    }
    let lower = format!(" {} ", nl.to_ascii_lowercase().replace('\n', " "));
    lower.contains(" that has ")
        || lower.contains(" that have ")
        || lower.contains(" with the highest ")
        || lower.contains(" with the lowest ")
        || lower.contains(" with an ")
        || lower.contains(" with a ")
}

fn graph_rank_query_frame_trace(
    nl: &str,
    entities: &[EntityRow],
    fields: &[FieldRow],
    relationships: &[RelationshipRow],
    sample_values: &[SampleValueRow],
    vocabulary: &[VocabularyEntry],
) -> Option<RuntimeQueryFrameTrace> {
    if !graph_prompt_requests_rank(nl) || graph_rank_prompt_has_unsafe_terms(nl) {
        return None;
    }
    let field_map = graph_field_map(fields);
    let entity_map = graph_entity_map(entities);
    let order_field = graph_rank_order_field(nl, fields, vocabulary)?;
    let predicates = graph_rank_predicates(nl, order_field, fields, sample_values, vocabulary);
    let projection_fields = graph_rank_projection_fields(
        nl,
        order_field,
        entities,
        fields,
        relationships,
        &predicates,
        vocabulary,
    )?;
    let base_entity = projection_fields
        .first()
        .map(|field| field.entity.clone())
        .unwrap_or_else(|| order_field.entity.clone());

    let mut required_entities: HashSet<String> =
        HashSet::from([base_entity.clone(), order_field.entity.clone()]);
    for field in &projection_fields {
        required_entities.insert(field.entity.clone());
    }
    for predicate in &predicates {
        if let Some(field) = field_map.get(&predicate.field) {
            required_entities.insert(field.entity.clone());
        }
    }
    if graph_ambiguous_physical_table_family_for_required_entities(entities, &required_entities)
        .is_some()
    {
        return None;
    }

    let joins = graph_join_plan(nl, &base_entity, &required_entities, relationships)?;
    let join_sql = graph_render_joins(&base_entity, &joins, &entity_map, &field_map)?;
    let where_sql = graph_render_where(&predicates, &field_map, &entity_map)?;
    let base = entity_map.get(&base_entity)?;
    let order_expr = graph_field_ref(order_field, &entity_map)?;
    let direction = graph_rank_direction(nl);
    let rank_alias = graph_rank_alias(order_field);

    let mut select_exprs = Vec::new();
    let mut projection_keys = Vec::new();
    for field in &projection_fields {
        let field_ref = graph_field_ref(field, &entity_map)?;
        if !select_exprs.contains(&field_ref) {
            select_exprs.push(field_ref);
        }
        projection_keys.push(field.canonical());
    }
    if !projection_keys
        .iter()
        .any(|key| key.eq_ignore_ascii_case(&order_field.canonical()))
    {
        select_exprs.push(order_expr.clone());
        projection_keys.push(order_field.canonical());
    }
    select_exprs.push(format!(
        "RANK() OVER (ORDER BY {order_expr} {direction}) AS {rank_alias}"
    ));

    let mut where_parts = Vec::new();
    if !where_sql.is_empty() {
        where_parts.push(where_sql);
    }
    for field in graph_rank_non_null_projection_fields(nl, &projection_fields) {
        where_parts.push(format!(
            "{} IS NOT NULL",
            graph_field_ref(field, &entity_map)?
        ));
    }

    let mut sql = format!(
        "SELECT {} FROM {}",
        select_exprs.join(", "),
        graph_quote_ident(&base.db_table)
    );
    if !join_sql.is_empty() {
        sql.push(' ');
        sql.push_str(&join_sql);
    }
    if !where_parts.is_empty() {
        sql.push_str(" WHERE ");
        sql.push_str(&where_parts.join(" AND "));
    }

    let projection = GraphQueryProjection {
        entity: base_entity.clone(),
        field: projection_fields.first().map(|field| field.canonical()),
        fields: projection_keys,
        expr: select_exprs.join(", "),
    };
    let mut required_entity_list: Vec<String> = required_entities.into_iter().collect();
    required_entity_list.sort();

    Some(RuntimeQueryFrameTrace {
        schema_version: 1,
        source: "runtime_graph_query_frame_rank".to_string(),
        question: nl.to_string(),
        routed: true,
        used_for_final_sql: false,
        route_reason: "routed_rank_window".to_string(),
        sql: Some(sql),
        projection: Some(graph_projection_trace(&projection)),
        predicates: predicates.iter().map(graph_predicate_trace).collect(),
        required_entities: required_entity_list,
        joins: joins.iter().map(graph_join_trace).collect(),
        order_by: Some(RuntimeQueryFrameOrderTrace {
            field: order_field.canonical(),
            expression: order_expr,
            direction,
            limit: 0,
        }),
    })
}

fn graph_prompt_requests_rank(nl: &str) -> bool {
    let tokens = graph_name_tokens(nl);
    tokens.contains("rank") || tokens.contains("ranked") || tokens.contains("ranking")
}

fn graph_rank_prompt_has_unsafe_terms(nl: &str) -> bool {
    let lower = format!(" {} ", nl.to_ascii_lowercase().replace('\n', " "));
    [
        " or ",
        " between ",
        " percent ",
        " percentage ",
        " ratio ",
        " rate ",
    ]
    .iter()
    .any(|needle| lower.contains(needle))
}

fn graph_rank_direction(nl: &str) -> String {
    let lower = format!(" {} ", nl.to_ascii_lowercase().replace('\n', " "));
    if [
        " ascending ",
        " lowest ",
        " least ",
        " smallest ",
        " fewest ",
        " worst ",
    ]
    .iter()
    .any(|needle| lower.contains(needle))
    {
        "ASC".to_string()
    } else {
        "DESC".to_string()
    }
}

fn graph_rank_order_field<'a>(
    nl: &str,
    fields: &'a [FieldRow],
    vocabulary: &[VocabularyEntry],
) -> Option<&'a FieldRow> {
    let lower = nl.to_ascii_lowercase();
    let q_tokens = graph_tokens_with_aliases(nl);
    let mut scored: Vec<(f32, &FieldRow)> = fields
        .iter()
        .filter(|field| graph_field_looks_numeric(field) && !graph_field_looks_unsafe_id(field))
        .filter_map(|field| {
            let tokens = graph_field_tokens_with_vocab(field, vocabulary);
            let mut score = tokens.intersection(&q_tokens).count() as f32 * 2.0
                + graph_projection_phrase_bonus(&lower, field)
                + graph_field_vocab_phrase_bonus(nl, field, vocabulary);
            if graph_rank_field_context_bonus(nl, field) {
                score += 6.0;
            }
            (score >= 4.0).then_some((score, field))
        })
        .collect();
    scored.sort_by(|a, b| {
        b.0.partial_cmp(&a.0)
            .unwrap_or(std::cmp::Ordering::Equal)
            .then_with(|| a.1.canonical().cmp(&b.1.canonical()))
    });
    scored.into_iter().map(|(_, field)| field).next()
}

fn graph_rank_field_context_bonus(nl: &str, field: &FieldRow) -> bool {
    let lower = nl.to_ascii_lowercase();
    let by_tail = lower
        .split_once(" by ")
        .map(|(_, tail)| tail)
        .unwrap_or(lower.as_str());
    let context_tokens = graph_tokens_with_aliases(by_tail);
    let field_tokens = graph_field_tokens(field);
    !field_tokens.is_disjoint(&context_tokens)
}

fn graph_rank_predicates(
    nl: &str,
    order_field: &FieldRow,
    fields: &[FieldRow],
    sample_values: &[SampleValueRow],
    vocabulary: &[VocabularyEntry],
) -> Vec<GraphQueryPredicate> {
    let mut out = Vec::new();
    if let Some(predicate) = graph_rank_order_threshold_predicate(nl, order_field) {
        out.push(predicate);
    }
    let field_map = graph_field_map(fields);
    for predicate in graph_query_predicates_with_vocab(nl, fields, sample_values, vocabulary) {
        if out
            .iter()
            .any(|existing| existing.field == predicate.field && existing.value == predicate.value)
        {
            continue;
        }
        if out.iter().any(|existing| {
            existing.field == order_field.canonical()
                && existing.value == predicate.value
                && predicate.field != order_field.canonical()
                && matches!(predicate.operator.as_str(), ">" | ">=" | "<" | "<=")
        }) {
            continue;
        }
        let Some(field) = field_map.get(&predicate.field) else {
            continue;
        };
        if predicate.field == order_field.canonical() {
            if matches!(predicate.operator.as_str(), ">" | ">=" | "<" | "<=") {
                out.push(predicate);
            }
            continue;
        }
        let predicate_trace = graph_predicate_trace(&predicate);
        if graph_predicate_value_is_grounded_with_vocab(
            nl,
            &predicate_trace,
            field,
            sample_values,
            vocabulary,
        ) && !graph_predicate_value_has_span_role_conflict(nl, &predicate_trace, field, fields)
        {
            out.push(predicate);
        }
        if out.len() == 3 {
            break;
        }
    }
    out.sort_by(|a, b| a.field.cmp(&b.field).then_with(|| a.value.cmp(&b.value)));
    out.dedup_by(|a, b| a.field == b.field && a.value == b.value && a.operator == b.operator);
    out
}

fn graph_rank_order_threshold_predicate(
    nl: &str,
    order_field: &FieldRow,
) -> Option<GraphQueryPredicate> {
    for literal in graph_structured_literals(nl) {
        if graph_literal_is_limit_value(nl, &literal)
            || !graph_literal_compatible_with_field(nl, &literal, order_field)
        {
            continue;
        }
        let operator = graph_operator_for_mention(nl, &literal);
        if matches!(operator, ">" | ">=" | "<" | "<=") {
            return Some(GraphQueryPredicate {
                field: order_field.canonical(),
                operator: operator.to_string(),
                value: literal,
            });
        }
    }
    None
}

fn graph_rank_projection_fields<'a>(
    nl: &str,
    order_field: &FieldRow,
    entities: &[EntityRow],
    fields: &'a [FieldRow],
    relationships: &[RelationshipRow],
    predicates: &[GraphQueryPredicate],
    vocabulary: &[VocabularyEntry],
) -> Option<Vec<&'a FieldRow>> {
    let lower = nl.to_ascii_lowercase();
    let q_tokens = graph_schema_match_tokens(nl);
    let projection_focus_tokens = graph_rank_projection_focus_tokens(nl);
    let has_projection_focus = !projection_focus_tokens.is_empty();
    let distinctive_projection_focus =
        graph_rank_distinctive_projection_focus(&projection_focus_tokens);
    let predicate_entities: HashSet<String> = predicates
        .iter()
        .filter_map(|predicate| predicate.field.split_once('.').map(|(entity, _)| entity))
        .map(str::to_string)
        .collect();
    let mut candidates: Vec<(f32, &FieldRow)> = fields
        .iter()
        .filter(|field| field.canonical() != order_field.canonical())
        .filter(|field| {
            graph_field_looks_display_field(field)
                && (!graph_field_looks_unsafe_id(field)
                    || graph_projection_id_field_requested(nl, field))
        })
        .filter(|field| {
            field.entity.eq_ignore_ascii_case(&order_field.entity)
                || graph_entities_are_related(&field.entity, &order_field.entity, relationships)
                || predicate_entities.contains(&field.entity)
                || predicate_entities
                    .iter()
                    .any(|entity| graph_entities_are_related(entity, &field.entity, relationships))
        })
        .filter_map(|field| {
            let tokens = graph_field_tokens_with_vocab(field, vocabulary);
            let focus_overlap = tokens.intersection(&projection_focus_tokens).count() as f32;
            let overlap = tokens.intersection(&q_tokens).count() as f32;
            let phrase_bonus = graph_projection_phrase_bonus(&lower, field)
                + graph_field_vocab_phrase_bonus(nl, field, vocabulary);
            let showing_bonus = graph_rank_showing_projection_bonus(&lower, field);
            if has_projection_focus && focus_overlap == 0.0 && showing_bonus == 0.0 {
                return None;
            }
            if !distinctive_projection_focus.is_empty()
                && tokens.is_disjoint(&distinctive_projection_focus)
            {
                return None;
            }
            let score = if has_projection_focus {
                focus_overlap * 4.0 + phrase_bonus + showing_bonus
            } else {
                overlap * 2.0 + phrase_bonus + showing_bonus
            };
            (score >= 2.0).then_some((score, field))
        })
        .collect();
    candidates.sort_by(|a, b| {
        b.0.partial_cmp(&a.0)
            .unwrap_or(std::cmp::Ordering::Equal)
            .then_with(|| a.1.canonical().cmp(&b.1.canonical()))
    });
    let mut out: Vec<&FieldRow> = candidates
        .into_iter()
        .map(|(_, field)| field)
        .take(3)
        .collect();
    if out.is_empty() {
        let subject = graph_subject_entity_with_vocab(nl, entities, fields, predicates, vocabulary)
            .unwrap_or_else(|| order_field.entity.clone());
        if let Some(field) =
            graph_default_display_field_for_entity_with_vocab(&subject, fields, vocabulary)
        {
            out.push(field);
        }
    }
    if out.is_empty() {
        return None;
    }
    graph_sort_projection_fields_by_mention_order(nl, &mut out, vocabulary);
    Some(out)
}

fn graph_rank_projection_focus_tokens(nl: &str) -> HashSet<String> {
    let lower = nl.to_ascii_lowercase();
    for marker in [" showing ", " show ", " display ", " listing ", " list "] {
        if let Some((_, tail)) = lower.split_once(marker) {
            return graph_schema_match_tokens(tail);
        }
    }
    HashSet::new()
}

fn graph_rank_distinctive_projection_focus(tokens: &HashSet<String>) -> HashSet<String> {
    let generic = [
        "number",
        "numbers",
        "num",
        "code",
        "codes",
        "id",
        "ids",
        "identifier",
        "identification",
        "their",
        "its",
        "field",
        "value",
    ];
    tokens
        .iter()
        .filter(|token| token.len() >= 3 && !generic.contains(&token.as_str()))
        .cloned()
        .collect()
}

fn graph_rank_showing_projection_bonus(lower_nl: &str, field: &FieldRow) -> f32 {
    if !(lower_nl.contains(" showing ")
        || lower_nl.contains(" show ")
        || lower_nl.contains(" list ")
        || lower_nl.contains(" display "))
    {
        return 0.0;
    }
    let tokens = graph_field_tokens(field);
    let mut score = 0.0;
    if lower_nl.contains("number") && (tokens.contains("num") || tokens.contains("number")) {
        score += 3.0;
    }
    if lower_nl.contains("code") && tokens.contains("code") {
        score += 3.0;
    }
    score
}

fn graph_rank_non_null_projection_fields<'a>(
    nl: &str,
    fields: &[&'a FieldRow],
) -> Vec<&'a FieldRow> {
    let lower = format!(" {} ", nl.to_ascii_lowercase().replace('\n', " "));
    if !(lower.contains(" showing ")
        || lower.contains(" with their ")
        || lower.contains(" with its "))
    {
        return Vec::new();
    }
    fields
        .iter()
        .copied()
        .filter(|field| {
            let compact = graph_compact_field_name(field);
            (compact.contains("code")
                || compact.contains("num")
                || compact.contains("number")
                || compact.contains("identifier"))
                && graph_field_looks_display_field(field)
        })
        .collect()
}

fn graph_rank_alias(order_field: &FieldRow) -> String {
    let alias = graph_measure_alias("rank", order_field);
    if alias == "rank" {
        "measure_rank".to_string()
    } else {
        alias
    }
}

fn graph_attribute_superlative_query_frame_trace(
    nl: &str,
    entities: &[EntityRow],
    fields: &[FieldRow],
    relationships: &[RelationshipRow],
    sample_values: &[SampleValueRow],
    vocabulary: &[VocabularyEntry],
) -> Option<RuntimeQueryFrameTrace> {
    if graph_attribute_prompt_has_unsafe_terms(nl) {
        return None;
    }
    let request = graph_attribute_superlative_request(nl)?;
    let field_map = graph_field_map(fields);
    let entity_map = graph_entity_map(entities);
    let attribute_match = graph_attribute_name_match(fields, sample_values, &request)?;
    let subject_entity = graph_subject_entity_with_vocab(nl, entities, fields, &[], vocabulary)?;
    if subject_entity.eq_ignore_ascii_case(&attribute_match.field.entity) {
        return None;
    }
    let projection_field = graph_attribute_subject_projection_field(nl, &subject_entity, fields)
        .or_else(|| {
            graph_default_display_field_for_entity_with_vocab(&subject_entity, fields, vocabulary)
        })?;
    let value_field = graph_attribute_value_field_for_request(
        nl,
        &subject_entity,
        attribute_match.field,
        fields,
        relationships,
    )?;
    let mut predicates = vec![GraphQueryPredicate {
        field: attribute_match.field.canonical(),
        value: attribute_match.value.clone(),
        operator: "=".to_string(),
    }];
    predicates.extend(graph_attribute_extra_predicates(
        nl,
        attribute_match.field,
        fields,
        sample_values,
        vocabulary,
    ));
    predicates.truncate(3);

    let mut required_entities: HashSet<String> = HashSet::from([
        subject_entity.clone(),
        attribute_match.field.entity.clone(),
        value_field.entity.clone(),
    ]);
    for predicate in &predicates {
        if let Some(field) = field_map.get(&predicate.field) {
            required_entities.insert(field.entity.clone());
        }
    }
    if graph_ambiguous_physical_table_family_for_required_entities(entities, &required_entities)
        .is_some()
    {
        return None;
    }

    let joins = graph_join_plan(nl, &subject_entity, &required_entities, relationships)?;
    let join_sql = graph_render_joins(&subject_entity, &joins, &entity_map, &field_map)?;
    let where_sql = graph_render_where(&predicates, &field_map, &entity_map)?;
    let base_entity = entity_map.get(&subject_entity)?;
    let projection_expr = graph_field_ref(projection_field, &entity_map)?;
    let order_expr = graph_field_ref(value_field, &entity_map)?;
    let mut sql = format!(
        "SELECT {projection_expr} FROM {}",
        graph_quote_ident(&base_entity.db_table)
    );
    if !join_sql.is_empty() {
        sql.push(' ');
        sql.push_str(&join_sql);
    }
    if !where_sql.is_empty() {
        sql.push_str(" WHERE ");
        sql.push_str(&where_sql);
    }
    sql.push_str(" ORDER BY ");
    sql.push_str(&order_expr);
    sql.push(' ');
    sql.push_str(&request.direction);
    sql.push_str(" LIMIT ");
    sql.push_str(&request.limit.to_string());

    let projection = GraphQueryProjection {
        entity: projection_field.entity.clone(),
        field: Some(projection_field.canonical()),
        fields: vec![projection_field.canonical()],
        expr: projection_expr,
    };
    let mut required_entity_list: Vec<String> = required_entities.into_iter().collect();
    required_entity_list.sort();
    Some(RuntimeQueryFrameTrace {
        schema_version: 1,
        source: "runtime_graph_query_frame_attribute".to_string(),
        question: nl.to_string(),
        routed: true,
        used_for_final_sql: false,
        route_reason: "routed_attribute_superlative".to_string(),
        sql: Some(sql),
        projection: Some(graph_projection_trace(&projection)),
        predicates: predicates.iter().map(graph_predicate_trace).collect(),
        required_entities: required_entity_list,
        joins: joins.iter().map(graph_join_trace).collect(),
        order_by: Some(RuntimeQueryFrameOrderTrace {
            field: value_field.canonical(),
            expression: order_expr,
            direction: request.direction,
            limit: request.limit,
        }),
    })
}

fn graph_attribute_superlative_request(nl: &str) -> Option<GraphAttributeSuperlativeRequest> {
    let tokens: Vec<String> = graph_norm(nl)
        .split_whitespace()
        .map(str::to_string)
        .collect();
    let limit = question_limit(nl).unwrap_or(1);
    for (index, token) in tokens.iter().enumerate() {
        let Some(direction) = graph_superlative_marker_direction(token) else {
            continue;
        };
        let aliases = graph_attribute_aliases_after_marker(&tokens[index + 1..]);
        if aliases.is_empty() {
            continue;
        }
        let concept = aliases[0].clone();
        return Some(GraphAttributeSuperlativeRequest {
            concept,
            aliases,
            direction: direction.to_string(),
            limit,
        });
    }
    None
}

fn graph_superlative_marker_direction(token: &str) -> Option<&'static str> {
    match token {
        "least" | "lowest" | "minimum" | "smallest" | "worst" => Some("ASC"),
        "most" | "highest" | "maximum" | "largest" | "best" | "top" => Some("DESC"),
        _ => None,
    }
}

fn graph_attribute_aliases_after_marker(tokens: &[String]) -> Vec<String> {
    let content: Vec<String> = tokens
        .iter()
        .filter(|token| !graph_attribute_marker_tail_stopword(token))
        .take(3)
        .cloned()
        .collect();
    if content.is_empty() {
        return Vec::new();
    }
    let mut aliases = Vec::new();
    graph_push_unique_alias(&mut aliases, content.join(" "));
    for token in &content {
        graph_push_unique_alias(&mut aliases, token.clone());
        for variant in graph_attribute_word_variants(token) {
            graph_push_unique_alias(&mut aliases, variant);
        }
    }
    aliases
}

fn graph_attribute_marker_tail_stopword(token: &str) -> bool {
    matches!(
        token,
        "a" | "an"
            | "the"
            | "of"
            | "by"
            | "in"
            | "on"
            | "at"
            | "to"
            | "with"
            | "for"
            | "person"
            | "people"
            | "item"
            | "items"
            | "product"
            | "products"
            | "customer"
            | "customers"
            | "account"
            | "accounts"
            | "record"
            | "records"
            | "row"
            | "rows"
            | "entity"
            | "entities"
    )
}

fn graph_attribute_word_variants(token: &str) -> Vec<String> {
    let mut variants = Vec::new();
    if let Some(stem) = token.strip_suffix("ent") {
        variants.push(format!("{stem}ence"));
    }
    if let Some(stem) = token.strip_suffix("ant") {
        variants.push(format!("{stem}ance"));
    }
    if let Some(stem) = token.strip_suffix("able") {
        variants.push(format!("{stem}ability"));
    }
    if let Some(stem) = token.strip_suffix("ible") {
        variants.push(format!("{stem}ibility"));
    }
    if let Some(stem) = token.strip_suffix("ive") {
        variants.push(format!("{stem}ivity"));
    }
    if let Some(stem) = token.strip_suffix("ful") {
        variants.push(stem.to_string());
    }
    variants
}

fn graph_push_unique_alias(aliases: &mut Vec<String>, alias: String) {
    let alias = alias.trim();
    if alias.is_empty() {
        return;
    }
    if aliases
        .iter()
        .any(|existing| existing.eq_ignore_ascii_case(alias))
    {
        return;
    }
    aliases.push(alias.to_string());
}

fn graph_attribute_prompt_has_unsafe_terms(nl: &str) -> bool {
    let lower = format!(" {} ", nl.to_ascii_lowercase().replace('\n', " "));
    [
        " average ",
        " avg ",
        " ratio ",
        " rate ",
        " percentage ",
        " percent ",
        " difference ",
        " compare ",
        " versus ",
        " vs ",
        " or ",
        " between ",
        " over time ",
        " trend ",
        " from ",
        " where ",
        " for ",
    ]
    .iter()
    .any(|needle| lower.contains(needle))
}

fn graph_attribute_name_match<'a>(
    fields: &'a [FieldRow],
    sample_values: &[SampleValueRow],
    request: &GraphAttributeSuperlativeRequest,
) -> Option<GraphAttributeNameMatch<'a>> {
    let field_map = graph_field_map(fields);
    let alias_norms: HashSet<String> = request
        .aliases
        .iter()
        .map(|alias| graph_norm(alias))
        .filter(|alias| !alias.is_empty())
        .collect();
    let mut matches = Vec::new();
    for row in sample_values {
        if row.pii_redacted {
            continue;
        }
        let Some(field) = field_map.get(&row.field_canonical).copied() else {
            continue;
        };
        if !graph_attribute_name_field_candidate(field) {
            continue;
        }
        for value in &row.examples {
            let value_norm = graph_norm(value);
            if !alias_norms.contains(&value_norm) {
                continue;
            }
            let mut score = 20.0;
            let tokens = graph_attribute_catalog_tokens(field);
            if tokens.contains("attribute") || tokens.contains("metric") {
                score += 4.0;
            }
            if tokens.contains("name") || tokens.contains("label") {
                score += 2.0;
            }
            if graph_norm(&request.concept) == value_norm {
                score += 2.0;
            }
            matches.push(GraphAttributeNameMatch {
                field,
                value: value.clone(),
                score,
            });
        }
    }
    matches.sort_by(|a, b| {
        b.score
            .partial_cmp(&a.score)
            .unwrap_or(std::cmp::Ordering::Equal)
            .then_with(|| a.field.canonical().cmp(&b.field.canonical()))
            .then_with(|| a.value.cmp(&b.value))
    });
    matches.into_iter().next()
}

fn graph_attribute_name_field_candidate(field: &FieldRow) -> bool {
    if !graph_field_looks_display_field(field) || graph_field_looks_unsafe_id(field) {
        return false;
    }
    let tokens = graph_attribute_catalog_tokens(field);
    let has_catalog_role = [
        "attribute",
        "attributes",
        "metric",
        "metrics",
        "measure",
        "measures",
        "trait",
        "traits",
        "property",
        "properties",
        "dimension",
        "dimensions",
        "rating",
        "ratings",
        "score",
        "scores",
    ]
    .iter()
    .any(|token| tokens.contains(*token));
    let has_name_role = ["name", "label", "type", "key"]
        .iter()
        .any(|token| tokens.contains(*token));
    has_catalog_role && has_name_role
}

fn graph_attribute_catalog_tokens(field: &FieldRow) -> HashSet<String> {
    let mut tokens = graph_field_tokens(field);
    tokens.extend(graph_name_tokens(&field.entity));
    tokens
}

fn graph_attribute_value_field_for_request<'a>(
    nl: &str,
    subject_entity: &str,
    attribute_name_field: &FieldRow,
    fields: &'a [FieldRow],
    relationships: &[RelationshipRow],
) -> Option<&'a FieldRow> {
    let q_tokens = graph_schema_match_tokens(nl);
    let mut candidates: Vec<(i32, &FieldRow)> = fields
        .iter()
        .filter(|field| graph_field_looks_numeric(field) && !graph_field_looks_unsafe_id(field))
        .filter(|field| {
            !field
                .entity
                .eq_ignore_ascii_case(&attribute_name_field.entity)
        })
        .filter(|field| {
            graph_entities_are_related(&field.entity, subject_entity, relationships)
                && graph_entities_are_related(
                    &field.entity,
                    &attribute_name_field.entity,
                    relationships,
                )
        })
        .filter_map(|field| {
            let required = HashSet::from([
                subject_entity.to_string(),
                attribute_name_field.entity.clone(),
                field.entity.clone(),
            ]);
            graph_join_plan(nl, subject_entity, &required, relationships)?;
            let tokens = graph_field_tokens(field);
            let entity_tokens = graph_name_tokens(&field.entity);
            let mut score = 1;
            if tokens.contains("value") {
                score += 12;
            }
            if tokens.contains("score")
                || tokens.contains("rating")
                || tokens.contains("points")
                || tokens.contains("amount")
            {
                score += 6;
            }
            if entity_tokens.contains("attribute")
                || entity_tokens.contains("metric")
                || entity_tokens.contains("measure")
                || entity_tokens.contains("score")
            {
                score += 4;
            }
            score += tokens.intersection(&q_tokens).count() as i32;
            Some((score, field))
        })
        .collect();
    candidates.sort_by(|a, b| {
        b.0.cmp(&a.0)
            .then_with(|| a.1.canonical().cmp(&b.1.canonical()))
    });
    candidates.into_iter().map(|(_, field)| field).next()
}

fn graph_attribute_subject_projection_field<'a>(
    nl: &str,
    subject_entity: &str,
    fields: &'a [FieldRow],
) -> Option<&'a FieldRow> {
    let q_tokens = graph_schema_match_tokens(nl);
    let subject_tokens = graph_name_tokens(subject_entity);
    let lower = nl.to_ascii_lowercase();
    let mut candidates: Vec<(i32, &FieldRow)> = fields
        .iter()
        .filter(|field| field.entity.eq_ignore_ascii_case(subject_entity))
        .filter(|field| {
            graph_field_looks_display_field(field) && !graph_field_looks_unsafe_id(field)
        })
        .map(|field| {
            let tokens = graph_field_tokens(field);
            let mut score = 0;
            score += tokens.intersection(&q_tokens).count() as i32 * 3;
            score += tokens.intersection(&subject_tokens).count() as i32 * 8;
            if tokens.contains("name") || tokens.contains("title") || tokens.contains("label") {
                score += 4;
            }
            if field.db_column.eq_ignore_ascii_case("full_name") && !lower.contains("full name") {
                score -= 2;
            }
            (score, field)
        })
        .filter(|(score, _)| *score > 0)
        .collect();
    candidates.sort_by(|a, b| {
        b.0.cmp(&a.0)
            .then_with(|| a.1.canonical().cmp(&b.1.canonical()))
    });
    candidates.into_iter().map(|(_, field)| field).next()
}

fn graph_attribute_extra_predicates(
    nl: &str,
    attribute_name_field: &FieldRow,
    fields: &[FieldRow],
    sample_values: &[SampleValueRow],
    vocabulary: &[VocabularyEntry],
) -> Vec<GraphQueryPredicate> {
    let field_map = graph_field_map(fields);
    let mut out = Vec::new();
    for predicate in graph_query_predicates_with_vocab(nl, fields, sample_values, vocabulary) {
        if predicate
            .field
            .eq_ignore_ascii_case(&attribute_name_field.canonical())
            || out
                .iter()
                .any(|existing: &GraphQueryPredicate| existing.field == predicate.field)
        {
            continue;
        }
        let Some(field) = field_map.get(&predicate.field) else {
            continue;
        };
        let predicate_trace = graph_predicate_trace(&predicate);
        if !graph_predicate_value_is_grounded_with_vocab(
            nl,
            &predicate_trace,
            field,
            sample_values,
            vocabulary,
        ) || graph_predicate_value_has_span_role_conflict(nl, &predicate_trace, field, fields)
        {
            continue;
        }
        out.push(predicate);
        if out.len() == 2 {
            break;
        }
    }
    out
}

fn graph_person_event_query_frame_trace(
    nl: &str,
    entities: &[EntityRow],
    fields: &[FieldRow],
    relationships: &[RelationshipRow],
    sample_values: &[SampleValueRow],
    vocabulary: &[VocabularyEntry],
) -> Option<RuntimeQueryFrameTrace> {
    if graph_person_event_prompt_has_unsafe_terms(nl) {
        return None;
    }
    let field_map = graph_field_map(fields);
    let entity_map = graph_entity_map(entities);
    let person = graph_person_name_match(nl, fields, sample_values)?;
    let projection_field = graph_person_event_projection_field(
        nl,
        person.first_field,
        fields,
        relationships,
        vocabulary,
    )?;
    let event_field = graph_person_event_id_field(nl, projection_field, fields, vocabulary)?;
    let event_value = graph_person_event_id_literal(nl, event_field)?;
    let predicates = vec![
        GraphQueryPredicate {
            field: event_field.canonical(),
            value: event_value,
            operator: "=".to_string(),
        },
        GraphQueryPredicate {
            field: person.first_field.canonical(),
            value: person.first_value,
            operator: "=".to_string(),
        },
        GraphQueryPredicate {
            field: person.last_field.canonical(),
            value: person.last_value,
            operator: "=".to_string(),
        },
    ];
    let mut required_entities: HashSet<String> = HashSet::from([
        projection_field.entity.clone(),
        event_field.entity.clone(),
        person.first_field.entity.clone(),
        person.last_field.entity.clone(),
    ]);
    for predicate in &predicates {
        if let Some(field) = field_map.get(&predicate.field) {
            required_entities.insert(field.entity.clone());
        }
    }
    if graph_ambiguous_physical_table_family_for_required_entities(entities, &required_entities)
        .is_some()
    {
        return None;
    }
    let joins = graph_join_plan(
        nl,
        &projection_field.entity,
        &required_entities,
        relationships,
    )?;
    let join_sql = graph_render_joins(&projection_field.entity, &joins, &entity_map, &field_map)?;
    let where_sql = graph_render_where(&predicates, &field_map, &entity_map)?;
    let base_entity = entity_map.get(&projection_field.entity)?;
    let projection_expr = graph_field_ref(projection_field, &entity_map)?;
    let mut sql = format!(
        "SELECT {projection_expr} FROM {}",
        graph_quote_ident(&base_entity.db_table)
    );
    if !join_sql.is_empty() {
        sql.push(' ');
        sql.push_str(&join_sql);
    }
    if !where_sql.is_empty() {
        sql.push_str(" WHERE ");
        sql.push_str(&where_sql);
    }
    let projection = GraphQueryProjection {
        entity: projection_field.entity.clone(),
        field: Some(projection_field.canonical()),
        fields: vec![projection_field.canonical()],
        expr: projection_expr,
    };
    let mut required_entity_list: Vec<String> = required_entities.into_iter().collect();
    required_entity_list.sort();
    Some(RuntimeQueryFrameTrace {
        schema_version: 1,
        source: "runtime_graph_query_frame_person_event".to_string(),
        question: nl.to_string(),
        routed: true,
        used_for_final_sql: false,
        route_reason: "routed_person_event_lookup".to_string(),
        sql: Some(sql),
        projection: Some(graph_projection_trace(&projection)),
        predicates: predicates.iter().map(graph_predicate_trace).collect(),
        required_entities: required_entity_list,
        joins: joins.iter().map(graph_join_trace).collect(),
        order_by: None,
    })
}

fn graph_person_event_prompt_has_unsafe_terms(nl: &str) -> bool {
    let lower = format!(" {} ", nl.to_ascii_lowercase().replace('\n', " "));
    [
        " average ",
        " avg ",
        " ratio ",
        " rate ",
        " percentage ",
        " percent ",
        " difference ",
        " compare ",
        " versus ",
        " vs ",
        " or ",
        " between ",
        " highest ",
        " lowest ",
        " top ",
        " rank ",
        " grouped ",
        " by each ",
    ]
    .iter()
    .any(|needle| lower.contains(needle))
}

fn graph_person_name_match<'a>(
    nl: &str,
    fields: &'a [FieldRow],
    sample_values: &[SampleValueRow],
) -> Option<GraphPersonNameMatch<'a>> {
    let pairs = graph_capitalized_name_pairs(nl);
    if pairs.is_empty() {
        return None;
    }
    let first_fields: Vec<&FieldRow> = fields
        .iter()
        .filter(|field| graph_person_first_name_field(field))
        .collect();
    let last_fields: Vec<&FieldRow> = fields
        .iter()
        .filter(|field| graph_person_last_name_field(field))
        .collect();
    let mut matches = Vec::new();
    for (first_value, last_value) in pairs {
        for first_field in &first_fields {
            if !graph_sample_value_contains(sample_values, &first_field.canonical(), &first_value) {
                continue;
            }
            for last_field in &last_fields {
                if !first_field.entity.eq_ignore_ascii_case(&last_field.entity)
                    || !graph_sample_value_contains(
                        sample_values,
                        &last_field.canonical(),
                        &last_value,
                    )
                {
                    continue;
                }
                matches.push((
                    20,
                    *first_field,
                    *last_field,
                    first_value.clone(),
                    last_value.clone(),
                ));
            }
        }
    }
    matches.sort_by(|a, b| {
        b.0.cmp(&a.0)
            .then_with(|| a.1.canonical().cmp(&b.1.canonical()))
            .then_with(|| a.2.canonical().cmp(&b.2.canonical()))
    });
    matches
        .into_iter()
        .next()
        .map(
            |(_, first_field, last_field, first_value, last_value)| GraphPersonNameMatch {
                first_field,
                last_field,
                first_value,
                last_value,
            },
        )
}

fn graph_person_first_name_field(field: &FieldRow) -> bool {
    if !graph_field_looks_display_field(field) || graph_field_looks_unsafe_id(field) {
        return false;
    }
    let tokens = graph_field_tokens(field);
    tokens.contains("forename")
        || tokens.contains("firstname")
        || (tokens.contains("first") && tokens.contains("name"))
        || (tokens.contains("given") && tokens.contains("name"))
}

fn graph_person_last_name_field(field: &FieldRow) -> bool {
    if !graph_field_looks_display_field(field) || graph_field_looks_unsafe_id(field) {
        return false;
    }
    let tokens = graph_field_tokens(field);
    tokens.contains("surname")
        || tokens.contains("lastname")
        || (tokens.contains("last") && tokens.contains("name"))
        || (tokens.contains("family") && tokens.contains("name"))
}

fn graph_capitalized_name_pairs(nl: &str) -> Vec<(String, String)> {
    let mut tokens = Vec::new();
    let mut current = String::new();
    for ch in nl.chars() {
        if ch.is_alphabetic() || ch == '-' {
            current.push(ch);
        } else {
            graph_push_capitalized_name_token(&mut tokens, &current);
            current.clear();
        }
    }
    graph_push_capitalized_name_token(&mut tokens, &current);
    let stop = [
        "What", "Which", "Who", "Whose", "Where", "When", "How", "Please", "Show", "List", "Give",
        "State",
    ];
    let mut out = Vec::new();
    for pair in tokens.windows(2) {
        if stop.contains(&pair[0].as_str()) || stop.contains(&pair[1].as_str()) {
            continue;
        }
        out.push((pair[0].clone(), pair[1].clone()));
    }
    out
}

fn graph_push_capitalized_name_token(out: &mut Vec<String>, token: &str) {
    let token = token.trim_matches('-');
    if token.len() < 2 {
        return;
    }
    let mut chars = token.chars();
    if chars.next().is_some_and(char::is_uppercase) && chars.any(char::is_lowercase) {
        out.push(token.to_string());
    }
}

fn graph_person_event_projection_field<'a>(
    nl: &str,
    person_field: &FieldRow,
    fields: &'a [FieldRow],
    relationships: &[RelationshipRow],
    vocabulary: &[VocabularyEntry],
) -> Option<&'a FieldRow> {
    let lower = nl.to_ascii_lowercase();
    let q_tokens = graph_schema_match_tokens(nl);
    let mut candidates: Vec<(f32, &FieldRow)> = fields
        .iter()
        .filter(|field| {
            !field.entity.eq_ignore_ascii_case(&person_field.entity)
                && graph_entities_are_related(&field.entity, &person_field.entity, relationships)
        })
        .filter(|field| {
            graph_field_looks_display_field(field) && !graph_field_looks_unsafe_id(field)
        })
        .filter_map(|field| {
            let tokens = graph_field_tokens_with_vocab(field, vocabulary);
            let mut score = tokens.intersection(&q_tokens).count() as f32 * 3.0;
            score += graph_projection_phrase_bonus(&lower, field)
                + graph_field_vocab_phrase_bonus(nl, field, vocabulary);
            if lower.contains("result") && graph_person_event_result_field(field) {
                score += 4.0;
            }
            (score >= 3.0).then_some((score, field))
        })
        .collect();
    candidates.sort_by(|a, b| {
        b.0.partial_cmp(&a.0)
            .unwrap_or(std::cmp::Ordering::Equal)
            .then_with(|| a.1.canonical().cmp(&b.1.canonical()))
    });
    candidates.into_iter().map(|(_, field)| field).next()
}

fn graph_person_event_result_field(field: &FieldRow) -> bool {
    let tokens = graph_field_tokens(field);
    tokens.contains("result")
        || tokens.contains("time")
        || tokens.contains("score")
        || tokens.contains("status")
        || graph_compact_field_name(field).starts_with('q')
}

fn graph_person_event_id_field<'a>(
    nl: &str,
    projection_field: &FieldRow,
    fields: &'a [FieldRow],
    vocabulary: &[VocabularyEntry],
) -> Option<&'a FieldRow> {
    let literal = graph_person_event_id_literal_text(nl)?;
    let context_tokens = graph_schema_match_tokens(&graph_mention_context(nl, &literal));
    let q_tokens = graph_schema_match_tokens(nl);
    let mut candidates: Vec<(f32, &FieldRow)> = fields
        .iter()
        .filter(|field| field.entity.eq_ignore_ascii_case(&projection_field.entity))
        .filter(|field| graph_field_looks_numeric(field))
        .filter_map(|field| {
            let tokens = graph_field_tokens_with_vocab(field, vocabulary);
            let context_overlap = tokens.intersection(&context_tokens).count() as f32;
            let query_overlap = tokens.intersection(&q_tokens).count() as f32;
            let id_role = if graph_field_looks_unsafe_id(field) {
                2.0
            } else {
                0.0
            };
            let score = context_overlap * 5.0 + query_overlap + id_role;
            (score >= 4.0).then_some((score, field))
        })
        .collect();
    candidates.sort_by(|a, b| {
        b.0.partial_cmp(&a.0)
            .unwrap_or(std::cmp::Ordering::Equal)
            .then_with(|| a.1.canonical().cmp(&b.1.canonical()))
    });
    candidates.into_iter().map(|(_, field)| field).next()
}

fn graph_person_event_id_literal(nl: &str, field: &FieldRow) -> Option<String> {
    let literal = graph_person_event_id_literal_text(nl)?;
    graph_person_event_id_literal_targets_field(nl, &literal, field).then_some(literal)
}

fn graph_person_event_id_literal_text(nl: &str) -> Option<String> {
    graph_structured_literals(nl).into_iter().find(|literal| {
        !graph_literal_is_limit_value(nl, literal)
            && literal.chars().all(|ch| ch.is_ascii_digit())
            && graph_literal_has_event_number_marker(nl, literal)
    })
}

fn graph_literal_has_event_number_marker(nl: &str, literal: &str) -> bool {
    let lower = nl.to_ascii_lowercase();
    let literal_lower = literal.to_ascii_lowercase();
    let mut offset = 0;
    while let Some(relative_index) = lower[offset..].find(&literal_lower) {
        let index = offset + relative_index;
        let prefix_start = index.saturating_sub(32);
        let prefix_norm = graph_norm(&lower[prefix_start..index]);
        if prefix_norm.ends_with(" no")
            || prefix_norm.ends_with(" number")
            || prefix_norm.ends_with(" id")
            || prefix_norm.ends_with(" race no")
            || prefix_norm.ends_with(" race number")
            || prefix_norm.ends_with(" race id")
            || prefix_norm.ends_with(" event no")
            || prefix_norm.ends_with(" event number")
            || prefix_norm.ends_with(" event id")
            || prefix_norm.ends_with(" order no")
            || prefix_norm.ends_with(" order number")
            || prefix_norm.ends_with(" order id")
        {
            return true;
        }
        offset = index + literal_lower.len();
    }
    false
}

fn graph_person_event_id_literal_targets_field(nl: &str, literal: &str, field: &FieldRow) -> bool {
    if !graph_is_plain_number(literal)
        || !graph_field_looks_numeric(field)
        || !graph_field_looks_unsafe_id(field)
        || !graph_literal_has_event_number_marker(nl, literal)
    {
        return false;
    }
    let context_tokens = graph_schema_match_tokens(&graph_mention_context(nl, literal));
    let mut role_tokens = graph_field_tokens(field);
    role_tokens.retain(|token| !matches!(token.as_str(), "id" | "ids" | "number" | "no"));
    if role_tokens.is_empty() {
        role_tokens.extend(graph_name_tokens(&field.entity));
    }
    !role_tokens.is_disjoint(&context_tokens)
}

fn graph_average_related_count_query_frame_trace(
    nl: &str,
    entities: &[EntityRow],
    fields: &[FieldRow],
    relationships: &[RelationshipRow],
    sample_values: &[SampleValueRow],
    vocabulary: &[VocabularyEntry],
) -> Option<RuntimeQueryFrameTrace> {
    if !graph_prompt_requests_average_related_count(nl) {
        return None;
    }
    let field_map = graph_field_map(fields);
    let entity_map = graph_entity_map(entities);
    let predicates = graph_query_predicates_with_vocab(nl, fields, sample_values, vocabulary);
    if predicates.len() != 1 {
        return None;
    }
    let predicate_field = field_map.get(&predicates[0].field)?;
    let subject_entity = predicate_field.entity.clone();
    let related_entity = graph_average_related_count_target_entity(nl, entities, &subject_entity)?;
    let (bridge_entity, subject_key_field, bridge_subject_field, bridge_related_field) =
        graph_related_count_bridge(
            &subject_entity,
            &related_entity,
            fields,
            relationships,
            &field_map,
        )?;

    let required_entities: HashSet<String> =
        HashSet::from([subject_entity.clone(), bridge_entity.clone()]);
    if graph_ambiguous_physical_table_family_for_required_entities(entities, &required_entities)
        .is_some()
    {
        return None;
    }
    let joins = vec![GraphJoinStep {
        from_entity: subject_entity.clone(),
        from_field: subject_key_field.field.clone(),
        to_entity: bridge_entity.clone(),
        to_field: bridge_subject_field.field.clone(),
    }];
    let join_sql = graph_render_joins(&subject_entity, &joins, &entity_map, &field_map)?;
    let where_sql = graph_render_where(&predicates, &field_map, &entity_map)?;
    let base_entity = entity_map.get(&subject_entity)?;
    let numerator = graph_field_ref(bridge_related_field, &entity_map)?;
    let denominator = graph_field_ref(subject_key_field, &entity_map)?;
    let expr = format!("CAST(COUNT({numerator}) AS REAL) / COUNT({denominator})");
    let mut sql = format!(
        "SELECT {expr} FROM {}",
        graph_quote_ident(&base_entity.db_table)
    );
    if !join_sql.is_empty() {
        sql.push(' ');
        sql.push_str(&join_sql);
    }
    if !where_sql.is_empty() {
        sql.push_str(" WHERE ");
        sql.push_str(&where_sql);
    }
    let mut required_entity_list = required_entities.into_iter().collect::<Vec<_>>();
    required_entity_list.sort();
    Some(RuntimeQueryFrameTrace {
        schema_version: 1,
        source: "runtime_graph_query_frame_avg_related_count".to_string(),
        question: nl.to_string(),
        routed: true,
        used_for_final_sql: false,
        route_reason: "routed_average_related_count".to_string(),
        sql: Some(sql),
        projection: Some(RuntimeQueryFrameProjectionTrace {
            entity: subject_entity,
            field: Some(bridge_related_field.canonical()),
            fields: vec![
                bridge_related_field.canonical(),
                subject_key_field.canonical(),
            ],
            expression: expr,
        }),
        predicates: predicates.iter().map(graph_predicate_trace).collect(),
        required_entities: required_entity_list,
        joins: joins.iter().map(graph_join_trace).collect(),
        order_by: None,
    })
}

fn graph_prompt_requests_average_related_count(nl: &str) -> bool {
    let lower = format!(" {} ", graph_norm(nl));
    (lower.contains(" average number of ")
        || lower.contains(" avg number of ")
        || lower.contains(" mean number of "))
        && (lower.contains(" have ") || lower.contains(" has ") || lower.contains(" per "))
}

fn graph_average_related_count_target_entity(
    nl: &str,
    entities: &[EntityRow],
    subject_entity: &str,
) -> Option<String> {
    let lower = format!(" {} ", graph_norm(nl));
    let mut candidates: Vec<(usize, String)> = entities
        .iter()
        .filter(|entity| !entity.canonical_name.eq_ignore_ascii_case(subject_entity))
        .filter_map(|entity| {
            let mut best = 0usize;
            for label in graph_entity_labels_for_prompt(entity) {
                let label_norm = graph_norm(&label);
                if label_norm.is_empty() {
                    continue;
                }
                if lower.contains(&format!(" {label_norm} ")) {
                    best = best.max(label_norm.len());
                }
                let singular = label_norm.strip_suffix('s').unwrap_or(&label_norm);
                if !singular.is_empty() && lower.contains(&format!(" {singular} ")) {
                    best = best.max(singular.len());
                }
                if !label_norm.ends_with('s') {
                    let plural = format!("{label_norm}s");
                    if lower.contains(&format!(" {plural} ")) {
                        best = best.max(plural.len());
                    }
                }
            }
            (best > 0).then_some((best, entity.canonical_name.clone()))
        })
        .collect();
    candidates.sort_by(|a, b| b.0.cmp(&a.0).then_with(|| a.1.cmp(&b.1)));
    candidates.into_iter().map(|(_, entity)| entity).next()
}

fn graph_entity_labels_for_prompt(entity: &EntityRow) -> Vec<String> {
    let mut labels = vec![
        entity.canonical_name.replace('_', " "),
        entity.db_table.replace('_', " "),
    ];
    if let Some(label) = &entity.singular_label {
        labels.push(label.clone());
    }
    if let Some(label) = &entity.plural_label {
        labels.push(label.clone());
    }
    labels.sort();
    labels.dedup();
    labels
}

fn graph_entity_vocab_terms_for_prompt(
    entity: &EntityRow,
    vocabulary: &[VocabularyEntry],
) -> Vec<String> {
    graph_entity_vocab_terms_for_entity_name(&entity.canonical_name, vocabulary)
}

fn graph_entity_vocab_terms_for_entity_name(
    entity_name: &str,
    vocabulary: &[VocabularyEntry],
) -> Vec<String> {
    let mut labels = vocabulary
        .iter()
        .filter(|entry| {
            entry.canonical_kind == "entity"
                && entry.confidence >= 0.4
                && entry.canonical_value.eq_ignore_ascii_case(entity_name)
        })
        .map(|entry| entry.term.clone())
        .collect::<Vec<_>>();
    labels.sort();
    labels.dedup();
    labels
}

fn graph_related_count_bridge<'a>(
    subject_entity: &str,
    related_entity: &str,
    fields: &'a [FieldRow],
    relationships: &[RelationshipRow],
    field_map: &HashMap<String, &'a FieldRow>,
) -> Option<(String, &'a FieldRow, &'a FieldRow, &'a FieldRow)> {
    let entity_names: HashSet<&str> = fields.iter().map(|field| field.entity.as_str()).collect();
    let mut bridge_entities = entity_names
        .into_iter()
        .filter(|entity| {
            !entity.eq_ignore_ascii_case(subject_entity)
                && !entity.eq_ignore_ascii_case(related_entity)
        })
        .collect::<Vec<_>>();
    bridge_entities.sort();
    for bridge_entity in bridge_entities {
        let Some((bridge_subject_key, subject_key)) =
            graph_relationship_fields_between(bridge_entity, subject_entity, relationships)
        else {
            continue;
        };
        let Some((bridge_related_key, _related_key)) =
            graph_relationship_fields_between(bridge_entity, related_entity, relationships)
        else {
            continue;
        };
        let subject_key_field = field_map.get(&format!("{subject_entity}.{subject_key}"))?;
        let bridge_subject_field =
            field_map.get(&format!("{bridge_entity}.{bridge_subject_key}"))?;
        let bridge_related_field =
            field_map.get(&format!("{bridge_entity}.{bridge_related_key}"))?;
        return Some((
            bridge_entity.to_string(),
            *subject_key_field,
            *bridge_subject_field,
            *bridge_related_field,
        ));
    }
    None
}

fn graph_relationship_fields_between(
    left_entity: &str,
    right_entity: &str,
    relationships: &[RelationshipRow],
) -> Option<(String, String)> {
    relationships.iter().find_map(|relationship| {
        if relationship.from_entity.eq_ignore_ascii_case(left_entity)
            && relationship.to_entity.eq_ignore_ascii_case(right_entity)
        {
            Some((
                relationship.from_field.clone(),
                relationship.to_field.clone(),
            ))
        } else if relationship.to_entity.eq_ignore_ascii_case(left_entity)
            && relationship.from_entity.eq_ignore_ascii_case(right_entity)
        {
            Some((
                relationship.to_field.clone(),
                relationship.from_field.clone(),
            ))
        } else {
            None
        }
    })
}

fn graph_metric_query_frame_trace(
    nl: &str,
    entities: &[EntityRow],
    fields: &[FieldRow],
    relationships: &[RelationshipRow],
    sample_values: &[SampleValueRow],
    vocabulary: &[VocabularyEntry],
) -> Option<RuntimeQueryFrameTrace> {
    if !graph_prompt_requests_metric_ratio(nl) || graph_metric_prompt_has_unsafe_terms(nl) {
        return None;
    }
    let field_map = graph_field_map(fields);
    let entity_map = graph_entity_map(entities);
    let metric = graph_best_metric_ratio_candidate(nl, fields, vocabulary)?;
    let predicates = graph_metric_predicates(
        nl,
        metric.numerator,
        metric.denominator,
        fields,
        sample_values,
        vocabulary,
    );
    let projects_metric_value = graph_metric_value_projection_requested(
        nl,
        metric.numerator,
        metric.denominator,
        vocabulary,
    );
    let projection_field = if !projects_metric_value && graph_metric_projection_requested(nl) {
        graph_metric_projection_field(
            nl,
            metric.numerator,
            fields,
            relationships,
            vocabulary,
            &predicates,
        )
    } else {
        None
    };
    let (direction, limit) = graph_order_direction_limit(nl).unwrap_or_else(|| {
        if graph_metric_lowest_prompt(nl) {
            ("ASC".to_string(), 1)
        } else {
            ("DESC".to_string(), 1)
        }
    });
    if projection_field.is_none() && predicates.is_empty() && !graph_metric_superlative_prompt(nl) {
        return None;
    }

    let metric_expr = graph_metric_ratio_expr(metric.numerator, metric.denominator, &entity_map)?;
    let base_entity = projection_field
        .map(|field| field.entity.clone())
        .unwrap_or_else(|| metric.numerator.entity.clone());
    let projection_expr = projection_field
        .and_then(|field| graph_field_ref(field, &entity_map))
        .unwrap_or_else(|| metric_expr.clone());
    let projection = GraphQueryProjection {
        entity: base_entity.clone(),
        field: projection_field
            .map(FieldRow::canonical)
            .or_else(|| Some(metric.numerator.canonical())),
        fields: projection_field
            .map(|field| vec![field.canonical()])
            .unwrap_or_else(|| vec![metric.numerator.canonical(), metric.denominator.canonical()]),
        expr: projection_expr,
    };

    let mut required_entities: HashSet<String> = HashSet::from([
        base_entity.clone(),
        metric.numerator.entity.clone(),
        metric.denominator.entity.clone(),
    ]);
    for predicate in &predicates {
        if let Some(field) = field_map.get(&predicate.field) {
            required_entities.insert(field.entity.clone());
        }
    }
    if graph_ambiguous_physical_table_family_for_required_entities(entities, &required_entities)
        .is_some()
    {
        return None;
    }
    let joins = graph_join_plan(nl, &base_entity, &required_entities, relationships)?;
    let join_sql = graph_render_joins(&base_entity, &joins, &entity_map, &field_map)?;
    let mut where_sql = graph_render_where(&predicates, &field_map, &entity_map)?;
    if !where_sql.is_empty() {
        where_sql.push_str(" AND ");
    }
    where_sql.push_str(&metric_expr);
    where_sql.push_str(" IS NOT NULL");
    let base = entity_map.get(&base_entity)?;
    let mut sql = format!(
        "SELECT {} FROM {}",
        projection.expr,
        graph_quote_ident(&base.db_table)
    );
    if !join_sql.is_empty() {
        sql.push(' ');
        sql.push_str(&join_sql);
    }
    if !where_sql.is_empty() {
        sql.push_str(" WHERE ");
        sql.push_str(&where_sql);
    }
    sql.push_str(" ORDER BY ");
    sql.push_str(&metric_expr);
    sql.push(' ');
    sql.push_str(&direction);
    sql.push_str(" LIMIT ");
    sql.push_str(&limit.to_string());

    let mut required_entity_list: Vec<String> = required_entities.into_iter().collect();
    required_entity_list.sort();
    Some(RuntimeQueryFrameTrace {
        schema_version: 1,
        source: "runtime_graph_query_frame_metric".to_string(),
        question: nl.to_string(),
        routed: true,
        used_for_final_sql: false,
        route_reason: "routed_metric_ratio".to_string(),
        sql: Some(sql),
        projection: Some(graph_projection_trace(&projection)),
        predicates: predicates.iter().map(graph_predicate_trace).collect(),
        required_entities: required_entity_list,
        joins: joins.iter().map(graph_join_trace).collect(),
        order_by: Some(RuntimeQueryFrameOrderTrace {
            field: metric.numerator.canonical(),
            expression: metric_expr,
            direction,
            limit,
        }),
    })
}

fn graph_scalar_aggregate_query_frame_trace(
    nl: &str,
    entities: &[EntityRow],
    fields: &[FieldRow],
    relationships: &[RelationshipRow],
    sample_values: &[SampleValueRow],
    vocabulary: &[VocabularyEntry],
) -> Option<RuntimeQueryFrameTrace> {
    let lower = format!(" {} ", graph_norm(nl));
    if graph_prompt_requests_count(&lower) {
        return None;
    }
    if lower.contains(" by ")
        || graph_order_direction_limit(nl).is_some()
        || graph_prompt_requests_metric_ratio(nl)
        || graph_metric_prompt_has_unsafe_terms(nl)
    {
        return None;
    }
    let aggregate_kind = graph_aggregate_kind(&lower)?;
    let field_map = graph_field_map(fields);
    let entity_map = graph_entity_map(entities);
    let mut predicates = graph_query_predicates_with_vocab(nl, fields, sample_values, vocabulary);
    graph_merge_comparison_value_predicate(nl, fields, sample_values, vocabulary, &mut predicates);
    graph_add_best_date_window_predicate(nl, fields, sample_values, vocabulary, &mut predicates);
    if predicates.len() > 3 {
        return None;
    }
    let measure = graph_infer_aggregate_measure_field(
        nl,
        entities,
        fields,
        relationships,
        &predicates,
        vocabulary,
    )?;
    if !graph_field_looks_numeric(measure) || graph_field_looks_unsafe_id(measure) {
        return None;
    }
    let base_entity = measure.entity.clone();
    let mut required_entities: HashSet<String> = HashSet::from([base_entity.clone()]);
    for predicate in &predicates {
        let field = field_map.get(&predicate.field)?;
        required_entities.insert(field.entity.clone());
    }
    if graph_ambiguous_physical_table_family_for_required_entities(entities, &required_entities)
        .is_some()
    {
        return None;
    }
    let joins = graph_join_plan_from_base(nl, &base_entity, &required_entities, relationships)?;
    let base = entity_map.get(&base_entity)?;
    let join_sql = graph_render_joins(&base_entity, &joins, &entity_map, &field_map)?;
    let mut where_sql = graph_render_where(&predicates, &field_map, &entity_map)?;
    let measure_ref = graph_field_ref(measure, &entity_map)?;
    if aggregate_kind == "avg" {
        if !where_sql.is_empty() {
            where_sql.push_str(" AND ");
        }
        where_sql.push_str(&measure_ref);
        where_sql.push_str(" IS NOT NULL");
    }
    let alias = graph_measure_alias(aggregate_kind, measure);
    let expr = match aggregate_kind {
        "avg" => format!("AVG({measure_ref})"),
        "sum" => format!("SUM({measure_ref})"),
        _ => return None,
    };
    let mut sql = format!(
        "SELECT {expr} AS {alias} FROM {}",
        graph_quote_ident(&base.db_table)
    );
    if !join_sql.is_empty() {
        sql.push(' ');
        sql.push_str(&join_sql);
    }
    if !where_sql.is_empty() {
        sql.push_str(" WHERE ");
        sql.push_str(&where_sql);
    }
    let mut required_entity_list: Vec<String> = required_entities.into_iter().collect();
    required_entity_list.sort();
    Some(RuntimeQueryFrameTrace {
        schema_version: 1,
        source: "runtime_graph_query_frame_scalar_aggregate".to_string(),
        question: nl.to_string(),
        routed: true,
        used_for_final_sql: false,
        route_reason: "routed_scalar_aggregate".to_string(),
        sql: Some(sql),
        projection: Some(RuntimeQueryFrameProjectionTrace {
            entity: base_entity,
            field: Some(measure.canonical()),
            fields: Vec::new(),
            expression: expr,
        }),
        predicates: predicates.iter().map(graph_predicate_trace).collect(),
        required_entities: required_entity_list,
        joins: joins.iter().map(graph_join_trace).collect(),
        order_by: None,
    })
}

fn graph_prompt_requests_metric_ratio(nl: &str) -> bool {
    let tokens = graph_name_tokens(nl);
    ["rate", "ratio", "percentage", "percent", "share"]
        .iter()
        .any(|token| tokens.contains(*token))
}

fn graph_prompt_requests_count(lower_nl: &str) -> bool {
    lower_nl.contains(" how many ")
        || lower_nl.contains(" number of ")
        || lower_nl.contains(" no of ")
        || lower_nl.contains(" no. of ")
        || lower_nl.contains(" count of ")
        || lower_nl.starts_with(" count ")
}

fn graph_metric_prompt_has_unsafe_terms(nl: &str) -> bool {
    let lower = format!(" {} ", nl.to_ascii_lowercase().replace('\n', " "));
    if lower.contains(" by ") && graph_order_direction_limit(nl).is_none() {
        return true;
    }
    [
        " or ",
        " between ",
        " difference ",
        " above average ",
        " below average ",
    ]
    .iter()
    .any(|needle| lower.contains(needle))
}

fn graph_metric_superlative_prompt(nl: &str) -> bool {
    graph_order_direction_limit(nl).is_some()
}

fn graph_metric_lowest_prompt(nl: &str) -> bool {
    graph_order_direction_limit(nl)
        .map(|(direction, _)| direction == "ASC")
        .unwrap_or(false)
}

fn graph_metric_value_projection_requested(
    nl: &str,
    numerator: &FieldRow,
    denominator: &FieldRow,
    vocabulary: &[VocabularyEntry],
) -> bool {
    let terms = runtime_explicit_projection_terms(nl);
    if terms.is_empty() {
        return false;
    }
    let numerator_tokens = graph_metric_field_tokens(numerator, vocabulary);
    let denominator_tokens = graph_metric_field_tokens(denominator, vocabulary);
    terms.iter().any(|term| {
        let term_tokens = graph_metric_query_tokens(term);
        graph_metric_field_mentions_percent(&term_tokens)
            && (numerator_tokens.intersection(&term_tokens).count()
                + denominator_tokens.intersection(&term_tokens).count())
                > 0
    })
}

fn graph_best_metric_ratio_candidate<'a>(
    nl: &str,
    fields: &'a [FieldRow],
    vocabulary: &[VocabularyEntry],
) -> Option<GraphMetricRatioCandidate<'a>> {
    let query_tokens = graph_metric_query_tokens(nl);
    let mut candidates = Vec::new();
    for numerator in fields {
        if !graph_metric_numeric_measure_candidate(numerator) {
            continue;
        }
        let numerator_tokens = graph_metric_field_tokens(numerator, vocabulary);
        let numerator_family = graph_metric_numerator_family_score(&numerator_tokens);
        if numerator_family <= 0.0 {
            continue;
        }
        for denominator in fields {
            if numerator.canonical() == denominator.canonical()
                || !numerator.entity.eq_ignore_ascii_case(&denominator.entity)
                || !graph_metric_numeric_measure_candidate(denominator)
            {
                continue;
            }
            let denominator_tokens = graph_metric_field_tokens(denominator, vocabulary);
            let denominator_family = graph_metric_denominator_family_score(&denominator_tokens);
            if denominator_family <= 0.0
                || graph_metric_denominator_has_numerator_role(&denominator_tokens)
            {
                continue;
            }
            let numerator_overlap = numerator_tokens.intersection(&query_tokens).count() as f32;
            let denominator_overlap = denominator_tokens.intersection(&query_tokens).count() as f32;
            let shared_specific =
                graph_metric_shared_specific_tokens(&numerator_tokens, &denominator_tokens);
            let shared_query_specific = shared_specific
                .iter()
                .filter(|token| query_tokens.contains(*token))
                .count() as f32;
            let mut score = numerator_overlap * 3.0
                + denominator_overlap
                + numerator_family
                + denominator_family
                + shared_query_specific * 3.0
                + shared_specific.len() as f32 * 0.5;
            if graph_metric_field_mentions_percent(&numerator_tokens) {
                score -= 4.0;
            }
            if graph_metric_query_mentions_entity(nl, &numerator.entity) {
                score += 1.0;
            }
            if score >= 6.0 {
                candidates.push(GraphMetricRatioCandidate {
                    numerator,
                    denominator,
                    score,
                });
            }
        }
    }
    candidates.sort_by(|a, b| {
        b.score
            .partial_cmp(&a.score)
            .unwrap_or(std::cmp::Ordering::Equal)
            .then_with(|| a.numerator.canonical().cmp(&b.numerator.canonical()))
            .then_with(|| a.denominator.canonical().cmp(&b.denominator.canonical()))
    });
    candidates.into_iter().next()
}

fn graph_metric_numeric_measure_candidate(field: &FieldRow) -> bool {
    graph_field_looks_numeric(field) && !graph_field_looks_unsafe_id(field)
}

fn graph_metric_query_tokens(nl: &str) -> HashSet<String> {
    let mut tokens = graph_schema_match_tokens(nl);
    tokens.extend(graph_metric_structured_alias_tokens(nl));
    if tokens.contains("excellence") || tokens.contains("excellent") {
        tokens.extend([
            "greater".to_string(),
            "equal".to_string(),
            "score".to_string(),
            "scores".to_string(),
            "high".to_string(),
        ]);
    }
    if graph_metric_query_mentions_population_subject(&tokens) {
        tokens.extend([
            "population".to_string(),
            "person".to_string(),
            "people".to_string(),
        ]);
    }
    tokens
}

fn graph_metric_query_mentions_population_subject(tokens: &HashSet<String>) -> bool {
    [
        "applicant",
        "applicants",
        "client",
        "clients",
        "customer",
        "customers",
        "employee",
        "employees",
        "member",
        "members",
        "patient",
        "patients",
        "people",
        "person",
        "student",
        "students",
        "subscriber",
        "subscribers",
        "user",
        "users",
    ]
    .iter()
    .any(|token| tokens.contains(*token))
}

fn graph_metric_field_tokens(field: &FieldRow, vocabulary: &[VocabularyEntry]) -> HashSet<String> {
    let mut tokens = graph_field_tokens_with_vocab(field, vocabulary);
    tokens.extend(graph_metric_structured_alias_tokens(&field.field));
    tokens.extend(graph_metric_structured_alias_tokens(&field.db_column));
    if let Some(label) = &field.display_label {
        tokens.extend(graph_metric_structured_alias_tokens(label));
    }
    let compact = graph_compact_field_name(field);
    if compact.contains("k12") {
        tokens.insert("k12".to_string());
    }
    if compact.contains("ages517") || compact.contains("age517") {
        tokens.insert("ages517".to_string());
    }
    if compact.contains("enroll") {
        tokens.extend([
            "population".to_string(),
            "person".to_string(),
            "people".to_string(),
        ]);
    }
    if compact.contains("numge") {
        tokens.extend([
            "number".to_string(),
            "count".to_string(),
            "greater".to_string(),
            "equal".to_string(),
        ]);
    }
    if compact.contains("numtst") || compact.contains("tsttak") {
        tokens.extend([
            "number".to_string(),
            "test".to_string(),
            "takers".to_string(),
        ]);
    }
    tokens.retain(|token| !graph_projection_order_stopword(token));
    tokens
}

fn graph_metric_structured_alias_tokens(text: &str) -> HashSet<String> {
    let lower = text.to_ascii_lowercase();
    let compact: String = lower
        .chars()
        .filter(|ch| ch.is_ascii_alphanumeric())
        .collect();
    let mut tokens = HashSet::new();
    if compact.contains("k12")
        || lower.contains("grades 1 through 12")
        || lower.contains("grades 1-12")
        || lower.contains("grades 1 to 12")
    {
        tokens.insert("k12".to_string());
        tokens.insert("12".to_string());
    }
    if compact.contains("ages517")
        || lower.contains("ages 5-17")
        || lower.contains("ages 5 to 17")
        || lower.contains("ages of 5 and 17")
        || lower.contains("between the ages of 5 and 17")
    {
        tokens.insert("ages517".to_string());
        tokens.insert("ages".to_string());
        tokens.insert("17".to_string());
    }
    tokens
}

fn graph_metric_numerator_family_score(tokens: &HashSet<String>) -> f32 {
    let mut score: f32 = 0.0;
    for token in [
        "count",
        "num",
        "number",
        "free",
        "eligible",
        "converted",
        "success",
        "won",
        "completed",
        "greater",
        "equal",
        "paid",
        "breach",
        "breached",
    ] {
        if tokens.contains(token) {
            score += 1.0;
        }
    }
    score.min(4.0)
}

fn graph_metric_denominator_family_score(tokens: &HashSet<String>) -> f32 {
    let mut score: f32 = 0.0;
    for token in [
        "enrollment",
        "total",
        "population",
        "count",
        "number",
        "takers",
        "users",
        "customers",
        "leads",
        "orders",
        "visits",
        "attempts",
    ] {
        if tokens.contains(token) {
            score += 1.0;
        }
    }
    score.min(4.0)
}

fn graph_metric_denominator_has_numerator_role(tokens: &HashSet<String>) -> bool {
    let numerator_role = [
        "free",
        "eligible",
        "converted",
        "success",
        "won",
        "completed",
        "greater",
        "equal",
        "paid",
        "breach",
        "breached",
    ]
    .iter()
    .any(|token| tokens.contains(*token));
    let total_role = ["total", "all", "overall", "population", "enrollment"]
        .iter()
        .any(|token| tokens.contains(*token));
    numerator_role && !total_role
}

fn graph_metric_shared_specific_tokens(
    left: &HashSet<String>,
    right: &HashSet<String>,
) -> Vec<String> {
    let generic = [
        "count", "number", "num", "total", "test", "taker", "takers", "score", "scores",
    ];
    left.intersection(right)
        .filter(|token| token.len() >= 2 && !generic.contains(&token.as_str()))
        .cloned()
        .collect()
}

fn graph_metric_field_mentions_percent(tokens: &HashSet<String>) -> bool {
    ["percent", "percentage", "pct", "rate", "ratio"]
        .iter()
        .any(|token| tokens.contains(*token))
}

fn graph_metric_query_mentions_entity(nl: &str, entity: &str) -> bool {
    let query_tokens = graph_schema_match_tokens(nl);
    !graph_name_tokens(entity).is_disjoint(&query_tokens)
}

