fn graph_metric_projection_field<'a>(
    nl: &str,
    numerator: &FieldRow,
    fields: &'a [FieldRow],
    relationships: &[RelationshipRow],
    vocabulary: &[VocabularyEntry],
    predicates: &[GraphQueryPredicate],
) -> Option<&'a FieldRow> {
    let lower = nl.to_ascii_lowercase();
    let q_tokens = graph_schema_match_tokens(nl);
    let predicate_fields: HashSet<&str> = predicates
        .iter()
        .map(|predicate| predicate.field.as_str())
        .collect();
    let mut candidates: Vec<(f32, &FieldRow)> = fields
        .iter()
        .filter(|field| !predicate_fields.contains(field.canonical().as_str()))
        .filter(|field| {
            !field
                .canonical()
                .eq_ignore_ascii_case(&numerator.canonical())
        })
        .filter(|field| {
            !graph_field_looks_unsafe_id(field) && graph_field_looks_display_field(field)
        })
        .filter(|field| {
            field.entity.eq_ignore_ascii_case(&numerator.entity)
                || graph_entities_are_related(&field.entity, &numerator.entity, relationships)
        })
        .filter_map(|field| {
            let tokens = graph_field_tokens_with_vocab(field, vocabulary);
            let score = tokens.intersection(&q_tokens).count() as f32 * 2.0
                + graph_projection_phrase_bonus(&lower, field)
                + graph_field_vocab_phrase_bonus(nl, field, vocabulary);
            (score >= 2.0).then_some((score, field))
        })
        .collect();
    candidates.sort_by(|a, b| {
        b.0.partial_cmp(&a.0)
            .unwrap_or(std::cmp::Ordering::Equal)
            .then_with(|| a.1.canonical().cmp(&b.1.canonical()))
    });
    candidates.into_iter().map(|(_, field)| field).next()
}

fn graph_metric_predicates(
    nl: &str,
    numerator: &FieldRow,
    denominator: &FieldRow,
    fields: &[FieldRow],
    sample_values: &[SampleValueRow],
    vocabulary: &[VocabularyEntry],
) -> Vec<GraphQueryPredicate> {
    let field_map = graph_field_map(fields);
    let mut predicates = graph_query_predicates_with_vocab(nl, fields, sample_values, vocabulary)
        .into_iter()
        .filter(|predicate| {
            predicate.field != numerator.canonical()
                && predicate.field != denominator.canonical()
                && field_map.get(&predicate.field).is_some_and(|field| {
                    let predicate_trace = graph_predicate_trace(predicate);
                    !graph_field_looks_numeric(field)
                        && graph_predicate_value_is_grounded_with_vocab(
                            nl,
                            &predicate_trace,
                            field,
                            sample_values,
                            vocabulary,
                        )
                        && !graph_predicate_value_has_span_role_conflict(
                            nl,
                            &predicate_trace,
                            field,
                            fields,
                        )
                })
        })
        .collect::<Vec<_>>();
    graph_metric_prefer_base_entity_value_predicates(
        &mut predicates,
        numerator,
        denominator,
        fields,
        sample_values,
        vocabulary,
    );
    predicates.sort_by(|a, b| {
        let a_metric_entity = field_map
            .get(&a.field)
            .is_some_and(|field| field.entity == numerator.entity);
        let b_metric_entity = field_map
            .get(&b.field)
            .is_some_and(|field| field.entity == numerator.entity);
        b_metric_entity
            .cmp(&a_metric_entity)
            .then_with(|| a.field.cmp(&b.field))
            .then_with(|| a.value.cmp(&b.value))
    });
    predicates.dedup_by(|a, b| a.field == b.field && a.value == b.value);
    predicates.truncate(3);
    predicates
}

fn graph_metric_prefer_base_entity_value_predicates(
    predicates: &mut [GraphQueryPredicate],
    numerator: &FieldRow,
    denominator: &FieldRow,
    fields: &[FieldRow],
    sample_values: &[SampleValueRow],
    vocabulary: &[VocabularyEntry],
) {
    let field_map = graph_field_map(fields);
    for predicate in predicates {
        let Some(source_field) = field_map.get(&predicate.field) else {
            continue;
        };
        if source_field.entity.eq_ignore_ascii_case(&numerator.entity)
            || graph_is_plain_number(&predicate.value)
        {
            continue;
        }
        let Some(base_field) = graph_metric_base_entity_value_field(
            &predicate.value,
            source_field,
            numerator,
            denominator,
            fields,
            sample_values,
            vocabulary,
        ) else {
            continue;
        };
        predicate.field = base_field.canonical();
    }
}

fn graph_metric_base_entity_value_field<'a>(
    value: &str,
    source_field: &FieldRow,
    numerator: &FieldRow,
    denominator: &FieldRow,
    fields: &'a [FieldRow],
    sample_values: &[SampleValueRow],
    vocabulary: &[VocabularyEntry],
) -> Option<&'a FieldRow> {
    let value_norm = graph_norm(value);
    if value_norm.len() < 2 {
        return None;
    }
    let sample_map: HashMap<String, &SampleValueRow> = sample_values
        .iter()
        .map(|row| (row.field_canonical.to_ascii_lowercase(), row))
        .collect();
    let source_tokens = graph_field_tokens_with_vocab(source_field, vocabulary);
    let mut candidates = fields
        .iter()
        .filter(|field| field.entity.eq_ignore_ascii_case(&numerator.entity))
        .filter(|field| {
            !field
                .canonical()
                .eq_ignore_ascii_case(&numerator.canonical())
                && !field
                    .canonical()
                    .eq_ignore_ascii_case(&denominator.canonical())
                && !graph_field_looks_numeric(field)
                && !graph_field_looks_unsafe_id(field)
        })
        .filter(|field| {
            sample_map
                .get(&field.canonical().to_ascii_lowercase())
                .is_some_and(|row| {
                    row.examples
                        .iter()
                        .map(|sample| graph_norm(sample))
                        .any(|sample_norm| sample_norm == value_norm)
                })
        })
        .map(|field| {
            let tokens = graph_field_tokens_with_vocab(field, vocabulary);
            let score = tokens.intersection(&source_tokens).count();
            (score, field)
        })
        .filter(|(score, _)| *score > 0)
        .collect::<Vec<_>>();
    candidates.sort_by(|left, right| {
        right
            .0
            .cmp(&left.0)
            .then_with(|| left.1.canonical().cmp(&right.1.canonical()))
    });
    candidates.into_iter().map(|(_, field)| field).next()
}

fn graph_metric_ratio_expr(
    numerator: &FieldRow,
    denominator: &FieldRow,
    entity_map: &HashMap<String, &EntityRow>,
) -> Option<String> {
    Some(format!(
        "CAST({} AS REAL) / {}",
        graph_field_ref(numerator, entity_map)?,
        graph_field_ref(denominator, entity_map)?
    ))
}

fn graph_dimension_measure_rank_prompt(
    nl: &str,
    projection_field: &FieldRow,
    order_field: &FieldRow,
) -> bool {
    if graph_order_direction_limit(nl).is_none() {
        return false;
    }
    let lower = format!(" {} ", nl.to_ascii_lowercase());
    let rank_language = [
        " by ",
        " highest ",
        " lowest ",
        " top ",
        " bottom ",
        " largest ",
        " smallest ",
        " most ",
        " least ",
    ]
    .iter()
    .any(|needle| lower.contains(needle));
    if !rank_language {
        return false;
    }
    let nl_tokens = graph_tokens(nl);
    let projection_tokens = graph_field_tokens(projection_field);
    let order_tokens = graph_field_tokens(order_field);
    let projection_entity_tokens = graph_name_tokens(&projection_field.entity);
    let order_entity_tokens = graph_name_tokens(&order_field.entity);
    let mentions_projection = !projection_tokens.is_disjoint(&nl_tokens)
        || !projection_entity_tokens.is_disjoint(&nl_tokens);
    let mentions_measure =
        !order_tokens.is_disjoint(&nl_tokens) || !order_entity_tokens.is_disjoint(&nl_tokens);
    mentions_projection && mentions_measure
}

fn graph_measure_alias(prefix: &str, field: &FieldRow) -> String {
    let suffix = graph_safe_sql_alias(&field.db_column);
    if suffix.is_empty() {
        prefix.to_string()
    } else {
        format!("{prefix}_{suffix}")
    }
}

fn graph_safe_sql_alias(value: &str) -> String {
    let mut out = String::new();
    for ch in value.chars() {
        if ch.is_ascii_alphanumeric() {
            out.push(ch.to_ascii_lowercase());
        } else if ch == '_' && !out.ends_with('_') {
            out.push('_');
        }
    }
    let trimmed = out.trim_matches('_').to_string();
    if trimmed.chars().next().is_some_and(|ch| ch.is_ascii_digit()) {
        format!("measure_{trimmed}")
    } else {
        trimmed
    }
}

fn graph_projection_trace(projection: &GraphQueryProjection) -> RuntimeQueryFrameProjectionTrace {
    RuntimeQueryFrameProjectionTrace {
        entity: projection.entity.clone(),
        field: projection.field.clone(),
        fields: projection.fields.clone(),
        expression: projection.expr.clone(),
    }
}

fn graph_predicate_trace(predicate: &GraphQueryPredicate) -> RuntimeQueryFramePredicateTrace {
    RuntimeQueryFramePredicateTrace {
        field: predicate.field.clone(),
        value: predicate.value.clone(),
        operator: predicate.operator.clone(),
    }
}

fn graph_join_trace(step: &GraphJoinStep) -> RuntimeQueryFrameJoinTrace {
    RuntimeQueryFrameJoinTrace {
        from_entity: step.from_entity.clone(),
        from_field: step.from_field.clone(),
        to_entity: step.to_entity.clone(),
        to_field: step.to_field.clone(),
    }
}

fn graph_order_trace(order: &GraphQueryOrder) -> RuntimeQueryFrameOrderTrace {
    RuntimeQueryFrameOrderTrace {
        field: order.field.clone(),
        expression: order.expr.clone(),
        direction: order.direction.clone(),
        limit: order.limit,
    }
}

#[derive(Clone, Debug)]
struct GraphPhysicalTableFamily {
    base: String,
    members: HashSet<String>,
}

fn graph_query_mentions_ambiguous_physical_table_family(nl: &str, entities: &[EntityRow]) -> bool {
    let tokens = graph_tokens(nl);
    let nl_norm = graph_norm(nl);
    graph_ambiguous_physical_table_families(entities)
        .iter()
        .any(|family| {
            graph_query_mentions_physical_family_base(&nl_norm, &tokens, &family.base)
                && !graph_query_mentions_specific_non_family_entity(&nl_norm, family, entities)
        })
}

fn graph_query_mentions_physical_family_base(
    nl_norm: &str,
    tokens: &HashSet<String>,
    base: &str,
) -> bool {
    let base_phrase = graph_norm(&base.replace('_', " "));
    if base_phrase.len() >= 2 && graph_norm_contains(nl_norm, &base_phrase) {
        return true;
    }
    let base_tokens = graph_name_tokens(base);
    !base_tokens.is_empty() && base_tokens.iter().all(|token| tokens.contains(token))
}

fn graph_query_mentions_specific_non_family_entity(
    nl_norm: &str,
    family: &GraphPhysicalTableFamily,
    entities: &[EntityRow],
) -> bool {
    let base_phrase = graph_norm(&family.base.replace('_', " "));
    let base_tokens = graph_name_tokens(&family.base);
    entities.iter().any(|entity| {
        if family
            .members
            .contains(&entity.canonical_name.to_ascii_lowercase())
        {
            return false;
        }
        let phrases = [
            entity.canonical_name.as_str(),
            entity.db_table.as_str(),
            entity.singular_label.as_deref().unwrap_or(""),
            entity.plural_label.as_deref().unwrap_or(""),
        ];
        phrases.iter().any(|phrase| {
            let norm = graph_norm(&phrase.replace('_', " "));
            if norm.len() <= base_phrase.len() || !graph_norm_contains(nl_norm, &norm) {
                return false;
            }
            let phrase_tokens = graph_tokens(&norm);
            !base_tokens.is_empty() && base_tokens.is_subset(&phrase_tokens)
        })
    })
}

fn graph_ambiguous_physical_table_family_for_required_entities(
    entities: &[EntityRow],
    required_entities: &HashSet<String>,
) -> Option<GraphPhysicalTableFamily> {
    let required: HashSet<String> = required_entities
        .iter()
        .map(|entity| entity.to_ascii_lowercase())
        .collect();
    graph_ambiguous_physical_table_families(entities)
        .into_iter()
        .find(|family| !family.members.is_disjoint(&required))
}

fn graph_ambiguous_physical_table_families(
    entities: &[EntityRow],
) -> Vec<GraphPhysicalTableFamily> {
    semsql_graph::read::physical_table_families_from_entities(entities)
        .into_iter()
        .map(|family| GraphPhysicalTableFamily {
            base: family.base_table,
            members: family
                .members
                .into_iter()
                .map(|member| member.entity.to_ascii_lowercase())
                .collect(),
        })
        .collect()
}

fn graph_query_looks_complex(nl: &str) -> bool {
    let lower = nl.to_ascii_lowercase();
    [
        " ratio",
        " difference",
        " rate ",
        " average of all",
        " above average",
        " below average",
        " or ",
        " between ",
        " most common",
        " rank ",
        " ranked ",
        " communication address",
        " mailing ",
    ]
    .iter()
    .any(|needle| lower.contains(needle))
        || ((lower.contains(" percentage") || lower.contains(" percent "))
            && !(graph_order_direction_limit(nl).is_some() && lower.contains(" by ")))
}

