fn graph_runtime_query_frame_final_sql_allowed_with_vocab(
    model_backed_run: bool,
    entities: &[EntityRow],
    fields: &[FieldRow],
    sample_values: &[SampleValueRow],
    vocabulary: &[VocabularyEntry],
    nl: &str,
    trace: &RuntimeQueryFrameTrace,
) -> bool {
    if graph_prompt_should_never_model_fallback(nl, fields)
        && !matches!(
            trace.source.as_str(),
            "runtime_graph_query_frame_grouped_ratio"
                | "runtime_graph_query_frame_conditional_rate"
                | "runtime_graph_query_frame_grouped_duration"
                | "runtime_graph_query_frame_anti_join_temporal"
        )
    {
        return false;
    }
    if graph_generic_route_has_lifecycle_event_ambiguity(nl, trace, fields, sample_values) {
        return false;
    }
    if !model_backed_run {
        return graph_runtime_query_frame_ops_safe(nl, trace, fields)
            || graph_runtime_query_frame_rank_safe(nl, trace, fields, sample_values, vocabulary)
            || graph_runtime_query_frame_attribute_safe(
                nl,
                trace,
                fields,
                sample_values,
                vocabulary,
            )
            || graph_runtime_query_frame_person_event_safe(
                nl,
                trace,
                fields,
                sample_values,
                vocabulary,
            )
            || graph_runtime_query_frame_avg_related_count_safe(
                nl,
                trace,
                fields,
                sample_values,
                vocabulary,
            )
            || graph_runtime_query_frame_grouped_aggregate_safe(
                nl,
                trace,
                fields,
                sample_values,
                vocabulary,
            )
            || graph_runtime_query_frame_grouped_ratio_safe(
                nl,
                trace,
                fields,
                sample_values,
                vocabulary,
            )
            || graph_runtime_query_frame_conditional_rate_safe(
                nl,
                trace,
                fields,
                sample_values,
                vocabulary,
            )
            || graph_runtime_query_frame_grouped_duration_safe(
                nl,
                trace,
                fields,
                sample_values,
                vocabulary,
            )
            || graph_runtime_query_frame_anti_join_temporal_safe(
                nl,
                trace,
                fields,
                sample_values,
                vocabulary,
            )
            || graph_runtime_query_frame_metric_safe(nl, trace, fields, sample_values, vocabulary)
            || graph_runtime_query_frame_scalar_aggregate_safe(
                nl,
                trace,
                fields,
                sample_values,
                vocabulary,
            )
            || graph_runtime_query_frame_safe_lookup(nl, trace)
            || graph_runtime_query_frame_count_safe(nl, trace, fields, sample_values, vocabulary)
            || graph_runtime_query_frame_display_lookup_safe(
                nl,
                trace,
                fields,
                sample_values,
                vocabulary,
            )
            || graph_runtime_query_frame_generic_safe_with_vocab(
                nl,
                trace,
                fields,
                sample_values,
                vocabulary,
            );
    }
    let _ = entities;
    graph_runtime_query_frame_ops_safe(nl, trace, fields)
        || graph_runtime_query_frame_rank_safe(nl, trace, fields, sample_values, vocabulary)
        || graph_runtime_query_frame_attribute_safe(nl, trace, fields, sample_values, vocabulary)
        || graph_runtime_query_frame_person_event_safe(nl, trace, fields, sample_values, vocabulary)
        || graph_runtime_query_frame_avg_related_count_safe(
            nl,
            trace,
            fields,
            sample_values,
            vocabulary,
        )
        || graph_runtime_query_frame_grouped_aggregate_safe(
            nl,
            trace,
            fields,
            sample_values,
            vocabulary,
        )
        || graph_runtime_query_frame_grouped_ratio_safe(
            nl,
            trace,
            fields,
            sample_values,
            vocabulary,
        )
        || graph_runtime_query_frame_conditional_rate_safe(
            nl,
            trace,
            fields,
            sample_values,
            vocabulary,
        )
        || graph_runtime_query_frame_grouped_duration_safe(
            nl,
            trace,
            fields,
            sample_values,
            vocabulary,
        )
        || graph_runtime_query_frame_anti_join_temporal_safe(
            nl,
            trace,
            fields,
            sample_values,
            vocabulary,
        )
        || graph_runtime_query_frame_metric_safe(nl, trace, fields, sample_values, vocabulary)
        || graph_runtime_query_frame_scalar_aggregate_safe(
            nl,
            trace,
            fields,
            sample_values,
            vocabulary,
        )
        || graph_runtime_query_frame_safe_lookup(nl, trace)
        || graph_runtime_query_frame_count_safe(nl, trace, fields, sample_values, vocabulary)
        || graph_runtime_query_frame_display_lookup_safe(
            nl,
            trace,
            fields,
            sample_values,
            vocabulary,
        )
        || graph_runtime_query_frame_generic_safe_with_vocab(
            nl,
            trace,
            fields,
            sample_values,
            vocabulary,
        )
}

fn graph_runtime_query_frame_ops_safe(
    nl: &str,
    trace: &RuntimeQueryFrameTrace,
    fields: &[FieldRow],
) -> bool {
    trace.routed
        && trace.source == "runtime_graph_query_frame_ops"
        && trace.sql.is_some()
        && !graph_prompt_should_never_model_fallback(nl, fields)
}

fn graph_runtime_query_frame_safe_lookup(nl: &str, trace: &RuntimeQueryFrameTrace) -> bool {
    let _ = (nl, trace);
    false
}

fn graph_runtime_query_frame_count_safe(
    nl: &str,
    trace: &RuntimeQueryFrameTrace,
    fields: &[FieldRow],
    sample_values: &[SampleValueRow],
    vocabulary: &[VocabularyEntry],
) -> bool {
    if !trace.routed
        || trace.sql.is_none()
        || trace.joins.len() > 2
        || trace.order_by.is_some()
        || trace.predicates.is_empty()
        || trace.predicates.len() > 3
        || graph_generic_route_has_unsafe_terms(nl, trace)
        || graph_trace_missing_group_for_by_prompt(nl, trace)
    {
        return false;
    }
    let Some(projection) = &trace.projection else {
        return false;
    };
    if projection.field.is_some()
        || !projection.fields.is_empty()
        || !projection.expression.eq_ignore_ascii_case("COUNT(*)")
    {
        return false;
    }
    graph_trace_predicates_are_grounded(nl, trace, fields, sample_values, vocabulary)
}

fn graph_runtime_query_frame_display_lookup_safe(
    nl: &str,
    trace: &RuntimeQueryFrameTrace,
    fields: &[FieldRow],
    sample_values: &[SampleValueRow],
    vocabulary: &[VocabularyEntry],
) -> bool {
    if !trace.routed
        || trace.sql.is_none()
        || trace.joins.len() > 2
        || trace.order_by.is_some()
        || trace.predicates.is_empty()
        || trace.predicates.len() > 2
        || graph_generic_route_has_unsafe_terms(nl, trace)
        || graph_trace_missing_group_for_by_prompt(nl, trace)
    {
        return false;
    }
    let Some(projection) = &trace.projection else {
        return false;
    };
    let field_map = graph_field_map(fields);
    let projection_fields = if projection.fields.is_empty() {
        projection
            .field
            .as_ref()
            .map(|field| vec![field.clone()])
            .unwrap_or_default()
    } else {
        projection.fields.clone()
    };
    if projection_fields.is_empty()
        || projection_fields.len() > 3
        || projection_fields.iter().any(|field_key| {
            !field_map.get(field_key).is_some_and(|field| {
                graph_field_looks_display_field(field) && !graph_field_looks_unsafe_id(field)
            })
        })
    {
        return false;
    }
    graph_trace_predicates_are_grounded(nl, trace, fields, sample_values, vocabulary)
}

fn graph_trace_missing_group_for_by_prompt(nl: &str, trace: &RuntimeQueryFrameTrace) -> bool {
    let lower = format!(" {} ", nl.to_ascii_lowercase().replace('\n', " "));
    let sql_lower = trace
        .sql
        .as_deref()
        .unwrap_or_default()
        .to_ascii_lowercase();
    lower.contains(" by ")
        && trace.order_by.is_none()
        && !sql_lower.contains(" group by ")
        && !lower.contains(" owned by ")
        && !lower.contains(" managed by ")
        && !lower.contains(" created by ")
        && !lower.contains(" assigned by ")
}

fn graph_trace_predicates_are_grounded(
    nl: &str,
    trace: &RuntimeQueryFrameTrace,
    fields: &[FieldRow],
    sample_values: &[SampleValueRow],
    vocabulary: &[VocabularyEntry],
) -> bool {
    let field_map = graph_field_map(fields);
    trace.predicates.iter().all(|predicate| {
        let Some(field) = field_map.get(&predicate.field) else {
            return false;
        };
        let grounded = graph_predicate_value_is_grounded_with_vocab(
            nl,
            predicate,
            field,
            sample_values,
            vocabulary,
        );
        if !grounded {
            return false;
        }
        let numeric_comparison = graph_field_looks_numeric(field)
            && matches!(predicate.operator.as_str(), ">" | "<" | ">=" | "<=");
        let date_range = graph_field_looks_date_like(field) && predicate.operator == "range";
        let date_comparison = graph_field_looks_date_like(field)
            && matches!(predicate.operator.as_str(), ">" | "<" | ">=" | "<=");
        predicate.operator == "=" || numeric_comparison || date_range || date_comparison
    })
}

fn graph_runtime_query_frame_generic_safe_with_vocab(
    nl: &str,
    trace: &RuntimeQueryFrameTrace,
    fields: &[FieldRow],
    sample_values: &[SampleValueRow],
    vocabulary: &[VocabularyEntry],
) -> bool {
    if !trace.routed || trace.predicates.len() > 3 {
        return false;
    }
    if trace.predicates.is_empty() && trace.order_by.is_none() {
        return false;
    }
    if trace.joins.len() > 3 || graph_generic_route_has_unsafe_terms(nl, trace) {
        return false;
    }
    if graph_generic_route_has_lifecycle_event_ambiguity(nl, trace, fields, sample_values) {
        return false;
    }
    let lower = format!(" {} ", nl.to_ascii_lowercase().replace('\n', " "));
    let sql_lower = trace
        .sql
        .as_deref()
        .unwrap_or_default()
        .to_ascii_lowercase();
    if lower.contains(" by ")
        && trace.order_by.is_none()
        && !sql_lower.contains(" group by ")
        && !lower.contains(" owned by ")
        && !lower.contains(" managed by ")
        && !lower.contains(" created by ")
        && !lower.contains(" assigned by ")
    {
        return false;
    }
    if trace.order_by.is_none()
        && runtime_prompt_requests_time_series_group_dimension(&lower)
        && !sql_lower.contains(" group by ")
    {
        return false;
    }
    let field_map = graph_field_map(fields);
    for predicate in &trace.predicates {
        let Some(field) = field_map.get(&predicate.field) else {
            return false;
        };
        let value_is_grounded = graph_predicate_value_is_grounded_with_vocab(
            nl,
            predicate,
            field,
            sample_values,
            vocabulary,
        );
        if graph_predicate_value_has_span_role_conflict(nl, predicate, field, fields) {
            return false;
        }
        let numeric_comparison = graph_field_looks_numeric(field)
            && matches!(predicate.operator.as_str(), ">" | "<" | ">=" | "<=");
        let date_range = graph_field_looks_date_like(field)
            && predicate.operator == "range"
            && value_is_grounded;
        let date_comparison = graph_field_looks_date_like(field)
            && matches!(predicate.operator.as_str(), ">" | "<" | ">=" | "<=")
            && value_is_grounded;
        let source_grounded_not_equal = predicate.operator == "!=" && value_is_grounded;
        if predicate.operator != "="
            && !numeric_comparison
            && !date_range
            && !date_comparison
            && !source_grounded_not_equal
        {
            return false;
        }
        if !value_is_grounded {
            return false;
        }
    }
    let Some(projection) = &trace.projection else {
        return false;
    };
    if !graph_projection_is_generic_safe_with_vocab(nl, projection, fields, vocabulary) {
        return false;
    }
    if let Some(order) = &trace.order_by {
        let Some(order_field) = field_map.get(&order.field) else {
            return false;
        };
        if order.limit > 20 {
            return false;
        }
        if !(graph_field_looks_numeric(order_field) || graph_field_looks_date_like(order_field)) {
            return false;
        }
    }
    true
}

fn graph_runtime_query_frame_metric_safe(
    nl: &str,
    trace: &RuntimeQueryFrameTrace,
    fields: &[FieldRow],
    sample_values: &[SampleValueRow],
    vocabulary: &[VocabularyEntry],
) -> bool {
    if !trace.routed
        || trace.source != "runtime_graph_query_frame_metric"
        || trace.sql.is_none()
        || trace.joins.len() > 3
        || graph_prompt_should_never_model_fallback(nl, fields)
    {
        return false;
    }
    let Some(projection) = &trace.projection else {
        return false;
    };
    if projection.expression.is_empty() || trace.order_by.is_none() {
        return false;
    }
    let field_map = graph_field_map(fields);
    for predicate in &trace.predicates {
        let Some(field) = field_map.get(&predicate.field) else {
            return false;
        };
        let numeric_comparison = graph_field_looks_numeric(field)
            && matches!(predicate.operator.as_str(), ">" | "<" | ">=" | "<=");
        if graph_predicate_value_has_span_role_conflict(nl, predicate, field, fields)
            || (!numeric_comparison
                && !graph_predicate_value_is_grounded_with_vocab(
                    nl,
                    predicate,
                    field,
                    sample_values,
                    vocabulary,
                ))
        {
            return false;
        }
    }
    true
}

fn graph_runtime_query_frame_scalar_aggregate_safe(
    nl: &str,
    trace: &RuntimeQueryFrameTrace,
    fields: &[FieldRow],
    sample_values: &[SampleValueRow],
    vocabulary: &[VocabularyEntry],
) -> bool {
    if !trace.routed
        || trace.source != "runtime_graph_query_frame_scalar_aggregate"
        || trace.sql.is_none()
        || trace.order_by.is_some()
        || trace.joins.len() > 3
        || trace.predicates.len() > 3
        || graph_prompt_should_never_model_fallback(nl, fields)
    {
        return false;
    }
    let lower = format!(" {} ", graph_norm(nl));
    if graph_aggregate_kind(&lower).is_none() || lower.contains(" by ") {
        return false;
    }
    let sql = trace
        .sql
        .as_deref()
        .unwrap_or_default()
        .to_ascii_lowercase();
    if sql.contains(" select *") || sql.contains(" group by ") {
        return false;
    }
    let Some(projection) = &trace.projection else {
        return false;
    };
    let expr = projection.expression.to_ascii_lowercase();
    if !(expr.starts_with("avg(") || expr.starts_with("sum(")) {
        return false;
    }
    let Some(field_key) = projection.field.as_deref() else {
        return false;
    };
    let field_map = graph_field_map(fields);
    let Some(field) = field_map.get(field_key) else {
        return false;
    };
    if !graph_field_looks_numeric(field) || graph_field_looks_unsafe_id(field) {
        return false;
    }
    graph_trace_predicates_are_grounded(nl, trace, fields, sample_values, vocabulary)
}

fn graph_runtime_query_frame_avg_related_count_safe(
    nl: &str,
    trace: &RuntimeQueryFrameTrace,
    fields: &[FieldRow],
    sample_values: &[SampleValueRow],
    vocabulary: &[VocabularyEntry],
) -> bool {
    if !trace.routed
        || trace.source != "runtime_graph_query_frame_avg_related_count"
        || trace.sql.is_none()
        || trace.predicates.len() != 1
        || trace.joins.len() != 1
        || !graph_prompt_requests_average_related_count(nl)
    {
        return false;
    }
    let Some(projection) = &trace.projection else {
        return false;
    };
    let expr = projection.expression.to_ascii_lowercase();
    if !expr.starts_with("cast(count(") || !expr.contains(" as real) / count(") {
        return false;
    }
    let field_map = graph_field_map(fields);
    for field_key in &projection.fields {
        if !field_map
            .get(field_key)
            .is_some_and(|field| graph_field_looks_unsafe_id(field))
        {
            return false;
        }
    }
    for predicate in &trace.predicates {
        let Some(field) = field_map.get(&predicate.field) else {
            return false;
        };
        if predicate.operator != "="
            || graph_predicate_value_has_span_role_conflict(nl, predicate, field, fields)
            || !graph_predicate_value_is_grounded_with_vocab(
                nl,
                predicate,
                field,
                sample_values,
                vocabulary,
            )
        {
            return false;
        }
    }
    true
}

fn graph_runtime_query_frame_grouped_aggregate_safe(
    nl: &str,
    trace: &RuntimeQueryFrameTrace,
    fields: &[FieldRow],
    sample_values: &[SampleValueRow],
    vocabulary: &[VocabularyEntry],
) -> bool {
    let metric_topk =
        graph_grouped_metric_topk_prompt(nl, graph_grouped_measure_field(nl, fields, vocabulary));
    if !trace.routed
        || trace.source != "runtime_graph_query_frame_grouped_aggregate"
        || trace.sql.is_none()
        || trace.joins.len() > 3
        || trace.predicates.len() > 3
        || !(graph_prompt_requests_grouped_aggregate(nl)
            || graph_prompt_requests_value_grouped_comparison(
                nl,
                fields,
                sample_values,
                vocabulary,
            )
            || metric_topk)
        || graph_prompt_should_never_model_fallback(nl, fields)
    {
        return false;
    }
    let sql = trace
        .sql
        .as_deref()
        .unwrap_or_default()
        .to_ascii_lowercase();
    if !sql.contains(" group by ") || sql.contains(" select *") {
        return false;
    }
    let Some(projection) = &trace.projection else {
        return false;
    };
    let expr = projection.expression.to_ascii_lowercase();
    if !(expr.starts_with("count(") || expr.starts_with("sum(") || expr.starts_with("avg(")) {
        return false;
    }
    let field_map = graph_field_map(fields);
    for field_key in &projection.fields {
        let Some(field) = field_map.get(field_key) else {
            return false;
        };
        if !graph_field_is_group_dimension(field)
            || graph_field_looks_identity_or_relationship_key(field, trace, vocabulary)
        {
            return false;
        }
    }
    if !expr.starts_with("count(")
        && !graph_grouped_aggregate_has_requested_measure(nl, trace, fields, vocabulary)
    {
        return false;
    }
    if !expr.starts_with("count(")
        && !fields.iter().any(|field| {
            graph_field_looks_numeric(field)
                && !graph_field_looks_unsafe_id(field)
                && !graph_field_looks_identity_or_relationship_key(field, trace, vocabulary)
                && graph_expr_contains_field_ref(&expr, field)
        })
    {
        return false;
    }
    if !expr.starts_with("count(")
        && graph_grouped_measure_anchor_mismatch(nl, trace, fields, vocabulary)
    {
        return false;
    }
    let groups = runtime_sql_group_by_expressions(trace.sql.as_deref().unwrap_or_default());
    if groups.is_empty() || groups.len() > 2 {
        return false;
    }
    let group_exprs: HashSet<String> = groups
        .iter()
        .map(|group| group.trim().to_ascii_lowercase())
        .collect();
    let group_fields = fields
        .iter()
        .filter(|field| {
            group_exprs
                .iter()
                .any(|expr| graph_group_expr_matches_field(expr, field))
        })
        .collect::<Vec<_>>();
    if group_fields.len() != groups.len()
        || group_fields.iter().any(|field| {
            !graph_field_is_group_dimension(field)
                || graph_field_looks_identity_or_relationship_key(field, trace, vocabulary)
        })
    {
        return false;
    }
    if let Some(base_entity) = projection.entity.split('.').next() {
        if graph_group_over_time_dimension_field(nl, base_entity, fields, vocabulary).is_some()
            && (group_fields.len() < 2
                || !group_fields
                    .iter()
                    .any(|field| graph_field_looks_date_like(field))
                || !group_fields
                    .iter()
                    .any(|field| !graph_field_looks_date_like(field)))
        {
            return false;
        }
    }
    let required_entities: HashSet<String> = trace
        .required_entities
        .iter()
        .map(|entity| entity.to_ascii_lowercase())
        .collect();
    if !required_entities.is_empty()
        && group_fields
            .iter()
            .any(|field| !required_entities.contains(&field.entity.to_ascii_lowercase()))
    {
        return false;
    }
    if graph_prompt_requests_actor_group(nl)
        && !group_fields
            .iter()
            .any(|field| graph_group_field_matches_actor_prompt(nl, field, vocabulary))
    {
        return false;
    }
    let field_map = graph_field_map(fields);
    for predicate in &trace.predicates {
        let Some(field) = field_map.get(&predicate.field) else {
            return false;
        };
        let numeric_comparison = graph_field_looks_numeric(field)
            && matches!(predicate.operator.as_str(), ">" | "<" | ">=" | "<=");
        if graph_predicate_value_has_span_role_conflict(nl, predicate, field, fields)
            || (!numeric_comparison
                && !graph_predicate_value_is_grounded_with_vocab(
                    nl,
                    predicate,
                    field,
                    sample_values,
                    vocabulary,
                ))
        {
            return false;
        }
    }
    true
}

fn graph_grouped_aggregate_has_requested_measure(
    nl: &str,
    trace: &RuntimeQueryFrameTrace,
    fields: &[FieldRow],
    vocabulary: &[VocabularyEntry],
) -> bool {
    graph_grouped_measure_field(nl, fields, vocabulary).is_some_and(|field| {
        !graph_field_looks_identity_or_relationship_key(field, trace, vocabulary)
    })
}

fn graph_grouped_measure_anchor_mismatch(
    nl: &str,
    trace: &RuntimeQueryFrameTrace,
    fields: &[FieldRow],
    vocabulary: &[VocabularyEntry],
) -> bool {
    let Some(projection) = &trace.projection else {
        return false;
    };
    let expr = projection.expression.to_ascii_lowercase();
    if expr.starts_with("count(") {
        return false;
    }
    let selected = graph_grouped_measure_fields_in_expr(&expr, fields);
    if selected
        .iter()
        .any(|field| graph_measure_entity_anchor_score(nl, field, vocabulary) >= 18.0)
    {
        return false;
    }
    if selected
        .iter()
        .any(|field| graph_field_exact_multi_token_phrase_bonus(nl, field) > 0.0)
    {
        return false;
    }
    let Some(anchor) = graph_prompt_entity_anchored_measure_field(nl, fields, vocabulary) else {
        return false;
    };
    let anchor_key = anchor.canonical();
    !selected.is_empty()
        && !selected
            .iter()
            .any(|field| field.canonical().eq_ignore_ascii_case(&anchor_key))
}

fn graph_grouped_measure_fields_in_expr<'a>(
    expr: &str,
    fields: &'a [FieldRow],
) -> Vec<&'a FieldRow> {
    fields
        .iter()
        .filter(|field| {
            graph_field_looks_numeric(field)
                && !graph_field_looks_actor_reference_numeric(field)
                && graph_expr_contains_field_ref(expr, field)
        })
        .collect()
}

fn graph_field_looks_identity_or_relationship_key(
    field: &FieldRow,
    trace: &RuntimeQueryFrameTrace,
    vocabulary: &[VocabularyEntry],
) -> bool {
    graph_field_looks_unsafe_id(field)
        || graph_trace_field_is_join_endpoint(trace, field)
        || graph_field_has_identity_alias(field, vocabulary)
        || graph_field_looks_actor_reference_numeric(field)
}

fn graph_trace_field_is_join_endpoint(trace: &RuntimeQueryFrameTrace, field: &FieldRow) -> bool {
    trace.joins.iter().any(|join| {
        graph_join_endpoint_matches_field(&join.from_entity, &join.from_field, field)
            || graph_join_endpoint_matches_field(&join.to_entity, &join.to_field, field)
    })
}

fn graph_join_endpoint_matches_field(entity: &str, endpoint: &str, field: &FieldRow) -> bool {
    if !entity.eq_ignore_ascii_case(&field.entity) {
        return false;
    }
    let endpoint = endpoint
        .rsplit_once('.')
        .map(|(_, field)| field)
        .unwrap_or(endpoint);
    endpoint.eq_ignore_ascii_case(&field.field)
        || endpoint.eq_ignore_ascii_case(&field.db_column)
        || format!("{entity}.{endpoint}").eq_ignore_ascii_case(&field.canonical())
}

fn graph_field_has_identity_alias(field: &FieldRow, vocabulary: &[VocabularyEntry]) -> bool {
    [
        field.field.as_str(),
        field.db_column.as_str(),
        field.display_label.as_deref().unwrap_or(""),
    ]
    .into_iter()
    .any(graph_text_looks_identity_alias)
        || vocabulary.iter().any(|entry| {
            entry.canonical_kind == "field"
                && entry.confidence >= 0.4
                && entry
                    .canonical_value
                    .eq_ignore_ascii_case(&field.canonical())
                && graph_text_looks_identity_alias(&entry.term)
        })
}

fn graph_text_looks_identity_alias(text: &str) -> bool {
    let tokens = graph_name_tokens(text);
    tokens.contains("id") || tokens.contains("identifier") || tokens.contains("uuid")
}

fn graph_prompt_requests_actor_group(nl: &str) -> bool {
    let group_phrase = graph_group_by_phrase(nl)
        .or_else(|| graph_topk_group_phrase_without_schema(nl))
        .unwrap_or_else(|| nl.to_string());
    let lower = format!(" {} ", graph_norm(&group_phrase));
    [
        " agent ",
        " agents ",
        " rep ",
        " reps ",
        " owner ",
        " owners ",
        " assignee ",
        " assignees ",
        " staff ",
        " member ",
        " members ",
        " user ",
        " users ",
        " manager ",
        " managers ",
    ]
    .iter()
    .any(|needle| lower.contains(needle))
}

fn graph_topk_group_phrase_without_schema(nl: &str) -> Option<String> {
    if graph_order_direction_limit(nl).is_none() || !graph_topk_group_dimension_prompt(nl) {
        return None;
    }
    let tokens = graph_ordered_tokens(nl);
    let start = tokens
        .iter()
        .position(|token| {
            matches!(
                token.as_str(),
                "which" | "who" | "what" | "top" | "show" | "list" | "display"
            )
        })
        .map(|idx| idx + 1)
        .unwrap_or(0);
    let end = tokens[start..]
        .iter()
        .position(|token| {
            matches!(
                token.as_str(),
                "most"
                    | "least"
                    | "highest"
                    | "lowest"
                    | "largest"
                    | "smallest"
                    | "biggest"
                    | "fewest"
                    | "greatest"
            )
        })
        .map(|idx| start + idx)
        .unwrap_or(tokens.len());
    let phrase = tokens[start..end]
        .iter()
        .filter(|token| {
            !matches!(
                token.as_str(),
                "the" | "a" | "an" | "with" | "of" | "by" | "for" | "has" | "have"
            )
        })
        .cloned()
        .collect::<Vec<_>>()
        .join(" ");
    (!phrase.is_empty()).then_some(phrase)
}

fn graph_group_field_matches_actor_prompt(
    nl: &str,
    field: &FieldRow,
    vocabulary: &[VocabularyEntry],
) -> bool {
    if !graph_field_looks_display_field(field) {
        return false;
    }
    let lower = graph_norm(nl);
    let actor_tokens = [
        "agent",
        "agents",
        "rep",
        "reps",
        "owner",
        "owners",
        "assignee",
        "assignees",
        "staff",
        "member",
        "members",
        "user",
        "users",
        "manager",
        "managers",
    ]
    .into_iter()
    .filter(|token| lower.contains(token))
    .map(ToString::to_string)
    .collect::<HashSet<_>>();
    if actor_tokens.is_empty() {
        return false;
    }
    let entity_tokens = graph_entity_tokens_with_vocab(&field.entity, vocabulary);
    !entity_tokens.is_disjoint(&actor_tokens)
}

fn graph_runtime_query_frame_grouped_ratio_safe(
    nl: &str,
    trace: &RuntimeQueryFrameTrace,
    fields: &[FieldRow],
    sample_values: &[SampleValueRow],
    vocabulary: &[VocabularyEntry],
) -> bool {
    if !trace.routed
        || trace.source != "runtime_graph_query_frame_grouped_ratio"
        || trace.sql.is_none()
        || trace.joins.len() > 3
        || trace.predicates.is_empty()
        || trace.predicates.len() > 3
        || !graph_prompt_requests_grouped_ratio(nl)
        || graph_grouped_ratio_prompt_has_unsafe_terms(nl)
    {
        return false;
    }
    let sql = trace
        .sql
        .as_deref()
        .unwrap_or_default()
        .to_ascii_lowercase();
    if !sql.contains(" group by ")
        || !sql.contains("sum(case when")
        || !sql.contains(" else 0 end)")
        || !sql.contains(" / count(")
        || sql.contains(" select *")
    {
        return false;
    }
    let Some(projection) = &trace.projection else {
        return false;
    };
    let expr = projection.expression.to_ascii_lowercase();
    if !expr.contains("sum(case when") || !expr.contains(" / count(") {
        return false;
    }
    let field_map = graph_field_map(fields);
    let Some(condition_field_key) = projection.field.as_deref() else {
        return false;
    };
    let Some(condition_field) = field_map.get(condition_field_key) else {
        return false;
    };
    if graph_field_looks_date_like(condition_field) || graph_field_looks_unsafe_id(condition_field)
    {
        return false;
    }
    let groups = runtime_sql_group_by_expressions(trace.sql.as_deref().unwrap_or_default());
    if groups.len() != 1 {
        return false;
    }
    let group_expr = groups[0].trim().to_ascii_lowercase();
    let Some(group_field) = fields
        .iter()
        .find(|field| graph_group_expr_matches_field(&group_expr, field))
    else {
        return false;
    };
    if !graph_field_is_group_dimension(group_field) {
        return false;
    }
    trace.predicates.iter().all(|predicate| {
        let Some(field) = field_map.get(&predicate.field) else {
            return false;
        };
        predicate.operator == "="
            && !graph_field_looks_date_like(field)
            && !graph_field_looks_unsafe_id(field)
            && !graph_predicate_value_has_span_role_conflict(nl, predicate, field, fields)
            && graph_predicate_value_is_grounded_with_vocab(
                nl,
                predicate,
                field,
                sample_values,
                vocabulary,
            )
    })
}

