    #[test]
    fn large_schema_grouped_metric_routes_when_measure_and_dimension_resolve() {
        let mut entities = vec![entity_row("email_imports")];
        let mut fields = vec![
            typed_field_row("email_imports", "retry_count", "INTEGER"),
            field_row("email_imports", "status"),
        ];
        for idx in 0..1_501 {
            fields.push(field_row("email_imports", &format!("display_{idx}")));
        }
        for idx in 0..130 {
            entities.push(entity_row(&format!("filler_{idx}")));
        }
        let question = "which status has the highest average retry count for email imports";

        assert!(graph_large_schema_grouped_metric_should_fail_fast(
            question,
            &entities,
            &fields,
            &[]
        ));
        let trace = graph_query_frame_trace(question, &entities, &fields, &[], &[]);

        assert!(trace.routed, "{trace:?}");
        assert_eq!(trace.source, "runtime_graph_query_frame_grouped_aggregate");
        assert!(
            graph_runtime_query_frame_final_sql_allowed(
                false,
                &entities,
                &fields,
                &[],
                question,
                &trace
            ),
            "{trace:?}"
        );

        let unresolved_question =
            "which segment has the highest average retry count for email imports";
        assert!(graph_large_schema_grouped_metric_should_fail_fast(
            unresolved_question,
            &entities,
            &fields,
            &[]
        ));
        let unresolved_trace =
            graph_query_frame_trace(unresolved_question, &entities, &fields, &[], &[]);
        assert!(!unresolved_trace.routed);
        assert_eq!(
            unresolved_trace.route_reason,
            "not_routed_large_schema_grouped_metric_needs_typed_proposal"
        );

        let invoice_entities = vec![entity_row("invoices")];
        let invoice_fields = vec![
            typed_field_row("invoices", "id", "BIGINT"),
            typed_field_row("invoices", "amount_billed", "FLOAT"),
            typed_field_row("invoices", "amount_paid", "FLOAT"),
            field_row("invoices", "status"),
        ];
        let invoice_question = "which status has the highest average amount paid for invoices";
        let invoice_subject =
            graph_grouped_metric_subject_entity(invoice_question, &invoice_entities, &[]);
        assert_eq!(invoice_subject.as_deref(), Some("invoices"));
        assert_eq!(
            graph_grouped_measure_field_scoped(
                invoice_question,
                &invoice_fields,
                &[],
                invoice_subject.as_deref(),
            )
            .map(FieldRow::canonical)
            .as_deref(),
            Some("invoices.amount_paid")
        );
        let invoice_trace = graph_query_frame_trace(
            invoice_question,
            &invoice_entities,
            &invoice_fields,
            &[],
            &[],
        );
        assert!(invoice_trace.routed, "{invoice_trace:?}");
        assert_eq!(
            invoice_trace
                .projection
                .as_ref()
                .map(|projection| projection.expression.as_str()),
            Some("AVG(\"invoices\".\"amount_paid\") AS avg_amount_paid")
        );
    }

    #[test]
    fn semantic_atlas_trace_infers_roles_aliases_and_sample_counts() {
        let (entities, fields, relationships, samples) = growth_ops_fixture();
        let vocabulary = vec![VocabularyEntry {
            term: "company".to_string(),
            canonical_kind: "field".to_string(),
            canonical_value: "accounts.company_name".to_string(),
            confidence: 0.9,
            source_layer: 3,
        }];
        let atlas =
            semantic_runtime_atlas(&entities, &fields, &relationships, &samples, &vocabulary);
        let trace = atlas.trace();
        assert_eq!(trace.entity_count, entities.len());
        assert_eq!(trace.relationship_count, relationships.len());
        let accounts = trace
            .entities
            .iter()
            .find(|entity| entity.entity == "accounts")
            .unwrap();
        assert_eq!(
            accounts.activity_hint.evidence_source,
            "graph_metadata_only"
        );
        assert_eq!(accounts.activity_hint.sample_value_field_count, 3);
        assert_eq!(accounts.activity_hint.relationship_count, 6);
        assert_eq!(accounts.activity_hint.evidence_level, "strong");
        assert!(
            accounts
                .activity_hint
                .evidence
                .iter()
                .any(|item| item.starts_with("sample_values:")),
            "{accounts:?}"
        );
        let company = trace
            .fields
            .iter()
            .find(|field| field.field == "accounts.company_name")
            .unwrap();
        assert!(
            company.roles.contains(&"display".to_string()),
            "{company:?}"
        );
        assert!(
            company.aliases.contains(&"company".to_string()),
            "{company:?}"
        );
        assert_eq!(company.sample_value_count, 2);
        let amount = trace
            .fields
            .iter()
            .find(|field| field.field == "invoices.amount")
            .unwrap();
        assert!(amount.roles.contains(&"measure".to_string()), "{amount:?}");
        assert!(amount.roles.contains(&"numeric".to_string()), "{amount:?}");
    }

