    #[test]
    fn runtime_query_frame_routes_named_month_count_with_date_window() {
        let (entities, fields, relationships, samples) = growth_ops_fixture();
        let question = "How many active accounts signed up in February 2024?";
        let trace = graph_query_frame_trace(question, &entities, &fields, &relationships, &samples);
        assert!(trace.routed, "{trace:?}");
        assert_eq!(trace.route_reason, "routed");
        assert!(
            trace.predicates.iter().any(|predicate| {
                predicate.field == "accounts.signup_date"
                    && predicate.operator == "range"
                    && predicate.value == "2024-02-01..2024-03-01"
            }),
            "{trace:?}"
        );
        let sql = trace.sql.as_deref().unwrap_or_default();
        assert!(
            sql.contains("\"accounts\".\"signup_date\" >= '2024-02-01'")
                && sql.contains("\"accounts\".\"signup_date\" < '2024-03-01'"),
            "{sql}"
        );
        let atlas = semantic_runtime_atlas(&entities, &fields, &relationships, &samples, &[]);
        let intent = runtime_intent_frame_from_trace(question, &trace, &atlas);
        let plan = runtime_bound_query_plan_from_trace(question, &trace, &atlas, &intent);
        assert!(plan.valid, "{plan:?}");
        assert!(plan.diagnostics.is_empty(), "{plan:?}");
        assert!(
            graph_runtime_query_frame_final_sql_allowed(
                false, &entities, &fields, &samples, question, &trace
            ),
            "{trace:?}"
        );
        assert!(
            graph_runtime_query_frame_final_sql_allowed(
                false, &entities, &fields, &samples, question, &trace
            ),
            "{trace:?}"
        );

        let paraphrase = "Show the support agent who resolved the most high priority tickets?";
        let paraphrase_trace =
            graph_query_frame_trace(paraphrase, &entities, &fields, &relationships, &samples);
        assert!(paraphrase_trace.routed, "{paraphrase_trace:?}");
        assert_eq!(
            paraphrase_trace.source,
            "runtime_graph_query_frame_grouped_aggregate"
        );
        assert!(
            paraphrase_trace
                .predicates
                .iter()
                .all(|predicate| predicate.field != "agents.team"),
            "{paraphrase_trace:?}"
        );
        let paraphrase_sql = paraphrase_trace.sql.as_deref().unwrap_or_default();
        assert!(
            paraphrase_sql
                .contains("\"agents\".\"full_name\", COUNT(\"tickets\".\"id\") AS ticket_count"),
            "{paraphrase_sql}"
        );
        assert!(
            paraphrase_sql.contains("GROUP BY \"agents\".\"full_name\""),
            "{paraphrase_sql}"
        );
        assert!(
            paraphrase_sql.contains("ORDER BY ticket_count DESC LIMIT 1"),
            "{paraphrase_sql}"
        );
        assert!(
            graph_runtime_query_frame_final_sql_allowed(
                false,
                &entities,
                &fields,
                &samples,
                paraphrase,
                &paraphrase_trace
            ),
            "{paraphrase_trace:?}"
        );
    }

    #[test]
    fn runtime_query_frame_prefers_requested_date_role_for_structured_date() {
        let entities = vec![entity_row("schools")];
        let fields = vec![
            FieldRow {
                entity: "schools".to_string(),
                field: "school".to_string(),
                db_column: "School".to_string(),
                field_type: "TEXT".to_string(),
                display_label: Some("School".to_string()),
            },
            FieldRow {
                entity: "schools".to_string(),
                field: "phone".to_string(),
                db_column: "Phone".to_string(),
                field_type: "TEXT".to_string(),
                display_label: Some("Phone".to_string()),
            },
            FieldRow {
                entity: "schools".to_string(),
                field: "charter".to_string(),
                db_column: "Charter".to_string(),
                field_type: "INTEGER".to_string(),
                display_label: Some("Charter".to_string()),
            },
            FieldRow {
                entity: "schools".to_string(),
                field: "fundingtype".to_string(),
                db_column: "FundingType".to_string(),
                field_type: "TEXT".to_string(),
                display_label: Some("Charter Funding Type".to_string()),
            },
            FieldRow {
                entity: "schools".to_string(),
                field: "opendate".to_string(),
                db_column: "OpenDate".to_string(),
                field_type: "DATE".to_string(),
                display_label: Some("Open Date".to_string()),
            },
            FieldRow {
                entity: "schools".to_string(),
                field: "closeddate".to_string(),
                db_column: "ClosedDate".to_string(),
                field_type: "DATE".to_string(),
                display_label: Some("Closed Date".to_string()),
            },
        ];
        let vocabulary = vec![
            scope_vocab_entry("charter", "schools.charter", "1"),
            scope_vocab_entry("directly funded", "schools.fundingtype", "directly funded"),
        ];
        let question = "show phone numbers of direct charter-funded schools opened after 2000/1/1";
        let trace =
            graph_query_frame_trace_with_vocab(question, &entities, &fields, &[], &[], &vocabulary);

        assert!(trace.routed, "{trace:?}");
        assert!(
            trace.predicates.iter().any(|predicate| {
                predicate.field == "schools.opendate"
                    && matches!(predicate.operator.as_str(), ">" | ">=")
                    && predicate.value == "2000/1/1"
            }),
            "{trace:?}"
        );
        assert!(
            trace
                .predicates
                .iter()
                .all(|predicate| predicate.field != "schools.closeddate"),
            "{trace:?}"
        );
        assert!(
            trace.predicates.iter().any(|predicate| {
                predicate.field == "schools.fundingtype" && predicate.value == "directly funded"
            }),
            "{trace:?}"
        );
        assert!(
            trace
                .predicates
                .iter()
                .any(|predicate| predicate.field == "schools.charter" && predicate.value == "1"),
            "{trace:?}"
        );
        assert_eq!(
            trace
                .projection
                .as_ref()
                .map(|projection| projection.fields.clone())
                .unwrap_or_default(),
            vec!["schools.phone".to_string()],
            "{trace:?}"
        );
        assert!(
            trace.order_by.is_none(),
            "date predicate should not become an implicit sort key without recency/sort intent: {trace:?}"
        );

        let atlas = semantic_runtime_atlas(&entities, &fields, &[], &[], &vocabulary);
        let intent = runtime_intent_frame_from_trace(question, &trace, &atlas);
        let plan = runtime_bound_query_plan_from_trace(question, &trace, &atlas, &intent);
        assert!(plan.valid, "{plan:?}");

        let date_question = "show open date of direct charter-funded schools opened after 2000/1/1";
        let date_trace = graph_query_frame_trace_with_vocab(
            date_question,
            &entities,
            &fields,
            &[],
            &[],
            &vocabulary,
        );
        assert!(date_trace.routed, "{date_trace:?}");
        assert!(
            date_trace
                .projection
                .as_ref()
                .is_some_and(|projection| projection
                    .fields
                    .iter()
                    .any(|field| field == "schools.opendate")),
            "{date_trace:?}"
        );
    }

    #[test]
    fn bound_query_plan_rejects_weaker_related_predicate_field_binding() {
        let entities = vec![entity_row("schools"), entity_row("frpm")];
        let fields = vec![
            typed_field_row("schools", "cdscode", "TEXT"),
            field_row("schools", "phone"),
            typed_field_row("schools", "charter", "INTEGER"),
            field_row("schools", "fundingtype"),
            typed_field_row("frpm", "cdscode", "TEXT"),
            labeled_field_row(
                "frpm",
                "charter_school_y_n",
                "INTEGER",
                "Charter School (Y/N)",
            ),
            labeled_field_row(
                "frpm",
                "charter_funding_type",
                "TEXT",
                "Charter Funding Type",
            ),
        ];
        let relationships = vec![RelationshipRow {
            from_entity: "frpm".to_string(),
            from_field: "cdscode".to_string(),
            to_entity: "schools".to_string(),
            to_field: "cdscode".to_string(),
            kind: "many_to_one".to_string(),
        }];
        let samples = vec![
            sample_row(
                "schools.fundingtype",
                &["Directly funded", "Locally funded"],
            ),
            sample_row(
                "frpm.charter_funding_type",
                &["Directly funded", "Locally funded"],
            ),
            sample_row("schools.charter", &["0", "1"]),
            sample_row("frpm.charter_school_y_n", &["0", "1"]),
        ];
        let atlas = semantic_runtime_atlas(&entities, &fields, &relationships, &samples, &[]);
        let question =
            "Please list the phone numbers of the direct charter-funded schools opened after 2000/1/1.";

        let weaker_plan = BoundQueryPlanTrace {
            predicates: vec![BoundPlanPredicateTrace {
                field: "schools.fundingtype".to_string(),
                operator: "=".to_string(),
                value: "Directly funded".to_string(),
                backed_by_atlas: true,
                evidence: vec!["sample_value".to_string()],
            }],
            ..BoundQueryPlanTrace::default()
        };
        assert!(runtime_prompt_related_predicate_field_ambiguity(
            question,
            &weaker_plan,
            &atlas
        ));

        let stronger_plan = BoundQueryPlanTrace {
            predicates: vec![BoundPlanPredicateTrace {
                field: "frpm.charter_funding_type".to_string(),
                operator: "=".to_string(),
                value: "Directly funded".to_string(),
                backed_by_atlas: true,
                evidence: vec!["sample_value".to_string()],
            }],
            ..BoundQueryPlanTrace::default()
        };
        assert!(!runtime_prompt_related_predicate_field_ambiguity(
            question,
            &stronger_plan,
            &atlas
        ));

        let field_scoped_plan = BoundQueryPlanTrace {
            predicates: vec![BoundPlanPredicateTrace {
                field: "schools.fundingtype".to_string(),
                operator: "=".to_string(),
                value: "Directly funded".to_string(),
                backed_by_atlas: true,
                evidence: vec!["scope_predicate_vocabulary".to_string()],
            }],
            ..BoundQueryPlanTrace::default()
        };
        assert!(!runtime_prompt_related_predicate_field_ambiguity(
            question,
            &field_scoped_plan,
            &atlas
        ));
    }

