    #[test]
    fn graph_query_predicates_prefer_multiword_sample_over_component_value() {
        let fields = vec![
            field_row("leads", "source_channel"),
            field_row("leads", "status"),
            field_row("leads", "created_on"),
            field_row("invoices", "paid_on"),
            field_row("invoices", "status"),
        ];
        let samples = vec![
            sample_row("leads.source_channel", &["paid_search", "organic"]),
            sample_row("leads.status", &["new", "converted"]),
            sample_row("invoices.status", &["paid", "open"]),
        ];
        let vocabulary = vec![
            VocabularyEntry {
                term: "new".to_string(),
                canonical_kind: "scope_predicate".to_string(),
                canonical_value:
                    r#"{"scope":"leads.new","field":"leads.status","operator":"=","rawValue":"new"}"#
                        .to_string(),
                confidence: 0.95,
                source_layer: 6,
            },
            VocabularyEntry {
                term: "paid".to_string(),
                canonical_kind: "scope_predicate".to_string(),
                canonical_value:
                    r#"{"scope":"invoices.paid","field":"invoices.status","operator":"=","rawValue":"paid"}"#
                        .to_string(),
                confidence: 0.95,
                source_layer: 6,
            },
        ];
        let status_field = fields
            .iter()
            .find(|field| field.canonical() == "leads.status")
            .expect("leads.status");
        for question in [
            "How many new leads came from paid search in February 2024?",
            "Show count of new leads came from paid search in February 2024?",
        ] {
            assert!(
                graph_sample_value_is_temporal_subject_descriptor(
                    question,
                    "new",
                    status_field,
                    &vocabulary
                ),
                "{question}"
            );
            let predicates =
                graph_query_predicates_with_vocab(question, &fields, &samples, &vocabulary);
            assert!(
                predicates.iter().any(|predicate| {
                    predicate.field == "leads.source_channel" && predicate.value == "paid_search"
                }),
                "{question}: {predicates:?}"
            );
            assert!(
                predicates.iter().any(|predicate| {
                    predicate.field == "leads.created_on"
                        && predicate.operator == "range"
                        && predicate.value == "2024-02-01..2024-03-01"
                }),
                "{question}: {predicates:?}"
            );
            assert!(
                !predicates
                    .iter()
                    .any(|predicate| predicate.field == "leads.status"),
                "{question}: {predicates:?}"
            );
            assert!(
                !predicates.iter().any(|predicate| {
                    predicate.field == "invoices.status" && predicate.value == "paid"
                }),
                "{question}: {predicates:?}"
            );
            assert!(
                !predicates
                    .iter()
                    .any(|predicate| predicate.field == "invoices.paid_on"),
                "{question}: {predicates:?}"
            );
        }
    }

