    #[test]
    fn runtime_query_frame_routes_grouped_sum_by_related_dimension() {
        let (entities, fields, relationships, _) = business_analytics_fixture();
        let samples = vec![
            sample_row("accounts.status", &["active", "paused"]),
            sample_row("regions.name", &["EMEA", "APAC"]),
        ];
        let vocabulary = vec![VocabularyEntry {
            term: "customer".to_string(),
            canonical_kind: "entity".to_string(),
            canonical_value: "accounts".to_string(),
            confidence: 0.9,
            source_layer: 2,
        }];
        let question = "Total ARR by region for active customers";
        let trace = graph_query_frame_trace_with_vocab(
            question,
            &entities,
            &fields,
            &relationships,
            &samples,
            &vocabulary,
        );
        assert!(trace.routed, "{trace:?}");
        assert_eq!(trace.source, "runtime_graph_query_frame_grouped_aggregate");
        assert_eq!(
            trace
                .projection
                .as_ref()
                .and_then(|projection| projection.field.as_deref()),
            Some("regions.name")
        );
        assert_eq!(
            trace
                .projection
                .as_ref()
                .map(|projection| projection.fields.clone()),
            Some(vec!["regions.name".to_string()])
        );
        let sql = trace.sql.as_deref().unwrap_or_default();
        assert!(
            sql.contains("\"regions\".\"name\", SUM(\"accounts\".\"arr\") AS total_arr"),
            "{sql}"
        );
        assert!(
            sql.contains(
                "INNER JOIN \"regions\" ON \"accounts\".\"region_id\" = \"regions\".\"id\""
            ),
            "{sql}"
        );
        assert!(
            sql.contains("\"accounts\".\"status\" = 'active'"),
            "{trace:?}"
        );
        assert!(sql.contains("GROUP BY \"regions\".\"name\""), "{sql}");
        assert!(sql.contains("ORDER BY total_arr DESC"), "{sql}");
        assert!(
            graph_runtime_query_frame_final_sql_allowed_with_vocab(
                false,
                &entities,
                &fields,
                &samples,
                &vocabulary,
                question,
                &trace
            ),
            "{trace:?}"
        );
        let no_vocab_trace =
            graph_query_frame_trace(question, &entities, &fields, &relationships, &samples);
        assert!(no_vocab_trace.routed, "{no_vocab_trace:?}");
        assert!(
            no_vocab_trace.predicates.iter().any(
                |predicate| predicate.field == "accounts.status" && predicate.value == "active"
            ),
            "{no_vocab_trace:?}"
        );
        assert!(
            no_vocab_trace
                .predicates
                .iter()
                .all(|predicate| predicate.field != "reps.active"),
            "{no_vocab_trace:?}"
        );
    }

