    fn large_schema_grouped_average_prefers_base_dimension_and_named_value_filter() {
        let mut entities = vec![
            entity_row("shared_inbox_conversations"),
            entity_row("organizations"),
            entity_row("domains"),
            entity_row("servers"),
            entity_row("access_permissions"),
        ];
        let mut fields = vec![
            typed_field_row("shared_inbox_conversations", "id", "BIGINT"),
            typed_field_row(
                "shared_inbox_conversations",
                "external_message_count",
                "INTEGER",
            ),
            field_row("shared_inbox_conversations", "status"),
            field_row("shared_inbox_conversations", "priority"),
            typed_field_row("shared_inbox_conversations", "organization_id", "BIGINT"),
            typed_field_row("organizations", "id", "BIGINT"),
            typed_field_row("domains", "id", "BIGINT"),
            typed_field_row("domains", "organization_id", "BIGINT"),
            typed_field_row("domains", "server_id", "BIGINT"),
            typed_field_row("domains", "is_external", "BOOLEAN"),
            typed_field_row("servers", "id", "BIGINT"),
            field_row("servers", "last_connection_status"),
            typed_field_row("access_permissions", "id", "BIGINT"),
            typed_field_row("access_permissions", "organization_id", "BIGINT"),
            typed_field_row("access_permissions", "is_enabled", "BOOLEAN"),
        ];
        for idx in 0..130 {
            let entity = format!("filler_{idx}");
            entities.push(entity_row(&entity));
            for field_idx in 0..12 {
                fields.push(field_row(&entity, &format!("status_{field_idx}")));
            }
        }
        let relationships = vec![
            relationship_row(
                "shared_inbox_conversations",
                "organization_id",
                "organizations",
            ),
            relationship_row("domains", "organization_id", "organizations"),
            relationship_row("domains", "server_id", "servers"),
            relationship_row("access_permissions", "organization_id", "organizations"),
        ];
        let samples = vec![
            sample_row("shared_inbox_conversations.priority", &["normal", "urgent"]),
            sample_row("shared_inbox_conversations.status", &["open", "closed"]),
            sample_row("servers.last_connection_status", &["normal", "failed"]),
        ];
        let question = "which status has the highest average external message count for shared inbox conversations where priority is 'normal'";

        let trace = graph_query_frame_trace(question, &entities, &fields, &relationships, &samples);

        assert!(trace.routed, "{trace:?}");
        assert_eq!(trace.source, "runtime_graph_query_frame_grouped_aggregate");
        assert_eq!(
            trace
                .projection
                .as_ref()
                .and_then(|projection| projection.field.as_deref()),
            Some("shared_inbox_conversations.status")
        );
        assert!(
            trace.predicates.iter().any(|predicate| {
                predicate.field == "shared_inbox_conversations.priority"
                    && predicate.value == "normal"
            }),
            "{trace:?}"
        );
        assert!(
            trace
                .predicates
                .iter()
                .all(|predicate| predicate.field != "domains.is_external"
                    && predicate.field != "access_permissions.is_enabled"),
            "{trace:?}"
        );
        assert!(
            graph_runtime_query_frame_final_sql_allowed(
                false, &entities, &fields, &samples, question, &trace
            ),
            "{trace:?}"
        );
    }

