    #[test]
    fn semantic_alias_scalar_count_uses_vocab_subject_and_samples() {
        let (entities, fields, relationships, samples, vocabulary) =
            business_analytics_semantic_alias_fixture();
        let question = "How many new leads came from paid search in February 2024?";
        let status_field = fields
            .iter()
            .find(|field| field.canonical() == "prospects.status")
            .unwrap();
        assert!(graph_scope_term_is_temporal_subject_descriptor(
            question,
            "new",
            status_field,
            &fields,
            &vocabulary
        ));

        let trace = graph_query_frame_trace_with_vocab(
            question,
            &entities,
            &fields,
            &relationships,
            &samples,
            &vocabulary,
        );

        assert!(trace.routed, "{trace:?}");
        assert!(
            graph_runtime_query_frame_final_sql_allowed_with_vocab(
                false,
                &entities,
                &fields,
                &samples,
                &vocabulary,
                question,
                &trace,
            ),
            "{trace:?}"
        );
        let sql = trace.sql.as_deref().unwrap_or_default();
        assert!(sql.contains("FROM \"prospects\""), "{sql}");
        assert!(
            sql.contains("\"prospects\".\"acquisition_channel\" = 'paid_search'"),
            "{sql}"
        );
        assert!(
            sql.contains("\"prospects\".\"captured_on\" >= '2024-02-01'"),
            "{sql}"
        );
        assert!(!sql.contains("\"prospects\".\"status\" = 'new'"), "{sql}");
    }

