    #[test]
    fn runtime_query_frame_routes_grouped_conditional_ratios() {
        let (entities, fields, relationships, _) = business_analytics_fixture();
        let samples = vec![
            sample_row("leads.status", &["new", "converted", "disqualified"]),
            sample_row("campaigns.name", &["Brand Search", "Partner Webinar"]),
            sample_row("accounts.segment", &["enterprise", "mid_market"]),
        ];

        let conversion_question = "Lead-to-customer conversion rate by campaign";
        let conversion = graph_query_frame_trace(
            conversion_question,
            &entities,
            &fields,
            &relationships,
            &samples,
        );
        assert!(conversion.routed, "{conversion:?}");
        assert_eq!(conversion.source, "runtime_graph_query_frame_grouped_ratio");
        assert!(
            conversion.predicates.iter().any(|predicate| {
                predicate.field == "leads.status" && predicate.value == "converted"
            }),
            "{conversion:?}"
        );
        let conversion_sql = conversion.sql.as_deref().unwrap_or_default();
        assert!(
            conversion_sql.contains("\"campaigns\".\"name\", CAST(SUM(CASE WHEN"),
            "{conversion_sql}"
        );
        assert!(
            conversion_sql.contains("\"leads\".\"status\" = 'converted'"),
            "{conversion_sql}"
        );
        assert!(
            conversion_sql.contains("* 100.0 / COUNT(\"leads\".\"id\") AS conversion_rate"),
            "{conversion_sql}"
        );
        assert!(
            conversion_sql.contains("GROUP BY \"campaigns\".\"name\""),
            "{conversion_sql}"
        );
        assert!(
            graph_runtime_query_frame_final_sql_allowed(
                false,
                &entities,
                &fields,
                &samples,
                conversion_question,
                &conversion,
            ),
            "{conversion:?}"
        );

        let sla_question = "SLA breach rate by segment";
        let sla =
            graph_query_frame_trace(sla_question, &entities, &fields, &relationships, &samples);
        assert!(sla.routed, "{sla:?}");
        assert_eq!(sla.source, "runtime_graph_query_frame_grouped_ratio");
        assert!(
            sla.predicates.iter().any(|predicate| {
                predicate.field == "tickets.sla_breached" && predicate.value == "1"
            }),
            "{sla:?}"
        );
        let sla_sql = sla.sql.as_deref().unwrap_or_default();
        assert!(
            sla_sql.contains("\"accounts\".\"segment\", CAST(SUM(CASE WHEN"),
            "{sla_sql}"
        );
        assert!(
            sla_sql.contains("\"tickets\".\"sla_breached\" = TRUE"),
            "{sla_sql}"
        );
        assert!(
            sla_sql.contains("* 100.0 / COUNT(\"tickets\".\"id\") AS sla_breach_rate"),
            "{sla_sql}"
        );
        assert!(
            sla_sql.contains("GROUP BY \"accounts\".\"segment\""),
            "{sla_sql}"
        );
        assert!(
            graph_runtime_query_frame_final_sql_allowed(
                false,
                &entities,
                &fields,
                &samples,
                sla_question,
                &sla,
            ),
            "{sla:?}"
        );
    }

    #[test]
    fn runtime_query_frame_routes_scalar_conditional_rate() {
        let entities = vec![
            entity_row("fraud_reports"),
            entity_row("external_mails"),
            entity_row("mail_attachments"),
            entity_row("external_mail_attachments"),
        ];
        let fields = vec![
            typed_field_row("fraud_reports", "id", "INTEGER"),
            typed_field_row("fraud_reports", "has_police_report", "BOOLEAN"),
            typed_field_row("external_mails", "id", "INTEGER"),
            typed_field_row("external_mails", "is_external", "BOOLEAN"),
            typed_field_row("mail_attachments", "id", "INTEGER"),
            typed_field_row("mail_attachments", "is_inline", "BOOLEAN"),
            typed_field_row("external_mail_attachments", "id", "INTEGER"),
            typed_field_row("external_mail_attachments", "is_inline", "BOOLEAN"),
        ];
        let trace = graph_query_frame_trace(
            "what percentage of fraud reports have police report",
            &entities,
            &fields,
            &[],
            &[],
        );
        assert!(trace.routed, "{trace:?}");
        assert_eq!(trace.source, "runtime_graph_query_frame_conditional_rate");
        assert!(
            trace.predicates.iter().any(|predicate| {
                predicate.field == "fraud_reports.has_police_report" && predicate.value == "1"
            }),
            "{trace:?}"
        );
        let sql = trace.sql.as_deref().unwrap_or_default();
        assert!(
            sql.contains("SUM(CASE WHEN \"fraud_reports\".\"has_police_report\" = TRUE"),
            "{sql}"
        );
        assert!(
            sql.contains("* 100.0 / NULLIF(COUNT(\"fraud_reports\".\"id\"), 0)"),
            "{sql}"
        );
        assert!(!sql.contains("GROUP BY"), "{sql}");
        assert!(
            graph_runtime_query_frame_final_sql_allowed(
                false,
                &entities,
                &fields,
                &[],
                "what percentage of fraud reports have police report",
                &trace,
            ),
            "{trace:?}"
        );

        let inline_question = "what percentage of external mail attachments are inline";
        let inline_subject = graph_rate_subject_entity(inline_question, &entities);
        assert_eq!(inline_subject.as_deref(), Some("external_mail_attachments"));
        let (inline_condition, _) = graph_conditional_rate_boolean_condition(
            inline_question,
            &fields,
            &[],
            &[],
            inline_subject.as_deref(),
        )
        .expect("inline condition");
        assert_eq!(
            inline_condition.field,
            "external_mail_attachments.is_inline"
        );
        let inline_trace = graph_query_frame_trace(inline_question, &entities, &fields, &[], &[]);
        assert!(inline_trace.routed, "{inline_trace:?}");
        assert_eq!(
            inline_trace.source,
            "runtime_graph_query_frame_conditional_rate"
        );
        assert!(
            inline_trace.predicates.iter().any(|predicate| {
                predicate.field == "external_mail_attachments.is_inline" && predicate.value == "1"
            }),
            "{inline_trace:?}"
        );
    }

