    #[test]
    fn runtime_query_frame_has_boolean_rate_prefers_fact_subject_over_child_entity() {
        let entities = vec![
            entity_row("case_reports"),
            entity_row("entity_case_reports"),
            entity_row("verification_reports"),
        ];
        let fields = vec![
            typed_field_row("case_reports", "id", "INTEGER"),
            typed_field_row("case_reports", "has_verification_report", "BOOLEAN"),
            typed_field_row("entity_case_reports", "id", "INTEGER"),
            typed_field_row("entity_case_reports", "case_report_id", "INTEGER"),
            typed_field_row("verification_reports", "id", "INTEGER"),
            typed_field_row("verification_reports", "case_report_id", "INTEGER"),
        ];
        let relationships = vec![
            RelationshipRow {
                from_entity: "entity_case_reports".to_string(),
                from_field: "case_report_id".to_string(),
                to_entity: "case_reports".to_string(),
                to_field: "id".to_string(),
                kind: "many_to_one".to_string(),
            },
            RelationshipRow {
                from_entity: "verification_reports".to_string(),
                from_field: "case_report_id".to_string(),
                to_entity: "case_reports".to_string(),
                to_field: "id".to_string(),
                kind: "many_to_one".to_string(),
            },
        ];
        let question = "what percentage of case reports have verification report";

        let trace = graph_query_frame_trace(question, &entities, &fields, &relationships, &[]);

        assert!(trace.routed, "{trace:?}");
        assert_eq!(trace.source, "runtime_graph_query_frame_conditional_rate");
        assert_eq!(
            trace
                .projection
                .as_ref()
                .and_then(|projection| projection.field.as_deref()),
            Some("case_reports.has_verification_report")
        );
        assert!(
            trace
                .sql
                .as_deref()
                .unwrap_or_default()
                .contains("FROM \"case_reports\""),
            "{trace:?}"
        );
        assert!(trace.predicates.iter().any(|predicate| {
            predicate.field == "case_reports.has_verification_report" && predicate.value == "1"
        }));
    }

