    #[test]
    fn runtime_query_frame_routes_sample_backed_grouped_comparison() {
        let (entities, fields, relationships, samples) = growth_ops_fixture();
        let question = "Compare February paid invoice totals for EMEA and APAC";
        let inferred = graph_inferred_month_date_window_predicates(
            question,
            &fields,
            &samples,
            &[],
            &std::collections::HashSet::from([
                "paid".to_string(),
                "emea".to_string(),
                "apac".to_string(),
            ]),
        );
        assert!(
            inferred.iter().any(
                |(_, _, field, value, operator)| field == "invoices.issued_on"
                    && value == "2024-02-01..2024-03-01"
                    && operator == "range"
            ),
            "{inferred:?}"
        );
        let mut refill_predicates = vec![
            super::GraphQueryPredicate {
                field: "invoices.status".to_string(),
                value: "paid".to_string(),
                operator: "=".to_string(),
            },
            super::GraphQueryPredicate {
                field: "regions.name".to_string(),
                value: "EMEA|APAC".to_string(),
                operator: "in".to_string(),
            },
        ];
        graph_add_best_date_window_predicate(
            question,
            &fields,
            &samples,
            &[],
            &mut refill_predicates,
        );
        assert!(
            refill_predicates.iter().any(|predicate| {
                predicate.field == "invoices.issued_on"
                    && predicate.operator == "range"
                    && predicate.value == "2024-02-01..2024-03-01"
            }),
            "refill={refill_predicates:?} inferred={inferred:?}"
        );
        let trace = graph_query_frame_trace(question, &entities, &fields, &relationships, &samples);
        assert!(trace.routed, "{trace:?}");
        assert_eq!(trace.source, "runtime_graph_query_frame_grouped_aggregate");
        assert!(
            trace.predicates.iter().any(|predicate| {
                predicate.field == "regions.name"
                    && predicate.operator == "in"
                    && predicate.value == "EMEA|APAC"
            }),
            "{trace:?}"
        );
        assert!(
            trace
                .predicates
                .iter()
                .any(|predicate| predicate.field == "invoices.status" && predicate.value == "paid"),
            "{trace:?}"
        );
        assert!(
            trace.predicates.iter().any(|predicate| {
                predicate.field == "invoices.issued_on"
                    && predicate.operator == "range"
                    && predicate.value == "2024-02-01..2024-03-01"
            }),
            "{trace:?}"
        );
        let sql = trace.sql.as_deref().unwrap_or_default();
        assert!(
            sql.contains("\"regions\".\"name\", SUM(\"invoices\".\"amount\") AS total_amount"),
            "{sql}"
        );
        assert!(
            sql.contains("\"regions\".\"name\" IN ('EMEA', 'APAC')"),
            "{sql}"
        );
        assert!(
            sql.contains("\"invoices\".\"issued_on\" >= '2024-02-01'")
                && sql.contains("\"invoices\".\"issued_on\" < '2024-03-01'"),
            "{sql}"
        );
        assert!(sql.contains("GROUP BY \"regions\".\"name\""), "{sql}");
        assert!(sql.contains("ORDER BY \"regions\".\"name\""), "{sql}");
        assert!(
            graph_runtime_query_frame_grouped_aggregate_safe(
                question,
                &trace,
                &fields,
                &samples,
                &[]
            ),
            "{trace:?}"
        );
        assert!(
            graph_runtime_query_frame_final_sql_allowed(
                false, &entities, &fields, &samples, question, &trace
            ),
            "{trace:?}"
        );

        let paraphrase = "Show February paid invoice totals for EMEA and APAC";
        let paraphrase_trace =
            graph_query_frame_trace(paraphrase, &entities, &fields, &relationships, &samples);
        assert!(paraphrase_trace.routed, "{paraphrase_trace:?}");
        assert_eq!(
            paraphrase_trace.source,
            "runtime_graph_query_frame_grouped_aggregate"
        );
        assert!(
            paraphrase_trace.predicates.iter().any(|predicate| {
                predicate.field == "regions.name"
                    && predicate.operator == "in"
                    && predicate.value == "EMEA|APAC"
            }),
            "{paraphrase_trace:?}"
        );
        let paraphrase_sql = paraphrase_trace.sql.as_deref().unwrap_or_default();
        assert!(
            paraphrase_sql.contains("\"regions\".\"name\", SUM(\"invoices\".\"amount\")"),
            "{paraphrase_sql}"
        );
        assert!(
            paraphrase_sql.contains("\"regions\".\"name\" IN ('EMEA', 'APAC')"),
            "{paraphrase_sql}"
        );
        assert!(paraphrase_sql.contains("GROUP BY \"regions\".\"name\""));
        assert!(paraphrase_sql.contains("ORDER BY \"regions\".\"name\""));
        assert!(
            graph_runtime_query_frame_final_sql_allowed(
                false,
                &entities,
                &fields,
                &samples,
                paraphrase,
                &paraphrase_trace
            ),
            "{paraphrase_trace:?}"
        );
    }

