    #[test]
    fn semantic_alias_churn_list_uses_related_lifecycle_table() {
        let entities = ["organizations", "recurring_contracts"]
            .into_iter()
            .map(entity_row)
            .collect::<Vec<_>>();
        let fields = vec![
            typed_field_row("organizations", "id", "INTEGER"),
            field_row("organizations", "organization_name"),
            field_row("organizations", "market_segment"),
            typed_field_row("organizations", "annual_recurring_revenue", "REAL"),
            field_row("organizations", "account_state"),
            field_row("organizations", "created_date"),
            typed_field_row("recurring_contracts", "organization_id", "INTEGER"),
            field_row("recurring_contracts", "subscription_state"),
            field_row("recurring_contracts", "ended_date"),
        ];
        let relationships = vec![relationship_row(
            "recurring_contracts",
            "organization_id",
            "organizations",
        )];
        let samples = vec![
            sample_row("organizations.account_state", &["active", "churned"]),
            sample_row("organizations.created_date", &["2024-01-10", "2024-02-12"]),
            sample_row(
                "recurring_contracts.subscription_state",
                &["active", "cancelled"],
            ),
            sample_row("recurring_contracts.ended_date", &["2024-02-10"]),
        ];
        let vocabulary = vec![
            vocab_entry("entity", "accounts", "organizations"),
            vocab_entry("entity", "account", "organizations"),
            vocab_entry("entity", "subscriptions", "recurring_contracts"),
            vocab_entry("field", "segment", "organizations.market_segment"),
            vocab_entry("field", "arr", "organizations.annual_recurring_revenue"),
            vocab_entry("field", "status", "organizations.account_state"),
            vocab_entry("field", "status", "recurring_contracts.subscription_state"),
            vocab_entry("field", "ended date", "recurring_contracts.ended_date"),
        ];
        let question = "List churned accounts in Q1 2024 with segment and ARR";
        let trace = graph_query_frame_trace_with_vocab(
            question,
            &entities,
            &fields,
            &relationships,
            &samples,
            &vocabulary,
        );
        assert!(trace.routed, "{trace:?}");
        assert!(
            trace.predicates.iter().any(|predicate| {
                predicate.field == "recurring_contracts.subscription_state"
                    && predicate.value == "cancelled"
            }),
            "{trace:?}"
        );
        assert!(
            trace.predicates.iter().any(|predicate| {
                predicate.field == "recurring_contracts.ended_date"
                    && predicate.operator == "range"
                    && predicate.value == "2024-01-01..2024-04-01"
            }),
            "{trace:?}"
        );
        assert!(
            trace
                .predicates
                .iter()
                .all(|predicate| predicate.field != "organizations.account_state"
                    && predicate.field != "organizations.created_date"),
            "{trace:?}"
        );
        let projection = trace.projection.as_ref().expect("projection");
        assert!(
            projection
                .fields
                .iter()
                .any(|field| field == "organizations.market_segment"),
            "{trace:?}"
        );
        assert!(
            projection
                .fields
                .iter()
                .any(|field| field == "organizations.annual_recurring_revenue"),
            "{trace:?}"
        );
        assert!(
            trace.joins.iter().any(|join| {
                join.from_entity == "organizations" && join.to_entity == "recurring_contracts"
            }),
            "{trace:?}"
        );
        assert!(
            trace.order_by.as_ref().is_some_and(|order| {
                order.field == "organizations.annual_recurring_revenue" && order.direction == "DESC"
            }),
            "{trace:?}"
        );
        assert!(
            graph_runtime_query_frame_final_sql_allowed_with_vocab(
                false,
                &entities,
                &fields,
                &samples,
                &vocabulary,
                question,
                &trace,
            ),
            "{trace:?}"
        );
        let atlas =
            semantic_runtime_atlas(&entities, &fields, &relationships, &samples, &vocabulary);
        let intent = runtime_intent_frame_from_trace(question, &trace, &atlas);
        let plan = runtime_bound_query_plan_from_trace(question, &trace, &atlas, &intent);
        assert!(plan.valid, "{plan:?}");
    }

