        assert!(sql.contains("\"reps\".\"full_name\""), "{sql}");
        assert!(sql.contains("SUM(\"opportunities\".\"amount\")"), "{sql}");
        assert!(sql.contains("\"opportunities\".\"stage\" IN"), "{sql}");
