    #[test]
    fn runtime_query_frame_routes_seeded_commerce_lookup_shapes() {
        let entities = ["customers", "orders", "products", "regions"]
            .into_iter()
            .map(entity_row)
            .collect::<Vec<_>>();
        let fields = vec![
            typed_field_row("customers", "id", "INTEGER"),
            field_row("customers", "name"),
            field_row("customers", "status"),
            typed_field_row("customers", "region_id", "INTEGER"),
            field_row("customers", "external_code"),
            typed_field_row("orders", "id", "INTEGER"),
            typed_field_row("orders", "customer_id", "INTEGER"),
            typed_field_row("orders", "product_id", "INTEGER"),
            typed_field_row("orders", "amount", "REAL"),
            field_row("orders", "ordered_on"),
            field_row("orders", "zip_code"),
            typed_field_row("products", "id", "INTEGER"),
            field_row("products", "name"),
            typed_field_row("regions", "id", "INTEGER"),
            field_row("regions", "name"),
        ];
        let relationships = vec![
            relationship_row("customers", "region_id", "regions"),
            relationship_row("orders", "customer_id", "customers"),
            relationship_row("orders", "product_id", "products"),
        ];
        let samples = vec![
            sample_row("customers.status", &["active", "paused"]),
            sample_row("customers.name", &["Acme 4744", "Northstar 123"]),
            sample_row("customers.external_code", &["00D4", "0613360"]),
            sample_row("orders.ordered_on", &["2024-02-13", "2024-03-17"]),
            sample_row("orders.zip_code", &["78116-2526", "11758-9727"]),
            sample_row("regions.name", &["APAC", "EMEA", "LATAM"]),
        ];

        let list = graph_query_frame_trace(
            "list active customers",
            &entities,
            &fields,
            &relationships,
            &samples,
        );
        assert!(list.routed, "{list:?}");
        assert_eq!(
            list.projection.as_ref().and_then(|p| p.field.as_deref()),
            Some("customers.name")
        );
        assert!(graph_runtime_query_frame_final_sql_allowed(
            true,
            &entities,
            &fields,
            &samples,
            "list active customers",
            &list
        ));

        let count = graph_query_frame_trace(
            "how many active customers are in LATAM",
            &entities,
            &fields,
            &relationships,
            &samples,
        );
        assert!(count.routed, "{count:?}");
        assert!(count
            .predicates
            .iter()
            .any(|predicate| predicate.field == "regions.name" && predicate.value == "LATAM"));
        assert!(!count
            .predicates
            .iter()
            .any(|predicate| predicate.field == "customers.external_code"));
        assert!(graph_runtime_query_frame_final_sql_allowed(
            true,
            &entities,
            &fields,
            &samples,
            "how many active customers are in LATAM",
            &count
        ));

        let total = graph_query_frame_trace(
            "total order amount for Acme 4744",
            &entities,
            &fields,
            &relationships,
            &samples,
        );
        assert!(total.routed, "{total:?}");
        assert_eq!(
            total.projection.as_ref().and_then(|p| p.field.as_deref()),
            Some("orders.amount")
        );
        assert!(
            total
                .predicates
                .iter()
                .any(|predicate| predicate.field == "customers.name"
                    && predicate.value == "Acme 4744")
        );

        let sum_paraphrase = graph_query_frame_trace(
            "sum of orders for Acme 4744",
            &entities,
            &fields,
            &relationships,
            &samples,
        );
        assert!(sum_paraphrase.routed, "{sum_paraphrase:?}");
        assert_eq!(
            sum_paraphrase
                .projection
                .as_ref()
                .and_then(|p| p.field.as_deref()),
            Some("orders.amount")
        );
        assert!(
            sum_paraphrase
                .projection
                .as_ref()
                .map(|projection| projection.expression.starts_with("SUM("))
                .unwrap_or(false),
            "{sum_paraphrase:?}"
        );

        let avg_paraphrase = graph_query_frame_trace(
            "avg order amount for LATAM customers",
            &entities,
            &fields,
            &relationships,
            &samples,
        );
        assert!(avg_paraphrase.routed, "{avg_paraphrase:?}");
        assert!(
            avg_paraphrase
                .projection
                .as_ref()
                .map(|projection| projection.expression.starts_with("AVG("))
                .unwrap_or(false),
            "{avg_paraphrase:?}"
        );

        let date_lookup = graph_query_frame_trace(
            "orders placed on 2024-02-13",
            &entities,
            &fields,
            &relationships,
            &samples,
        );
        assert_eq!(
            date_lookup
                .projection
                .as_ref()
                .and_then(|p| p.field.as_deref()),
            Some("orders.id")
        );

        let external_code_lookup = graph_query_frame_trace(
            "customer with external code 00D4",
            &entities,
            &fields,
            &relationships,
            &samples,
        );
        assert!(external_code_lookup.routed, "{external_code_lookup:?}");
        assert_eq!(
            external_code_lookup
                .projection
                .as_ref()
                .and_then(|p| p.field.as_deref()),
            Some("customers.name")
        );
        let atlas =
            RuntimeSemanticAtlas::from_rows(&entities, &fields, &relationships, &samples, &[]);
        assert!(!runtime_prompt_requested_projection_missing(
            "customer with external code 00D4",
            &external_code_lookup,
            &atlas,
        ));

        let grouped = graph_query_frame_trace(
            "top 2 products by order amount",
            &entities,
            &fields,
            &relationships,
            &samples,
        );
        assert!(grouped.routed, "{grouped:?}");
        assert_eq!(
            grouped.order_by.as_ref().map(|order| order.field.as_str()),
            Some("orders.amount")
        );
        assert_eq!(grouped.order_by.as_ref().map(|order| order.limit), Some(2));
        let grouped_sql = grouped.sql.as_deref().unwrap_or_default();
        assert!(
            grouped_sql.contains("SUM(\"orders\".\"amount\") AS total_amount"),
            "{grouped_sql}"
        );
        assert!(
            grouped_sql.contains("GROUP BY \"products\".\"name\""),
            "{grouped_sql}"
        );
        assert!(
            grouped_sql.contains("ORDER BY total_amount DESC LIMIT 2"),
            "{grouped_sql}"
        );

        let highest_paraphrase = graph_query_frame_trace(
            "which 2 products have the highest order amount",
            &entities,
            &fields,
            &relationships,
            &samples,
        );
        assert!(highest_paraphrase.routed, "{highest_paraphrase:?}");
        assert_eq!(
            highest_paraphrase
                .projection
                .as_ref()
                .and_then(|p| p.field.as_deref()),
            Some("products.name")
        );
        let sql = highest_paraphrase.sql.as_deref().unwrap_or_default();
        assert!(sql.contains("SUM(\"orders\".\"amount\") AS total_amount"));
        assert!(sql.contains("GROUP BY \"products\".\"name\""));
        assert!(sql.contains("ORDER BY total_amount DESC LIMIT 2"));
        assert_eq!(
            highest_paraphrase
                .order_by
                .as_ref()
                .map(|order| order.limit),
            Some(2)
        );
    }

