    #[test]
    fn runtime_query_frame_treats_top_n_number_as_limit_not_predicate() {
        let entities = ["catalog_items", "sales"]
            .into_iter()
            .map(entity_row)
            .collect::<Vec<_>>();
        let fields = vec![
            typed_field_row("catalog_items", "id", "INTEGER"),
            field_row("catalog_items", "name"),
            typed_field_row("sales", "id", "INTEGER"),
            typed_field_row("sales", "item_id", "INTEGER"),
            typed_field_row("sales", "amount", "REAL"),
        ];
        let relationships = vec![relationship_row("sales", "item_id", "catalog_items")];
        let samples = vec![
            sample_row("catalog_items.name", &["Atlas 561", "Beacon 941"]),
            sample_row("sales.amount", &["75.25", "120.5", "200"]),
            sample_row("sales.item_id", &["10", "11"]),
        ];

        let grouped = graph_query_frame_trace(
            "top 2 items by sale amount",
            &entities,
            &fields,
            &relationships,
            &samples,
        );

        assert!(grouped.routed, "{grouped:?}");
        assert!(!grouped
            .predicates
            .iter()
            .any(|predicate| predicate.field == "sales.amount" && predicate.value == "2"));
        assert_eq!(grouped.order_by.as_ref().map(|order| order.limit), Some(2));
        let sql = grouped.sql.as_deref().unwrap_or_default();
        assert!(sql.contains("SUM(\"sales\".\"amount\") AS total_amount"));
        assert!(sql.contains("GROUP BY \"catalog_items\".\"name\""));
        assert!(sql.contains("ORDER BY total_amount DESC LIMIT 2"));
    }

