    #[test]
    fn runtime_query_frame_routes_score_date_and_source_vocab_reason() {
        let entities = ["orders", "archived_orders", "customer_profiles"]
            .into_iter()
            .map(entity_row)
            .collect::<Vec<_>>();
        let fields = vec![
            typed_field_row("orders", "id", "INTEGER"),
            field_row("orders", "description"),
            typed_field_row("orders", "score", "REAL"),
            typed_field_row("orders", "event_date", "DATE"),
            field_row("orders", "source_reason"),
            typed_field_row("archived_orders", "id", "INTEGER"),
            field_row("archived_orders", "description"),
            typed_field_row("archived_orders", "score", "REAL"),
            typed_field_row("archived_orders", "event_date", "DATE"),
            field_row("archived_orders", "source_reason"),
            typed_field_row("customer_profiles", "last_order_amount", "REAL"),
        ];
        let vocabulary = vec![VocabularyEntry {
            term: "velocity".to_string(),
            canonical_kind: "enum_value".to_string(),
            canonical_value: "orders.source_reason:R".to_string(),
            confidence: 0.86,
            source_layer: 3,
        }];
        let samples = Vec::new();
        let question = "show orders with score 20 from yesterday tagged velocity";

        let trace = graph_query_frame_trace_with_vocab(
            question,
            &entities,
            &fields,
            &[],
            &samples,
            &vocabulary,
        );

        assert!(trace.routed, "{trace:?}");
        assert_eq!(
            trace.projection.as_ref().and_then(|p| p.field.as_deref()),
            Some("orders.id")
        );
        assert!(trace
            .predicates
            .iter()
            .any(|predicate| predicate.field == "orders.score" && predicate.value == "20"));
        assert!(trace.predicates.iter().any(|predicate| {
            predicate.field == "orders.event_date"
                && predicate.value == graph_date_literal_days_from_today(-1)
        }));
        assert!(trace.predicates.iter().any(|predicate| {
            predicate.field == "orders.source_reason" && predicate.value == "R"
        }));
        assert!(!trace
            .predicates
            .iter()
            .any(|predicate| predicate.field == "customer_profiles.last_order_amount"));
        assert!(!graph_prompt_should_never_model_fallback(question, &fields));
        assert!(!graph_generic_route_has_unsafe_terms(question, &trace));
        assert!(trace.joins.len() <= 3, "{trace:?}");
        assert!(graph_projection_is_generic_safe(
            question,
            trace.projection.as_ref().unwrap(),
            &fields
        ));
        let field_map = graph_field_map(&fields);
        for predicate in &trace.predicates {
            let field = field_map.get(&predicate.field).unwrap();
            assert!(
                graph_predicate_value_is_grounded_with_vocab(
                    question,
                    predicate,
                    field,
                    &samples,
                    &vocabulary
                ),
                "{predicate:?}"
            );
        }
        assert!(graph_runtime_query_frame_final_sql_allowed_with_vocab(
            true,
            &entities,
            &fields,
            &samples,
            &vocabulary,
            question,
            &trace
        ));
    }

