        let vocabulary = vec![
            VocabularyEntry {
                term: "held".to_string(),
                canonical_kind: "scope_predicate".to_string(),
                canonical_value:
                    r#"{"scope":"jobs.held","field":"jobs.is_released","operator":"=","rawValue":"0"}"#
                        .to_string(),
                confidence: 0.78,
                source_layer: 3,
            },
            VocabularyEntry {
                term: "held".to_string(),
                canonical_kind: "scope_predicate".to_string(),
                canonical_value:
                    r#"{"scope":"jobs.held","field":"jobs.needs_review","operator":"!=","rawValue":"0"}"#
                        .to_string(),
                confidence: 0.78,
                source_layer: 3,
            },
            VocabularyEntry {
                term: "held".to_string(),
                canonical_kind: "scope_predicate".to_string(),
                canonical_value:
                    r#"{"scope":"jobs.held","field":"jobs.review_score","operator":">","rawValue":"0"}"#
                        .to_string(),
                confidence: 0.78,
                source_layer: 3,
            },
        ];
        let samples = Vec::new();
