    fn runtime_query_frame_prefers_explicit_scope_entity_phrase() {
        let entities = ["jobs", "archived_jobs"]
            .into_iter()
            .map(entity_row)
            .collect::<Vec<_>>();
        let fields = vec![
            typed_field_row("jobs", "id", "INTEGER"),
            typed_field_row("jobs", "is_released", "INTEGER"),
            typed_field_row("jobs", "review_score", "REAL"),
            typed_field_row("jobs", "needs_review", "INTEGER"),
            typed_field_row("archived_jobs", "id", "INTEGER"),
            typed_field_row("archived_jobs", "needs_review", "INTEGER"),
        ];
        let vocabulary = vec![
            VocabularyEntry {
                term: "held".to_string(),
                canonical_kind: "scope_predicate".to_string(),
                canonical_value:
                    r#"{"scope":"archived_jobs.held","field":"archived_jobs.needs_review","operator":"!=","rawValue":"0"}"#
                        .to_string(),
                confidence: 0.78,
                source_layer: 3,
            },
            VocabularyEntry {
                term: "held".to_string(),
                canonical_kind: "scope_predicate".to_string(),
                canonical_value:
                    r#"{"scope":"jobs.held","field":"jobs.is_released","operator":"=","rawValue":"0"}"#
                        .to_string(),
                confidence: 0.78,
                source_layer: 3,
            },
            VocabularyEntry {
                term: "held".to_string(),
                canonical_kind: "scope_predicate".to_string(),
                canonical_value:
                    r#"{"scope":"jobs.held","field":"jobs.needs_review","operator":"!=","rawValue":"0"}"#
                        .to_string(),
                confidence: 0.78,
                source_layer: 3,
            },
            VocabularyEntry {
                term: "held".to_string(),
                canonical_kind: "scope_predicate".to_string(),
                canonical_value:
                    r#"{"scope":"jobs.held","field":"jobs.review_score","operator":">","rawValue":"0"}"#
                        .to_string(),
                confidence: 0.78,
                source_layer: 3,
            },
        ];
        let samples = Vec::new();
        let question = "show held archived jobs";

        let trace = graph_query_frame_trace_with_vocab(
            question,
            &entities,
            &fields,
            &[],
            &samples,
            &vocabulary,
        );

        assert!(trace.routed, "{trace:?}");
        assert_eq!(trace.predicates.len(), 1, "{trace:?}");
        assert_eq!(trace.predicates[0].field, "archived_jobs.needs_review");
        assert_eq!(trace.predicates[0].operator, "!=");
        assert_eq!(trace.predicates[0].value, "0");
    }

    #[test]
    fn runtime_query_frame_uses_vocab_field_aliases_for_projection() {
        let entities = ["orders"].into_iter().map(entity_row).collect::<Vec<_>>();
        let fields = vec![
            typed_field_row("orders", "id", "INTEGER"),
            typed_field_row("orders", "amount", "REAL"),
            typed_field_row("orders", "event_date", "DATE"),
        ];
        let vocabulary = vec![VocabularyEntry {
            term: "turnover".to_string(),
            canonical_kind: "field".to_string(),
            canonical_value: "orders.amount".to_string(),
            confidence: 0.68,
            source_layer: 3,
        }];
        let samples = Vec::new();
        let question = "total turnover for orders yesterday";

        let trace = graph_query_frame_trace_with_vocab(
            question,
            &entities,
            &fields,
            &[],
            &samples,
            &vocabulary,
        );

        assert!(trace.routed, "{trace:?}");
        assert_eq!(
            trace.projection.as_ref().and_then(|p| p.field.as_deref()),
            Some("orders.amount")
        );
        assert!(trace
            .projection
            .as_ref()
            .is_some_and(|projection| projection.expression.starts_with("SUM(")));
        assert!(trace.predicates.iter().any(|predicate| {
            predicate.field == "orders.event_date"
                && predicate.value == graph_date_literal_days_from_today(-1)
        }));
        assert!(!graph_prompt_should_never_model_fallback(question, &fields));
        assert!(!graph_generic_route_has_unsafe_terms(question, &trace));
        assert!(graph_projection_is_generic_safe(
            question,
            trace.projection.as_ref().unwrap(),
            &fields
        ));
        let field_map = graph_field_map(&fields);
        for predicate in &trace.predicates {
            let field = field_map.get(&predicate.field).unwrap();
            assert!(
                graph_predicate_value_is_grounded_with_vocab(
                    question,
                    predicate,
                    field,
                    &samples,
                    &vocabulary
                ),
                "{predicate:?}"
            );
        }
        assert!(
            graph_runtime_query_frame_generic_safe_with_vocab(
                question,
                &trace,
                &fields,
                &samples,
                &vocabulary
            ),
            "{trace:?}"
        );
        assert!(graph_runtime_query_frame_final_sql_allowed_with_vocab(
            true,
            &entities,
            &fields,
            &samples,
            &vocabulary,
            question,
            &trace
        ));
    }

    #[test]
    fn runtime_query_frame_fails_closed_for_underspecified_generic_prompts() {
        let fields = vec![
            field_row("customers", "name"),
            field_row("customers", "status"),
            field_row("products", "name"),
            typed_field_row("orders", "amount", "REAL"),
        ];
        let status_trace =
            RuntimeQueryFrameTrace::rejected("show status", "not_routed_no_predicates");
        assert!(graph_model_fallback_should_fail_closed(
            "show status",
            &status_trace,
            &fields
        ));
        let ambiguous =
            RuntimeQueryFrameTrace::rejected("average amount by name", "not_routed_no_predicates");
        assert!(graph_model_fallback_should_fail_closed(
            "average amount by name",
            &ambiguous,
            &fields
        ));
    }

