    #[test]
    fn graph_query_frame_routes_exact_value_lookup_with_join() {
        let dir = tempdir().unwrap();
        let path = dir.path().join("products.semsql");
        let conn = writer(&path).unwrap();
        for (entity, table) in [
            ("products", "products"),
            ("product_statuses", "product_statuses"),
        ] {
            insert_entity(
                &conn,
                EntityInsert {
                    canonical_name: entity,
                    db_table: table,
                    db_schema: None,
                    singular_label: Some(entity),
                    plural_label: Some(entity),
                },
            )
            .unwrap();
        }
        for (entity, field, db_column, display_label) in [
            ("products", "product_code", "product_code", "Product Code"),
            ("products", "name", "name", "Name"),
            (
                "product_statuses",
                "product_code",
                "product_code",
                "Product Code",
            ),
            ("product_statuses", "status", "status", "Status"),
        ] {
            insert_field(
                &conn,
                FieldInsert {
                    entity,
                    field,
                    db_column,
                    field_type: "TEXT",
                    display_label: Some(display_label),
                    enum_canonical: None,
                    unit_canonical: None,
                },
            )
            .unwrap();
        }
        insert_relationship(
            &conn,
            RelationshipInsert {
                from_entity: "product_statuses",
                from_field: "product_code",
                to_entity: "products",
                to_field: "product_code",
                kind: "many_to_one",
                relation_name: None,
            },
        )
        .unwrap();
        insert_sample_values(
            &conn,
            SampleValuesInsert {
                field_canonical: "products.name",
                examples_json: r#"["Cloud Console"]"#,
                pii_redacted: false,
            },
        )
        .unwrap();
        drop(conn);

        let cascade = Cascade::load(&path, None).unwrap();
        let outcome = cascade
            .run(r#"What is the status of product "Cloud Console"?"#)
            .unwrap();
        assert_eq!(
            outcome.sql_text,
            "SELECT \"product_statuses\".\"status\" FROM \"product_statuses\" INNER JOIN \"products\" ON \"product_statuses\".\"product_code\" = \"products\".\"product_code\" WHERE \"products\".\"name\" = 'Cloud Console'"
        );
        let trace = outcome.runtime_query_frame.as_ref().unwrap();
        assert!(trace.routed);
        assert!(trace.used_for_final_sql);
        assert_eq!(trace.route_reason, "routed");
        assert_eq!(trace.predicates[0].field, "products.name");
        assert_eq!(trace.joins[0].from_entity, "product_statuses");
    }

