    #[test]
    fn graph_query_frame_routes_metric_ratio_ordered_lookup_with_join() {
        let dir = tempdir().unwrap();
        let path = dir.path().join("metric_join.semsql");
        let conn = writer(&path).unwrap();
        for (entity, table, singular, plural) in [
            ("schools", "schools", "school", "schools"),
            (
                "score_metrics",
                "score_metrics",
                "score metric",
                "score metrics",
            ),
        ] {
            insert_entity(
                &conn,
                EntityInsert {
                    canonical_name: entity,
                    db_table: table,
                    db_schema: None,
                    singular_label: Some(singular),
                    plural_label: Some(plural),
                },
            )
            .unwrap();
        }
        for (entity, field, db_column, field_type, label) in [
            ("schools", "cds_code", "cds_code", "TEXT", "School Code"),
            ("schools", "phone", "phone", "TEXT", "Phone"),
            (
                "score_metrics",
                "cds_code",
                "cds_code",
                "TEXT",
                "School Code",
            ),
            (
                "score_metrics",
                "num_ge_1500",
                "NumGE1500",
                "INTEGER",
                "Number of Test Takers Whose Total SAT Scores Are Greater or Equal to 1500",
            ),
            (
                "score_metrics",
                "num_test_takers",
                "NumTstTakr",
                "INTEGER",
                "Number of Test Takers",
            ),
        ] {
            insert_field(
                &conn,
                FieldInsert {
                    entity,
                    field,
                    db_column,
                    field_type,
                    display_label: Some(label),
                    enum_canonical: None,
                    unit_canonical: None,
                },
            )
            .unwrap();
        }
        insert_relationship(
            &conn,
            RelationshipInsert {
                from_entity: "score_metrics",
                from_field: "cds_code",
                to_entity: "schools",
                to_field: "cds_code",
                kind: "many_to_one",
                relation_name: None,
            },
        )
        .unwrap();
        drop(conn);

        let cascade = Cascade::load(&path, None).unwrap();
        let outcome = cascade
            .run_with_options(
                "Please list the phone numbers of the schools with the top 3 SAT excellence rate.",
                &CascadeRunOptions {
                    capture_runtime_query_frame: true,
                    ..CascadeRunOptions::default()
                },
            )
            .unwrap();
        let trace = outcome.runtime_query_frame.as_ref().unwrap();
        assert_eq!(trace.source, "runtime_graph_query_frame_metric");
        assert!(trace.used_for_final_sql, "{trace:?}");
        assert_eq!(
            outcome.sql_text,
            "SELECT \"schools\".\"phone\" FROM \"schools\" INNER JOIN \"score_metrics\" ON \"schools\".\"cds_code\" = \"score_metrics\".\"cds_code\" WHERE CAST(\"score_metrics\".\"NumGE1500\" AS REAL) / \"score_metrics\".\"NumTstTakr\" IS NOT NULL ORDER BY CAST(\"score_metrics\".\"NumGE1500\" AS REAL) / \"score_metrics\".\"NumTstTakr\" DESC LIMIT 3"
        );

        let top_measure_query = "What is the phone number of the school that has the highest number of test takers with an SAT score of over 1500?";
        let trace = cascade.graph_query_frame_trace(top_measure_query);
        assert!(trace.routed, "{trace:?}");
        assert!(
            cascade.runtime_query_frame_final_sql_allowed(top_measure_query, &trace),
            "{trace:?}"
        );
        let outcome = cascade
            .run_with_options(
                top_measure_query,
                &CascadeRunOptions {
                    capture_runtime_query_frame: true,
                    ..CascadeRunOptions::default()
                },
            )
            .unwrap();
        let trace = outcome.runtime_query_frame.as_ref().unwrap();
        assert_eq!(trace.source, "runtime_graph_query_frame");
        assert!(trace.used_for_final_sql, "{trace:?}");
        assert_eq!(
            outcome.sql_text,
            "SELECT \"schools\".\"phone\" FROM \"schools\" INNER JOIN \"score_metrics\" ON \"schools\".\"cds_code\" = \"score_metrics\".\"cds_code\" ORDER BY \"score_metrics\".\"NumGE1500\" DESC LIMIT 1"
        );
    }

