    #[test]
    fn predicate_operator_is_adjacent_to_slot() {
        let skeleton = "SELECT * FROM @entity1 INNER JOIN @entity2 ON @field1 = @field2 WHERE @field3 = @val1 AND @field4 > @val2 AND @field5 BETWEEN @val3 AND @val4";
        assert_eq!(
            predicate_operator_for_slot(skeleton, "@field4"),
            Some(">".to_string())
        );
        assert_eq!(
            predicate_operator_for_slot(skeleton, "@val2"),
            Some(">".to_string())
        );
        assert_eq!(
            predicate_operator_for_slot(skeleton, "@field5"),
            Some("BETWEEN".to_string())
        );
        assert_eq!(
            predicate_operator_for_slot(skeleton, "@val3"),
            Some("BETWEEN".to_string())
        );
        assert_eq!(
            predicate_operator_for_slot(skeleton, "@val4"),
            Some("BETWEEN".to_string())
        );
    }

    #[test]
    fn field_slot_role_detects_join_keys() {
        let skeleton = "SELECT @field3 FROM @entity1 INNER JOIN @entity2 ON @field1 = @field2 WHERE @field4 = @val1";
        assert!(field_slot_is_join_key(skeleton, "@field1"));
        assert!(field_slot_is_join_key(skeleton, "@field2"));
        assert!(!field_slot_is_join_key(skeleton, "@field3"));
        assert!(!field_slot_is_join_key(skeleton, "@field4"));
    }

    #[test]
    fn slot_role_parser_classifies_common_slots() {
        let skeleton = "SELECT @field3 FROM @entity1 INNER JOIN @entity2 ON @field1 = @field2 WHERE @field4 = @val1 GROUP BY @field5 ORDER BY @field6 DESC LIMIT @val2";
        assert_eq!(slot_role_for(skeleton, "@field1"), "join_key");
        assert_eq!(slot_role_for(skeleton, "@field2"), "join_key");
        assert_eq!(slot_role_for(skeleton, "@field3"), "projection_field");
        assert_eq!(slot_role_for(skeleton, "@field4"), "predicate_field");
        assert_eq!(slot_role_for(skeleton, "@val1"), "predicate_value");
        assert_eq!(slot_role_for(skeleton, "@field5"), "group_field");
        assert_eq!(slot_role_for(skeleton, "@field6"), "order_field");
        assert_eq!(slot_role_for(skeleton, "@val2"), "limit_value");
    }

    #[test]
    fn query_frame_trace_groups_pre_stage3_slots_and_candidates() {
        let linked = LinkerOutput {
            top_entities: vec!["users".to_string()],
            top_fields: vec!["users.name".to_string(), "users.status".to_string()],
            top_score: 1.0,
        };
        let slots = vec![
            SlotInput {
                slot_name: "@field1".to_string(),
                candidates: vec!["users.name".to_string()],
                slot_role: "projection_field".to_string(),
                context_window: "SELECT @field1 FROM @entity1".to_string(),
                ..Default::default()
            },
            SlotInput {
                slot_name: "@field2".to_string(),
                candidates: vec!["users.status".to_string()],
                slot_role: "predicate_field".to_string(),
                predicate_operator: Some("=".to_string()),
                context_window: "WHERE @field2 = @val1".to_string(),
                ..Default::default()
            },
            SlotInput {
                slot_name: "@val1".to_string(),
                candidates: vec!["'active'".to_string()],
                candidate_source_fields: vec![vec!["users.status".to_string()]],
                slot_role: "predicate_value".to_string(),
                predicate_operator: Some("=".to_string()),
                predicate_field_slot: Some("@field2".to_string()),
                context_window: "WHERE @field2 = @val1".to_string(),
                ..Default::default()
            },
        ];

        let frame = build_query_frame_trace(
            "active users",
            "SELECT @field1 FROM @entity1 WHERE @field2 = @val1",
            &linked,
            &slots,
        );

        assert_eq!(frame.source, "pre_stage3_slot_inputs");
        assert!(frame
            .mentions
            .iter()
            .any(|mention| mention.kind == "enum_keyword" && mention.normalized == "active"));
        assert_eq!(frame.frame.projections[0].slot, "@field1");
        assert_eq!(frame.frame.predicates[0].slot, "@field2");
        assert_eq!(frame.frame.predicates[1].slot, "@val1");
        assert_eq!(
            frame.frame.predicates[1].predicate_field_slot.as_deref(),
            Some("@field2")
        );
        assert_eq!(frame.slots[2].candidates[0].value, "'active'");
        assert_eq!(
            frame.slots[2].candidates[0].source_fields,
            vec!["users.status".to_string()]
        );
    }

