    #[test]
    fn join_injection_single_hop() {
        use super::{inject_join_if_needed, RelationshipRow};
        let edges = vec![RelationshipRow {
            from_entity: "order_scores".into(),
            from_field: "cds".into(),
            to_entity: "customers".into(),
            to_field: "cds_code".into(),
            kind: "many_to_one".into(),
        }];
        let sql = "SELECT customers.customer FROM order_scores WHERE order_scores.math > 400";
        let out = inject_join_if_needed(sql, &edges);
        assert!(
            out.contains("INNER JOIN customers ON customers.cds_code = order_scores.cds"),
            "{out}"
        );
    }

