    #[test]
    fn join_injection_extends_existing_join_chain() {
        use super::{inject_join_if_needed, RelationshipRow};
        let edges = vec![RelationshipRow {
            from_entity: "order_scores".into(),
            from_field: "cds".into(),
            to_entity: "customers".into(),
            to_field: "cds_code".into(),
            kind: "many_to_one".into(),
        }];
        let sql = "SELECT customers.name, order_scores.numtsttakr FROM customer_metrics INNER JOIN customers ON customers.cds_code = customer_metrics.cds_code WHERE order_scores.numtsttakr > 100";
        let out = inject_join_if_needed(sql, &edges);
        assert!(
            out.contains("INNER JOIN order_scores ON order_scores.cds = customers.cds_code"),
            "{out}"
        );
        assert!(
            out.find("INNER JOIN order_scores").unwrap() < out.find(" WHERE ").unwrap(),
            "{out}"
        );
    }

