    #[test]
    fn quotes_reserved_entity_names_without_clobbering_order_by() {
        use super::quote_reserved_entity_references;
        let mut col_map = std::collections::HashMap::new();
        col_map.insert("order.account_id".to_string(), "account_id".to_string());
        col_map.insert("account.account_id".to_string(), "account_id".to_string());

        let sql = "SELECT order.account_id FROM order INNER JOIN account ON account.account_id = order.account_id ORDER BY order.account_id";
        let out = quote_reserved_entity_references(sql, &col_map);

        assert!(out.contains("SELECT `order`.account_id"), "{out}");
        assert!(out.contains("FROM `order` INNER JOIN account"), "{out}");
        assert!(out.contains("ORDER BY `order`.account_id"), "{out}");
        assert!(!out.contains("`order` BY"), "{out}");
    }

    #[test]
    fn reserved_entity_quote_makes_match_surface_parseable() {
        use super::quote_reserved_entity_references;
        let mut col_map = std::collections::HashMap::new();
        col_map.insert("match.id".to_string(), "id".to_string());
        col_map.insert("match.league_id".to_string(), "league_id".to_string());
        col_map.insert("league.id".to_string(), "id".to_string());
        col_map.insert("league.name".to_string(), "name".to_string());

        let sql =
            "SELECT COUNT(match.id) FROM match INNER JOIN league ON league.id = match.league_id";
        let quoted = quote_reserved_entity_references(sql, &col_map);

        assert!(quoted.contains("COUNT(`match`.id)"), "{quoted}");
        assert!(
            quoted.contains("FROM `match` INNER JOIN league"),
            "{quoted}"
        );
        assert!(semsql_natsql::validate_select_sql_surface(&quoted).is_ok());
    }

