    #[test]
    #[cfg(feature = "onnx")]
    fn list_query_distinct_repair_skips_aggregates() {
        use super::add_distinct_for_list_query;
        let sql = "SELECT bond.molecule_id FROM bond WHERE bond.bond_type = '#'";
        assert_eq!(
            add_distinct_for_list_query("List the molecules with triple bonds.", sql),
            sql
        );
        assert_eq!(
            add_distinct_for_list_query("List the distinct molecules with triple bonds.", sql),
            "SELECT DISTINCT bond.molecule_id FROM bond WHERE bond.bond_type = '#'"
        );
        let aggregate = "SELECT COUNT(bond.molecule_id) FROM bond";
        assert_eq!(
            add_distinct_for_list_query("How many molecules have bonds?", aggregate),
            aggregate
        );
        let phone = "SELECT customers.phone FROM customers";
        assert_eq!(
            add_distinct_for_list_query("Please list the phone numbers.", phone),
            phone
        );
        let badges = "SELECT badges.name FROM badges WHERE badges.date = '2010-07-19'";
        assert_eq!(
            add_distinct_for_list_query("Please list the names of badges.", badges),
            badges
        );
        let thrombosis =
            "SELECT patient.id FROM patient INNER JOIN laboratory ON laboratory.id = patient.id WHERE laboratory.cpk < 250 AND patient.admission = '-'";
        assert_eq!(
            add_distinct_for_list_query(
                "List all outpatient within normal range of creatinine phosphokinase. Give me the distinct ids.",
                thrombosis
            ),
            "SELECT DISTINCT patient.id FROM patient INNER JOIN laboratory ON laboratory.id = patient.id WHERE laboratory.cpk < 250 AND patient.admission = '-'"
        );
    }

    #[test]
    #[cfg(feature = "onnx")]
    fn count_distinct_repair_targets_joined_entity_key_counts() {
        use super::add_count_distinct_for_joined_entity_key_count;

        let district_count = "SELECT COUNT(district.district_id) FROM district INNER JOIN client ON client.district_id = district.district_id WHERE client.gender = 'F' AND district.a11 BETWEEN 6000 AND 10000";
        assert_eq!(
            add_count_distinct_for_joined_entity_key_count(
                "List out the no. of districts that have female average salary is more than 6000 but less than 10000?",
                district_count,
            ),
            "SELECT COUNT(DISTINCT district.district_id) FROM district INNER JOIN client ON client.district_id = district.district_id WHERE client.gender = 'F' AND district.a11 BETWEEN 6000 AND 10000"
        );

        let no_join = "SELECT COUNT(district.district_id) FROM district WHERE district.a11 BETWEEN 6000 AND 10000";
        assert_eq!(
            add_count_distinct_for_joined_entity_key_count(
                "How many districts have average salary between 6000 and 10000?",
                no_join,
            ),
            no_join
        );

        let percentage = "SELECT CAST(SUM(CASE WHEN products.color = 'black' THEN 1 ELSE 0 END) AS REAL) * 100 / COUNT(products.id) FROM products INNER JOIN product_statuses ON products.uuid = product_statuses.uuid";
        assert_eq!(
            add_count_distinct_for_joined_entity_key_count(
                "What percentage of products have black border?",
                percentage,
            ),
            percentage
        );
    }

