    #[test]
    fn renderability_repair_rewrites_invalid_field_to_unique_scoped_owner() {
        use super::repair_invalid_scoped_references;
        let mut col_map = std::collections::HashMap::new();
        col_map.insert("member.first_name".to_string(), "first_name".to_string());
        col_map.insert("member.last_name".to_string(), "last_name".to_string());
        col_map.insert(
            "member.link_to_major".to_string(),
            "link_to_major".to_string(),
        );
        col_map.insert("major.major_id".to_string(), "major_id".to_string());
        col_map.insert("major.college".to_string(), "college".to_string());

        let sql = "SELECT member.first_name, member.college, member.last_name FROM member INNER JOIN major ON major.major_id = member.link_to_major WHERE member.first_name = 'Ann'";
        let out = repair_invalid_scoped_references(sql, &col_map);

        assert!(out.contains("major.college"), "{out}");
        assert!(!out.contains("member.college"), "{out}");
    }

    #[test]
    fn renderability_repair_drops_unjoinable_bad_projection() {
        use super::repair_invalid_scoped_references;
        let mut col_map = std::collections::HashMap::new();
        col_map.insert(
            "team_attributes.team_api_id".to_string(),
            "team_api_id".to_string(),
        );
        col_map.insert(
            "team_attributes.buildupplaydribbling".to_string(),
            "buildUpPlayDribbling".to_string(),
        );
        col_map.insert(
            "team_attributes.chancecreationpassing".to_string(),
            "chanceCreationPassing".to_string(),
        );

        let sql = "SELECT player_attributes.dribbling, team_attributes.buildupplaydribbling, team_attributes.chancecreationpassing FROM team_attributes";
        let out = repair_invalid_scoped_references(sql, &col_map);

        assert_eq!(
            out,
            "SELECT team_attributes.buildupplaydribbling, team_attributes.chancecreationpassing FROM team_attributes"
        );
    }

